// arithmetic provides arithmetic operations for Uint objects.
// This includes basic binary operations such as addition, subtraction, multiplication, division, and modulo operations
// as well as overflow checks, and negation. These functions are essential for numeric
// calculations using 256-bit unsigned integers.
package uint256

import "math/bits"

// Add sets z to the sum x+y and returns z.
func (z *Uint) Add(x, y *Uint) *Uint {
	var carry uint64
	z[0], carry = bits.Add64(x[0], y[0], 0)
	z[1], carry = bits.Add64(x[1], y[1], carry)
	z[2], carry = bits.Add64(x[2], y[2], carry)
	z[3], _ = bits.Add64(x[3], y[3], carry)
	return z
}

// AddOverflow sets z to the sum x+y and returns z and true if overflow occurred.
func (z *Uint) AddOverflow(x, y *Uint) (*Uint, bool) {
	var carry uint64
	z[0], carry = bits.Add64(x[0], y[0], 0)
	z[1], carry = bits.Add64(x[1], y[1], carry)
	z[2], carry = bits.Add64(x[2], y[2], carry)
	z[3], carry = bits.Add64(x[3], y[3], carry)
	return z, carry != 0
}

// Sub sets z to the difference x-y and returns z.
func (z *Uint) Sub(x, y *Uint) *Uint {
	var carry uint64
	z[0], carry = bits.Sub64(x[0], y[0], 0)
	z[1], carry = bits.Sub64(x[1], y[1], carry)
	z[2], carry = bits.Sub64(x[2], y[2], carry)
	z[3], _ = bits.Sub64(x[3], y[3], carry)
	return z
}

// SubOverflow sets z to the difference x-y and returns z and true if underflow occurred.
func (z *Uint) SubOverflow(x, y *Uint) (*Uint, bool) {
	var carry uint64
	z[0], carry = bits.Sub64(x[0], y[0], 0)
	z[1], carry = bits.Sub64(x[1], y[1], carry)
	z[2], carry = bits.Sub64(x[2], y[2], carry)
	z[3], carry = bits.Sub64(x[3], y[3], carry)
	return z, carry != 0
}

// Neg returns -x mod 2^256.
func (z *Uint) Neg(x *Uint) *Uint {
	return z.Sub(Zero(), x)
}

// Mul sets z to the product x*y and returns z.
func (z *Uint) Mul(x, y *Uint) *Uint {
	var (
		res              Uint
		carry            uint64
		res1, res2, res3 uint64
	)

	carry, res[0] = bits.Mul64(x[0], y[0])
	carry, res1 = umulHop(carry, x[1], y[0])
	carry, res2 = umulHop(carry, x[2], y[0])
	res3 = x[3]*y[0] + carry

	carry, res[1] = umulHop(res1, x[0], y[1])
	carry, res2 = umulStep(res2, x[1], y[1], carry)
	res3 = res3 + x[2]*y[1] + carry

	carry, res[2] = umulHop(res2, x[0], y[2])
	res3 = res3 + x[1]*y[2] + carry

	res[3] = res3 + x[0]*y[3]

	return z.Set(&res)
}

// MulOverflow sets z to the product x*y and returns z and true if overflow occurred.
func (z *Uint) MulOverflow(x, y *Uint) (*Uint, bool) {
	p := umul(x, y)
	copy(z[:], p[:4])
	return z, (p[4] | p[5] | p[6] | p[7]) != 0
}

// Div sets z to the quotient x/y and returns z.
// If y == 0, z is set to 0.
func (z *Uint) Div(x, y *Uint) *Uint {
	if y.IsZero() || y.Gt(x) {
		return z.Clear()
	}
	if x.Eq(y) {
		return z.SetOne()
	}
	// Shortcut some cases
	if x.IsUint64() {
		return z.SetUint64(x.Uint64() / y.Uint64())
	}

	// At this point, we know
	// x/y ; x > y > 0

	var quot Uint
	udivrem(quot[:], x[:], y)
	return z.Set(&quot)
}

// Mod sets z to the modulus x%y for y != 0 and returns z.
// If y == 0, z is set to 0 (this differs from big.Int behavior).
func (z *Uint) Mod(x, y *Uint) *Uint {
	if x.IsZero() || y.IsZero() {
		return z.Clear()
	}
	switch x.Cmp(y) {
	case -1:
		// x < y
		copy(z[:], x[:])
		return z
	case 0:
		// x == y
		return z.Clear() // They are equal
	}

	// At this point:
	// x != 0
	// y != 0
	// x > y

	// Shortcut trivial case
	if x.IsUint64() {
		return z.SetUint64(x.Uint64() % y.Uint64())
	}

	var quot Uint
	*z = udivrem(quot[:], x[:], y)
	return z
}

// MulMod sets z to (x * y) mod m and returns z.
// If m == 0, z is set to 0 (this differs from big.Int behavior).
func (z *Uint) MulMod(x, y, m *Uint) *Uint {
	if x.IsZero() || y.IsZero() || m.IsZero() {
		return z.Clear()
	}
	p := umul(x, y)

	if m[3] != 0 {
		mu := Reciprocal(m)
		r := reduce4(p, m, mu)
		return z.Set(&r)
	}

	var (
		pl Uint
		ph Uint
	)

	pl[0], pl[1], pl[2], pl[3] = p[0], p[1], p[2], p[3]
	ph[0], ph[1], ph[2], ph[3] = p[4], p[5], p[6], p[7]

	// If the multiplication is within 256 bits use Mod().
	if ph.IsZero() {
		return z.Mod(&pl, m)
	}

	var quot [8]uint64
	rem := udivrem(quot[:], p[:], m)
	return z.Set(&rem)
}

// DivMod sets z to the quotient x/y and m to the modulus x%y, returning the pair (z, m).
// If y == 0, both z and m are set to 0 (this differs from big.Int behavior).
func (z *Uint) DivMod(x, y, m *Uint) (*Uint, *Uint) {
	if y.IsZero() {
		return z.Clear(), m.Clear()
	}

	switch x.Cmp(y) {
	case -1:
		// x < y
		return z.Clear(), m.Set(x)
	case 0:
		// x == y
		return z.SetOne(), m.Clear()
	}

	// At this point:
	// x != 0
	// y != 0
	// x > y

	// Shortcut trivial case
	if x.IsUint64() {
		x0, y0 := x.Uint64(), y.Uint64()
		return z.SetUint64(x0 / y0), m.SetUint64(x0 % y0)
	}

	var quot Uint
	*m = udivrem(quot[:], x[:], y)
	*z = quot
	return z, m
}

// udivrem divides u by d and produces both quotient and remainder.
// The quotient is stored in provided quot - len(u)-len(d)+1 words.
// It loosely follows the Knuth's division algorithm (sometimes referenced as "schoolbook" division) using 64-bit words.
// See Knuth, Volume 2, section 4.3.1, Algorithm D.
func udivrem(quot, u []uint64, d *Uint) (rem Uint) {
	var dLen int
	for i := len(d) - 1; i >= 0; i-- {
		if d[i] != 0 {
			dLen = i + 1
			break
		}
	}

	shift := uint(bits.LeadingZeros64(d[dLen-1]))

	var dnStorage Uint
	dn := dnStorage[:dLen]
	for i := dLen - 1; i > 0; i-- {
		dn[i] = (d[i] << shift) | (d[i-1] >> (64 - shift))
	}
	dn[0] = d[0] << shift

	var uLen int
	for i := len(u) - 1; i >= 0; i-- {
		if u[i] != 0 {
			uLen = i + 1
			break
		}
	}

	if uLen < dLen {
		copy(rem[:], u)
		return rem
	}

	var unStorage [9]uint64
	un := unStorage[:uLen+1]
	un[uLen] = u[uLen-1] >> (64 - shift)
	for i := uLen - 1; i > 0; i-- {
		un[i] = (u[i] << shift) | (u[i-1] >> (64 - shift))
	}
	un[0] = u[0] << shift

	if dLen == 1 {
		r := udivremBy1(quot, un, dn[0])
		rem.SetUint64(r >> shift)
		return rem
	}

	udivremKnuth(quot, un, dn)

	for i := 0; i < dLen-1; i++ {
		rem[i] = (un[i] >> shift) | (un[i+1] << (64 - shift))
	}
	rem[dLen-1] = un[dLen-1] >> shift

	return rem
}

// umul computes full 256 x 256 -> 512 multiplication.
func umul(x, y *Uint) [8]uint64 {
	var res [8]uint64

	topX := highestNonZeroWord(x)
	topY := highestNonZeroWord(y)

	if topX < 0 || topY < 0 {
		return res
	}

	lenX := topX + 1
	lenY := topY + 1

	for i := 0; i < lenX; i++ {
		xi := x[i]
		if xi == 0 {
			continue
		}
		var carry uint64
		k := i
		for j := 0; j < lenY; j++ {
			hi, lo := bits.Mul64(xi, y[j])
			lo, c := bits.Add64(lo, res[k], 0)
			hi += c
			lo, c = bits.Add64(lo, carry, 0)
			hi += c
			res[k] = lo
			carry = hi
			k++
		}
		res[i+lenY] = carry
	}

	return res
}

// highestNonZeroWord returns the highest index with non-zero value or -1 if the Uint is zero.
func highestNonZeroWord(u *Uint) int {
	for i := 3; i >= 0; i-- {
		if u[i] != 0 {
			return i
		}
	}
	return -1
}

// umulStep computes (hi * 2^64 + lo) = z + (x * y) + carry.
func umulStep(z, x, y, carry uint64) (hi, lo uint64) {
	hi, lo = bits.Mul64(x, y)
	lo, carry = bits.Add64(lo, carry, 0)
	hi += carry
	lo, carry = bits.Add64(lo, z, 0)
	hi += carry
	return hi, lo
}

// umulHop computes (hi * 2^64 + lo) = z + (x * y)
func umulHop(z, x, y uint64) (hi, lo uint64) {
	hi, lo = bits.Mul64(x, y)
	lo, carry := bits.Add64(lo, z, 0)
	hi += carry
	return hi, lo
}

// udivremBy1 divides u by single normalized word d and produces both quotient and remainder.
// The quotient is stored in provided quot.
func udivremBy1(quot, u []uint64, d uint64) (rem uint64) {
	reciprocal := reciprocal2by1(d)
	rem = u[len(u)-1] // Set the top word as remainder.
	for j := len(u) - 2; j >= 0; j-- {
		quot[j], rem = udivrem2by1(rem, u[j], d, reciprocal)
	}
	return rem
}

// udivremKnuth implements the division of u by normalized multiple word d from the Knuth's division algorithm.
// The quotient is stored in provided quot - len(u)-len(d) words.
// Updates u to contain the remainder - len(d) words.
func udivremKnuth(quot, u, d []uint64) {
	dLen := len(d)
	dh := d[dLen-1]
	dl := d[dLen-2]
	reciprocal := reciprocal2by1(dh)

	for j := len(u) - dLen - 1; j >= 0; j-- {
		u2 := u[j+dLen]
		u1 := u[j+dLen-1]
		u0 := u[j+dLen-2]

		var qhat, rhat uint64
		if u2 >= dh { // Division overflows.
			qhat = MAX_UINT64
			// NOTE: Add "qhat one to big" adjustment (not needed for correctness, but helps avoiding "add back" case).
		} else {
			qhat, rhat = udivrem2by1(u2, u1, dh, reciprocal)
			ph, pl := bits.Mul64(qhat, dl)
			if ph > rhat || (ph == rhat && pl > u0) {
				qhat--
				// NOTE: Add "qhat one to big" adjustment (not needed for correctness, but helps avoiding "add back" case).
			}
		}

		// Multiply and subtract.
		borrow := subMulTo(u[j:], d, qhat)
		u[j+dLen] = u2 - borrow
		if u2 < borrow { // Too much subtracted, add back.
			qhat--
			u[j+dLen] += addTo(u[j:], d)
		}

		quot[j] = qhat // Store quotient digit.
	}
}

// isBitSet returns true if bit n-th is set, where n = 0 is LSB.
// The n must be <= 255.
func (z *Uint) isBitSet(n uint) bool {
	return (z[n/64] & (1 << (n % 64))) != 0
}

func (z *Uint) IsOverflow() bool {
	return z.isBitSet(255)
}

// addTo computes x += y.
// Requires len(x) >= len(y).
func addTo(x, y []uint64) uint64 {
	var carry uint64
	for i := 0; i < len(y); i++ {
		x[i], carry = bits.Add64(x[i], y[i], carry)
	}
	return carry
}

// subMulTo computes x -= y * multiplier.
// Requires len(x) >= len(y).
func subMulTo(x, y []uint64, multiplier uint64) uint64 {
	var borrow uint64
	for i := 0; i < len(y); i++ {
		s, carry1 := bits.Sub64(x[i], borrow, 0)
		ph, pl := bits.Mul64(y[i], multiplier)
		t, carry2 := bits.Sub64(s, pl, 0)
		x[i] = t
		borrow = ph + carry1 + carry2
	}
	return borrow
}

// reciprocal2by1 computes <^d, ^0> / d.
func reciprocal2by1(d uint64) uint64 {
	reciprocal, _ := bits.Div64(^d, MAX_UINT64, d)
	return reciprocal
}

// udivrem2by1 divides <uh, ul> / d and produces both quotient and remainder.
// It uses the provided d's reciprocal.
// Implementation ported from https://github.com/chfast/intx and is based on
// "Improved division by invariant integers", Algorithm 4.
func udivrem2by1(uh, ul, d, reciprocal uint64) (quot, rem uint64) {
	qh, ql := bits.Mul64(reciprocal, uh)
	ql, carry := bits.Add64(ql, ul, 0)
	qh, _ = bits.Add64(qh, uh, carry)
	qh++

	r := ul - qh*d

	if r > ql {
		qh--
		r += d
	}

	if r >= d {
		qh++
		r -= d
	}

	return qh, r
}

// MustDiv sets z to the quotient x/y and returns z.
// It panics if y == 0. Used in critical AMM paths where division by zero represents a programming error.
func (z *Uint) MustDiv(x, y *Uint) *Uint {
	if y.IsZero() {
		panic("division by zero")
	}
	return z.Div(x, y)
}

// MustMod sets z to the modulus x%y and returns z.
// It panics if y == 0. Used in critical AMM paths where modulo by zero represents a programming error.
func (z *Uint) MustMod(x, y *Uint) *Uint {
	if y.IsZero() {
		panic("modulo by zero")
	}
	return z.Mod(x, y)
}

// MustMulMod sets z to (x * y) mod m and returns z.
// It panics if m == 0. Used in critical AMM paths where modulo by zero represents a programming error.
func (z *Uint) MustMulMod(x, y, m *Uint) *Uint {
	if m.IsZero() {
		panic("modulo by zero")
	}
	return z.MulMod(x, y, m)
}

// MustDivMod sets z to the quotient x/y and m to the modulus x%y, returning the pair (z, m).
// It panics if y == 0. Used in critical AMM paths where division by zero represents a programming error.
func (z *Uint) MustDivMod(x, y, m *Uint) (*Uint, *Uint) {
	if y.IsZero() {
		panic("division by zero")
	}
	return z.DivMod(x, y, m)
}

// MustMul sets z to the product x*y and returns z.
// It panics on overflow. Used in critical AMM calculations where overflow represents a programming error.
func (z *Uint) MustMul(x, y *Uint) *Uint {
	result, overflow := z.MulOverflow(x, y)
	if overflow {
		panic("uint256: multiplication overflow")
	}
	return result
}

// bitwise contains bitwise operations for Uint instances.
// This file includes functions to perform bitwise AND, OR, XOR, and NOT operations, as well as bit shifting.
// These operations are crucial for manipulating individual bits within a 256-bit unsigned integer.
package uint256

import (
	"math/bits"
)

// Or sets z to the bitwise OR of x and y and returns z.
func (z *Uint) Or(x, y *Uint) *Uint {
	z[0] = x[0] | y[0]
	z[1] = x[1] | y[1]
	z[2] = x[2] | y[2]
	z[3] = x[3] | y[3]
	return z
}

// And sets z to the bitwise AND of x and y and returns z.
func (z *Uint) And(x, y *Uint) *Uint {
	z[0] = x[0] & y[0]
	z[1] = x[1] & y[1]
	z[2] = x[2] & y[2]
	z[3] = x[3] & y[3]
	return z
}

// Not sets z to the bitwise NOT of x and returns z.
func (z *Uint) Not(x *Uint) *Uint {
	z[3], z[2], z[1], z[0] = ^x[3], ^x[2], ^x[1], ^x[0]
	return z
}

// AndNot sets z to x AND NOT y and returns z.
func (z *Uint) AndNot(x, y *Uint) *Uint {
	z[0] = x[0] &^ y[0]
	z[1] = x[1] &^ y[1]
	z[2] = x[2] &^ y[2]
	z[3] = x[3] &^ y[3]
	return z
}

// Xor sets z to the bitwise XOR of x and y and returns z.
func (z *Uint) Xor(x, y *Uint) *Uint {
	z[0] = x[0] ^ y[0]
	z[1] = x[1] ^ y[1]
	z[2] = x[2] ^ y[2]
	z[3] = x[3] ^ y[3]
	return z
}

// Lsh sets z to x left-shifted by n bits and returns z.
// Panics if the shift would cause non-zero bits to overflow.
func (z *Uint) Lsh(x *Uint, n uint) *Uint {
	if x.IsZero() {
		return z.Clear()
	}

	if n == 0 {
		return z.Set(x)
	}

	// overflow check
	if n >= 256 {
		panic("Lsh: overflow")
	}

	// headroom check
	top := -1
	for i := 3; i >= 0; i-- {
		if x[i] != 0 {
			top = i
			break
		}
	}

	usedBits := bits.Len64(x[top])  // 1..64
	msbIndex := top*64 + (usedBits - 1) // 0..255
	headroom := 255 - msbIndex          // 0..255
	if n > uint(headroom) {
		panic("Lsh: overflow")
	}

	// Perform the shift
	return z.lsh(x, n)
}

// lsh performs left shift without overflow checking
func (z *Uint) lsh(x *Uint, n uint) *Uint {
	// n % 64 == 0
	if n&0x3f == 0 {
		switch n {
		case 0:
			return z.Set(x)
		case 64:
			return z.lsh64(x)
		case 128:
			return z.lsh128(x)
		case 192:
			return z.lsh192(x)
		default:
			return z.Clear()
		}
	}
	var a, b uint64
	// Big swaps first
	switch {
	case n > 192:
		z.lsh192(x)
		n -= 192
		goto sh192
	case n > 128:
		z.lsh128(x)
		n -= 128
		goto sh128
	case n > 64:
		z.lsh64(x)
		n -= 64
		goto sh64
	default:
		z.Set(x)
	}

	// remaining shifts
	a = z[0] >> (64 - n)
	z[0] = z[0] << n

sh64:
	b = z[1] >> (64 - n)
	z[1] = (z[1] << n) | a

sh128:
	a = z[2] >> (64 - n)
	z[2] = (z[2] << n) | b

sh192:
	z[3] = (z[3] << n) | a

	return z
}

// Rsh sets z to x right-shifted by n bits and returns z.
// If n >= 256, z is set to 0.
func (z *Uint) Rsh(x *Uint, n uint) *Uint {
	// n % 64 == 0
	if n&0x3f == 0 {
		switch n {
		case 0:
			return z.Set(x)
		case 64:
			return z.rsh64(x)
		case 128:
			return z.rsh128(x)
		case 192:
			return z.rsh192(x)
		default:
			return z.Clear()
		}
	}
	var a, b uint64
	// Big swaps first
	switch {
	case n > 192:
		if n > 256 {
			return z.Clear()
		}
		z.rsh192(x)
		n -= 192
		goto sh192
	case n > 128:
		z.rsh128(x)
		n -= 128
		goto sh128
	case n > 64:
		z.rsh64(x)
		n -= 64
		goto sh64
	default:
		z.Set(x)
	}

	// remaining shifts
	a = z[3] << (64 - n)
	z[3] = z[3] >> n

sh64:
	b = z[2] << (64 - n)
	z[2] = (z[2] >> n) | a

sh128:
	a = z[1] << (64 - n)
	z[1] = (z[1] >> n) | b

sh192:
	z[0] = (z[0] >> n) | a

	return z
}

// SRsh sets z to x arithmetically right-shifted by n bits and returns z.
// It treats x as a signed two's complement integer. For negative values,
// high-order bits are filled with 1s instead of 0s. If n >= 256 and x is negative, z is set to all 1s.
func (z *Uint) SRsh(x *Uint, n uint) *Uint {
	// If the MSB is 0, SRsh is same as Rsh.
	if !x.isBitSet(255) {
		return z.Rsh(x, n)
	}
	if n%64 == 0 {
		switch n {
		case 0:
			return z.Set(x)
		case 64:
			return z.srsh64(x)
		case 128:
			return z.srsh128(x)
		case 192:
			return z.srsh192(x)
		default:
			return z.SetAllOne()
		}
	}
	var a uint64 = MAX_UINT64 << (64 - n%64)
	// Big swaps first
	switch {
	case n > 192:
		if n > 256 {
			return z.SetAllOne()
		}
		z.srsh192(x)
		n -= 192
		goto sh192
	case n > 128:
		z.srsh128(x)
		n -= 128
		goto sh128
	case n > 64:
		z.srsh64(x)
		n -= 64
		goto sh64
	default:
		z.Set(x)
	}

	// remaining shifts
	z[3], a = (z[3]>>n)|a, z[3]<<(64-n)

sh64:
	z[2], a = (z[2]>>n)|a, z[2]<<(64-n)

sh128:
	z[1], a = (z[1]>>n)|a, z[1]<<(64-n)

sh192:
	z[0] = (z[0] >> n) | a

	return z
}

func (z *Uint) lsh64(x *Uint) *Uint {
	z[3], z[2], z[1], z[0] = x[2], x[1], x[0], 0
	return z
}

func (z *Uint) lsh128(x *Uint) *Uint {
	z[3], z[2], z[1], z[0] = x[1], x[0], 0, 0
	return z
}

func (z *Uint) lsh192(x *Uint) *Uint {
	z[3], z[2], z[1], z[0] = x[0], 0, 0, 0
	return z
}

func (z *Uint) rsh64(x *Uint) *Uint {
	z[3], z[2], z[1], z[0] = 0, x[3], x[2], x[1]
	return z
}

func (z *Uint) rsh128(x *Uint) *Uint {
	z[3], z[2], z[1], z[0] = 0, 0, x[3], x[2]
	return z
}

func (z *Uint) rsh192(x *Uint) *Uint {
	z[3], z[2], z[1], z[0] = 0, 0, 0, x[3]
	return z
}

func (z *Uint) srsh64(x *Uint) *Uint {
	z[3], z[2], z[1], z[0] = MAX_UINT64, x[3], x[2], x[1]
	return z
}

func (z *Uint) srsh128(x *Uint) *Uint {
	z[3], z[2], z[1], z[0] = MAX_UINT64, MAX_UINT64, x[3], x[2]
	return z
}

func (z *Uint) srsh192(x *Uint) *Uint {
	z[3], z[2], z[1], z[0] = MAX_UINT64, MAX_UINT64, MAX_UINT64, x[3]
	return z
}

// cmp (or, comparisons) includes methods for comparing Uint instances.
// These comparison functions cover a range of operations including equality checks, less than/greater than
// evaluations, and specialized comparisons such as signed greater than. These are fundamental for logical
// decision making based on Uint values.
package uint256

import "math/bits"

// Cmp compares z and x and returns -1 if z < x, 0 if z == x, or +1 if z > x.
func (z *Uint) Cmp(x *Uint) (r int) {
	// z < x <=> z - x < 0 i.e. when subtraction overflows.
	d0, carry := bits.Sub64(z[0], x[0], 0)
	d1, carry := bits.Sub64(z[1], x[1], carry)
	d2, carry := bits.Sub64(z[2], x[2], carry)
	d3, carry := bits.Sub64(z[3], x[3], carry)
	if carry == 1 {
		return -1
	}
	if d0|d1|d2|d3 == 0 {
		return 0
	}
	return 1
}

// IsZero returns true if z equals 0.
func (z *Uint) IsZero() bool {
	return (z[0] | z[1] | z[2] | z[3]) == 0
}

// Sign returns the sign of z interpreted as a two's complement signed number.
// It returns -1 if z < 0, 0 if z == 0, or +1 if z > 0.
func (z *Uint) Sign() int {
	if z.IsZero() {
		return 0
	}
	if z[3] < 0x8000000000000000 {
		return 1
	}
	return -1
}

// Lt returns true if z is less than x.
func (z *Uint) Lt(x *Uint) bool {
	// z < x <=> z - x < 0 i.e. when subtraction overflows.
	_, carry := bits.Sub64(z[0], x[0], 0)
	_, carry = bits.Sub64(z[1], x[1], carry)
	_, carry = bits.Sub64(z[2], x[2], carry)
	_, carry = bits.Sub64(z[3], x[3], carry)

	return carry != 0
}

// Gt returns true if z is greater than x.
func (z *Uint) Gt(x *Uint) bool {
	return x.Lt(z)
}

// Lte returns true if z is less than or equal to x.
func (z *Uint) Lte(x *Uint) bool {
	return !x.Lt(z)
}

// Gte returns true if z is greater than or equal to x.
func (z *Uint) Gte(x *Uint) bool {
	return !z.Lt(x)
}

// Eq returns true if z equals x.
func (z *Uint) Eq(x *Uint) bool {
	return (z[0] == x[0]) && (z[1] == x[1]) && (z[2] == x[2]) && (z[3] == x[3])
}

// Neq returns true if z does not equal x.
func (z *Uint) Neq(x *Uint) bool {
	return !z.Eq(x)
}

// conversions contains methods for converting Uint instances to other types and vice versa.
// This includes conversions to and from basic types such as uint64 and int32, as well as string representations
// and byte slices. Additionally, it covers marshaling and unmarshaling for JSON and other text formats.
package uint256

import (
	"encoding/binary"
	"strconv"
)

// Uint64 returns the lower 64 bits of z as a uint64.
func (z *Uint) Uint64() uint64 {
	return z[0]
}

// Int64 returns the lower 64 bits of z as an int64.
func (z *Uint) Int64() int64 {
	return int64(z.Uint64())
}

// Uint64WithOverflow returns the lower 64 bits of z and true if overflow occurred.
func (z *Uint) Uint64WithOverflow() (uint64, bool) {
	return z[0], (z[1] | z[2] | z[3]) != 0
}

// SetUint64 sets z to the value of x and returns z.
func (z *Uint) SetUint64(x uint64) *Uint {
	z[3], z[2], z[1], z[0] = 0, 0, 0, x
	return z
}

// IsUint64 reports whether z can be represented as a uint64.
func (z *Uint) IsUint64() bool {
	return (z[1] | z[2] | z[3]) == 0
}

// Dec returns the decimal representation of z.
func (z *Uint) Dec() string {
	if z.IsZero() {
		return "0"
	}
	if z.IsUint64() {
		return strconv.FormatUint(z.Uint64(), 10)
	}

	// The max uint64 value being 18446744073709551615, the largest
	// power-of-ten below that is 10000000000000000000.
	// When we do a DivMod using that number, the remainder that we
	// get back is the lower part of the output.
	//
	// The ascii-output of remainder will never exceed 19 bytes (since it will be
	// below 10000000000000000000).
	//
	// Algorithm example using 100 as divisor
	//
	// 12345 % 100 = 45   (rem)
	// 12345 / 100 = 123  (quo)
	// -> output '45', continue iterate on 123
	var (
		// out is 98 bytes long: 78 (max size of a string without leading zeroes,
		// plus slack so we can copy 19 bytes every iteration).
		// We init it with zeroes, because when strconv appends the ascii representations,
		// it will omit leading zeroes.
		out      [98]byte
		divisor  Uint
		y        = *z                 // copy z to avoid modifying it
		pos      = len(out)           // position to write to
		buf      [19]byte             // buffer to write uint64:s to
		bufSlice []byte     = buf[:0] // slice for strconv.AppendUint
	)

	// Initialize out array with '0's
	for i := range out {
		out[i] = '0'
	}

	// Set divisor to 10^19
	divisor.SetUint64(10000000000000000000)

	for {
		// Obtain Q and R for divisor
		var quot Uint
		rem := udivrem(quot[:], y[:], &divisor)
		y = quot // Set Q for next loop
		// Convert the R to ascii representation
		bufSlice = strconv.AppendUint(bufSlice[:0], rem.Uint64(), 10)
		// Copy in the ascii digits
		copy(out[pos-len(bufSlice):], bufSlice)
		if y.IsZero() {
			break
		}
		// Move 19 digits left
		pos -= 19
	}
	// skip leading zeroes by only using the 'used size' of bufSlice
	return string(out[pos-len(bufSlice):])
}


// ToString returns the decimal string representation of z.
// Returns an empty string if z is nil. This method doesn't exist in holiman's uint256.
func (z *Uint) ToString() string {
	if z == nil {
		return ""
	}

	return z.Dec()
}

// SetBytes interprets buf as a big-endian unsigned integer and sets z to that value.
// If buf is larger than 32 bytes, uses only the last 32 bytes. Returns z.
func (z *Uint) SetBytes(buf []byte) *Uint {
	switch l := len(buf); l {
	case 0:
		z.Clear()
	case 1:
		z.SetBytes1(buf)
	case 2:
		z.SetBytes2(buf)
	case 3:
		z.SetBytes3(buf)
	case 4:
		z.SetBytes4(buf)
	case 5:
		z.SetBytes5(buf)
	case 6:
		z.SetBytes6(buf)
	case 7:
		z.SetBytes7(buf)
	case 8:
		z.SetBytes8(buf)
	case 9:
		z.SetBytes9(buf)
	case 10:
		z.SetBytes10(buf)
	case 11:
		z.SetBytes11(buf)
	case 12:
		z.SetBytes12(buf)
	case 13:
		z.SetBytes13(buf)
	case 14:
		z.SetBytes14(buf)
	case 15:
		z.SetBytes15(buf)
	case 16:
		z.SetBytes16(buf)
	case 17:
		z.SetBytes17(buf)
	case 18:
		z.SetBytes18(buf)
	case 19:
		z.SetBytes19(buf)
	case 20:
		z.SetBytes20(buf)
	case 21:
		z.SetBytes21(buf)
	case 22:
		z.SetBytes22(buf)
	case 23:
		z.SetBytes23(buf)
	case 24:
		z.SetBytes24(buf)
	case 25:
		z.SetBytes25(buf)
	case 26:
		z.SetBytes26(buf)
	case 27:
		z.SetBytes27(buf)
	case 28:
		z.SetBytes28(buf)
	case 29:
		z.SetBytes29(buf)
	case 30:
		z.SetBytes30(buf)
	case 31:
		z.SetBytes31(buf)
	default:
		z.SetBytes32(buf[l-32:])
	}
	return z
}

// SetBytes1 sets z from a 1-byte big-endian slice and returns z.
// Panics if input is shorter than 1 byte.
func (z *Uint) SetBytes1(in []byte) *Uint {
	z[3], z[2], z[1] = 0, 0, 0
	z[0] = uint64(in[0])
	return z
}

// SetBytes2 sets z from a 2-byte big-endian slice and returns z.
// Panics if input is shorter than 2 bytes.
func (z *Uint) SetBytes2(in []byte) *Uint {
	_ = in[1] // bounds check hint to compiler; see golang.org/issue/14808
	z[3], z[2], z[1] = 0, 0, 0
	z[0] = uint64(binary.BigEndian.Uint16(in[0:2]))
	return z
}

// SetBytes3 sets z from a 3-byte big-endian slice and returns z.
// Panics if input is shorter than 3 bytes.
func (z *Uint) SetBytes3(in []byte) *Uint {
	_ = in[2] // bounds check hint to compiler; see golang.org/issue/14808
	z[3], z[2], z[1] = 0, 0, 0
	z[0] = uint64(binary.BigEndian.Uint16(in[1:3])) | uint64(in[0])<<16
	return z
}

// SetBytes4 sets z from a 4-byte big-endian slice and returns z.
// Panics if input is shorter than 4 bytes.
func (z *Uint) SetBytes4(in []byte) *Uint {
