package referral

import (
	"errors"

	"gno.land/p/nt/ufmt"
)

var (
	ErrInvalidAddress  = errors.New("invalid address format")
	ErrSelfReferral    = errors.New("self referral is not allowed")
	ErrUnauthorized    = errors.New("unauthorized caller")
	ErrTooManyRequests = errors.New("too many requests: operations allowed once per 24 hours for each address")
	ErrNotFound        = errors.New("referral not found")
	ErrInvalidTime     = errors.New("invalid time format")
)

func makeErrorWithDetails(err error, detail string) error {
	return ufmt.Errorf("%s: %s", err.Error(), detail)
}

package referral

import (
	"chain"
	"chain/runtime"
)

var gReferralKeeper ReferralKeeper

const EventRegisterFailed = "ReferralRegistrationFailed"

func init() {
	if gReferralKeeper == nil {
		gReferralKeeper = NewKeeper()
	}
}

// GetReferral returns the referral address for the given address.
func GetReferral(addr string) string {
	referral, err := gReferralKeeper.get(address(addr))
	if err != nil {
		return ""
	}
	return referral.String()
}

// HasReferral returns true if the given address has a referral.
func HasReferral(addr string) bool {
	_, err := gReferralKeeper.get(address(addr))
	return err == nil
}

// IsEmpty returns true if no referrals exist in the system.
func IsEmpty() bool {
	return gReferralKeeper.isEmpty()
}

// GetLastOpTimestamp returns the last operation timestamp for the given address.
// Returns ErrNotFound if no operation exists.
func GetLastOpTimestamp(addr string) (int64, error) {
	return gReferralKeeper.getLastOpTimestamp(address(addr))
}

// ContractAddress returns the address of the referral contract.
// Use this address as the referral parameter in TryRegister to remove an existing referral.
func ContractAddress() string {
	return selfAddress.String()
}

// TryRegister attempts to register a new referral.
//
// Parameters:
//   - addr: address to register
//   - referral: referral address string
//
// Returns true on success, false on failure.
// Panics if the caller is not authorized.
func TryRegister(cur realm, addr address, referral string) bool {
	caller := runtime.PreviousRealm().Address()
	assertValidCaller(caller)

	refAddr := address(referral)

	err := gReferralKeeper.register(addr, refAddr)
	if err != nil {
		chain.Emit(
			EventRegisterFailed,
			"address", addr.String(),
			"error", err.Error(),
		)

		return false
	}

	chain.Emit(
		"RegisterReferral",
		"prevAddr", caller.String(),
		"address", addr.String(),
		"referral", refAddr.String(),
	)

	return true
}

package referral

import (
	"time"

	"gno.land/p/nt/avl"
)

const (
	// MinTimeBetweenUpdates is minimum duration between operations (24 hours).
	MinTimeBetweenUpdates int64 = 24 * 60 * 60
)

// keeper implements ReferralKeeper using AVL tree storage.
// It includes rate limiting to prevent abuse.
type keeper struct {
	store   *avl.Tree // address(string) -> referral address(string)
	lastOps *avl.Tree // address(string) -> last operation timestamp(int64)
}

var _ ReferralKeeper = &keeper{}

// NewKeeper creates a new ReferralKeeper instance.
func NewKeeper() ReferralKeeper {
	return &keeper{
		store:   avl.NewTree(),
		lastOps: avl.NewTree(),
	}
}

// register creates or updates a referral relationship between addresses.
// Setting refAddr to the contract's own address removes the referral.
func (k *keeper) register(addr, refAddr address) error {
	if err := k.validateAddresses(addr, refAddr); err != nil {
		return err
	}

	addrStr := addr.String()
	refAddrStr := refAddr.String()

	if isRemovalRequest(refAddr) {
		if k.has(addr) {
			_, ok := k.store.Remove(addrStr)
			if !ok {
				return ErrNotFound
			}
		}

		return nil
	}

	if err := k.checkRateLimit(addrStr); err != nil {
		return err
	}

	k.store.Set(addrStr, refAddrStr)
	k.lastOps.Set(addrStr, time.Now().Unix())

	return nil
}

// validateAddresses validates that addresses are properly formatted and not self-referencing.
func (k *keeper) validateAddresses(addr, refAddr address) error {
	if !addr.IsValid() || (!isRemovalRequest(refAddr) && !refAddr.IsValid()) {
		return ErrInvalidAddress
	}
	if addr == refAddr {
		return ErrSelfReferral
	}
	return nil
}

// has returns true if a referral exists for the given address.
func (k *keeper) has(addr address) bool {
	_, exists := k.store.Get(addr.String())
	return exists
}

// get retrieves the referral address for a given address.
// Returns ErrNotFound if no referral exists.
func (k *keeper) get(addr address) (address, error) {
	if !addr.IsValid() {
		return zeroAddress, ErrInvalidAddress
	}

	val, ok := k.store.Get(addr.String())
	if !ok {
		return zeroAddress, ErrNotFound
	}

	refAddr, ok := val.(string)
	if !ok {
		return zeroAddress, ErrInvalidAddress
	}

	return address(refAddr), nil
}

// isEmpty returns true if no referrals exist in the store.
func (k *keeper) isEmpty() bool {
	return k.store.Size() == 0
}

// getLastOpTimestamp retrieves the last operation timestamp for a given address.
// Returns ErrNotFound if no operation exists.
func (k *keeper) getLastOpTimestamp(addr address) (int64, error) {
	if !addr.IsValid() {
		return 0, ErrInvalidAddress
	}

	val, ok := k.lastOps.Get(addr.String())
	if !ok {
		return 0, ErrNotFound
	}

	ts, ok := val.(int64)
	if !ok {
		return 0, ErrInvalidTime
	}

	return ts, nil
}

// checkRateLimit verifies if enough time has passed since the last operation.
// Returns ErrTooManyRequests if rate limit is exceeded.
func (k *keeper) checkRateLimit(addr string) error {
	now := time.Now().Unix()

	lastOpTimeRaw, exists := k.lastOps.Get(addr)
	if !exists {
		return nil
	}

	lastOpTime, ok := lastOpTimeRaw.(int64)
	if !ok {
		return ErrInvalidTime
	}

	timeSinceLastOp := now - lastOpTime
	if timeSinceLastOp < MinTimeBetweenUpdates {
		return ErrTooManyRequests
	}

	return nil
}

package referral

import "chain/runtime"

var (
	zeroAddress = address("")
	// selfAddress is cached at package initialization to ensure consistent comparison.
	selfAddress address
)

func init() {
	selfAddress = runtime.CurrentRealm().Address()
}

// contractAddress returns the address of the referral contract.
// This is used as a sentinel value for removing referrals.
func contractAddress() address {
	return selfAddress
}

// isRemovalRequest checks if the given address indicates a removal request.
// Removal is indicated by passing the contract's own address as the referral.
func isRemovalRequest(refAddr address) bool {
	return refAddr == selfAddress
}

// ReferralKeeper defines the interface for managing referral relationships.
type ReferralKeeper interface {
	// register creates or updates a referral relationship between addresses.
	// Setting refAddr to the contract's own address removes the referral.
	register(addr, refAddr address) error

	// has returns true if a referral exists for the given address.
	has(addr address) bool

	// get retrieves the referral address for a given address.
	get(addr address) (address, error)

	// isEmpty returns true if no referrals exist in the system.
	isEmpty() bool

	// getLastOpTimestamp returns the last operation timestamp for an address.
	getLastOpTimestamp(addr address) (int64, error)
}

// Package gns implements the GNS governance and utility token for GnoSwap.
//
// GNS is a GRC20-compliant token with a deflationary emission schedule.
// The emission follows a 12-year schedule with halving every 2 years:
//   - Years 1-2:  225,000,000 GNS per year (100%)
//   - Years 3-4:  112,500,000 GNS per year (50%)
//   - Years 5-6:   56,250,000 GNS per year (25%)
//   - Years 7-8:   28,125,000 GNS per year (12.5%)
//   - Years 9-12:  14,062,500 GNS per year (6.25%)
//
// Token Economics:
//   - Maximum Supply: 1,000,000,000 GNS
//   - Initial Mint:     100,000,000 GNS
//   - Total Emission:   900,000,000 GNS
//
// Key Functions:
//   - InitEmissionState: Initializes emission schedule (emission contract only)
//   - MintGns: Mints tokens per emission schedule (emission contract only)
//   - Burn: Burns tokens from circulation (admin only)
//   - Transfer/TransferFrom/Approve: Standard GRC20 operations
//
// The emission state tracks accumulated and remaining amounts per halving year,
// ensuring precise token distribution according to the schedule.
package gns

package gns

import (
	"chain"
	"chain/runtime"
	"time"

	"gno.land/r/gnoswap/access"
)

// InitEmissionState initializes emission schedule with start timestamp.
// Only callable by emission contract. Sets up 12-year emission schedule
// with halving every 2 years. Panics if caller is not emission contract.
func InitEmissionState(cur realm, createdHeight int64, startTimestamp int64) {
	previousRealm := runtime.PreviousRealm()
	caller := previousRealm.Address()
	access.AssertIsEmission(caller)

	emissionState = NewEmissionState(createdHeight, startTimestamp)

	chain.Emit(
		"InitEmissionState",
		"prevAddr", caller.String(),
		"prevRealm", previousRealm.PkgPath(),
		"height", formatInt(createdHeight),
		"timestamp", formatInt(time.Now().Unix()),
		"startTimestamp", formatInt(emissionState.getStartTimestamp()),
		"endTimestamp", formatInt(emissionState.getEndTimestamp()),
	)
}

package gns

import (
	"chain/runtime"
	"time"

	"gno.land/p/nt/ufmt"
)

var emissionState *EmissionState

func init() {
	emissionState = NewEmissionState(0, 0)
}

// EmissionState manages emission state and halving data.
// Tracks emission timing, status, and halving year information for 12-year schedule.
type EmissionState struct {
	createdHeight  int64
	startTimestamp int64
	endTimestamp   int64
	halvingData    *HalvingData
}

// isInitialized returns true if emission state has been initialized with valid height and timestamp.
func (e *EmissionState) isInitialized() bool {
	return e.createdHeight != 0 && e.startTimestamp != 0
}

// isActive returns true if emission is currently active at the given timestamp.
// Returns false if not initialized or timestamp is outside emission period.
func (e *EmissionState) isActive(timestamp int64) bool {
	if !e.isInitialized() {
		return false
	}

	if e.startTimestamp > timestamp {
		return false
	}

	if e.endTimestamp < timestamp {
		return false
	}

	return true
}

// isEnded returns true if emission has ended at the given timestamp.
func (e *EmissionState) isEnded(timestamp int64) bool {
	return e.endTimestamp < timestamp
}

// getCurrentYear returns the halving year (1-12) for the given timestamp, or 0 if outside emission period.
func (e *EmissionState) getCurrentYear(timestamp int64) int64 {
	if timestamp < e.startTimestamp {
		return 0
	}

	if timestamp > e.endTimestamp {
		return 0
	}

	year := (timestamp - e.startTimestamp) / SECONDS_IN_YEAR
	return year + 1
}

// getCreatedHeight returns the blockchain height when emission started.
func (e *EmissionState) getCreatedHeight() int64 {
	return e.createdHeight
}

// getStartTimestamp returns the timestamp when emission started.
func (e *EmissionState) getStartTimestamp() int64 {
	return e.startTimestamp
}

// getEndTimestamp returns the timestamp when emission ends.
func (e *EmissionState) getEndTimestamp() int64 {
	return e.endTimestamp
}

// getHalvingData returns the halving data containing emission schedule details.
func (e *EmissionState) getHalvingData() *HalvingData {
	return e.halvingData
}

// getHalvingYearStartTimestamp returns the start timestamp for the specified halving year.
func (e *EmissionState) getHalvingYearStartTimestamp(year int64) int64 {
	return e.halvingData.getStartTimestamp(year)
}

// getHalvingYearEndTimestamp returns the end timestamp for the specified halving year.
func (e *EmissionState) getHalvingYearEndTimestamp(year int64) int64 {
	return e.halvingData.getEndTimestamp(year)
}

// getHalvingYearAmountPerSecond returns the emission rate per second for the specified halving year.
func (e *EmissionState) getHalvingYearAmountPerSecond(year int64) int64 {
	return e.halvingData.getAmountPerSecond(year)
}

// getHalvingYearAccumulatedAmount returns the accumulated emission amount for the specified halving year.
func (e *EmissionState) getHalvingYearAccumulatedAmount(year int64) int64 {
	return e.halvingData.getAccumAmount(year)
}

// getHalvingYearLeftAmount returns the remaining emission amount for the specified halving year.
func (e *EmissionState) getHalvingYearLeftAmount(year int64) int64 {
	return e.halvingData.getLeftAmount(year)
}

// addHalvingYearAccumulatedAmount adds to the accumulated emission amount for the specified halving year.
// Returns error if year is invalid (0 or outside 1-12 range).
func (e *EmissionState) addHalvingYearAccumulatedAmount(year int64, amount int64) error {
	if year == 0 {
		return makeErrorWithDetails(errInvalidYear, ufmt.Sprintf("year: %d", year))
	}

	accumulatedAmount := e.halvingData.getAccumAmount(year)
	accumulatedAmount = safeAddInt64(accumulatedAmount, amount)

	return e.halvingData.setAccumAmount(year, accumulatedAmount)
}

// subHalvingYearLeftAmount subtracts from the remaining emission amount for the specified halving year.
// Returns error if year is invalid (0 or outside 1-12 range).
func (e *EmissionState) subHalvingYearLeftAmount(year int64, amount int64) error {
	if year == 0 {
		return makeErrorWithDetails(errInvalidYear, ufmt.Sprintf("year: %d", year))
	}

	leftAmount := e.halvingData.getLeftAmount(year)
	leftAmount = safeSubInt64(leftAmount, amount)

	return e.halvingData.setLeftAmount(year, leftAmount)
}

func (e *EmissionState) Clone() *EmissionState {
	return &EmissionState{
		createdHeight:  e.createdHeight,
		startTimestamp: e.startTimestamp,
		endTimestamp:   e.endTimestamp,
		halvingData:    e.halvingData.Clone(),
	}
}

// NewEmissionState creates a new EmissionState with specified start height and timestamp.
// Calculates emission end time based on 12-year schedule and initializes halving data.
func NewEmissionState(createdHeight int64, startTimestamp int64) *EmissionState {
	emissionEndTime := safeAddInt64(startTimestamp, SECONDS_IN_YEAR*HALVING_END_YEAR-1)

	return &EmissionState{
		createdHeight:  createdHeight,
		startTimestamp: startTimestamp,
		endTimestamp:   emissionEndTime,
		halvingData:    NewHalvingData(startTimestamp),
	}
}

// getEmissionState returns the singleton emission state instance.
func getEmissionState() *EmissionState {
	if emissionState == nil {
		emissionState = NewEmissionState(runtime.ChainHeight(), time.Now().Unix())
	}

	return emissionState
}

