}

// GetCurrentYear returns the current halving year (1-12) or 0 if emission is not active.
func GetCurrentYear() int64 {
	return getEmissionState().getCurrentYear(time.Now().Unix())
}

// GetEmissionAmountPerSecondInRange returns halving timestamps and emission rates for the given time range.
// Returns two slices: timestamps when halving periods start and corresponding emission rates per second.
func GetEmissionAmountPerSecondInRange(fromTime, toTime int64) ([]int64, []int64) {
	halvingData := getEmissionState().getHalvingData()
	halvingTimes := make([]int64, 0, HALVING_END_YEAR)
	halvingEmissions := make([]int64, 0, HALVING_END_YEAR)

	for year := HALVING_START_YEAR; year <= HALVING_END_YEAR; year++ {
		startTimestamp := halvingData.getStartTimestamp(year)
		if startTimestamp < fromTime {
			continue
		}

		if toTime < startTimestamp {
			break
		}

		halvingTimes = append(halvingTimes, startTimestamp)
		halvingEmissions = append(halvingEmissions, halvingData.getAmountPerSecond(year))
	}

	return halvingTimes, halvingEmissions
}

// GetEmissionAmountPerSecondByTimestamp returns the emission rate per second for a given timestamp.
// Returns 0 if timestamp is outside emission period.
func GetEmissionAmountPerSecondByTimestamp(timestamp int64) int64 {
	state := getEmissionState()
	year := state.getCurrentYear(timestamp)
	return state.getHalvingYearAmountPerSecond(year)
}

// GetEmissionLeftAmountByTimestamp returns the remaining emission amount for the halving year at given timestamp.
// Returns 0 if timestamp is outside emission period.
func GetEmissionLeftAmountByTimestamp(timestamp int64) int64 {
	state := getEmissionState()
	year := state.getCurrentYear(timestamp)
	return state.getHalvingYearLeftAmount(year)
}

// GetEmissionAccumulatedAmountByTimestamp returns the accumulated emission amount for the halving year at given timestamp.
// Returns 0 if timestamp is outside emission period.
func GetEmissionAccumulatedAmountByTimestamp(timestamp int64) int64 {
	state := getEmissionState()
	year := state.getCurrentYear(timestamp)
	return state.getHalvingYearAccumulatedAmount(year)
}

// GetHalvingYearStartTimestamp returns the start timestamp for the specified halving year.
func GetHalvingYearStartTimestamp(year int64) int64 {
	halvingData := getEmissionState().getHalvingData()
	return halvingData.getStartTimestamp(year)
}

// GetHalvingYearEndTimestamp returns the end timestamp for the specified halving year.
func GetHalvingYearEndTimestamp(year int64) int64 {
	halvingData := getEmissionState().getHalvingData()
	return halvingData.getEndTimestamp(year)
}

// GetHalvingYearMaxAmount returns the maximum token issuance for the specified halving year.
func GetHalvingYearMaxAmount(year int64) int64 {
	halvingData := getEmissionState().getHalvingData()
	return halvingData.getMaxAmount(year)
}

// GetHalvingYearMintAmount returns the amount of tokens minted for the specified halving year.
func GetHalvingYearMintAmount(year int64) int64 {
	halvingData := getEmissionState().getHalvingData()
	return halvingData.getMintedAmount(year)
}

// GetHalvingYearLeftAmount returns the remaining token issuance for the specified halving year.
func GetHalvingYearLeftAmount(year int64) int64 {
	halvingData := getEmissionState().getHalvingData()
	return halvingData.getLeftAmount(year)
}

// GetHalvingYearAccuAmount returns the accumulated token issuance for the specified halving year.
func GetHalvingYearAccuAmount(year int64) int64 {
	halvingData := getEmissionState().getHalvingData()
	return halvingData.getAccumAmount(year)
}

// GetAmountPerSecondPerHalvingYear returns the emission rate per second for the specified halving year.
func GetAmountPerSecondPerHalvingYear(year int64) int64 {
	halvingData := getEmissionState().getHalvingData()
	return halvingData.getAmountPerSecond(year)
}

// GetHalvingAmountsPerYear returns the total emission amount allocated for the specified year.
// Returns 0 if year is outside the valid range (1-12).
func GetHalvingAmountsPerYear(year int64) int64 {
	if validYear(year) != nil {
		return 0
	}
	return halvingAmountsPerYear[year-1]
}

// GetEmissionCreatedHeight returns the block height when emission schedule was created.
func GetEmissionCreatedHeight() int64 {
	return getEmissionState().getCreatedHeight()
}

// GetEmissionStartTimestamp returns the timestamp when emission schedule begins.
func GetEmissionStartTimestamp() int64 {
	return getEmissionState().getStartTimestamp()
}

// GetEmissionEndTimestamp returns the timestamp when emission schedule ends.
func GetEmissionEndTimestamp() int64 {
	return getEmissionState().getEndTimestamp()
}

// GetHalvingYearInfo returns the halving year, start timestamp, and end timestamp for a given timestamp.
// Returns (year, startTimestamp, endTimestamp). Year is 0 if outside emission period.
func GetHalvingYearInfo(timestamp int64) (int64, int64, int64) {
	state := getEmissionState()
	year := state.getCurrentYear(timestamp)

	// If outside emission period, return 0 values
	if year == 0 {
		return 0, 0, 0
	}

	// Use cached timestamps from HalvingData
	halvingData := state.getHalvingData()
	return year, halvingData.getStartTimestamp(year), halvingData.getEndTimestamp(year)
}

// GetHalvingInfo returns a clone of the halving data.
func GetHalvingInfo() *HalvingData {
	return getEmissionState().getHalvingData().Clone()
}

// CalculateMintGnsAmount returns the amount of GNS that would be minted for the given timestamp range.
func CalculateMintGnsAmount(fromTimestamp, toTimestamp int64) int64 {
	state := getEmissionState().Clone()

	amountToMint, err := calculateAmountToMint(state, fromTimestamp, toTimestamp)
	if err != nil {
		return 0
	}

	return amountToMint
}

package gns

import (
	"chain"
	"chain/runtime"
	"strings"
	"time"

	"gno.land/p/demo/tokens/grc20"
	"gno.land/p/nt/ufmt"

	"gno.land/r/demo/defi/grc20reg"
	"gno.land/r/gnoswap/access"

	prabc "gno.land/p/gnoswap/rbac"
	_ "gno.land/r/gnoswap/rbac"
)

const (
	MAXIMUM_SUPPLY      = int64(1_000_000_000_000_000)
	INITIAL_MINT_AMOUNT = int64(100_000_000_000_000)
	MAX_EMISSION_AMOUNT = int64(900_000_000_000_000) // MAXIMUM_SUPPLY - INITIAL_MINT_AMOUNT
)

var (
	token, privateLedger = grc20.NewToken("Gnoswap", "GNS", 6)
	UserTeller           = token.CallerTeller()

	leftEmissionAmount   int64 // amount of GNS can be minted for emission
	mintedEmissionAmount int64 // amount of GNS that has been minted for emission
	lastMintedTimestamp  int64 // last block time that gns was minted for emission
)

func init() {
	adminAddr := access.MustGetAddress(prabc.ROLE_ADMIN.String())
	err := privateLedger.Mint(adminAddr, INITIAL_MINT_AMOUNT)
	if err != nil {
		panic(err.Error())
	}

	grc20reg.Register(cross, token, "")

	// Initial amount set to 900_000_000_000_000 (MAXIMUM_SUPPLY - INITIAL_MINT_AMOUNT).
	// leftEmissionAmount will decrease as tokens are minted.
	setLeftEmissionAmount(MAX_EMISSION_AMOUNT)
	setMintedEmissionAmount(0)
	setLastMintedTimestamp(0)
}

// Name returns the name of the GNS token.
func Name() string { return token.GetName() }

// Symbol returns the symbol of the GNS token.
func Symbol() string { return token.GetSymbol() }

// Decimals returns the number of decimal places for GNS token.
func Decimals() int { return token.GetDecimals() }

// TotalSupply returns the total supply of GNS tokens in circulation.
func TotalSupply() int64 { return token.TotalSupply() }

// KnownAccounts returns the number of addresses that have held GNS.
func KnownAccounts() int { return token.KnownAccounts() }

// BalanceOf returns the GNS balance of a specific address.
func BalanceOf(owner address) int64 { return token.BalanceOf(owner) }

// Allowance returns the amount of GNS that a spender is allowed to transfer from an owner.
func Allowance(owner, spender address) int64 { return token.Allowance(owner, spender) }

// MintGns mints new GNS tokens according to the emission schedule.
//
// Parameters:
//   - address: recipient address for minted tokens
//
// Returns amount minted.
// Only callable by emission contract.
//
// Note: Halt check is performed by the caller (emission.MintAndDistributeGns)
// to allow graceful handling. This function assumes caller has already verified
// halt status before invoking.
func MintGns(cur realm, address address) int64 {
	previousRealm := runtime.PreviousRealm()
	caller := previousRealm.Address()
	access.AssertIsEmission(caller)

	lastGNSMintedTimestamp := LastMintedTimestamp()
	currentTime := time.Now().Unix()

	// Skip if already minted this timestamp or emission ended.
	if lastGNSMintedTimestamp == currentTime || lastGNSMintedTimestamp >= GetEmissionEndTimestamp() {
		return 0
	}

	amountToMint, err := calculateAmountToMint(getEmissionState(), lastGNSMintedTimestamp+1, currentTime)
	if err != nil {
		panic(err)
	}

	err = validEmissionAmount(amountToMint)
	if err != nil {
		panic(err)
	}

	setLastMintedTimestamp(currentTime)
	setMintedEmissionAmount(safeAddInt64(MintedEmissionAmount(), amountToMint))
	setLeftEmissionAmount(safeSubInt64(LeftEmissionAmount(), amountToMint))

	err = privateLedger.Mint(address, amountToMint)
	if err != nil {
		panic(err.Error())
	}

	chain.Emit(
		"MintGNS",
		"prevAddr", caller.String(),
		"prevRealm", previousRealm.PkgPath(),
		"mintedBlockTime", formatInt(currentTime),
		"mintedGNSAmount", formatInt(amountToMint),
		"accumMintedGNSAmount", formatInt(MintedEmissionAmount()),
		"accumLeftMintGNSAmount", formatInt(LeftEmissionAmount()),
	)

	return amountToMint
}

// Transfer transfers GNS tokens from caller to recipient.
//
// Parameters:
//   - to: recipient address
//   - amount: amount to transfer
func Transfer(cur realm, to address, amount int64) {
	userTeller := token.CallerTeller()
	checkErr(userTeller.Transfer(to, amount))
}

// Approve allows spender to transfer GNS tokens from caller's account.
//
// Parameters:
//   - spender: address authorized to spend
//   - amount: maximum amount spender can transfer
func Approve(cur realm, spender address, amount int64) {
	userTeller := token.CallerTeller()
	checkErr(userTeller.Approve(spender, amount))
}

// TransferFrom transfers GNS tokens on behalf of owner.
//
// Parameters:
//   - from: token owner address
//   - to: recipient address
//   - amount: amount to transfer
func TransferFrom(cur realm, from, to address, amount int64) {
	userTeller := token.CallerTeller()
	checkErr(userTeller.TransferFrom(from, to, amount))
}

// Render returns token information for web interface.
func Render(path string) string {
	parts := strings.Split(path, "/")
	c := len(parts)

	switch {
	case path == "":
		return token.RenderHome()
	case c == 2 && parts[0] == "balance":
		owner := address(parts[1])
		balance := token.BalanceOf(owner)
		return ufmt.Sprintf("%d\n", balance)
	default:
		return "404\n"
	}
}

// checkErr panics if error is not nil.
func checkErr(err error) {
	if err != nil {
		panic(err.Error())
	}
}

// calculateAmountToMint calculates and allocates GNS tokens to mint for given timestamp range.
// This function has side effects: it updates the accumulated and remaining amounts
// for each halving year in the emission state.
func calculateAmountToMint(state *EmissionState, fromTimestamp, toTimestamp int64) (int64, error) {
	// Cache state to avoid repeated lookups
	endTimestamp := state.getEndTimestamp()
	if toTimestamp > endTimestamp {
		toTimestamp = endTimestamp
	}

	if fromTimestamp > toTimestamp {
		return 0, nil
	}

	startTimestamp := state.getStartTimestamp()
	if fromTimestamp < startTimestamp {
		fromTimestamp = startTimestamp
	}

	if toTimestamp < startTimestamp {
		return 0, nil
	}

	fromYear := state.getCurrentYear(fromTimestamp)
	toYear := state.getCurrentYear(toTimestamp)

	if fromYear == 0 || toYear == 0 {
		return 0, nil
	}

	totalAmountToMint := int64(0)

	for year := fromYear; year <= toYear; year++ {
		yearEndTimestamp := state.getHalvingYearEndTimestamp(year)
		currentToTimestamp := i64Min(toTimestamp, yearEndTimestamp)

		seconds := currentToTimestamp - fromTimestamp + 1
		if seconds <= 0 {
			break
		}

		amountPerSecond := state.getHalvingYearAmountPerSecond(year)
		yearAmountToMint := safeMulInt64(amountPerSecond, seconds)

		if currentToTimestamp >= yearEndTimestamp {
			leftover := safeSubInt64(state.getHalvingYearLeftAmount(year), yearAmountToMint)
			yearAmountToMint = safeAddInt64(yearAmountToMint, leftover)
		}

		totalAmountToMint = safeAddInt64(totalAmountToMint, yearAmountToMint)

		err := state.addHalvingYearAccumulatedAmount(year, yearAmountToMint)
		if err != nil {
			return 0, err
		}

		err = state.subHalvingYearLeftAmount(year, yearAmountToMint)
		if err != nil {
			return 0, err
		}

		fromTimestamp = currentToTimestamp + 1

		if fromTimestamp > toTimestamp {
			break
		}
	}

	return totalAmountToMint, nil
}

// LastMintedTimestamp returns the timestamp of the last GNS emission mint.
func LastMintedTimestamp() int64 { return lastMintedTimestamp }

// LeftEmissionAmount returns the remaining GNS tokens available for emission.
func LeftEmissionAmount() int64 { return leftEmissionAmount }

// MintedEmissionAmount returns the total GNS tokens minted through emission,
// excluding the initial mint amount.
func MintedEmissionAmount() int64 { return mintedEmissionAmount }

// setLastMintedTimestamp sets the timestamp of the last emission mint.
func setLastMintedTimestamp(timestamp int64) { lastMintedTimestamp = timestamp }

// setLeftEmissionAmount sets the remaining emission amount.
func setLeftEmissionAmount(amount int64) { leftEmissionAmount = amount }

// setMintedEmissionAmount sets the total minted emission amount.
func setMintedEmissionAmount(amount int64) { mintedEmissionAmount = amount }

package gns

// HalvingData stores emission data for each halving period.
// Contains timestamps, amounts, and rates for the 12-year emission schedule.
type HalvingData struct {
	startTimestamps []int64
	endTimestamps   []int64
	maxAmount       []int64
	mintedAmount    []int64
	leftAmount      []int64
	accumAmount     []int64
	amountPerSecond []int64
}

// getStartTimestamp returns the start timestamp for the specified halving year.
// Returns 0 if year is invalid.
func (h *HalvingData) getStartTimestamp(year int64) int64 {
	if validYear(year) != nil {
		return 0
	}

	return h.startTimestamps[year-1]
}

// getEndTimestamp returns the end timestamp for the specified halving year.
// Returns 0 if year is invalid.
func (h *HalvingData) getEndTimestamp(year int64) int64 {
	if validYear(year) != nil {
		return 0
	}

	return h.endTimestamps[year-1]
}

// getMaxAmount returns the maximum emission amount for the specified halving year.
// Returns 0 if year is invalid.
func (h *HalvingData) getMaxAmount(year int64) int64 {
	if validYear(year) != nil {
		return 0
	}

	return h.maxAmount[year-1]
}

// getMintedAmount returns the amount already minted for the specified halving year.
func (h *HalvingData) getMintedAmount(year int64) int64 {
	if validYear(year) != nil {
		return 0
	}
	return h.mintedAmount[year-1]
}

// getAccumAmount returns the accumulated emission amount for the specified halving year.
func (h *HalvingData) getAccumAmount(year int64) int64 {
	if validYear(year) != nil {
		return 0
	}
	return h.accumAmount[year-1]
}

// getLeftAmount returns the remaining emission amount for the specified halving year.
func (h *HalvingData) getLeftAmount(year int64) int64 {
	if validYear(year) != nil {
		return 0
	}
	return h.leftAmount[year-1]
}

// getAmountPerSecond returns the emission rate per second for the specified halving year.
// Returns 0 if year is invalid.
func (h *HalvingData) getAmountPerSecond(year int64) int64 {
	if validYear(year) != nil {
		return 0
	}
	return h.amountPerSecond[year-1]
}

// setStartTimestamp sets the start timestamp for the specified halving year.
// Returns error if year is invalid.
func (h *HalvingData) setStartTimestamp(year int64, timestamp int64) error {
	err := validYear(year)
	if err != nil {
		return err
	}

	h.startTimestamps[year-1] = timestamp

	return nil
}

// setEndTimestamp sets the end timestamp for the specified halving year.
// Returns error if year is invalid.
func (h *HalvingData) setEndTimestamp(year int64, timestamp int64) error {
	err := validYear(year)
	if err != nil {
		return err
	}

	h.endTimestamps[year-1] = timestamp

	return nil
}

// setMaxAmount sets the maximum emission amount for the specified halving year.
// Returns error if year is invalid.
func (h *HalvingData) setMaxAmount(year, amount int64) error {
	err := validYear(year)
	if err != nil {
		return err
	}

	h.maxAmount[year-1] = amount

	return nil
}

// setMintedAmount sets the minted amount for the specified halving year.
// Returns error if year is invalid.
func (h *HalvingData) setMintedAmount(year, amount int64) error {
	err := validYear(year)
	if err != nil {
		return err
	}

	h.mintedAmount[year-1] = amount

	return nil
}

// setAccumAmount sets the accumulated amount for the specified halving year.
// Returns error if year is invalid.
func (h *HalvingData) setAccumAmount(year, amount int64) error {
	err := validYear(year)
	if err != nil {
		return err
	}

	h.accumAmount[year-1] = amount

	return nil
}

// setLeftAmount sets the remaining amount for the specified halving year.
// Returns error if year is invalid.
func (h *HalvingData) setLeftAmount(year, amount int64) error {
	err := validYear(year)
	if err != nil {
		return err
	}

	h.leftAmount[year-1] = amount

	return nil
}

// addAccumAmount adds to the accumulated amount for the specified halving year.
// Returns error if year is invalid.
func (h *HalvingData) addAccumAmount(year, amount int64) error {
	err := validYear(year)
	if err != nil {
		return err
	}

	h.accumAmount[year-1] = safeAddInt64(h.accumAmount[year-1], amount)

	return nil
}

// setAmountPerSecond sets the emission rate per second for the specified halving year.
// Returns error if year is invalid.
func (h *HalvingData) setAmountPerSecond(year, amount int64) error {
	err := validYear(year)
	if err != nil {
		return err
	}

	h.amountPerSecond[year-1] = amount

	return nil
}

func (h *HalvingData) Clone() *HalvingData {
	startTimestamps := make([]int64, len(h.startTimestamps))
	endTimestamps := make([]int64, len(h.endTimestamps))
	maxAmount := make([]int64, len(h.maxAmount))
	mintedAmount := make([]int64, len(h.mintedAmount))
	leftAmount := make([]int64, len(h.leftAmount))
	accumAmount := make([]int64, len(h.accumAmount))
	amountPerSecond := make([]int64, len(h.amountPerSecond))

	copy(startTimestamps, h.startTimestamps)
	copy(endTimestamps, h.endTimestamps)
	copy(maxAmount, h.maxAmount)
	copy(mintedAmount, h.mintedAmount)
	copy(leftAmount, h.leftAmount)
	copy(accumAmount, h.accumAmount)
	copy(amountPerSecond, h.amountPerSecond)

	return &HalvingData{
		startTimestamps: startTimestamps,
		endTimestamps:   endTimestamps,
		maxAmount:       maxAmount,
		mintedAmount:    mintedAmount,
		leftAmount:      leftAmount,
		accumAmount:     accumAmount,
		amountPerSecond: amountPerSecond,
	}
}

// NewHalvingData creates a new HalvingData instance with emission schedule.
// Initializes 12 years of halving periods with timestamps, amounts, and rates based on startTimestamp.
func NewHalvingData(startTimestamp int64) *HalvingData {
	halvingData := &HalvingData{
		startTimestamps: make([]int64, HALVING_END_YEAR),
		endTimestamps:   make([]int64, HALVING_END_YEAR),
		maxAmount:       make([]int64, HALVING_END_YEAR),
		mintedAmount:    make([]int64, HALVING_END_YEAR),
		leftAmount:      make([]int64, HALVING_END_YEAR),
		accumAmount:     make([]int64, HALVING_END_YEAR),
		amountPerSecond: make([]int64, HALVING_END_YEAR),
	}

	for year := HALVING_START_YEAR; year <= HALVING_END_YEAR; year++ {
		yearStartTimestamp := startTimestamp + (SECONDS_IN_YEAR * (year - 1))
		yearEndTimestamp := yearStartTimestamp + SECONDS_IN_YEAR - 1
		yearDistributionAmount := GetHalvingAmountsPerYear(year)
		yearAmountPerSecond := yearDistributionAmount / SECONDS_IN_YEAR

		halvingData.setStartTimestamp(year, yearStartTimestamp)
		halvingData.setEndTimestamp(year, yearEndTimestamp)
		halvingData.setMaxAmount(year, yearDistributionAmount)
		halvingData.setMintedAmount(year, 0)
		halvingData.setAccumAmount(year, 0)
		halvingData.setAmountPerSecond(year, yearAmountPerSecond)
		halvingData.setLeftAmount(year, yearDistributionAmount)
	}

	return halvingData
}

package gns

import (
	"math"
	"strconv"

	"gno.land/p/nt/ufmt"
)

// validBlockTime validates that block time is within acceptable range.
// Returns error if block time is <= 0 or >= 1e9.
func validBlockTime(blockTime int64) error {
	if blockTime <= 0 || blockTime >= 1e9 {
		return errInvalidAvgBlockTimeInMs
	}

	return nil
}

// validYear validates that year is within halving period range (1-12).
// Returns error if year is outside the valid range.
func validYear(year int64) error {
	if year < HALVING_START_YEAR || year > HALVING_END_YEAR {
		return makeErrorWithDetails(errInvalidYear, ufmt.Sprintf("year: %d", year))
	}

	return nil
}

// validEmissionAmount validates that the emission amount does not exceed maximum.
// Returns error if minting the amount would exceed MAX_EMISSION_AMOUNT.
func validEmissionAmount(amount int64) error {
	if amount < 0 {
		return makeErrorWithDetails(errInvalidEmissionAmount, ufmt.Sprintf("emission amount cannot be negative: %d", amount))
	}

	if safeAddInt64(amount, MintedEmissionAmount()) > MAX_EMISSION_AMOUNT {
		return makeErrorWithDetails(errTooManyEmission, ufmt.Sprintf("too many emission amount: %d", amount))
	}

	return nil
}

// i64Min returns the smaller of two int64 values.
func i64Min(x, y int64) int64 {
	if x < y {
		return x
	}
	return y
}

// formatUint formats unsigned integer types to string.
// Supports uint8, uint32, and uint64. Panics for unsupported types.
func formatUint(v any) string {
	switch v := v.(type) {
	case uint8:
		return strconv.FormatUint(uint64(v), 10)
	case uint32:
		return strconv.FormatUint(uint64(v), 10)
	case uint64:
		return strconv.FormatUint(v, 10)
	default:
		panic(ufmt.Sprintf("invalid type: %T", v))
	}
}

// formatInt formats signed integer types to string.
// Supports int32, int64, and int. Panics for unsupported types.
func formatInt(v any) string {
	switch v := v.(type) {
	case int32:
		return strconv.FormatInt(int64(v), 10)
	case int64:
		return strconv.FormatInt(v, 10)
	case int:
		return strconv.Itoa(v)
	default:
		panic(ufmt.Sprintf("invalid type: %T", v))
	}
}

// safeAddInt64 performs safe addition of int64 values, panicking on overflow or underflow
func safeAddInt64(a, b int64) int64 {
	if a > 0 && b > math.MaxInt64-a {
		panic("int64 addition overflow")
	}
	if a < 0 && b < math.MinInt64-a {
		panic("int64 addition underflow")
	}
	return a + b
}

// safeSubInt64 performs safe subtraction of int64 values, panicking on overflow or underflow
func safeSubInt64(a, b int64) int64 {
	if b > 0 && a < math.MinInt64+b {
		panic("int64 subtraction underflow")
	}
	if b < 0 && a > math.MaxInt64+b {
		panic("int64 subtraction overflow")
	}
	return a - b
}

// safeMulInt64 performs safe multiplication of int64 values, panicking on overflow or underflow
func safeMulInt64(a, b int64) int64 {
	if a == 0 || b == 0 {
		return 0
	}

	if a > 0 && b > 0 {
		if a > math.MaxInt64/b {
			panic("int64 multiplication overflow")
		}
	} else if a < 0 && b < 0 {
		if a < math.MaxInt64/b {
			panic("int64 multiplication overflow")
		}
	} else if a > 0 && b < 0 {
		if b < math.MinInt64/a {
			panic("int64 multiplication underflow")
		}
	} else { // a < 0 && b > 0
		if a < math.MinInt64/b {
			panic("int64 multiplication underflow")
		}
	}

	return a * b
}

package emission

import (
	"gno.land/p/nt/ufmt"
)

// assertValidDistributionTargets panics if any of the four distribution targets is invalid
// or if there are duplicate targets. All four distribution targets must be unique and valid.
func assertValidDistributionTargets(target01, target02, target03, target04 int) {
	validTargets := map[int]bool{
		LIQUIDITY_STAKER: false,
		DEVOPS:           false,
		COMMUNITY_POOL:   false,
		GOV_STAKER:       false,
	}

	currentTargets := []int{target01, target02, target03, target04}

	for _, target := range currentTargets {
		if _, ok := validTargets[target]; !ok {
			panic(makeErrorWithDetails(
				errInvalidEmissionTarget,
				ufmt.Sprintf("invalid target(%d)", target),
			))
		}

		validTargets[target] = true
	}

	for _, valid := range validTargets {
		if !valid {
			panic(errDuplicateTarget)
		}
	}
}

// assertValidDistributionTarget panics if the given distribution target is invalid.
func assertValidDistributionTarget(target int) {
	validTargets := map[int]bool{
		LIQUIDITY_STAKER: false,
		DEVOPS:           false,
		COMMUNITY_POOL:   false,
		GOV_STAKER:       false,
	}

	if _, ok := validTargets[target]; !ok {
		panic(makeErrorWithDetails(
			errInvalidEmissionTarget,
			ufmt.Sprintf("invalid target(%d)", target),
		))
	}
}

// assertValidDistributionPct ensures the sum of all distribution percentages equals 10000 (100%).
// Panics if the sum does not equal exactly 10000 basis points.
func assertValidDistributionPct(pct01, pct02, pct03, pct04 int64) {
	// Validate individual percentages are non-negative and reasonable
	percentages := []int64{pct01, pct02, pct03, pct04}
	for i, pct := range percentages {
		if pct < 0 {
			panic(makeErrorWithDetails(
				errInvalidEmissionPct,
				ufmt.Sprintf("percentage %d cannot be negative: %d", i+1, pct),
			))
		}

		if pct > 10000 {
			panic(makeErrorWithDetails(
				errInvalidEmissionPct,
				ufmt.Sprintf("percentage %d cannot exceed 100%%: %d", i+1, pct),
			))
		}
	}

	sum := pct01 + pct02 + pct03 + pct04
	if sum != 10000 {
		panic(makeErrorWithDetails(
			errInvalidEmissionPct,
			ufmt.Sprintf("sum of percentages must be 10000, got %d", sum),
		))
	}
}

package emission

import (
	"chain"
	"chain/runtime"
	"time"

	"gno.land/p/nt/ufmt"

	prbac "gno.land/p/gnoswap/rbac"

	"gno.land/r/gnoswap/access"
	"gno.land/r/gnoswap/gns"
	"gno.land/r/gnoswap/halt"
)

const (
	_ int = iota
	LIQUIDITY_STAKER
	DEVOPS
	COMMUNITY_POOL
	GOV_STAKER
)

var (
	// Stores the percentage (in basis points) for each distribution target
	// 1 basis point = 0.01%
	// These percentages can be modified through governance.
	distributionBpsPct map[int]int64

	distributedToStaker        int64 // can be cleared by staker contract
	distributedToDevOps        int64
	distributedToCommunityPool int64
	distributedToGovStaker     int64 // can be cleared by governance staker

	// Historical total distributions (never reset)
	accuDistributedToStaker        int64
	accuDistributedToDevOps        int64
	accuDistributedToCommunityPool int64
	accuDistributedToGovStaker     int64
)

// Initialize default distribution percentages:
// - Liquidity Stakers: 75%
// - DevOps: 20%
// - Community Pool: 5%
// - Governance Stakers: 0%
//
// ref: https://docs.gnoswap.io/gnoswap-token/emission
func init() {
	distributionBpsPct = map[int]int64{
		LIQUIDITY_STAKER: 7500,
		DEVOPS:           2000,
		COMMUNITY_POOL:   500,
		GOV_STAKER:       0,
	}
}

// ChangeDistributionPct changes distribution percentages for emission targets.
//
// This function redistributes how newly minted GNS tokens are allocated across
// protocol components. Before applying new ratios, it distributes any accumulated
// emissions using the current ratios, ensuring emissions are distributed according
// to the ratios in effect when they were generated. This prevents retroactive
// application of new ratios to past emissions.
//
// Parameters:
//   - target01-04: Target identifiers (1=LIQUIDITY_STAKER, 2=DEVOPS, 3=COMMUNITY_POOL, 4=GOV_STAKER)
//   - pct01-04: Percentage in basis points (100 = 1%, 10000 = 100%)
//
// Requirements:
//   - All four targets must be specified (use current values if unchanged)
//   - Percentages must sum to exactly 10000 (100%)
//   - Each percentage must be 0-10000
//   - Targets must be unique (no duplicates)
//
// Example:
//
//	ChangeDistributionPct(
//	  1, 7000,  // 70% to liquidity stakers
//	  2, 2000,  // 20% to devops
//	  3, 1000,  // 10% to community pool
//	  4, 0      // 0% to governance stakers
//	)
//
// Only callable by admin or governance.
func ChangeDistributionPct(
	cur realm,
	target01 int, pct01 int64,
	target02 int, pct02 int64,
	target03 int, pct03 int64,
	target04 int, pct04 int64,
) {
	halt.AssertIsNotHaltedEmission()

	caller := runtime.PreviousRealm().Address()
	access.AssertIsAdminOrGovernance(caller)

	assertValidDistributionTargets(target01, target02, target03, target04)
	assertValidDistributionPct(pct01, pct02, pct03, pct04)

	// Distribute accumulated emissions with current ratios before changing ratios.
	// This prevents retroactive application of new ratios to emissions that occurred
	// under previous ratio configurations.
	MintAndDistributeGns(cross)

	if onDistributionPctChangeCallback != nil {
		currentTimestamp := time.Now().Unix()
		emissionAmountPerSecond := GetEmissionAmountPerSecondBy(currentTimestamp, pct01)
		onDistributionPctChangeCallback(emissionAmountPerSecond)
	}

	changeDistributionPcts(
		target01, pct01,
		target02, pct02,
		target03, pct03,
		target04, pct04,
	)

	previousRealm := runtime.PreviousRealm()
	chain.Emit(
		"ChangeDistributionPct",
		"prevAddr", previousRealm.Address().String(),
		"prevRealm", previousRealm.PkgPath(),
		"target01", targetToStr(target01),
		"pct01", formatInt(pct01),
		"target02", targetToStr(target02),
		"pct02", formatInt(pct02),
		"target03", targetToStr(target03),
		"pct03", formatInt(pct03),
		"target04", targetToStr(target04),
		"pct04", formatInt(pct04),
	)
}

// changeDistributionPcts updates the distribution percentages in the AVL tree.
func changeDistributionPcts(
	target01 int, pct01 int64,
	target02 int, pct02 int64,
	target03 int, pct03 int64,
	target04 int, pct04 int64,
) {
	// First, cache the percentage of the staker just before it changes Callback if needed
	// (check if the LIQUIDITY_STAKER was located between target01 and 04)
	setDistributionBpsPct(target01, pct01)
	setDistributionBpsPct(target02, pct02)
	setDistributionBpsPct(target03, pct03)
	setDistributionBpsPct(target04, pct04)
}

// distributeToTarget distributes tokens according to configured percentages.
//
// Returns total amount distributed and any error.
func distributeToTarget(amount int64) (int64, error) {
	totalSent := int64(0)

	for target, pct := range distributionBpsPct {
		distAmount := calculateAmount(amount, pct)

		// Skip zero amounts to avoid unnecessary transfers
		if distAmount == 0 {
			continue
		}

		totalSent = safeAddInt64(totalSent, distAmount)

		err := transferToTarget(target, distAmount)
		if err != nil {
			return totalSent, err
		}
	}

	return totalSent, nil
}

func calculateDistributableAmounts(amount int64, bps map[int]int64) (map[int]int64, int64) {
	distributed := make(map[int]int64, 0)
	if bps == nil {
		return distributed, amount
	}

	targets := []int{LIQUIDITY_STAKER, DEVOPS, COMMUNITY_POOL, GOV_STAKER}
	totalSent := int64(0)

	for _, target := range targets {
		pct := bps[target]
		distAmount := calculateAmount(amount, pct)
		if distAmount == 0 {
			continue
		}

		distributed[target] = distAmount
		totalSent = safeAddInt64(totalSent, distAmount)
	}

	leftAmount := safeSubInt64(amount, totalSent)
	return distributed, leftAmount
}

// calculateAmount converts basis points to actual token amount.
func calculateAmount(amount, bptPct int64) int64 {
	if amount < 0 || bptPct < 0 || bptPct > 10000 {
		panic("invalid amount or bptPct")
	}

	// More precise overflow prevention
	const maxInt64 = 9223372036854775807
	if amount > maxInt64/10000 {
		panic("amount too large, would cause overflow")
	}

	// Additional safety check for zero division
	if bptPct == 0 {
		return 0
	}

	return amount * bptPct / 10000
}

// transferToTarget sends tokens to the appropriate target address.
//
// Returns error if target address not found.
func transferToTarget(target int, amount int64) error {
	switch target {
	case LIQUIDITY_STAKER:
		stakerAddr, ok := access.GetAddress(prbac.ROLE_STAKER.String())
		if !ok {
			return makeErrorWithDetails(
				errDistributionAddressNotFound,
				ufmt.Sprintf("%s not found", prbac.ROLE_STAKER.String()),
			)
		}

		distributedToStaker = safeAddInt64(distributedToStaker, amount)
		accuDistributedToStaker = safeAddInt64(accuDistributedToStaker, amount)
		gns.Transfer(cross, stakerAddr, amount)

	case DEVOPS:
		devOpsAddr, ok := access.GetAddress(prbac.ROLE_DEVOPS.String())
		if !ok {
			return makeErrorWithDetails(
				errDistributionAddressNotFound,
				ufmt.Sprintf("%s not found", prbac.ROLE_DEVOPS.String()),
			)
		}

		distributedToDevOps = safeAddInt64(distributedToDevOps, amount)
		accuDistributedToDevOps = safeAddInt64(accuDistributedToDevOps, amount)
		gns.Transfer(cross, devOpsAddr, amount)

	case COMMUNITY_POOL:
		communityPoolAddr, ok := access.GetAddress(prbac.ROLE_COMMUNITY_POOL.String())
		if !ok {
			return makeErrorWithDetails(
				errDistributionAddressNotFound,
				ufmt.Sprintf("%s not found", prbac.ROLE_COMMUNITY_POOL.String()),
			)
		}

		distributedToCommunityPool = safeAddInt64(distributedToCommunityPool, amount)
		accuDistributedToCommunityPool = safeAddInt64(accuDistributedToCommunityPool, amount)
		gns.Transfer(cross, communityPoolAddr, amount)

	case GOV_STAKER:
		govStakerAddr, ok := access.GetAddress(prbac.ROLE_GOV_STAKER.String())
		if !ok {
			return makeErrorWithDetails(
				errDistributionAddressNotFound,
				ufmt.Sprintf("%s not found", prbac.ROLE_GOV_STAKER.String()),
			)
		}

		distributedToGovStaker = safeAddInt64(distributedToGovStaker, amount)
		accuDistributedToGovStaker = safeAddInt64(accuDistributedToGovStaker, amount)
		gns.Transfer(cross, govStakerAddr, amount)

	default:
		return makeErrorWithDetails(
			errInvalidEmissionTarget,
			ufmt.Sprintf("invalid target(%d)", target),
		)
	}

	return nil
}

// GetDistributionBpsPct returns the distribution percentage in basis points for a specific target.
func GetDistributionBpsPct(target int) int64 {
	assertValidDistributionTarget(target)
	if distributionBpsPct == nil {
		panic("distributionBpsPct is nil")
	}

	pct, exist := distributionBpsPct[target]
	if !exist {
		panic(makeErrorWithDetails(
			errInvalidEmissionTarget,
			ufmt.Sprintf("invalid target(%d)", target),
		))
	}

	return pct
}

// GetDistributedToStaker returns pending GNS for liquidity stakers.
func GetDistributedToStaker() int64 {
	return distributedToStaker
}

// GetDistributedToDevOps returns accumulated GNS for DevOps.
func GetDistributedToDevOps() int64 {
	return distributedToDevOps
}

// GetDistributedToCommunityPool returns the amount of GNS distributed to Community Pool.
func GetDistributedToCommunityPool() int64 {
	return distributedToCommunityPool
}

// GetDistributedToGovStaker returns the amount of GNS distributed to governance stakers since last clear.
func GetDistributedToGovStaker() int64 {
	return distributedToGovStaker
}

func AccumulateDistributedInfo() (toStaker, toDevOps, toCommunityPool, toGovStaker int64) {
    toStaker = GetDistributedToStaker()
    toDevOps = GetDistributedToDevOps()
    toCommunityPool = GetDistributedToCommunityPool()
    toGovStaker = GetDistributedToGovStaker()
    return
}

// GetAccuDistributedToStaker returns the total historical GNS distributed to liquidity stakers.
func GetAccuDistributedToStaker() int64 {
	return accuDistributedToStaker
}

// GetAccuDistributedToDevOps returns the total historical GNS distributed to DevOps.
func GetAccuDistributedToDevOps() int64 {
	return accuDistributedToDevOps
}

// GetAccuDistributedToCommunityPool returns the total historical GNS distributed to Community Pool.
func GetAccuDistributedToCommunityPool() int64 {
	return accuDistributedToCommunityPool
}

// GetAccuDistributedToGovStaker returns the total historical GNS distributed to governance stakers.
func GetAccuDistributedToGovStaker() int64 {
	return accuDistributedToGovStaker
}

// GetEmissionAmountPerSecondBy returns the emission amount per second for a given timestamp and distribution percentage.
func GetEmissionAmountPerSecondBy(timestamp, distributionPct int64) int64 {
	return calculateAmount(gns.GetEmissionAmountPerSecondByTimestamp(timestamp), distributionPct)
}

// GetStakerEmissionAmountPerSecond returns the current per-second emission amount allocated to liquidity stakers.
func GetStakerEmissionAmountPerSecond() int64 {
	currentTimestamp := time.Now().Unix()
	return GetEmissionAmountPerSecondBy(currentTimestamp, GetDistributionBpsPct(LIQUIDITY_STAKER))
}

// GetStakerEmissionAmountPerSecondInRange returns emission amounts allocated to liquidity stakers for a time range.
func GetStakerEmissionAmountPerSecondInRange(start, end int64) ([]int64, []int64) {
	halvingBlocks, halvingEmissions := gns.GetEmissionAmountPerSecondInRange(start, end)
	for i := range halvingBlocks {
		// Applying staker ratio for past halving blocks
		halvingEmissions[i] = calculateAmount(halvingEmissions[i], GetDistributionBpsPct(LIQUIDITY_STAKER))
	}

	return halvingBlocks, halvingEmissions
}

// ClearDistributedToStaker resets the pending distribution amount for liquidity stakers.
//
// Only callable by staker contract.
func ClearDistributedToStaker(cur realm) {
	caller := runtime.PreviousRealm().Address()
	access.AssertIsStaker(caller)

	distributedToStaker = 0
}

// ClearDistributedToGovStaker resets the pending distribution amount for governance stakers.
//
// Only callable by governance staker contract.
func ClearDistributedToGovStaker(cur realm) {
	caller := runtime.PreviousRealm().Address()
	access.AssertIsGovStaker(caller)
	distributedToGovStaker = 0
}

// setDistributionBpsPct changes percentage of each target for how much GNS it will get by emission.
// Creates new AVL tree if nil.
func setDistributionBpsPct(target int, pct int64) {
	if distributionBpsPct == nil {
		distributionBpsPct = make(map[int]int64)
	}

	distributionBpsPct[target] = pct
}

// targetToStr converts target constant to string representation.
func targetToStr(target int) string {
	switch target {
	case LIQUIDITY_STAKER:
		return "LIQUIDITY_STAKER"
	case DEVOPS:
		return "DEVOPS"
	case COMMUNITY_POOL:
		return "COMMUNITY_POOL"
	case GOV_STAKER:
		return "GOV_STAKER"
	default:
		return "UNKNOWN"
	}
}

// Package emission manages GNS token emission and distribution for GnoSwap.
//
// The emission system controls creation and distribution of new GNS tokens
// with a deflationary model featuring periodic halvings over 12 years.
//
// Emission Schedule:
//   - Year 1-2:  100% emission rate (225,000,000 GNS/year)
//   - Year 3-4:   50% emission rate (112,500,000 GNS/year)
//   - Year 5-6:   25% emission rate  (56,250,000 GNS/year)
//   - Year 7-8: 12.5% emission rate  (28,125,000 GNS/year)
//   - Year 9-12: 6.25% emission rate (14,062,500 GNS/year)
//
// Distribution Targets (configurable via governance):
//   - LIQUIDITY_STAKER: Rewards for LP providers (default 75%)
//   - DEVOPS: Development and operations fund (default 20%)
//   - COMMUNITY_POOL: Community-governed treasury (default 5%)
//   - GOV_STAKER: GNS staking rewards (default 0%)
//
// Key Functions:
//   - MintAndDistributeGns: Mints and distributes GNS per emission schedule
//   - SetDistributionStartTime: One-time setup of emission start timestamp
//   - ChangeDistributionPct: Updates distribution percentages
//   - ClearDistributedToStaker/GovStaker: Resets pending distribution amounts
package emission

package emission

import (
	"chain"
	"chain/runtime"
	"math"
	"time"

	"gno.land/r/gnoswap/access"
	"gno.land/r/gnoswap/gns"
	"gno.land/r/gnoswap/halt"
)

const totalDistributionDuration = 12 * 365 * 24 * 60 * 60 // 12 years

var (
	// leftGNSAmount tracks undistributed GNS tokens from previous distributions
	leftGNSAmount int64

	// lastExecutedTimestamp stores the last timestamp when distribution was executed
	lastExecutedTimestamp int64

	// emissionAddr is the address of the emission realm
	emissionAddr = runtime.CurrentRealm().Address()

	// distributionStartTimestamp is the timestamp from which emission distribution starts
	// Default is 0, meaning distribution is not started until explicitly set
	distributionStartTimestamp int64

	// onDistributionPctChangeCallback is called when distribution percentages change
	// This allows external contracts (like staker) to update their caches
	onDistributionPctChangeCallback func(emissionAmountPerSecond int64)
)

// setLeftGNSAmount updates the undistributed GNS token amount
func setLeftGNSAmount(amount int64) {
	if amount < 0 {
		panic("left GNS amount cannot be negative")
	}

	leftGNSAmount = amount
}

// setLastExecutedTimestamp updates the timestamp of the last emission distribution execution.
func setLastExecutedTimestamp(timestamp int64) {
	if timestamp < 0 {
		panic("last executed timestamp cannot be negative")
	}

	lastExecutedTimestamp = timestamp
}

// MintAndDistributeGns mints and distributes GNS tokens according to the emission schedule.
//
// This function is called automatically by protocol contracts during user interactions
// to trigger periodic GNS emission. It mints new tokens based on elapsed time since
// last distribution and distributes them to predefined targets (staker, devops, etc.).
//
// Returns:
//   - int64: Total amount of GNS distributed in this call
//
// Note: Distribution only occurs if start timestamp is set and reached.
// Any undistributed tokens from previous calls are carried forward.
func MintAndDistributeGns(cur realm) (int64, bool) {
	if halt.IsHaltedEmission() {
		return 0, false
	}

	currentHeight := runtime.ChainHeight()
	currentTimestamp := time.Now().Unix()

	// Check if distribution start timestamp is set and if current timestamp has reached it
	// If distributionStartTimestamp is 0 (default), skip distribution to prevent immediate start
	// If current timestamp is below start timestamp, skip distribution
	if distributionStartTimestamp == 0 || currentTimestamp < distributionStartTimestamp {
		return 0, true
	}

	// Skip if we've already minted tokens at this timestamp
	lastMintedTimestamp := gns.LastMintedTimestamp()
	if currentTimestamp <= lastMintedTimestamp {
		return 0, true
	}

	// Additional check to prevent re-entrancy
	if lastExecutedTimestamp >= currentTimestamp {
		// Skip if we've already processed this height in emission
		return 0, true
	}

	// Mint new tokens and add any leftover amounts from previous distribution
	mintedEmissionRewardAmount := gns.MintGns(cross, emissionAddr)

	// Validate minted amount
	if mintedEmissionRewardAmount < 0 {
		panic("minted emission reward amount cannot be negative")
	}

	distributableAmount := mintedEmissionRewardAmount
	prevLeftAmount := GetLeftGNSAmount()

	if leftGNSAmount > 0 {
		// Check for overflow before addition
		if distributableAmount > math.MaxInt64-prevLeftAmount {
			panic("distributable amount would overflow")
		}

		distributableAmount += prevLeftAmount
		setLeftGNSAmount(0)
	}

	// Distribute tokens and track any undistributed amount
	distributedGNSAmount, err := distributeToTarget(distributableAmount)
	if err != nil {
		panic(err)
	}

	// Validate distribution arithmetic
	if distributedGNSAmount < 0 {
		panic("distributed amount cannot be negative")
	}

	if distributedGNSAmount > distributableAmount {
		panic("distributed amount cannot exceed distributable amount")
	}

	if distributableAmount != distributedGNSAmount {
		remainder := safeSubInt64(distributableAmount, distributedGNSAmount)
		if remainder < 0 {
			panic("remainder calculation error")
		}
		setLeftGNSAmount(remainder)
	}

	setLastExecutedTimestamp(currentTimestamp)

	previousRealm := runtime.PreviousRealm()
	chain.Emit(
		"MintAndDistributeGns",
		"prevAddr", previousRealm.Address().String(),
		"prevRealm", previousRealm.PkgPath(),
		"lastTimestamp", formatInt(lastExecutedTimestamp),
		"currentTimestamp", formatInt(currentTimestamp),
		"currentHeight", formatInt(currentHeight),
		"mintedAmount", formatInt(mintedEmissionRewardAmount),
		"prevLeftAmount", formatInt(prevLeftAmount),
		"distributedAmount", formatInt(distributedGNSAmount),
		"currentLeftAmount", formatInt(GetLeftGNSAmount()),
		"gnsTotalSupply", formatInt(gns.TotalSupply()),
	)

	return distributedGNSAmount, true
}

// SetDistributionStartTime sets the timestamp when emission distribution starts.
//
// This function controls when GNS emission begins. Once set and reached, the protocol
// starts minting GNS tokens according to the emission schedule. The timestamp can only
// be set before distribution starts - it becomes immutable once active.
//
// Parameters:
//   - startTimestamp: Unix timestamp when emission should begin
//
// Requirements:
//   - Must be called before distribution starts (one-time setup)
//   - Timestamp must be in the future
//   - Cannot be negative
//
// Effects:
//   - Sets global distribution start time
//   - Initializes GNS emission state if not already started
//   - Emission begins automatically when timestamp is reached
//
// Only callable by admin or governance.
func SetDistributionStartTime(cur realm, startTimestamp int64) {
	halt.AssertIsNotHaltedEmission()
	halt.AssertIsNotHaltedWithdraw()

	caller := runtime.PreviousRealm().Address()
	access.AssertIsAdminOrGovernance(caller)

	if startTimestamp <= 0 {
		panic("distribution start timestamp must be positive")
	}

	if startTimestamp > math.MaxInt64-totalDistributionDuration {
		panic("distribution end timestamp must be before max int64 timestamp")
	}

	currentTimestamp := time.Now().Unix()

	// Must be in the future.
	if startTimestamp <= currentTimestamp {
		panic("distribution start timestamp must be greater than current timestamp")
	}

	// Cannot change after distribution started.
	if distributionStartTimestamp != 0 && distributionStartTimestamp <= currentTimestamp {
		panic("distribution has already started, cannot change start timestamp")
	}

	prevStartTimestamp := distributionStartTimestamp

	if gns.MintedEmissionAmount() == 0 {
		currentHeight := runtime.ChainHeight()
		gns.InitEmissionState(cross, currentHeight, startTimestamp)
	}

	distributionStartTimestamp = startTimestamp

	chain.Emit(
		"SetDistributionStartTime",
		"caller", caller.String(),
		"prevStartTimestamp", formatInt(prevStartTimestamp),
		"newStartTimestamp", formatInt(startTimestamp),
		"height", formatInt(runtime.ChainHeight()),
		"timestamp", formatInt(time.Now().Unix()),
	)
}

// SetOnDistributionPctChangeCallback sets a callback function to be called when distribution percentages change.
// This allows external contracts (like staker) to update their internal caches when governance changes emission rates.
//
// Only callable by the staker contract.
func SetOnDistributionPctChangeCallback(cur realm, callback func(int64)) {
	caller := runtime.PreviousRealm().Address()
	access.AssertIsStaker(caller)

	onDistributionPctChangeCallback = callback

	if onDistributionPctChangeCallback != nil {
		emissionAmountPerSecond := GetStakerEmissionAmountPerSecond()
		onDistributionPctChangeCallback(emissionAmountPerSecond)
	}
}

