import (
	"math"
	"strconv"

	"gno.land/p/nt/ufmt"
)

// formatUint converts various unsigned integer types to string representation.
// Panics if the type is not supported.
func formatUint(v any) string {
	switch v := v.(type) {
	case uint8:
		return strconv.FormatUint(uint64(v), 10)
	case uint32:
		return strconv.FormatUint(uint64(v), 10)
	case uint64:
		return strconv.FormatUint(v, 10)
	default:
		panic(ufmt.Sprintf("invalid type: %T", v))
	}
}

// formatInt converts various signed integer types to string representation.
// Panics if the type is not supported.
func formatInt(v any) string {
	switch v := v.(type) {
	case int32:
		return strconv.FormatInt(int64(v), 10)
	case int64:
		return strconv.FormatInt(v, 10)
	case int:
		return strconv.Itoa(v)
	default:
		panic(ufmt.Sprintf("invalid type: %T", v))
	}
}

// safeAddInt64 performs safe addition of int64 values, panicking on overflow or underflow
func safeAddInt64(a, b int64) int64 {
	if a > 0 && b > math.MaxInt64-a {
		panic("int64 addition overflow")
	}

	if a < 0 && b < math.MinInt64-a {
		panic("int64 addition underflow")
	}

	return a + b
}

// safeSubInt64 performs safe subtraction of int64 values, panicking on overflow or underflow
func safeSubInt64(a, b int64) int64 {
	if b > 0 && a < math.MinInt64+b {
		panic("int64 subtraction underflow")
	}

	if b < 0 && a > math.MaxInt64+b {
		panic("int64 subtraction overflow")
	}

	return a - b
}

package common

// AssertIsUserSendGNOTAmount validates that the user sent the expected GNOT amount.
// Panics with errNotSupportedCoins if unsupported native coins were sent.
// Panics with errInvalidGNOTAmount if the GNOT amount doesn't match the expected amount.
//
// Parameters:
//   - amount: expected GNOT amount in ugnot
//
// Use this when a function requires native GNOT payment.
func AssertIsUserSendGNOTAmount(amount int64) {
	if hasUnsupportedNativeCoins() {
		panic(errNotSupportedCoins)
	}

	if !isUserSendGNOTAmount(amount) {
		panic(errInvalidGNOTAmount)
	}
}

// AssertIsNotHandleNativeCoin validates that no native coins were sent with the transaction.
// Panics with errNotHandleNativeCoin if any native coins were sent.
//
// Use this when a function should only work with GRC20 tokens and not accept native coins.
func AssertIsNotHandleNativeCoin() {
	if ExistsUserSendCoins() {
		panic(errNotHandleNativeCoin)
	}
}

package common

import "chain/banker"

// IsGNOTPath checks if the given path is either native gnot or wrapped ugnot path.
//
// Parameters:
//   - path: token path to check
//
// Returns true if the path matches either GNOT_DENOM ("ugnot") or WUGNOT_PATH.
func IsGNOTPath(path string) bool {
	return path == GNOT_DENOM || path == WUGNOT_PATH
}

// IsGNOTNativePath checks if the given path is the native gnot path.
//
// Parameters:
//   - path: token path to check
//
// Returns true if the path matches GNOT_DENOM ("ugnot").
func IsGNOTNativePath(path string) bool {
	return path == GNOT_DENOM
}

// IsGNOTWrappedPath checks if the given path is the wrapped ugnot path.
//
// Parameters:
//   - path: token path to check
//
// Returns true if the path matches WUGNOT_PATH.
func IsGNOTWrappedPath(path string) bool {
	return path == WUGNOT_PATH
}

// ExistsUserSendCoins checks if the user has sent any coins with the transaction.
//
// Returns true if any coins (with positive amount) were sent with the transaction.
func ExistsUserSendCoins() bool {
	return len(getUserSendCoins()) > 0
}

// isUserSendGNOTAmount validates if the user sent the expected gnot amount
// Returns true in the following cases:
//   - GNOT was sent and amount matches expected
//
// Returns false in the following cases:
//   - GNOT was sent and amount does not match expected
func isUserSendGNOTAmount(amount int64) bool {
	sendCoins := getUserSendCoins()

	gnotAmount := int64(0)

	if amount, exists := sendCoins[GNOT_DENOM]; exists {
		gnotAmount = amount
	}

	return gnotAmount == amount
}

// hasUnsupportedNativeCoins checks if the user sent unsupported native coins
// Gnoswap only supports GNOT native coin, so this function detects:
// Returns true (has unsupported coins) in the following cases:
//   - Multiple coin types were sent (more than 1 coin type)
//   - Single non-GNOT coin was sent
//   - Single GNOT coin was sent but amount is zero or negative
//
// Returns false (no unsupported coins) in the following cases:
//   - No coins were sent at all
//   - Single GNOT coin was sent with positive amount
func hasUnsupportedNativeCoins() bool {
	sendCoins := getUserSendCoins()
	if len(sendCoins) == 0 {
		return false
	}

	if len(sendCoins) != 1 {
		return true
	}

	amount, ok := sendCoins[GNOT_DENOM]
	if !ok || amount <= 0 {
		return true
	}

	return false
}

// getUserSendCoins retrieves and aggregates all coins sent by the user in the current transaction
// Returns a map of denomination to total amount, filtering out zero or negative amounts
func getUserSendCoins() map[string]int64 {
	coinsMap := make(map[string]int64)

	for _, coin := range banker.OriginSend() {
		if coin.Amount <= 0 {
			continue
		}

		if _, exists := coinsMap[coin.Denom]; exists {
			coinsMap[coin.Denom] += coin.Amount
		} else {
			coinsMap[coin.Denom] = coin.Amount
		}
	}

	return coinsMap
}

package common

const (
	// minTick is the minimum valid tick index in the concentrated liquidity model.
	// Represents the lowest possible price: 1.0001^(-887272) ≈ 0
	minTick = -887272

	// maxTick is the maximum valid tick index in the concentrated liquidity model.
	// Represents the highest possible price: 1.0001^887272 ≈ infinity
	maxTick = 887272

	// GNOT_DENOM is the denomination for native GNOT tokens.
	// ugnot is the smallest unit of GNOT (1 GNOT = 1,000,000 ugnot).
	// Used in banker operations, pool pairs, and swap paths.
	GNOT_DENOM = "ugnot"

	// WUGNOT_PATH is the package path for wrapped ugnot (wugnot) token.
	// wrapped ugnot is an GRC20 representation of native GNOT for DeFi operations.
	WUGNOT_PATH = "gno.land/r/gnoland/wugnot"
)

// Package common provides shared utilities and mathematical functions for GnoSwap protocol contracts.
//
// The package contains essential mathematical functions, helper utilities, and shared
// logic used across the GnoSwap protocol. It provides implementations for concentrated liquidity
// calculations, price/tick conversions, GRC20 token operations, and native coin handling.
//
// This package serves as the mathematical foundation for the protocol, implementing algorithms
// based on Uniswap V3's concentrated liquidity model with Q64.96 fixed-point arithmetic.
//
// Key components:
// - Tick Math: Price-tick conversion functions for concentrated liquidity positions
// - Liquidity Math: Liquidity calculations based on token amounts and price ranges
// - GRC20 Registry Helpers: Convenient wrappers for GRC20 token operations
// - Coin Utilities: Native coin (GNOT) handling and validation
// - Assertion Utilities: Input validation and authorization checks
package common

