import (
	b64 "encoding/base64"
	"math/rand"
	"strconv"
	"strings"

	"gno.land/p/nt/ufmt"
)

// SVG template structure:
// The template is split at variable insertion points for efficient string concatenation.
// Full template with placeholders (for reference):
//
//	<svg width="135" height="135" viewBox="0 0 135 135" fill="none" xmlns="...">
//	  <g clip-path="url(#clip0_7698_56846)">
//	    <circle cx="67.5" cy="67.5" r="67.5" fill="url(#paint0_linear_7698_56846)"/>
//	    ... (path elements) ...
//	  </g>
//	  <defs>
//	    <linearGradient id="paint0_linear_7698_56846"
//	      x1="{x1}" y1="{y1}" x2="{x2}" y2="{y2}"   <-- variables
//	      gradientUnits="userSpaceOnUse">
//	      <stop stop-color="{color1}"/>             <-- variable
//	      <stop offset="1" stop-color="{color2}"/>  <-- variable
//	    </linearGradient>
//	    ...
//	  </defs>
//	</svg>

// svgTemplate holds pre-split template parts for efficient concatenation.
// Usage: svgTemplate[0] + x1 + svgTemplate[1] + y1 + ... + color2 + svgTemplate[6]
var svgTemplate = [7]string{
	// [0] SVG header and body (before x1)
	`<svg width="135" height="135" viewBox="0 0 135 135" fill="none" xmlns="http://www.w3.org/2000/svg">
<g clip-path="url(#clip0_7698_56846)">
<circle cx="67.5" cy="67.5" r="67.5" fill="url(#paint0_linear_7698_56846)"/>
<path d="M51.2905 42.9449L66.4895 33L97 52.8061L81.8241 62.7425L51.2905 42.9449Z" fill="white"/>
<path d="M51.6055 67.5059L66.8044 57.561L97 77.0657L82.1046 87.1793L51.6055 67.5059Z" fill="white" fill-opacity="0.4"/>
<path d="M36.0464 81.7559L51.2905 71.811L81.7336 91.6547L66.4895 101.508L36.0464 81.7559Z" fill="white" fill-opacity="0.6"/>
<path d="M36.001 52.8055L51.2884 42.9177L51.2884 71.8145L36.001 81.779L36.001 52.8055Z" fill="white"/>
<path d="M82.1051 87.1797L97.0016 77.0662L97.0016 81.7029L81.7896 91.629L82.1051 87.1797Z" fill="white" fill-opacity="0.5"/>
</g>
<defs>
<linearGradient id="paint0_linear_7698_56846" x1="`,
	// [1] between x1 and y1
	`" y1="`,
	// [2] between y1 and x2
	`" x2="`,
	// [3] between x2 and y2
	`" y2="`,
	// [4] between y2 and color1
	`" gradientUnits="userSpaceOnUse">
<stop stop-color="`,
	// [5] between color1 and color2
	`"/>
<stop offset="1" stop-color="`,
	// [6] SVG footer (after color2)
	`"/>
</linearGradient>
<clipPath id="clip0_7698_56846">
<rect width="135" height="135" fill="white"/>
</clipPath>
</defs>
</svg>
`,
}

// charset contains valid hex digits for color generation.
const charset = "0123456789ABCDEF"

// Parameter range constants for gradient coordinates.
const (
	x1Min = 7
	x1Max = 13
	y1Min = 7
	y1Max = 13
	x2Min = 121
	x2Max = 126
	y2Min = 121
	y2Max = 126

	x1Range = x1Max - x1Min + 1
	y1Range = y1Max - y1Min + 1
	x2Range = x2Max - x2Min + 1
	y2Range = y2Max - y2Min + 1
)

// genImageParamsString generates random gradient parameters and returns them as a compact string.
// Format: "x1,y1,x2,y2,color1,color2" (e.g., "10,12,125,123,#AABBCC,#DDEEFF")
func genImageParamsString(r *rand.Rand) string {
	x1 := x1Min + r.Uint64N(x1Range)
	y1 := y1Min + r.Uint64N(y1Range)
	x2 := x2Min + r.Uint64N(x2Range)
	y2 := y2Min + r.Uint64N(y2Range)

	var buf1 [7]byte
	var buf2 [7]byte
	buf1[0] = '#'
	buf2[0] = '#'
	for i := 1; i < 7; i++ {
		buf1[i] = charset[r.IntN(16)]
		buf2[i] = charset[r.IntN(16)]
	}
	color1 := string(buf1[:])
	color2 := string(buf2[:])

	return strconv.Itoa(int(x1)) + "," + strconv.Itoa(int(y1)) + "," +
		strconv.Itoa(int(x2)) + "," + strconv.Itoa(int(y2)) + "," +
		color1 + "," + color2
}

// ImageParams holds parsed and validated image parameters.
type ImageParams struct {
	x1, y1, x2, y2 int
	color1, color2 string
}

// validateCoordinate checks if a coordinate value is within valid range.
// Returns error with details about which coordinate failed if out of range.
func validateCoordinate(value int, min int, max int, name string) error {
	if value < min || value > max {
		details := ufmt.Sprintf("%s=%d (expected range: [%d, %d])", name, value, min, max)
		return makeErrorWithDetails(errInvalidTokenParamsRange, details)
	}
	return nil
}

// parseImageParams parses and validates parameters in one step.
// Returns parsed ImageParams pointer or error.
// Returns nil on error to avoid allocating zero-value struct.
// Expected format: "x1,y1,x2,y2,color1,color2"
func parseImageParams(s string) (*ImageParams, error) {
	parts := strings.Split(s, ",")
	if len(parts) != 6 {
		return nil, errInvalidTokenParams
	}

	x1, err := strconv.Atoi(parts[0])
	if err != nil {
		return nil, errInvalidTokenParams
	}

	y1, err := strconv.Atoi(parts[1])
	if err != nil {
		return nil, errInvalidTokenParams
	}

	x2, err := strconv.Atoi(parts[2])
	if err != nil {
		return nil, errInvalidTokenParams
	}

	y2, err := strconv.Atoi(parts[3])
	if err != nil {
		return nil, errInvalidTokenParams
	}

	// Validate coordinate ranges with detailed error messages
	if err := validateCoordinate(x1, x1Min, x1Max, "x1"); err != nil {
		return nil, err
	}
	if err := validateCoordinate(y1, y1Min, y1Max, "y1"); err != nil {
		return nil, err
	}
	if err := validateCoordinate(x2, x2Min, x2Max, "x2"); err != nil {
		return nil, err
	}
	if err := validateCoordinate(y2, y2Min, y2Max, "y2"); err != nil {
		return nil, err
	}

	color1 := parts[4]
	color2 := parts[5]

	// Validate color format (#XXXXXX)
	if !isValidHexColor(color1) || !isValidHexColor(color2) {
		return nil, errInvalidColorFormat
	}

	return &ImageParams{
		x1:     x1,
		y1:     y1,
		x2:     x2,
		y2:     y2,
		color1: color1,
		color2: color2,
	}, nil
}

// generateImageURI converts parsed image parameters to a base64-encoded SVG image URI.
func (params ImageParams) generateImageURI() string {
	svg := params.generateSVG()
	sEnc := b64.StdEncoding.EncodeToString([]byte(svg))

	return "data:image/svg+xml;base64," + sEnc
}

// generateSVG generates SVG image from parsed and validated parameters.
func (params ImageParams) generateSVG() string {
	return svgTemplate[0] + strconv.Itoa(params.x1) + svgTemplate[1] + strconv.Itoa(params.y1) +
		svgTemplate[2] + strconv.Itoa(params.x2) + svgTemplate[3] + strconv.Itoa(params.y2) +
		svgTemplate[4] + params.color1 + svgTemplate[5] + params.color2 + svgTemplate[6]
}

// isValidHexColor checks if a string is a valid hex color in #XXXXXX format.
func isValidHexColor(color string) bool {
	if len(color) != 7 || color[0] != '#' {
		return false
	}

	for i := 1; i < 7; i++ {
		c := color[i]

		isHex := (c >= '0' && c <= '9') || (c >= 'A' && c <= 'F') || (c >= 'a' && c <= 'f')
		if !isHex {
			return false
		}
	}

	return true
}

package gnft

import (
	"chain/runtime"
	"math/rand"
	"time"

	"gno.land/p/demo/tokens/grc721"
	"gno.land/p/nt/ufmt"
)

// generateRandInstance generates a new random instance.
func generateRandInstance() *rand.Rand {
	now := time.Now()
	seed1 := now.Unix() + TotalSupply()
	seed2 := now.UnixNano() + TotalSupply()
	pcg := rand.NewPCG(uint64(seed1), uint64(seed2))
	return rand.New(pcg)
}

// checkErr panics if an error occurs.
func checkErr(err error) {
	if err != nil {
		panic(err.Error())
	}
}

// checkTransferErr wraps transfer errors with more specific context.
func checkTransferErr(err error, from, to address, tid grc721.TokenID) {
	if err == nil {
		return
	}

	caller := runtime.PreviousRealm().Address()

	// Check if token exists
	owner, ownerErr := nft.OwnerOf(tid)
	if ownerErr != nil {
		panic(ownerErr)
	}

	switch err {
	case grc721.ErrCallerIsNotOwnerOrApproved:
		// Check if caller is the owner
		if caller == owner {
			panic(makeErrorWithDetails(grc721.ErrTransferFromIncorrectOwner, ufmt.Sprintf("owner mismatch - from: %s, actual owner: %s, token: %s", from, owner, string(tid))))
		}

		// Check if caller is approved for this specific token
		approved, _ := nft.GetApproved(tid)
		if approved != caller {
			// Check if caller is approved for all tokens
			if !nft.IsApprovedForAll(owner, caller) {
				panic(makeErrorWithDetails(grc721.ErrCallerIsNotOwnerOrApproved, ufmt.Sprintf("caller %s is not owner %s or approved for token %s", caller, owner, string(tid))))
			}
		}

	case grc721.ErrInvalidAddress:
		panic(makeErrorWithDetails(grc721.ErrInvalidAddress, ufmt.Sprintf("to address (%s)", to)))

	case grc721.ErrTransferFromIncorrectOwner:
		panic(makeErrorWithDetails(grc721.ErrTransferFromIncorrectOwner, ufmt.Sprintf("from %s is not the owner %s of token %s", from, owner, string(tid))))

	case grc721.ErrInvalidTokenId:
		panic(makeErrorWithDetails(grc721.ErrInvalidTokenId, ufmt.Sprintf("token %s", string(tid))))

	default:
		panic(err.Error())
	}
}

// checkApproveErr wraps approve errors with more specific context.
func checkApproveErr(err error, approved address, tid grc721.TokenID) {
	if err == nil {
		return
	}

	errMsg := err.Error()
	caller := runtime.PreviousRealm().Address()

	// Check if token exists
	owner, ownerErr := nft.OwnerOf(tid)
	if ownerErr != nil {
		panic(makeErrorWithDetails(errTokenNotExists, ufmt.Sprintf("token %s", string(tid))))
	}

	switch {
	case errMsg == "caller is not token owner or approved":
		panic(makeErrorWithDetails(errNotOwnerOrApproved, ufmt.Sprintf("caller %s cannot approve for token %s owned by %s", caller, string(tid), owner)))

	case errMsg == "approval to current owner":
		panic(makeErrorWithDetails(errTransferToSelf, ufmt.Sprintf("cannot approve to current owner %s for token %s", approved, string(tid))))

	default:
		panic(err.Error())
	}
}

// Package xgns implements the GRC20-compliant xGNS token that represents
// staked GNS tokens. It manages minting/burning operations and tracks
// voting power for governance.
package xgns

package xgns

import (
	"chain"
	"chain/runtime"
	"errors"
	"strings"

	"gno.land/p/demo/tokens/grc20"
	"gno.land/p/nt/ownable"
	"gno.land/p/nt/ufmt"

	"gno.land/r/gnoswap/access"
	"gno.land/r/gnoswap/halt"

	prbac "gno.land/p/gnoswap/rbac"
)

var (
	admin         = ownable.NewWithAddress(chain.PackageAddress(prbac.ROLE_GOV_STAKER.String()))
	token, ledger = grc20.NewToken("XGNS", "xGNS", 6)
)

// TotalSupply returns the total supply of xGNS tokens.
func TotalSupply() int64 {
	return token.TotalSupply()
}

// BalanceOf returns token balance for address.
//
// Parameters:
//   - owner: address to check balance for
//
// Returns balance amount.
func BalanceOf(owner address) int64 {
	return token.BalanceOf(owner)
}

// Render returns a formatted representation of the token state.
func Render(path string) string {
	if path == "" {
		return token.RenderHome()
	}

	parts := strings.Split(path, "/")
	switch parts[0] {
	case "balance":
		if len(parts) != 2 {
			return "404\n"
		}
		balance := token.BalanceOf(address(parts[1]))
		return ufmt.Sprintf("%d\n", balance)
	default:
		return "404\n"
	}
}

// Mint mints tokens to address.
//
// Parameters:
//   - to: recipient address
//   - amount: amount to mint
//
// Only callable by governance staker contract.
func Mint(cur realm, to address, amount int64) {
	halt.AssertIsNotHaltedXGns()

	caller := runtime.PreviousRealm().Address()
	access.AssertIsGovStaker(caller)

	checkErr(ledger.Mint(to, amount))
}

// Burn burns tokens from address.
//
// Parameters:
//   - from: address to burn from
//   - amount: amount to burn
//
// Only callable by governance staker contract.
func Burn(cur realm, from address, amount int64) {
	halt.AssertIsNotHaltedXGns()

	caller := runtime.PreviousRealm().Address()
	access.AssertIsGovStaker(caller)

	checkErr(ledger.Burn(from, amount))
}

// SupplyInfo returns supply breakdown information.
//
// Returns:
//   - totalIssued: total xGNS tokens issued
//   - issuedByDelegate: tokens issued through governance delegation
//   - issuedByDepositGns: tokens issued through launchpad deposit
//   - error: error if launchpad address not found
func SupplyInfo() (totalIssued, issuedByDelegate, issuedByDepositGns int64, err error) {
	launchpad, ok := access.GetAddress(prbac.ROLE_LAUNCHPAD.String())
	if !ok {
		return 0, 0, 0, errors.New("launchpad address not found")
	}

	totalIssued = token.TotalSupply()
	issuedByDepositGns = token.BalanceOf(launchpad)
	issuedByDelegate = totalIssued - issuedByDepositGns

	return totalIssued, issuedByDelegate, issuedByDepositGns, nil
}

func checkErr(err error) {
	if err != nil {
		panic(err)
	}
}

