package v1

import (
	"chain"
	"chain/runtime"

	prabc "gno.land/p/gnoswap/rbac"
	"gno.land/p/nt/ufmt"

	"gno.land/r/gnoswap/access"
	"gno.land/r/gnoswap/common"
	"gno.land/r/gnoswap/halt"
	pl "gno.land/r/gnoswap/pool"

	en "gno.land/r/gnoswap/emission"
	pf "gno.land/r/gnoswap/protocol_fee"

	"gno.land/r/gnoswap/gns"
)

const GNS_PATH string = "gno.land/r/gnoswap/gns"

// CreatePool creates a new concentrated liquidity pool.
//
// Deploys new AMM pool for token pair with specified fee tier.
// Charges 100 GNS creation fee to prevent spam.
// Sets initial price and tick spacing based on fee tier.
//
// Parameters:
//   - token0Path, token1Path: Token contract paths (ordered by address)
//   - fee: Fee tier (100=0.01%, 500=0.05%, 3000=0.3%, 10000=1%)
//   - sqrtPriceX96: Initial sqrt price in Q64.96 format
//
// Tick spacing by fee tier:
//   - 0.01%: 1 tick
//   - 0.05%: 10 ticks
//   - 0.30%: 60 ticks
//   - 1.00%: 200 ticks
//
// Requirements:
//   - Tokens must be different
//   - Fee tier must be supported
//   - Pool must not already exist
//   - Caller must have 100 GNS for creation fee
//
// IMPORTANT - Price Initialization Security:
//
//	The sqrtPriceX96 parameter allows arbitrary initial price setting without validation.
//	Extreme prices can make pools temporarily unusable (griefing attack).
//
// Recovery from Price Griefing:
//
//	If a pool is created with an incorrect price, it can be restored via atomic transaction:
//	1. Add wide-range liquidity at the distorted price
//	2. Execute swap to move price toward market rate
//	3. Remove the liquidity
//	The executor's LP losses offset arbitrage gains (minus fees).
func (i *poolV1) CreatePool(
	token0Path string,
	token1Path string,
	fee uint32,
	sqrtPriceX96 string,
) {
	halt.AssertIsNotHaltedPool()

	assertIsSupportedFeeTier(fee)
	assertIsNotExistsPoolPath(i, token0Path, token1Path, fee)

	en.MintAndDistributeGns(cross)

	slot0FeeProtocol := i.store.GetSlot0FeeProtocol()

	poolInfo := newPoolParams(
		token0Path,
		token1Path,
		fee,
		sqrtPriceX96,
		i.GetFeeAmountTickSpacing(fee),
		slot0FeeProtocol,
	)

	err := poolInfo.updateWithWrapping()
	if err != nil {
		panic(err)
	}

	// validate token paths are not the same after wrapping
	assertIsNotEqualsTokens(poolInfo.token0Path, poolInfo.token1Path)

	// check if wrapped token paths are registered
	common.MustRegistered(poolInfo.token0Path, poolInfo.token1Path)

	pool := newPool(poolInfo)
	poolPath := poolInfo.poolPath()

	pools := i.store.GetPools()
	pools.Set(poolPath, pool)

	err = i.store.SetPools(pools)
	if err != nil {
		panic(err)
	}

	poolCreationFee := i.store.GetPoolCreationFee()

	if poolCreationFee > 0 {
		protocolFeeAddr := access.MustGetAddress(prabc.ROLE_PROTOCOL_FEE.String())

		previousRealm := runtime.PreviousRealm()
		previousRealmAddr := previousRealm.Address()
		gns.TransferFrom(cross, previousRealmAddr, protocolFeeAddr, poolCreationFee)
		pf.AddToProtocolFee(cross, GNS_PATH, poolCreationFee)

		chain.Emit(
			"PoolCreationFee",
			"prevAddr", previousRealmAddr.String(),
			"prevRealm", previousRealm.PkgPath(),
			"poolPath", poolPath,
			"feeTokenPath", GNS_PATH,
			"feeAmount", formatInt(poolCreationFee),
		)
	}

	previousRealm := runtime.PreviousRealm()
	chain.Emit(
		"CreatePool",
		"prevAddr", previousRealm.Address().String(),
		"prevRealm", previousRealm.PkgPath(),
		"token0Path", token0Path,
		"token1Path", token1Path,
		"fee", formatUint(fee),
		"sqrtPriceX96", sqrtPriceX96,
		"poolPath", poolPath,
		"tick", formatInt(pool.Slot0Tick()),
		"tickSpacing", formatInt(poolInfo.TickSpacing()),
	)
}

// SetFeeProtocol sets the protocol fee percentage for all pools.
//
// Parameters:
//   - feeProtocol0, feeProtocol1: fee percentages (0-10)
//
// Only callable by admin or governance.
func (i *poolV1) SetFeeProtocol(feeProtocol0, feeProtocol1 uint8) {
	halt.AssertIsNotHaltedPool()

	caller := runtime.PreviousRealm().Address()
	access.AssertIsAdminOrGovernance(caller)

	err := i.setFeeProtocolInternal(feeProtocol0, feeProtocol1)
	if err != nil {
		panic(err)
	}
}

// setFeeAmountTickSpacing associates a tick spacing value with a fee amount.
func (i *poolV1) setFeeAmountTickSpacing(fee uint32, tickSpacing int32) error {
	feeAmountTickSpacing := i.store.GetFeeAmountTickSpacing()
	feeAmountTickSpacing[fee] = tickSpacing

	return i.store.SetFeeAmountTickSpacing(feeAmountTickSpacing)
}

func (i *poolV1) getPool(poolPath string) (*pl.Pool, error) {
	pools := i.store.GetPools()

	iPool, exist := pools.Get(poolPath)
	if !exist {
		return nil, ufmt.Errorf("expected poolPath(%s) to exist", poolPath)
	}

	p, ok := iPool.(*pl.Pool)
	if !ok {
		return nil, ufmt.Errorf("failed to cast pool to *Pool: %T", iPool)
	}

	return p, nil
}

// mustGetPool retrieves a pool instance by its path and ensures it exists.
func (i *poolV1) mustGetPool(poolPath string) (pool *pl.Pool) {
	p, err := i.getPool(poolPath)
	if err != nil {
		panic(makeErrorWithDetails(errDataNotFound, err.Error()))
	}

	return p
}

func (i *poolV1) mustGetPoolBy(token0Path, token1Path string, fee uint32) *pl.Pool {
	poolPath := GetPoolPath(token0Path, token1Path, fee)
	return i.mustGetPool(poolPath)
}

// savePool updates a pool in the pools map and persists to storage.
// This ensures that modifications to pool objects are properly saved.
func (i *poolV1) savePool(pool *pl.Pool) error {
	pools := i.store.GetPools()
	pools.Set(pool.PoolPath(), pool)

	return i.store.SetPools(pools)
}

// setFeeProtocolInternal updates the protocol fee for all pools and emits an event.
func (i *poolV1) setFeeProtocolInternal(feeProtocol0, feeProtocol1 uint8) error {
	oldFee := i.store.GetSlot0FeeProtocol()
	newFee, err := i.setFeeProtocol(feeProtocol0, feeProtocol1)
	if err != nil {
		return err
	}

	feeProtocol0Old := oldFee % 16
	feeProtocol1Old := oldFee >> 4

	previousRealm := runtime.PreviousRealm()
	chain.Emit(
		"SetFeeProtocol",
		"prevAddr", previousRealm.Address().String(),
		"prevRealm", previousRealm.PkgPath(),
		"prevFeeProtocol0", formatUint(feeProtocol0Old),
		"prevFeeProtocol1", formatUint(feeProtocol1Old),
		"feeProtocol0", formatUint(feeProtocol0),
		"feeProtocol1", formatUint(feeProtocol1),
		"newFee", formatUint(newFee),
	)

	return nil
}

// setFeeProtocol updates the protocol fee configuration for all managed pools.
//
// This function combines the protocol fee values for token0 and token1 into a single `uint8` value,
// where:
//   - Lower 4 bits store feeProtocol0 (for token0).
//   - Upper 4 bits store feeProtocol1 (for token1).
//
// The updated fee protocol is applied uniformly to all pools managed by the system.
//
// Parameters:
//   - feeProtocol0: protocol fee for token0 (must be 0 or between 4 and 10 inclusive).
//   - feeProtocol1: protocol fee for token1 (must be 0 or between 4 and 10 inclusive).
//
// Returns:
//   - newFee (uint8): the combined fee protocol value.
//
// Example:
// If feeProtocol0 = 4 and feeProtocol1 = 5:
//
//	newFee = 4 + (5 << 4)
//	// Results in: 0x54 (84 in decimal)
//	// Binary: 0101 0100
//	//         ^^^^ ^^^^
//	//       fee1=5  fee0=4
//
// Notes:
//   - This function ensures that all pools under management are updated to use the same fee protocol.
//   - Caller restrictions (e.g., admin or governance) are not enforced in this function.
//   - Ensure the system is not halted before updating fees.
func (i *poolV1) setFeeProtocol(feeProtocol0, feeProtocol1 uint8) (uint8, error) {
	if err := validateFeeProtocol(feeProtocol0, feeProtocol1); err != nil {
		return 0, err
	}

	// combine both protocol fee into a single byte:
	// - feePrtocol0 occupies the lower 4 bits
	// - feeProtocol1 is shifted the lower 4 positions to occupy the upper 4 bits
	newFee := feeProtocol0 + (feeProtocol1 << 4) // ( << 4 ) = ( * 16 )

	pools := i.store.GetPools()

	// Update slot0 for each pool
	pools.Iterate("", "", func(poolPath string, poolI any) bool {
		pool, ok := poolI.(*pl.Pool)
		if !ok {
			panic(ufmt.Errorf("failed to cast pool to *Pool: %T", pool))
		}

		slot0 := pool.Slot0()
		slot0.SetFeeProtocol(newFee)

		pool.SetSlot0(slot0)
		return false
	})

	// update slot0
	err := i.store.SetSlot0FeeProtocol(newFee)
	if err != nil {
		return 0, err
	}

	return newFee, nil
}

// validateFeeProtocol validates the fee protocol values for token0 and token1.
//
// This function checks whether the provided fee protocol values (`feeProtocol0` and `feeProtocol1`)
// are valid using the `isValidFeeProtocolValue` function. If either value is invalid, it returns
// an error indicating that the protocol fee percentage is invalid.
//
// Parameters:
//   - feeProtocol0: uint8, the fee protocol value for token0.
//   - feeProtocol1: uint8, the fee protocol value for token1.
//
// Returns:
//   - error: Returns `errInvalidProtocolFeePct` if either `feeProtocol0` or `feeProtocol1` is invalid.
//     Returns `nil` if both values are valid.
func validateFeeProtocol(feeProtocol0, feeProtocol1 uint8) error {
	if !isValidFeeProtocolValue(feeProtocol0) || !isValidFeeProtocolValue(feeProtocol1) {
		return errInvalidProtocolFeePct
	}
	return nil
}

// isValidFeeProtocolValue checks if a fee protocol value is within acceptable range.
// Valid values are either 0 (disabled) or between 4 and 10 inclusive.
//
// The value is used as a denominator: protocolFee = swapFee / feeProtocol
// (e.g., feeProtocol=4 means 1/4 = 25% of swap fees go to protocol)
func isValidFeeProtocolValue(value uint8) bool {
	return value == 0 || (value >= 4 && value <= 10)
}

package v1

import (
	"errors"
	"time"

	u256 "gno.land/p/gnoswap/uint256"
	pl "gno.land/r/gnoswap/pool"
)

var max160 = u256.Zero().Sub(u256.Zero().Lsh(u256.One(), 160), u256.One()) // 2^160 - 1

// maxObservationCardinality defines the maximum number of observations to store
const maxObservationCardinality uint16 = 65535

// GetTWAP calculates the time-weighted average price between two points in time
// Returns the arithmetic mean tick and harmonic mean liquidity over the time period
func getTWAP(p *pl.Pool, secondsAgo uint32) (int32, *u256.Uint, error) {
	if secondsAgo == 0 {
		return 0, nil, errors.New("secondsAgo must be greater than 0")
	}

	if p.ObservationState() == nil {
		return 0, nil, errors.New("observation state not initialized")
	}

	// Get observations for current time and secondsAgo
	secondsAgos := []uint32{secondsAgo, 0}
	currentTime := time.Now().Unix()

	tickCumulatives, secondsPerLiquidityCumulativeX128s, err := observe(
		p.ObservationState(),
		currentTime,
		secondsAgos,
		p.Slot0Tick(),
		p.ObservationState().Index(),
		p.Liquidity(),
		p.ObservationState().Cardinality(),
	)
	if err != nil {
		return 0, nil, err
	}

	tickCumulativesDelta := tickCumulatives[1] - tickCumulatives[0]
	secondsPerLiquidityDelta := u256.Zero().Sub(
		secondsPerLiquidityCumulativeX128s[1],
		secondsPerLiquidityCumulativeX128s[0],
	)

	arithmeticMeanTick := int32(tickCumulativesDelta / int64(secondsAgo))
	if tickCumulativesDelta < 0 && (tickCumulativesDelta%int64(secondsAgo) != 0) {
		arithmeticMeanTick--
	}

	if secondsPerLiquidityDelta.IsZero() {
		return arithmeticMeanTick, u256.Zero(), nil
	}

	// Calculate harmonic mean liquidity
	secondsAgoX160 := u256.Zero().Mul(u256.NewUint(uint64(secondsAgo)), max160)
	denominator := u256.Zero().Lsh(secondsPerLiquidityDelta, 32)
	harmonicMeanLiquidity := u256.Zero().Div(secondsAgoX160, denominator)

	return arithmeticMeanTick, harmonicMeanLiquidity, nil
}

func writeObservationByPool(
	p *pl.Pool,
	currentTime int64,
	tick int32,
	liquidity *u256.Uint,
) error {
	if p.ObservationState() == nil {
		p.SetObservationState(pl.NewObservationState(currentTime))
	}

	err := writeObservation(p.ObservationState(), currentTime, tick, liquidity)
	if err != nil {
		return err
	}

	return nil
}

func increaseObservationCardinalityNextByPool(p *pl.Pool, observationCardinalityNext uint16) error {
	observationState := p.ObservationState()

	if observationState == nil {
		return errors.New("observation state not initialized")
	}

	if observationCardinalityNext > maxObservationCardinality {
		return errors.New("observation cardinality next exceeds maximum")
	}

	if observationCardinalityNext <= observationState.CardinalityNext() {
		return errors.New("observation cardinality next must be greater than current")
	}

	observationCardinalityNextNew, err := grow(observationState, observationState.Cardinality(), observationCardinalityNext)
	if err != nil {
		return err
	}

	observationState.SetCardinalityNext(observationCardinalityNextNew)

	return nil
}

func transform(lastObservation *pl.Observation, currentTime int64, tick int32, liquidity *u256.Uint) (*pl.Observation, error) {
	timeDelta := currentTime - lastObservation.BlockTimestamp()
	if timeDelta < 0 {
		return nil, errors.New("time delta must be greater than 0")
	}

	// calculate cumulative values
	tickCumulative := lastObservation.TickCumulative() + int64(tick)*timeDelta

	// calculate liquidity cumulative
	liquidityDelta, overflow := u256.Zero().MulOverflow(liquidity, u256.NewUintFromInt64(timeDelta))
	if overflow {
		panic(errOverflow)
	}

	liquidityCumulative := u256.Zero().Add(lastObservation.LiquidityCumulative(), liquidityDelta)

	// calculate seconds per liquidity
	liquidityForCalc := liquidity
	if liquidity.IsZero() {
		liquidityForCalc = u256.One()
	}

	// secondsPerLiquidity += timeDelta * 2^128 / max(1, liquidity)
	secondsPerLiquidityDelta := u256.MulDiv(
		u256.NewUintFromInt64(timeDelta),
		q128FromDecimal,
		liquidityForCalc,
	)

	secondsPerLiquidityCumulativeX128 := lastObservation.SecondsPerLiquidityCumulativeX128().Clone()
	secondsPerLiquidityCumulativeX128 = u256.Zero().Add(
		secondsPerLiquidityCumulativeX128,
		secondsPerLiquidityDelta,
	)

	return pl.NewObservation(
		currentTime,
		tickCumulative,
		liquidityCumulative,
		secondsPerLiquidityCumulativeX128,
		true,
	), nil
}

func grow(os *pl.ObservationState, currentCardinality, nextCardinality uint16) (uint16, error) {
	if currentCardinality <= 0 {
		return currentCardinality, errors.New("currentCardinality must be greater than 0")
	}

	if nextCardinality <= currentCardinality {
		return currentCardinality, nil
	}

	if nextCardinality > maxObservationCardinality {
		return currentCardinality, errors.New("nextCardinality exceeds maximum")
	}

	// This is more efficient than checking all slots from 0
	for i := currentCardinality; i < nextCardinality; i++ {
		observation := pl.NewDefaultObservation()
		observation.SetBlockTimestamp(1)
		os.Observations()[i] = observation
	}

	return nextCardinality, nil
}

func lte(time, a, b int64) bool {
	if (a <= time) && (time <= b) {
		return a <= b
	}

	aAdjusted := u256.NewUintFromInt64(a)
	bAdjusted := u256.NewUintFromInt64(b)
	timeUint256 := u256.NewUintFromInt64(time)

	if aAdjusted.Gt(timeUint256) {
		aAdjusted = aAdjusted.Add(aAdjusted, u256.NewUintFromInt64(1<<32))
	}

	if bAdjusted.Gt(timeUint256) {
		bAdjusted = bAdjusted.Add(bAdjusted, u256.NewUintFromInt64(1<<32))
	}

	return aAdjusted.Lte(bAdjusted)
}

func writeObservation(
	os *pl.ObservationState,
	currentTime int64,
	tick int32,
	liquidity *u256.Uint,
) error {
	lastObservation, err := lastObservation(os)
	if err != nil {
		return err
	}

	if lastObservation.BlockTimestamp() == currentTime {
		return nil
	}

	// Check if we need to grow the cardinality
	if os.CardinalityNext() > os.Cardinality() && os.Index() == os.Cardinality()-1 {
		os.SetCardinality(os.CardinalityNext())
	}

	nextIndex := (os.Index() + 1) % os.Cardinality()

	// Ensure the slot exists before writing
	if _, ok := os.Observations()[nextIndex]; !ok {
		os.Observations()[nextIndex] = pl.NewDefaultObservation()
	}

	observation, err := transform(lastObservation, currentTime, tick, liquidity)
	if err != nil {
		return err
	}

	os.Observations()[nextIndex] = observation
	os.SetIndex(nextIndex)

	return nil
}

func lastObservation(os *pl.ObservationState) (*pl.Observation, error) {
	observation, ok := os.Observations()[os.Index()]
	if !ok || observation == nil {
		return nil, errNotInitializedObservation
	}

	return observation, nil
}

// observationAt returns the observation at a specific index
// Returns error if the observation doesn't exist
func observationAt(os *pl.ObservationState, index uint16) (*pl.Observation, error) {
	obs, ok := os.Observations()[index]
	if !ok || obs == nil {
		return nil, errNotInitializedObservation
	}

	return obs, nil
}

// observeSingle returns the data for a single observation at a specific time ago
func observeSingle(
	os *pl.ObservationState,
	currentTime int64,
	secondsAgo uint32,
	tick int32,
	index uint16,
	liquidity *u256.Uint,
	cardinality uint16,
) (int64, *u256.Uint, error) {
	if secondsAgo == 0 {
		// if secondsAgo is 0, return current values
		last, err := observationAt(os, index)
		if err != nil {
			return 0, nil, err
		}

		if last.BlockTimestamp() != currentTime {
			// need to create virtual observation for current time
			transformed, err := transform(last, currentTime, tick, liquidity)
			if err != nil {
				return 0, nil, err
			}

			return transformed.TickCumulative(), transformed.SecondsPerLiquidityCumulativeX128(), nil
		}

		return last.TickCumulative(), last.SecondsPerLiquidityCumulativeX128(), nil
	}

	target := currentTime - int64(secondsAgo)

	// find the observations before and after the target
	beforeOrAt, atOrAfter, err := getSurroundingObservations(
		os,
		target,
		currentTime,
		tick,
		index,
		liquidity,
		cardinality,
	)
	if err != nil {
		return 0, nil, err
	}

	if target == beforeOrAt.BlockTimestamp() {
		return beforeOrAt.TickCumulative(), beforeOrAt.SecondsPerLiquidityCumulativeX128(), nil
	}

	if target == atOrAfter.BlockTimestamp() {
		return atOrAfter.TickCumulative(), atOrAfter.SecondsPerLiquidityCumulativeX128(), nil
	}

	// interpolate between the two observations
	observationTimeDelta := atOrAfter.BlockTimestamp() - beforeOrAt.BlockTimestamp()
	targetDelta := target - beforeOrAt.BlockTimestamp()

	// tickCumulative += (tickCumulativeAfter - tickCumulativeBefore) / observationTimeDelta * targetDelta
	tickCumulative := beforeOrAt.TickCumulative() +
		((atOrAfter.TickCumulative()-beforeOrAt.TickCumulative())/observationTimeDelta)*targetDelta

	// for secondsPerLiquidity, need to interpolate carefully
	secondsPerLiquidityDelta := u256.Zero().Sub(
		atOrAfter.SecondsPerLiquidityCumulativeX128(),
		beforeOrAt.SecondsPerLiquidityCumulativeX128(),
	)

	secondsPerLiquidity := u256.Zero().Add(
		beforeOrAt.SecondsPerLiquidityCumulativeX128(),
		u256.MulDiv(
			secondsPerLiquidityDelta,
			u256.NewUintFromInt64(targetDelta),
			u256.NewUintFromInt64(observationTimeDelta),
		),
	)

	return tickCumulative, secondsPerLiquidity, nil
}

// getSurroundingObservations finds the observations immediately before and after the target timestamp.
// It uses binary search over the logical time-ordered view of the circular buffer.
// Logical order starts at (index+1) % cardinality (oldest) and ends at index (latest).
func getSurroundingObservations(
	os *pl.ObservationState,
	target int64,
	currentTime int64,
	tick int32,
	index uint16,
	liquidity *u256.Uint,
	cardinality uint16,
) (*pl.Observation, *pl.Observation, error) {
	// Optimistically set before to the newest observation
	beforeOrAt, err := observationAt(os, index)
	if err != nil {
		return nil, nil, err
	}

	// If the target is chronologically at or after the newest observation, we can early return
	if lte(currentTime, beforeOrAt.BlockTimestamp(), target) {
		if beforeOrAt.BlockTimestamp() == target {
			// If newest observation equals target, we're in the same block, so we can ignore atOrAfter
			return beforeOrAt, nil, nil
		}
		// Otherwise, we need to transform
		atOrAfter, err := transform(beforeOrAt, target, tick, liquidity)
		if err != nil {
			return nil, nil, err
		}
		return beforeOrAt, atOrAfter, nil
	}

	// Now, set before to the oldest observation
	start := (index + 1) % cardinality
	beforeOrAt, err = observationAt(os, start)
	if err != nil || !beforeOrAt.Initialized() {
		beforeOrAt, err = observationAt(os, 0)
		if err != nil {
			return nil, nil, err
		}
	}

	// Ensure that the target is chronologically at or after the oldest observation
	if !lte(currentTime, beforeOrAt.BlockTimestamp(), target) {
		return nil, nil, errObservationTooOld
	}

	// If we've reached this point, we have to binary search
	return binarySearch(os, currentTime, target, index, cardinality)
}

func binarySearch(
	os *pl.ObservationState,
	currentTime int64,
	target int64,
	index uint16,
	cardinality uint16,
) (*pl.Observation, *pl.Observation, error) {
	l := uint64((index + 1) % cardinality) // oldest observation
	r := l + uint64(cardinality) - 1       // newest observation
	var i uint64
	var beforeOrAt, atOrAfter *pl.Observation
	var err error

	for {
		i = (l + r) / 2

		beforeIndex := uint16(i % uint64(cardinality))
		beforeOrAt, err = observationAt(os, beforeIndex)
		if err != nil || !beforeOrAt.Initialized() {
			// we've landed on an uninitialized tick, keep searching higher (more recently)
			l = i + 1
			continue
		}

		afterIndex := uint16((i + 1) % uint64(cardinality))
		atOrAfter, err = observationAt(os, afterIndex)
		if err != nil {
			return nil, nil, err
		}

		targetAtOrAfter := lte(currentTime, beforeOrAt.BlockTimestamp(), target)

		// check if we've found the answer!
		if targetAtOrAfter && lte(currentTime, target, atOrAfter.BlockTimestamp()) {
			break
		}

		if !targetAtOrAfter {
			r = i - 1
		} else {
			l = i + 1
		}
	}

	return beforeOrAt, atOrAfter, nil
}

// observe returns the cumulative tick and liquidity as of each timestamp secondsAgo from the current time.
func observe(
	os *pl.ObservationState,
	currentTime int64,
	secondsAgos []uint32,
	tick int32,
	index uint16,
	liquidity *u256.Uint,
	cardinality uint16,
) ([]int64, []*u256.Uint, error) {
	if cardinality <= 0 {
		return nil, nil, errors.New("observation cardinality must be greater than 0")
	}

	historyCount := len(secondsAgos)
	tickCumulatives := make([]int64, historyCount)
	secondsPerLiquidityCumulativeX128s := make([]*u256.Uint, historyCount)

	for i, secondsAgo := range secondsAgos {
		tickCumulative, secondsPerLiquidity, err := observeSingle(
			os,
			currentTime,
			secondsAgo,
			tick,
			index,
			liquidity,
			cardinality,
		)
		if err != nil {
			return nil, nil, err
		}

		tickCumulatives[i] = tickCumulative
		secondsPerLiquidityCumulativeX128s[i] = secondsPerLiquidity
	}

	return tickCumulatives, secondsPerLiquidityCumulativeX128s, nil
}

package v1

import (
	"chain"
	"chain/runtime"

	"gno.land/r/gnoswap/common"
	"gno.land/r/gnoswap/halt"
	pl "gno.land/r/gnoswap/pool"

	i256 "gno.land/p/gnoswap/int256"
	u256 "gno.land/p/gnoswap/uint256"

	prabc "gno.land/p/gnoswap/rbac"
	_ "gno.land/r/gnoswap/rbac"

	"gno.land/r/gnoswap/access"
)

// Mint adds liquidity to a pool position.
//
// Increases liquidity for a position within specified tick range.
// Calculates required token amounts based on current pool price.
// Updates tick state and transfers tokens atomically.
//
// Parameters:
//   - token0Path, token1Path: Token contract paths
//   - fee: Fee tier (100, 500, 3000, 10000 = 0.01%, 0.05%, 0.3%, 1%)
//   - tickLower, tickUpper: Price range boundaries (must be tick-aligned)
//   - liquidityAmount: Liquidity to add (decimal string)
//   - positionCaller: Address that provides tokens for the mint operation
//
// Returns:
//   - amount0: Token0 amount consumed (decimal string)
//   - amount1: Token1 amount consumed (decimal string)
//
// Requirements:
//   - Pool must exist for token pair and fee
//   - Liquidity amount must be positive
//   - Ticks must be valid and aligned to spacing
//
// Only callable by position contract.
func (i *poolV1) Mint(
	token0Path string,
	token1Path string,
	fee uint32,
	tickLower int32,
	tickUpper int32,
	liquidityAmount string,
	positionCaller address,
) (string, string) {
	halt.AssertIsNotHaltedPool()

	caller := runtime.PreviousRealm().Address()
	access.AssertIsPosition(caller)
	access.AssertIsValidAddress(positionCaller)

	liquidity := u256.MustFromDecimal(liquidityAmount)
	if liquidity.IsZero() {
		panic(errZeroLiquidity)
	}

	pool := i.mustGetPoolBy(token0Path, token1Path, fee)

	tickSpacing := pool.TickSpacing()
	checkTickSpacing(tickLower, tickSpacing)
	checkTickSpacing(tickUpper, tickSpacing)

	liquidityDelta := safeConvertToInt128(liquidity)
	positionParam := newModifyPositionParams(positionCaller, tickLower, tickUpper, liquidityDelta)
	_, amount0, amount1, err := modifyPosition(pool, positionParam)
	if err != nil {
		panic(err)
	}

	poolAddr := access.MustGetAddress(prabc.ROLE_POOL.String())

	if amount0.Gt(zero) {
		i.safeTransferFrom(pool, positionCaller, poolAddr, pool.Token0Path(), amount0, true)
	}

	if amount1.Gt(zero) {
		i.safeTransferFrom(pool, positionCaller, poolAddr, pool.Token1Path(), amount1, false)
	}

	// Save pool state after modifyPosition may have updated liquidity
	err = i.savePool(pool)
	if err != nil {
		panic(err)
	}

	return amount0.ToString(), amount1.ToString()
}

// Burn removes liquidity from a position.
//
// Decreases liquidity and calculates tokens owed to position owner.
// Updates tick state but doesn't transfer tokens (use Collect).
// Two-step process prevents reentrancy attacks.
//
// Parameters:
//   - token0Path, token1Path: Token contract paths
//   - fee: Fee tier matching the pool
//   - tickLower, tickUpper: Position's price range
//   - liquidityAmount: Liquidity to remove (uint128)
//   - positionCaller: Position owner for validation
//
// Returns:
//   - amount0: Token0 owed to position (decimal string)
//   - amount1: Token1 owed to position (decimal string)
//
// Note: Tokens remain in pool until Collect is called.
// Only callable by position contract.
func (i *poolV1) Burn(
	token0Path string,
	token1Path string,
	fee uint32,
	tickLower int32,
	tickUpper int32,
	liquidityAmount string, // uint128
	positionCaller address,
) (string, string) {
	halt.AssertIsNotHaltedPool()

	caller := runtime.PreviousRealm().Address()
	access.AssertIsPosition(caller)
	access.AssertIsValidAddress(positionCaller)

	liqAmount := u256.MustFromDecimal(liquidityAmount)
	liqAmountInt256 := safeConvertToInt128(liqAmount)
	liqDelta := i256.Zero().Neg(liqAmountInt256)

	posParams := newModifyPositionParams(positionCaller, tickLower, tickUpper, liqDelta)
	pool := i.mustGetPoolBy(token0Path, token1Path, fee)
	position, amount0, amount1, err := modifyPosition(pool, posParams)
	if err != nil {
		panic(err)
	}

	if amount0.Gt(zero) || amount1.Gt(zero) {
		amount0 = toUint128(amount0)
		amount1 = toUint128(amount1)

		tokensOwed0, overflow := u256.Zero().AddOverflow(position.TokensOwed0(), amount0)
		if overflow {
			panic(errOverflow)
		}
		position.SetTokensOwed0(tokensOwed0)

		tokensOwed1, overflow := u256.Zero().AddOverflow(position.TokensOwed1(), amount1)
		if overflow {
			panic(errOverflow)
		}
		position.SetTokensOwed1(tokensOwed1)
	}

	positionKey := getPositionKey(tickLower, tickUpper)

	setPosition(pool, positionKey, position)
	mustGetPositionByPool(pool, positionKey)

	// Save pool state after modifyPosition may have updated liquidity
	err = i.savePool(pool)
	if err != nil {
		panic(err)
	}

	// actual token transfer happens in Collect()
	return amount0.ToString(), amount1.ToString()
}

// Collect transfers owed tokens from a position to recipient.
//
// Claims tokens from burned liquidity and accumulated fees.
// Supports partial collection via amount limits.
//
// Parameters:
//   - token0Path, token1Path: Token contract paths
//   - fee: Fee tier of the pool
//   - recipient: Address to receive tokens
//   - tickLower, tickUpper: Position's price range
//   - amount0Requested, amount1Requested: Max amounts to collect (use MAX_UINT128 for all)
//
// Returns:
//   - amount0: Token0 amount transferred (before any withdrawal fees)
//   - amount1: Token1 amount transferred (before any withdrawal fees)
//
// Note: Withdrawal fees are applied by the position contract, not here.
// Only callable by position contract.
func (i *poolV1) Collect(
	token0Path string,
	token1Path string,
	fee uint32,
	recipient address,
	tickLower int32,
	tickUpper int32,
	amount0Requested string,
	amount1Requested string,
) (string, string) {
	halt.AssertIsNotHaltedPool()
	halt.AssertIsNotHaltedWithdraw()

	caller := runtime.PreviousRealm().Address()
	access.AssertIsPosition(caller)
	access.AssertIsValidAddress(recipient)

	pool := i.mustGetPoolBy(token0Path, token1Path, fee)
	// Generate position key by combining position contract path with tick range
	// The key is composed of the position contract's address and the tick boundaries,
	// allowing the pool to uniquely identify and access position data.
	positionKey := getPositionKey(tickLower, tickUpper)
	position := mustGetPositionByPool(pool, positionKey)

	var amount0, amount1 *u256.Uint

	amount0Req := u256.MustFromDecimal(amount0Requested)
	amount0 = u256Min(amount0Req, position.TokensOwed0())

	amount1Req := u256.MustFromDecimal(amount1Requested)
	amount1 = u256Min(amount1Req, position.TokensOwed1())

	positionAddr := access.MustGetAddress(prabc.ROLE_POSITION.String())

	if amount0.Gt(zero) {
		tokenOwed0, overflow := u256.Zero().SubOverflow(position.TokensOwed0(), amount0)
		if overflow {
			panic(errOverflow)
		}

		token0Balance, overflow := u256.Zero().SubOverflow(pool.BalanceToken0(), amount0)
		if overflow {
			panic(errOverflow)
		}

		position.SetTokensOwed0(tokenOwed0)
		pool.SetBalanceToken0(token0Balance)
		common.SafeGRC20Approve(cross, pool.Token0Path(), positionAddr, safeConvertToInt64(amount0))
	}
	if amount1.Gt(zero) {
		tokenOwed1, overflow := u256.Zero().SubOverflow(position.TokensOwed1(), amount1)
		if overflow {
			panic(errOverflow)
		}

		token1Balance, overflow := u256.Zero().SubOverflow(pool.BalanceToken1(), amount1)
		if overflow {
			panic(errOverflow)
		}

		position.SetTokensOwed1(tokenOwed1)
		pool.SetBalanceToken1(token1Balance)
		common.SafeGRC20Approve(cross, pool.Token1Path(), positionAddr, safeConvertToInt64(amount1))
	}

	setPosition(pool, positionKey, *position)

	if err := i.savePool(pool); err != nil {
		panic(err)
	}

	return amount0.ToString(), amount1.ToString()
}

// CollectProtocol collects accumulated protocol fees from swap operations.
// Only callable by admin or governance.
// Returns amount0, amount1 representing protocol fees collected.
func (i *poolV1) CollectProtocol(
	token0Path string,
	token1Path string,
	fee uint32,
	recipient address,
	amount0Requested string, // uint128
	amount1Requested string, // uint128
) (string, string) {
	halt.AssertIsNotHaltedPool()
	halt.AssertIsNotHaltedWithdraw()

	previousRealm := runtime.PreviousRealm()
	caller := previousRealm.Address()
	access.AssertIsAdminOrGovernance(caller)

	common.MustRegistered(token0Path, token1Path)

	amount0, amount1 := i.collectProtocol(
		token0Path,
		token1Path,
		fee,
		recipient,
		amount0Requested,
		amount1Requested,
	)

	chain.Emit(
		"CollectProtocol",
		"prevAddr", caller.String(),
		"prevRealm", previousRealm.PkgPath(),
		"token0Path", token0Path,
		"token1Path", token1Path,
		"fee", formatUint(fee),
		"recipient", recipient.String(),
		"internal_amount0", amount0,
		"internal_amount1", amount1,
	)

	return amount0, amount1
}

// collectProtocol performs the actual protocol fee collection.
// It ensures requested amounts don't exceed available protocol fees.
// Returns amount0, amount1 as strings representing collected fees.
func (i *poolV1) collectProtocol(
	token0Path string,
	token1Path string,
	fee uint32,
	recipient address,
	amount0Requested string,
	amount1Requested string,
) (string, string) {
	pool := i.mustGetPoolBy(token0Path, token1Path, fee)

	amount0Req := u256.MustFromDecimal(amount0Requested)
	amount1Req := u256.MustFromDecimal(amount1Requested)
	if amount0Req.IsZero() && amount1Req.IsZero() {
		return "0", "0"
	}

	amount0 := u256Min(amount0Req, pool.ProtocolFeesToken0())
	amount1 := u256Min(amount1Req, pool.ProtocolFeesToken1())

	amount0, amount1 = i.saveProtocolFees(pool, amount0.Clone(), amount1.Clone())
	uAmount0 := safeConvertToInt64(amount0)
	uAmount1 := safeConvertToInt64(amount1)

	common.SafeGRC20Transfer(cross, pool.Token0Path(), recipient, uAmount0)
	newBalanceToken0, err := updatePoolBalance(pool.BalanceToken0(), pool.BalanceToken1(), amount0, true)
	if err != nil {
		panic(err)
	}
	pool.SetBalanceToken0(newBalanceToken0)

	common.SafeGRC20Transfer(cross, pool.Token1Path(), recipient, uAmount1)
	newBalanceToken1, err := updatePoolBalance(pool.BalanceToken0(), pool.BalanceToken1(), amount1, false)
	if err != nil {
		panic(err)
	}
	pool.SetBalanceToken1(newBalanceToken1)

	err = i.savePool(pool)
	if err != nil {
		panic(err)
	}

	return amount0.ToString(), amount1.ToString()
}

// saveProtocolFees updates the protocol fee balances after collection.
// Returns amount0, amount1 representing the fees deducted from protocol reserves.
func (i *poolV1) saveProtocolFees(pool *pl.Pool, amount0, amount1 *u256.Uint) (*u256.Uint, *u256.Uint) {
	token0Fees, underflow := u256.Zero().SubOverflow(pool.ProtocolFeesToken0(), amount0)
	if underflow {
		panic(errOverflow)
	}
	pool.SetProtocolFeesToken0(token0Fees)

	token1Fees, underflow := u256.Zero().SubOverflow(pool.ProtocolFeesToken1(), amount1)
	if underflow {
		panic(errUnderflow)
	}
	pool.SetProtocolFeesToken1(token1Fees)

	return amount0, amount1
}

func (i *poolV1) IncreaseObservationCardinalityNext(
	token0Path string,
	token1Path string,
	fee uint32,
	cardinalityNext uint16,
) {
	halt.AssertIsNotHaltedPool()

	pool := i.mustGetPoolBy(token0Path, token1Path, fee)
	err := increaseObservationCardinalityNextByPool(pool, cardinalityNext)
	if err != nil {
		panic(err)
	}

	previousRealm := runtime.PreviousRealm()
	chain.Emit(
		"IncreaseObservationCardinalityNext",
		"prevAddr", previousRealm.Address().String(),
		"prevRealm", previousRealm.PkgPath(),
		"poolPath", pool.PoolPath(),
		"cardinalityNext", formatUint(cardinalityNext),
	)
}

package v1

import (
	"encoding/base64"
	"strconv"
	"time"

	plp "gno.land/p/gnoswap/gnsmath"
	i256 "gno.land/p/gnoswap/int256"
	u256 "gno.land/p/gnoswap/uint256"
	"gno.land/p/nt/ufmt"

	"gno.land/r/gnoswap/common"
	pl "gno.land/r/gnoswap/pool"
)

const positionPackagePath = "gno.land/r/gnoswap/position"

// getPositionKey generates a unique base64-encoded key for a liquidity position.
//
// Creates deterministic identifier for position tracking.
// Ensures unique positions per (position package path, price range) combination.
//
// Used internally for position state management.
//
// Parameters:
//   - tickLower: Lower boundary tick of position range
//   - tickUpper: Upper boundary tick of position range
//
// Key Format:
//
//	base64(position_package_path + "__" + tickLower + "__" + tickUpper)
//
// Returns base64-encoded position key or error.
// Combines position package path, tickLower, and tickUpper.
func getPositionKey(
	tickLower int32,
	tickUpper int32,
) string {
	positionKey := positionPackagePath + "__" + strconv.Itoa(int(tickLower)) + "__" + strconv.Itoa(int(tickUpper))
	encodedPositionKey := base64.StdEncoding.EncodeToString([]byte(positionKey))
	return encodedPositionKey
}

// positionUpdate updates a position's liquidity and calculates fees owed.
// Returns the updated position information and any error.
func positionUpdate(
	position pl.PositionInfo,
	liquidityDelta *i256.Int,
	feeGrowthInside0X128 *u256.Uint,
	feeGrowthInside1X128 *u256.Uint,
) (pl.PositionInfo, error) {
	isZeroLiquidityDelta := liquidityDelta.IsZero()

	if position.Liquidity().IsZero() && isZeroLiquidityDelta {
		return pl.NewDefaultPositionInfo(), makeErrorWithDetails(
			errZeroLiquidity,
			"both liquidityDelta and current position's liquidity are zero",
		)
	}

	if liquidityDelta.IsNeg() {
		// absolute value of negative liquidity delta must be less than current liquidity
		absDelta := i256.Zero().Set(liquidityDelta).Abs()
		currentLiquidity := position.Liquidity()
		if absDelta.Gt(currentLiquidity) {
			return pl.NewDefaultPositionInfo(), makeErrorWithDetails(
				errZeroLiquidity,
				ufmt.Sprintf("liquidity delta(%s) is greater than current liquidity(%s)",
					liquidityDelta.ToString(), position.Liquidity().ToString()),
			)
		}
	}

	var liquidityNext *u256.Uint
	if isZeroLiquidityDelta {
		liquidityNext = position.Liquidity()
	} else {
		liquidityNext = common.LiquidityMathAddDelta(position.Liquidity(), liquidityDelta)
	}

	// validate negative feeGrowth before calculation
	diff0 := u256.Zero().Sub(feeGrowthInside0X128, position.FeeGrowthInside0LastX128())
	diff1 := u256.Zero().Sub(feeGrowthInside1X128, position.FeeGrowthInside1LastX128())

	// calculate tokensOwed
	tokensOwed0 := u256.Zero()
	if !diff0.IsZero() {
		tokensOwed0 = u256.MulDiv(diff0, position.Liquidity(), q128FromDecimal)
	}

	tokensOwed1 := u256.Zero()
	if !diff1.IsZero() {
		tokensOwed1 = u256.MulDiv(diff1, position.Liquidity(), q128FromDecimal)
	}

	if !isZeroLiquidityDelta {
		position.SetLiquidity(liquidityNext)
	}

	position.SetFeeGrowthInside0LastX128(feeGrowthInside0X128)
	position.SetFeeGrowthInside1LastX128(feeGrowthInside1X128)

	// add tokensOwed only when it's greater than 0
	if tokensOwed0.Gt(zero) || tokensOwed1.Gt(zero) {
		owed0, overflow := u256.Zero().AddOverflow(position.TokensOwed0(), tokensOwed0)
		if overflow {
			return pl.NewDefaultPositionInfo(), errOverflow
		}
		owed1, overflow := u256.Zero().AddOverflow(position.TokensOwed1(), tokensOwed1)
		if overflow {
			return pl.NewDefaultPositionInfo(), errOverflow
		}

		position.SetTokensOwed0(owed0)
		position.SetTokensOwed1(owed1)
	}

	return position, nil
}

// calculateToken0Amount calculates the amount of token0 based on price range and liquidity delta.
func calculateToken0Amount(sqrtPriceLower, sqrtPriceUpper *u256.Uint, liquidityDelta *i256.Int) *i256.Int {
	return plp.GetAmount0Delta(sqrtPriceLower, sqrtPriceUpper, liquidityDelta)
}

// calculateToken1Amount calculates the amount of token1 based on price range and liquidity delta.
func calculateToken1Amount(sqrtPriceLower, sqrtPriceUpper *u256.Uint, liquidityDelta *i256.Int) *i256.Int {
	return plp.GetAmount1Delta(sqrtPriceLower, sqrtPriceUpper, liquidityDelta)
}

// PositionLiquidity returns the liquidity of a position.
func PositionLiquidity(p *pl.Pool, key string) *u256.Uint {
	return mustGetPositionByPool(p, key).Liquidity()
}

// PositionFeeGrowthInside0LastX128 returns the fee growth of token0 inside a position.
func PositionFeeGrowthInside0LastX128(p *pl.Pool, key string) *u256.Uint {
	return mustGetPositionByPool(p, key).FeeGrowthInside0LastX128()
}

// PositionFeeGrowthInside1LastX128 returns the fee growth of token1 inside a position.
func PositionFeeGrowthInside1LastX128(p *pl.Pool, key string) *u256.Uint {
	return mustGetPositionByPool(p, key).FeeGrowthInside1LastX128()
}

// PositionTokensOwed0 returns the amount of token0 owed by a position.
func PositionTokensOwed0(p *pl.Pool, key string) *u256.Uint {
	return mustGetPositionByPool(p, key).TokensOwed0()
}

// PositionTokensOwed1 returns the amount of token1 owed by a position.
func PositionTokensOwed1(p *pl.Pool, key string) *u256.Uint {
	return mustGetPositionByPool(p, key).TokensOwed1()
}

// GetPosition returns the position info for a given key.
func GetPositionByPool(p *pl.Pool, key string) (pl.PositionInfo, bool) {
	iPositionInfo, exist := p.Positions().Get(key)
	if !exist {
		newPosition := pl.NewDefaultPositionInfo()
		return newPosition, false
	}

	positionInfo, ok := iPositionInfo.(pl.PositionInfo)
	if !ok {
		panic(ufmt.Sprintf("failed to cast iPositionInfo to PositionInfo: %T", iPositionInfo))
	}

	return positionInfo, true
}

// positionUpdateWithKey updates a position in the pool and returns the updated position.
func positionUpdateWithKey(
	p *pl.Pool,
	positionKey string,
	liquidityDelta *i256.Int,
	feeGrowthInside0X128, feeGrowthInside1X128 *u256.Uint,
) (pl.PositionInfo, error) {
	// if position does not exist, create a new position
	//
	// Note: The positionUpdate function is designed to handle both new positions and existing positions,
	// so there's no need to check for existence in GetPosition.
	positionToUpdate, _ := GetPositionByPool(p, positionKey)
	positionAfterUpdate, err := positionUpdate(positionToUpdate, liquidityDelta, feeGrowthInside0X128, feeGrowthInside1X128)
	if err != nil {
		return pl.NewDefaultPositionInfo(), err
	}

	setPosition(p, positionKey, positionAfterUpdate)

	return positionAfterUpdate, nil
}

// setPosition sets the position info for a given key.
func setPosition(p *pl.Pool, posKey string, positionInfo pl.PositionInfo) {
	p.Positions().Set(posKey, positionInfo)
}

// mustGetPosition returns the position info for a given key.
func mustGetPositionByPool(p *pl.Pool, positionKey string) *pl.PositionInfo {
	positionInfo, exist := GetPositionByPool(p, positionKey)
	if !exist {
		panic(newErrorWithDetail(
			errDataNotFound,
			ufmt.Sprintf("positionKey(%s) does not exist", positionKey),
		))
	}

	return &positionInfo
}

// modifyPosition updates a position in the pool and calculates the amount of tokens
// needed (for minting) or returned (for burning). The calculation depends on the current
// price (tick) relative to the position's price range.
//
// The function handles three cases:
//  1. Current price below range (tick < tickLower): only token0 is used/returned
//  2. Current price in range (tickLower <= tick < tickUpper): both tokens are used/returned
//  3. Current price above range (tick >= tickUpper): only token1 is used/returned
//
// Parameters:
//   - params: ModifyPositionParams containing owner, tickLower, tickUpper, and liquidityDelta
//
// Returns:
//   - PositionInfo: updated position information
//   - *u256.Uint: amount of token0 needed/returned
//   - *u256.Uint: amount of token1 needed/returned
func modifyPosition(p *pl.Pool, params ModifyPositionParams) (pl.PositionInfo, *u256.Uint, *u256.Uint, error) {
	if err := validateTicks(params.tickLower, params.tickUpper); err != nil {
		return pl.NewDefaultPositionInfo(), zero, zero, err
	}

	// get current state and price bounds
	tick := p.Slot0Tick()
	// update position state
	position, err := updatePosition(p, params, tick)
	if err != nil {
		return pl.NewDefaultPositionInfo(), zero, zero, err
	}

	liqDelta := params.liquidityDelta
	if liqDelta.IsZero() {
		return position, zero, zero, nil
	}

	amount0, amount1 := i256.Zero(), i256.Zero()

	// covert ticks to sqrt price to use in amount calculations
	// price = 1.0001^tick, but we use sqrtPriceX96
	sqrtRatioLower := common.TickMathGetSqrtRatioAtTick(params.tickLower)
	sqrtRatioUpper := common.TickMathGetSqrtRatioAtTick(params.tickUpper)
	sqrtPriceX96 := p.Slot0SqrtPriceX96()

	// calculate token amounts based on current price position relative to range
	switch {
	case tick < params.tickLower:
		// case 1
		// full range between lower and upper tick is used for token0
		// current tick is below the passed range; liquidity can only become in range by crossing from left to
		// right, when we'll need _more_ token0 (it's becoming more valuable) so user must provide it
		amount0 = calculateToken0Amount(sqrtRatioLower, sqrtRatioUpper, liqDelta)

	case tick < params.tickUpper:
		// case 2: Current price is within the position range
		liquidityBefore := p.Liquidity()
		currentTime := time.Now().Unix()

		// Update oracle BEFORE liquidity changes
		err := writeObservationByPool(p, currentTime, tick, liquidityBefore)
		if err != nil {
			return pl.NewDefaultPositionInfo(), zero, zero, err
		}

		// token0 used from current price to upper tick
		amount0 = calculateToken0Amount(sqrtPriceX96, sqrtRatioUpper, liqDelta)
		// token1 used from lower tick to current price
		amount1 = calculateToken1Amount(sqrtRatioLower, sqrtPriceX96, liqDelta)
		// update pool's active liquidity since price is in range
		p.SetLiquidity(common.LiquidityMathAddDelta(liquidityBefore, liqDelta))

	default:
		// case 3
		// full range between lower and upper tick is used for token1
		// current tick is above the passed range; liquidity can only become in range by crossing from right to
		// left, when we'll need _more_ token1 (it's becoming more valuable) so user must provide it
		amount1 = calculateToken1Amount(sqrtRatioLower, sqrtRatioUpper, liqDelta)
	}

	return position, amount0.Abs(), amount1.Abs(), nil
}

// updatePosition modifies the position's liquidity and updates the corresponding tick states.
//
// This function updates the position data based on the specified liquidity delta and tick range.
// It also manages the fee growth, tick state flipping, and cleanup of unused tick data.
//
// Parameters:
//   - positionParams: ModifyPositionParams, the parameters for the position modification, which include:
//   - owner: The address of the position owner.
//   - tickLower: The lower tick boundary of the position.
//   - tickUpper: The upper tick boundary of the position.
//   - liquidityDelta: The change in liquidity (positive or negative).
//   - tick: int32, the current tick position.
//
// Returns:
//   - PositionInfo: The updated position information.
//
// Workflow:
//  1. Clone the global fee growth values (token 0 and token 1).
//  2. If the liquidity delta is non-zero:
//     - Update the lower and upper ticks using `tickUpdate`, flipping their states if necessary.
//     - If a tick's state was flipped, update the tick bitmap to reflect the new state.
//  3. Calculate the fee growth inside the tick range using `getFeeGrowthInside`.
//  4. Generate a unique position key and update the position data using `positionUpdateWithKey`.
//  5. If liquidity is being removed (negative delta), clean up unused tick data by deleting the tick entries.
//  6. Return the updated position.
//
// Notes:
//   - The function flips the tick states and cleans up unused tick data when liquidity is removed.
//   - It ensures fee growth and position data remain accurate after the update.
//
// Example Usage:
//
// ```gno
//
//	updatedPosition := pool.updatePosition(positionParams, currentTick)
//	println("Updated Position Info:", updatedPosition)
//
// ```
func updatePosition(p *pl.Pool, positionParams ModifyPositionParams, tick int32) (pl.PositionInfo, error) {
	feeGrowthGlobal0X128 := p.FeeGrowthGlobal0X128().Clone()
	feeGrowthGlobal1X128 := p.FeeGrowthGlobal1X128().Clone()
	liquidityDelta := positionParams.liquidityDelta

	var flippedLower, flippedUpper bool
	if !liquidityDelta.IsZero() {
		flippedLower = tickUpdate(
			p,
			positionParams.tickLower,
			tick,
			liquidityDelta,
			feeGrowthGlobal0X128,
			feeGrowthGlobal1X128,
			false,
			p.MaxLiquidityPerTick(),
		)

		flippedUpper = tickUpdate(
			p,
			positionParams.tickUpper,
			tick,
			liquidityDelta,
			feeGrowthGlobal0X128,
			feeGrowthGlobal1X128,
			true,
			p.MaxLiquidityPerTick(),
		)

		if flippedLower {
			tickBitmapFlipTick(p, positionParams.tickLower, p.TickSpacing())
		}

		if flippedUpper {
			tickBitmapFlipTick(p, positionParams.tickUpper, p.TickSpacing())
		}
	}

	feeGrowthInside0X128, feeGrowthInside1X128 := getFeeGrowthInside(
		p,
		positionParams.tickLower,
		positionParams.tickUpper,
		tick,
		feeGrowthGlobal0X128,
		feeGrowthGlobal1X128,
	)

	positionKey := getPositionKey(positionParams.tickLower, positionParams.tickUpper)

	position, err := positionUpdateWithKey(
		p,
		positionKey,
		liquidityDelta,
		feeGrowthInside0X128.Clone(),
		feeGrowthInside1X128.Clone(),
	)
	if err != nil {
		return pl.NewDefaultPositionInfo(), err
	}

	// clear any tick data that is no longer needed
	if liquidityDelta.IsNeg() {
		if flippedLower {
			deleteTick(p, positionParams.tickLower)
		}
		if flippedUpper {
			deleteTick(p, positionParams.tickUpper)
		}
	}

	return position, nil
}

package v1

import (
	"chain"
	"chain/runtime"

	prabc "gno.land/p/gnoswap/rbac"
	u256 "gno.land/p/gnoswap/uint256"
	"gno.land/p/nt/ufmt"

	"gno.land/r/gnoswap/access"
	"gno.land/r/gnoswap/common"
	"gno.land/r/gnoswap/halt"
	pf "gno.land/r/gnoswap/protocol_fee"
)

const (
	MaxBpsValue = uint64(1000) // 10%
	ZeroBps     = uint64(0)
)

// HandleWithdrawalFee withdraws the fee from the user and returns the amount after the fee
// Only position contract can call this function
// Input:
// - positionId: the id of the LP token
// - token0Path: the path of the token0
// - amount0: the amount of token0
// - token1Path: the path of the token1
// - amount1: the amount of token1
// - poolPath: the path of the pool
// - positionCaller: the original caller of the position contract
// Output:
// - the amount of token0 after the fee
// - the amount of token1 after the fee
func (i *poolV1) HandleWithdrawalFee(
	positionId uint64,
	token0Path string,
	amount0 string, // uint256
	token1Path string,
	amount1 string, // uint256
	poolPath string,
	positionCaller address,
) (string, string) { // uint256 x2
	halt.AssertIsNotHaltedPool()
	halt.AssertIsNotHaltedWithdraw()

	// only position contract can call this function
	previousRealm := runtime.PreviousRealm()
	caller := previousRealm.Address()
	access.AssertIsPosition(caller)

	common.MustRegistered(token0Path, token1Path)

	fee := i.store.GetWithdrawalFeeBPS()
	if fee == ZeroBps {
		return amount0, amount1
	}

	feeU256 := u256.NewUint(fee)
	feeAmount0, afterAmount0 := calculateAmountWithFee(u256.MustFromDecimal(amount0), feeU256)
	feeAmount1, afterAmount1 := calculateAmountWithFee(u256.MustFromDecimal(amount1), feeU256)

	protocolFeeAddr := access.MustGetAddress(prabc.ROLE_PROTOCOL_FEE.String())

	pf.AddToProtocolFee(cross, token0Path, safeConvertToInt64(feeAmount0))
	common.SafeGRC20TransferFrom(cross, token0Path, positionCaller, protocolFeeAddr, safeConvertToInt64(feeAmount0))
	pf.AddToProtocolFee(cross, token1Path, safeConvertToInt64(feeAmount1))
	common.SafeGRC20TransferFrom(cross, token1Path, positionCaller, protocolFeeAddr, safeConvertToInt64(feeAmount1))

	afterAmount0Str := afterAmount0.ToString()
	afterAmount1Str := afterAmount1.ToString()

	chain.Emit(
		"WithdrawalFee",
		"prevAddr", caller.String(),
		"prevRealm", previousRealm.PkgPath(),
		"lpTokenId", formatUint(positionId),
		"poolPath", poolPath,
		"feeAmount0", feeAmount0.ToString(),
		"feeAmount1", feeAmount1.ToString(),
		"amount0WithoutFee", afterAmount0Str,
		"amount1WithoutFee", afterAmount1Str,
	)

	return afterAmount0Str, afterAmount1Str
}

// SetPoolCreationFee sets the poolCreationFee.
// Only admin or governance can call this function.
func (i *poolV1) SetPoolCreationFee(fee int64) {
	halt.AssertIsNotHaltedPool()

	previousRealm := runtime.PreviousRealm()
	caller := previousRealm.Address()
	access.AssertIsAdminOrGovernance(caller)

	prevPoolCreationFee := i.store.GetPoolCreationFee()
	err := i.setPoolCreationFee(fee)
	if err != nil {
		panic(err)
	}

	chain.Emit(
		"SetPoolCreationFee",
		"prevAddr", caller.String(),
		"prevRealm", previousRealm.PkgPath(),
		"prevFee", formatInt(prevPoolCreationFee),
		"newFee", formatInt(fee),
	)
}

// SetWithdrawalFee sets the withdrawal fee.
// Only admin or governance can call this function.
func (i *poolV1) SetWithdrawalFee(fee uint64) {
	halt.AssertIsNotHaltedPool()

	previousRealm := runtime.PreviousRealm()
	caller := previousRealm.Address()
	access.AssertIsAdminOrGovernance(caller)

	prevWithdrawalFee := i.store.GetWithdrawalFeeBPS()

	err := i.setWithdrawalFee(fee)
	if err != nil {
		panic(err)
	}

	chain.Emit(
		"SetWithdrawalFee",
		"prevAddr", caller.String(),
		"prevRealm", previousRealm.PkgPath(),
		"prevFee", formatUint(prevWithdrawalFee),
		"newFee", formatUint(fee),
	)
}

// calculateAmountWithFee calculates the fee amount and the amount after the fee
//
// Inputs:
// - amount: the amount before the fee
// - fee: the fee in BPS
//
// Outputs:
// - the fee amount
// - the amount after the fee applied
func calculateAmountWithFee(amount, fee *u256.Uint) (feeAmount, afterAmount *u256.Uint) {
	feeAmount, overflow := u256.Zero().MulOverflow(amount, fee)
	if overflow {
		panic(errOverflow)
	}
	feeAmount = u256.Zero().Div(feeAmount, u256.NewUint(MaxBpsValue))
	afterAmount = u256.Zero().Sub(amount, feeAmount)
	return feeAmount, afterAmount
}

// setPoolCreationFee this function is internal function called by SetPoolCreationFee
// And SetPoolCreationFee
func (i *poolV1) setPoolCreationFee(fee int64) error {
	if fee < 0 {
		return makeErrorWithDetails(
			errInvalidInput,
			"pool creation fee cannot be negative",
		)
	}

	// update pool creation fee
	err := i.store.SetPoolCreationFee(fee)
	if err != nil {
		return err
	}

	return nil
}

// setWithdrawalFee this function is internal function called by SetWithdrawalFee
// function and SetWithdrawalFee function
func (i *poolV1) setWithdrawalFee(fee uint64) error {
	if fee > MaxBpsValue {
		return makeErrorWithDetails(
			errInvalidWithdrawalFeePct,
			ufmt.Sprintf("fee(%d) must be in range 0 ~ %d", fee, MaxBpsValue),
		)
	}

	err := i.store.SetWithdrawalFeeBPS(fee)
	if err != nil {
		return err
	}

	return nil
}

package v1

import (
	"chain"
	"chain/runtime"
	"strconv"
	"time"

	"gno.land/p/nt/ufmt"
	"gno.land/r/gnoswap/access"
	"gno.land/r/gnoswap/common"
	"gno.land/r/gnoswap/halt"

	plp "gno.land/p/gnoswap/gnsmath"
	i256 "gno.land/p/gnoswap/int256"
	u256 "gno.land/p/gnoswap/uint256"

	pl "gno.land/r/gnoswap/pool"
)

// Hook functions allow external contracts to be notified of swap events.
var (
	// MUST BE IMMUTABLE.
	// DO NOT USE THIS VALUE IN ANY ARITHMETIC OPERATIONS' INITIALIZATION
	zero           = u256.Zero()
	zeroI256       = i256.Zero() /* readonly */
	fixedPointQ128 = u256.MustFromDecimal(Q128)

	maxInt256 = u256.MustFromDecimal(MAX_INT256)
	maxInt64  = i256.Zero().SetInt64(INT64_MAX)
	minInt64  = i256.Zero().SetInt64(INT64_MIN)
)

// SetTickCrossHook sets the hook function called when a tick is crossed during swaps.
//
// Allows staker to monitor liquidity changes at price levels.
// Used for reward calculation when positions enter/exit range.
//
// Only callable by staker contract.
func (i *poolV1) SetTickCrossHook(hook func(cur realm, poolPath string, tickId int32, zeroForOne bool, timestamp int64)) {
	halt.AssertIsNotHaltedPool()

	caller := runtime.PreviousRealm().Address()
	access.AssertIsStaker(caller)

	err := i.store.SetTickCrossHook(hook)
	if err != nil {
		panic(err)
	}
}

// SetSwapStartHook sets the hook function called at the beginning of a swap.
//
// Enables pre-swap state tracking for reward distribution.
// Captures timestamp for time-weighted calculations.
//
// Only callable by staker contract.
func (i *poolV1) SetSwapStartHook(hook func(cur realm, poolPath string, timestamp int64)) {
	halt.AssertIsNotHaltedPool()

	caller := runtime.PreviousRealm().Address()
	access.AssertIsStaker(caller)

	err := i.store.SetSwapStartHook(hook)
	if err != nil {
		panic(err)
	}
}

// SetSwapEndHook sets the hook function called at the end of a swap.
//
// Finalizes reward calculations after swap completion.
// Allows error propagation to revert invalid swaps.
//
// Only callable by staker contract.
func (i *poolV1) SetSwapEndHook(hook func(cur realm, poolPath string) error) {
	halt.AssertIsNotHaltedPool()

	caller := runtime.PreviousRealm().Address()
	access.AssertIsStaker(caller)

	err := i.store.SetSwapEndHook(hook)
	if err != nil {
		panic(err)
	}
}

// SwapResult encapsulates all state changes from a swap.
// It ensures atomic state transitions that can be applied at once.
type SwapResult struct {
	Amount0              *i256.Int
	Amount1              *i256.Int
	NewSqrtPrice         *u256.Uint
	NewTick              int32
	NewLiquidity         *u256.Uint
	NewProtocolFees      pl.ProtocolFees
	FeeGrowthGlobal0X128 *u256.Uint
	FeeGrowthGlobal1X128 *u256.Uint
}

// SwapComputation encapsulates the pure computation logic for swaps.
type SwapComputation struct {
	AmountSpecified   *i256.Int
	SqrtPriceLimitX96 *u256.Uint
	ZeroForOne        bool
	ExactInput        bool
	InitialState      SwapState
	Cache             *SwapCache
}

// Swap executes a swap with callback pattern for optimistic transfers.
// This allows flash swaps where tokens are sent before payment is received.
//
// The flow is:
// 1. Pool sends output tokens to recipient
// 2. Pool calls callback on msg.sender
// 3. Callback must ensure pool receives input tokens
// 4. Pool validates its balance increased correctly
//
// Parameters:
//   - token0Path: Path of token0 in the pool
//   - token1Path: Path of token1 in the pool
//   - fee: Pool fee tier
//   - recipient: Address to receive output tokens
//   - zeroForOne: Direction of swap (true = token0 to token1)
//   - amountSpecified: Exact input (positive) or exact output (negative)
//   - sqrtPriceLimitX96: Price limit for the swap
//   - payer: Address that provides input tokens
//   - swapCallback: Callback function to handle token transfers
//
// Returns amount0 and amount1 deltas as strings.
func (i *poolV1) Swap(
	token0Path string,
	token1Path string,
	fee uint32,
	recipient address,
	zeroForOne bool,
	amountSpecified string,
	sqrtPriceLimitX96 string,
	payer address,
	swapCallback func(cur realm, amount0Delta, amount1Delta int64, _ *pl.CallbackMarker) error,
) (string, string) {
	halt.AssertIsNotHaltedPool()

	previousRealm := runtime.PreviousRealm()
	assertIsNotAllowedEOA(previousRealm)
	assertIsValidTokenOrder(token0Path, token1Path)

	if amountSpecified == "0" {
		panic(newErrorWithDetail(
			errInvalidSwapAmount,
			"amountSpecified == 0",
		))
	}

	pool := i.mustGetPoolBy(token0Path, token1Path, fee)

	slot0Start := pool.Slot0()
	if !slot0Start.Unlocked() {
		panic(errLockedPool)
	}

	// no liquidity -> no swap, return zero amounts
	if pool.Liquidity().IsZero() {
		return "0", "0"
	}

	// Apply reentrancy lock to the actual pool state
	slot0Start.SetUnlocked(false)
	pool.SetSlot0(slot0Start)
	startTick := pool.Slot0Tick()

	// Call swap start hook if set
	if i.store.HasSwapStartHook() {
		swapStartHook := i.store.GetSwapStartHook()

		if swapStartHook != nil {
			currentTime := time.Now().Unix()
			swapStartHook(cross, pool.PoolPath(), currentTime)
		}
	}

	defer func() {
		// Release reentrancy lock on the actual pool state
		slot0End := pool.Slot0()
		slot0End.SetUnlocked(true)
		pool.SetSlot0(slot0End)

		if i.store.HasSwapEndHook() {
			swapEndHook := i.store.GetSwapEndHook()

			if swapEndHook != nil {
				err := swapEndHook(cross, pool.PoolPath())
				if err != nil {
					panic(err)
				}
			}
		}
	}()

	sqrtPriceLimit := u256.MustFromDecimal(sqrtPriceLimitX96)
	validatePriceLimits(slot0Start, zeroForOne, sqrtPriceLimit)

	amounts := i256.MustFromDecimal(amountSpecified)
	feeGrowthGlobalX128 := getFeeGrowthGlobal(pool, zeroForOne)
	feeProtocol := getFeeProtocol(slot0Start, zeroForOne)
	cache := newSwapCache(feeProtocol, pool.Liquidity().Clone())
	state := newSwapState(amounts, feeGrowthGlobalX128, cache.liquidityStart.Clone(), slot0Start)

	comp := SwapComputation{
		AmountSpecified:   amounts,
		SqrtPriceLimitX96: sqrtPriceLimit,
		ZeroForOne:        zeroForOne,
		ExactInput:        amounts.Gt(zeroI256),
		InitialState:      state,
		Cache:             cache,
	}

	result, err := i.computeSwap(pool, comp)
	if err != nil {
		panic(err)
	}

	// Update oracle BEFORE applying swap result (using pre-swap state)
	if result.NewTick != pool.Slot0Tick() {
		currentTime := time.Now().Unix()

		err := writeObservationByPool(pool, currentTime, pool.Slot0Tick(), pool.Liquidity())
		if err != nil {
			panic(err)
		}
	}

	applySwapResult(pool, result)

	// transfer swap result to recipient then receive input tokens from swap callback
	if zeroForOne {
		// receive token0 from swap callback
		// send token1 to recipient (output)
		if result.Amount1.IsNeg() {
			i.safeTransfer(pool, recipient, token1Path, result.Amount1.Abs(), false)
		}
		i.safeSwapCallback(pool, token0Path, result.Amount0, result.Amount1, zeroForOne, swapCallback)
	} else {
		// receive token1 from swap callback
		// send token0 to recipient (output)
		if result.Amount0.IsNeg() {
			i.safeTransfer(pool, recipient, token0Path, result.Amount0.Abs(), true)
		}
		i.safeSwapCallback(pool, token1Path, result.Amount1, result.Amount0, zeroForOne, swapCallback)
	}

	lastObservation, err := lastObservation(pool.ObservationState())
	if err != nil {
		panic(err)
	}

	token0Amount := result.Amount0.ToString()
	token1Amount := result.Amount1.ToString()

	chain.Emit(
		"Swap",
		"prevAddr", previousRealm.Address().String(),
		"prevRealm", previousRealm.PkgPath(),
		"poolPath", pool.PoolPath(),
		"zeroForOne", formatBool(zeroForOne),
		"requestAmount", amountSpecified,
		"sqrtPriceLimitX96", sqrtPriceLimitX96,
		"payer", payer.String(),
		"recipient", recipient.String(),
		"token0Amount", token0Amount,
		"token1Amount", token1Amount,
		"protocolFee0", pool.ProtocolFeesToken0().ToString(),
		"protocolFee1", pool.ProtocolFeesToken1().ToString(),
		"sqrtPriceX96", pool.Slot0SqrtPriceX96().ToString(),
		"exactIn", strconv.FormatBool(comp.ExactInput),
		"currentTick", strconv.FormatInt(int64(pool.Slot0Tick()), 10),
		"liquidity", pool.Liquidity().ToString(),
		"feeGrowthGlobal0X128", pool.FeeGrowthGlobal0X128().ToString(),
		"feeGrowthGlobal1X128", pool.FeeGrowthGlobal1X128().ToString(),
		"balanceToken0", pool.BalanceToken0().ToString(),
		"balanceToken1", pool.BalanceToken1().ToString(),
		"ticks", ticksToString(pool, startTick, pool.Slot0Tick()),
		"tickCumulative", formatInt(lastObservation.TickCumulative()),
		"liquidityCumulative", lastObservation.LiquidityCumulative().ToString(),
		"secondsPerLiquidityCumulativeX128", lastObservation.SecondsPerLiquidityCumulativeX128().ToString(),
		"observationTimestamp", formatInt(lastObservation.BlockTimestamp()),
	)

	return token0Amount, token1Amount
}

// DrySwap simulates a swap without modifying pool state.
// Returns amount0, amount1 and a success boolean.
// Returns false if pool is locked, has no liquidity, or computation fails.
func (i *poolV1) DrySwap(
	token0Path string,
	token1Path string,
	fee uint32,
	zeroForOne bool,
	amountSpecified string,
	sqrtPriceLimitX96 string,
) (string, string, bool) {
	if amountSpecified == "0" {
		return "0", "0", false
	}

	pool := i.mustGetPoolBy(token0Path, token1Path, fee)

	// no liquidity -> simulation fails
	if pool.Liquidity().IsZero() {
		return "0", "0", false
	}

	slot0Start := pool.Slot0()
	sqrtPriceLimit := u256.MustFromDecimal(sqrtPriceLimitX96)
	validatePriceLimits(slot0Start, zeroForOne, sqrtPriceLimit)

	amounts := i256.MustFromDecimal(amountSpecified)
	feeGrowthGlobalX128 := getFeeGrowthGlobal(pool, zeroForOne)
	feeProtocol := getFeeProtocol(slot0Start, zeroForOne)
	cache := newSwapCache(feeProtocol, pool.Liquidity().Clone())
	state := newSwapState(amounts, feeGrowthGlobalX128, cache.liquidityStart, slot0Start)

	comp := SwapComputation{
		AmountSpecified:   amounts,
		SqrtPriceLimitX96: sqrtPriceLimit,
		ZeroForOne:        zeroForOne,
		ExactInput:        amounts.Gt(zeroI256),
		InitialState:      state,
		Cache:             cache,
	}

	result, err := i.computeSwap(pool, comp)
	if err != nil {
		return "0", "0", false
	}

	if zeroForOne {
		if pool.BalanceToken1().Lt(result.Amount1.Abs()) {
			return "0", "0", false
		}
	} else {
		if pool.BalanceToken0().Lt(result.Amount0.Abs()) {
			return "0", "0", false
		}
	}

	return result.Amount0.ToString(), result.Amount1.ToString(), true
}

// computeSwap performs the core swap computation without modifying pool state.
// The computation continues until either:
// - The entire amount is consumed (amountSpecifiedRemaining = 0)
// - The price limit is reached (sqrtPriceX96 = sqrtPriceLimitX96)
//
// Important: This function is critical for AMM price discovery. It iterates through
// tick ranges, calculating swap amounts and fees for each liquidity segment.
// Returns an error if the computation fails at any step.
func (i *poolV1) computeSwap(pool *pl.Pool, comp SwapComputation) (*SwapResult, error) {
	state := comp.InitialState
	var err error

	// Compute swap steps until completion
	for shouldContinueSwap(state, comp.SqrtPriceLimitX96) {
		state, err = i.computeSwapStep(state, pool, comp.ZeroForOne, comp.SqrtPriceLimitX96, comp.ExactInput, comp.Cache)
		if err != nil {
			return nil, err
		}
	}

	// Calculate final amounts
	amount0 := state.amountCalculated
	amount1 := i256.Zero().Sub(comp.AmountSpecified, state.amountSpecifiedRemaining)
	if comp.ZeroForOne == comp.ExactInput {
		amount0, amount1 = amount1, amount0
	}

	// Prepare result
	result := &SwapResult{
		Amount0:              amount0,
		Amount1:              amount1,
		NewSqrtPrice:         state.sqrtPriceX96,
		NewTick:              state.tick,
		NewLiquidity:         state.liquidity,
		NewProtocolFees:      pool.ProtocolFees(),
		FeeGrowthGlobal0X128: pool.FeeGrowthGlobal0X128(),
		FeeGrowthGlobal1X128: pool.FeeGrowthGlobal1X128(),
	}

	// Update protocol fees if necessary
	if comp.ZeroForOne {
		if state.protocolFee.Gt(zero) {
			result.NewProtocolFees.Token0().Add(result.NewProtocolFees.Token0(), state.protocolFee)
		}
		result.FeeGrowthGlobal0X128 = state.feeGrowthGlobalX128.Clone()
	} else {
		if state.protocolFee.Gt(zero) {
			result.NewProtocolFees.Token1().Add(result.NewProtocolFees.Token1(), state.protocolFee)
		}
		result.FeeGrowthGlobal1X128 = state.feeGrowthGlobalX128.Clone()
	}

	return result, nil
}

// applySwapResult updates pool state with computed results.
// All state changes are applied at once to maintain consistency
func applySwapResult(pool *pl.Pool, result *SwapResult) {
	slot0 := pool.Slot0()
	slot0.SetSqrtPriceX96(result.NewSqrtPrice)
	slot0.SetTick(result.NewTick)
	pool.SetSlot0(slot0)

	pool.SetLiquidity(result.NewLiquidity)
	pool.SetProtocolFees(result.NewProtocolFees)
	pool.SetFeeGrowthGlobal0X128(result.FeeGrowthGlobal0X128)
	pool.SetFeeGrowthGlobal1X128(result.FeeGrowthGlobal1X128)
}

// validatePriceLimits ensures the provided price limit is valid for the swap direction
// The function enforces that:
// For zeroForOne (selling token0):
//   - Price limit must be below current price
//   - Price limit must be above MIN_SQRT_RATIO
//
// For !zeroForOne (selling token1):
//   - Price limit must be above current price
//   - Price limit must be below MAX_SQRT_RATIO
func validatePriceLimits(slot0 pl.Slot0, zeroForOne bool, sqrtPriceLimitX96 *u256.Uint) {
	if zeroForOne {
		cond1 := sqrtPriceLimitX96.Lt(slot0.SqrtPriceX96())
		cond2 := sqrtPriceLimitX96.Gt(minSqrtRatio)
		if !(cond1 && cond2) {
			panic(newErrorWithDetail(
				errPriceOutOfRange,
				ufmt.Sprintf("sqrtPriceLimitX96(%s) < slot0Start.sqrtPriceX96(%s) && sqrtPriceLimitX96(%s) > MIN_SQRT_RATIO(%s)",
					sqrtPriceLimitX96.ToString(),
					slot0.SqrtPriceX96().ToString(),
					sqrtPriceLimitX96.ToString(),
					MIN_SQRT_RATIO),
			))
		}
	} else {
		cond1 := sqrtPriceLimitX96.Gt(slot0.SqrtPriceX96())
		cond2 := sqrtPriceLimitX96.Lt(maxSqrtRatio)
		if !(cond1 && cond2) {
			panic(newErrorWithDetail(
				errPriceOutOfRange,
				ufmt.Sprintf("sqrtPriceLimitX96(%s) > slot0Start.sqrtPriceX96(%s) && sqrtPriceLimitX96(%s) < MAX_SQRT_RATIO(%s)",
					sqrtPriceLimitX96.ToString(),
					slot0.SqrtPriceX96().ToString(),
					sqrtPriceLimitX96.ToString(),
					MAX_SQRT_RATIO),
			))
		}
	}
}

// getFeeProtocol returns the appropriate fee protocol based on zero for one.
// When zeroForOne is true, we want the lower 4 bits (% 16).
// Otherwise, we want the upper 4 bits (/ 16).
func getFeeProtocol(slot0 pl.Slot0, zeroForOne bool) uint8 {
	shift := uint8(0)
	if !zeroForOne {
		shift = 4
	}
	return (slot0.FeeProtocol() >> shift) & uint8(0xF)
}

// getFeeGrowthGlobal returns the appropriate fee growth global based on zero for one.
func getFeeGrowthGlobal(pool *pl.Pool, zeroForOne bool) *u256.Uint {
	if zeroForOne {
		return pool.FeeGrowthGlobal0X128().Clone()
	}
	return pool.FeeGrowthGlobal1X128().Clone()
}

// shouldContinueSwap checks if swap should continue based on remaining amount and price limit.
func shouldContinueSwap(state SwapState, sqrtPriceLimitX96 *u256.Uint) bool {
	return !state.amountSpecifiedRemaining.IsZero() && !state.sqrtPriceX96.Eq(sqrtPriceLimitX96)
}

// computeSwapStep executes a single step of swap and returns new state
func (i *poolV1) computeSwapStep(
	state SwapState,
	pool *pl.Pool,
	zeroForOne bool,
	sqrtPriceLimitX96 *u256.Uint,
	exactInput bool,
	cache *SwapCache,
) (SwapState, error) {
	step := computeSwapStepInit(state, pool, zeroForOne)

	// determining the price target for this step
	sqrtRatioTargetX96 := computeTargetSqrtRatio(step, sqrtPriceLimitX96, zeroForOne).Clone()

	// computing the amounts to be swapped at this step
	var (
		newState SwapState
		err      error
	)

	newState, step = computeAmounts(state, sqrtRatioTargetX96, pool, step)
	newState, err = updateAmounts(step, newState, exactInput)
	if err != nil {
		return state, err
	}

	// if the protocol fee is on, calculate how much is owed,
	// decrement fee amount, and increment protocol fee
	if cache.feeProtocol > 0 {
		newState, step, err = updateFeeProtocol(step, cache.feeProtocol, newState)
		if err != nil {
			return state, err
		}
	}

	// update global fee tracker
	if newState.liquidity.Gt(u256.Zero()) {
		update := u256.MulDiv(step.feeAmount, fixedPointQ128, newState.liquidity)
		feeGrowthGlobalX128 := u256.Zero().Add(newState.feeGrowthGlobalX128, update)
		newState.setFeeGrowthGlobalX128(feeGrowthGlobalX128)
	}

	// handling tick transitions
	if newState.sqrtPriceX96.Eq(step.sqrtPriceNextX96) {
		newState = i.tickTransition(step, zeroForOne, newState, pool, cache)
	} else if newState.sqrtPriceX96.Neq(step.sqrtPriceStartX96) {
		newState.setTick(common.TickMathGetTickAtSqrtRatio(newState.sqrtPriceX96))
	}

	return newState, nil
}

// updateFeeProtocol calculates and updates protocol fees for the current step.
func updateFeeProtocol(step StepComputations, feeProtocol uint8, state SwapState) (SwapState, StepComputations, error) {
	delta := u256.Zero().Div(step.feeAmount, u256.NewUint(uint64(feeProtocol)))

	newFeeAmount, overflow := u256.Zero().SubOverflow(step.feeAmount, delta)
	if overflow {
		return state, step, errUnderflow
	}

	step.feeAmount = newFeeAmount

	newProtocolFee, overflow := u256.Zero().AddOverflow(state.protocolFee, delta)
	if overflow {
		return state, step, errOverflow
	}
	state.protocolFee = newProtocolFee

	return state, step, nil
}

// computeSwapStepInit initializes the computation for a single swap step.
func computeSwapStepInit(state SwapState, pool *pl.Pool, zeroForOne bool) StepComputations {
	var step StepComputations
	step.sqrtPriceStartX96 = state.sqrtPriceX96
	tickNext, initialized := tickBitmapNextInitializedTickWithInOneWord(
		pool,
		state.tick,
		pool.TickSpacing(),
		zeroForOne,
	)

	step.tickNext = tickNext
	step.initialized = initialized

	// prevent overshoot the min/max tick
	step.clampTickNext()
	// get the price for the next tick
	step.sqrtPriceNextX96 = common.TickMathGetSqrtRatioAtTick(step.tickNext)
	return step
}

// computeTargetSqrtRatio determines the target sqrt price for the current swap step.
func computeTargetSqrtRatio(step StepComputations, sqrtPriceLimitX96 *u256.Uint, zeroForOne bool) *u256.Uint {
	if shouldUsePriceLimit(step.sqrtPriceNextX96, sqrtPriceLimitX96, zeroForOne) {
		return sqrtPriceLimitX96
	}
	return step.sqrtPriceNextX96
}

// shouldUsePriceLimit returns true if the price limit should be used instead of the next tick price
func shouldUsePriceLimit(sqrtPriceNext, sqrtPriceLimit *u256.Uint, zeroForOne bool) bool {
	if zeroForOne {
		return sqrtPriceNext.Lt(sqrtPriceLimit)
	}
	return sqrtPriceNext.Gt(sqrtPriceLimit)
}

// computeAmounts calculates the input and output amounts for the current swap step.
func computeAmounts(state SwapState, sqrtRatioTargetX96 *u256.Uint, pool *pl.Pool, step StepComputations) (SwapState, StepComputations) {
	sqrtPriceX96, amountIn, amountOut, feeAmount := plp.SwapMathComputeSwapStep(
		state.sqrtPriceX96,
		sqrtRatioTargetX96,
		state.liquidity,
		state.amountSpecifiedRemaining,
		uint64(pool.Fee()),
	)

	step.amountIn = amountIn
	step.amountOut = amountOut
	step.feeAmount = feeAmount

	state.setSqrtPriceX96(sqrtPriceX96)

	return state, step
}

// updateAmounts calculates new remaining and calculated amounts based on the swap step.
// For exact input swaps:
//   - Decrements remaining input amount by (amountIn + feeAmount)
//   - Decrements calculated amount by amountOut
//
// For exact output swaps:
//   - Increments remaining output amount by amountOut
//   - Increments calculated amount by (amountIn + feeAmount)
func updateAmounts(step StepComputations, state SwapState, exactInput bool) (SwapState, error) {
	amountInWithFeeU256 := u256.Zero().Add(step.amountIn, step.feeAmount)
	if amountInWithFeeU256.Gt(maxInt256) {
		return state, errOverflow
	}

	amountInWithFee := i256.FromUint256(amountInWithFeeU256)
	if step.amountOut.Gt(maxInt256) {
		return state, errOverflow
	}

	var (
		amountSpecifiedRemaining *i256.Int
		amountCalculated         *i256.Int
		overflow                 bool
	)

	if exactInput {
		amountSpecifiedRemaining, overflow = i256.Zero().SubOverflow(state.amountSpecifiedRemaining, amountInWithFee)
		if overflow {
			return state, errUnderflow
		}
		amountCalculated, overflow = i256.Zero().SubOverflow(state.amountCalculated, i256.FromUint256(step.amountOut))
		if overflow {
			return state, errUnderflow
		}
	} else {
		amountSpecifiedRemaining, overflow = i256.Zero().AddOverflow(state.amountSpecifiedRemaining, i256.FromUint256(step.amountOut))
		if overflow {
			return state, errOverflow
		}
		amountCalculated, overflow = i256.Zero().AddOverflow(state.amountCalculated, amountInWithFee)
		if overflow {
			return state, errOverflow
		}
	}

	// If an overflowed value is stored in state, it may cause problems in the next step
	if amountCalculated.Gt(maxInt64) || amountSpecifiedRemaining.Gt(maxInt64) {
		return state, errOverflow
	}

	// If an underflowed value is stored in state, it may cause problems in the next step
	if amountCalculated.Lt(minInt64) || amountSpecifiedRemaining.Lt(minInt64) {
		return state, errUnderflow
	}

	state.amountSpecifiedRemaining = amountSpecifiedRemaining
	state.amountCalculated = amountCalculated

	return state, nil
}

// tickTransition handles the transition between price ticks during a swap
func (i *poolV1) tickTransition(step StepComputations, zeroForOne bool, state SwapState, pool *pl.Pool, cache *SwapCache) SwapState {
	// ensure existing state to keep immutability
	newState := state

	if step.initialized {
		// Compute oracle values on first initialized tick cross
		if !cache.computedLatestObservation {
			observationState := pool.ObservationState()
			if observationState != nil {
				tickCumulative, secondsPerLiquidity, err := observeSingle(
					observationState,
					cache.blockTimestamp,
					0,
					state.tick,
					observationState.Index(),
					cache.liquidityStart,
					observationState.Cardinality(),
				)
				if err == nil {
					cache.tickCumulative = tickCumulative
					cache.secondsPerLiquidityCumulativeX128 = secondsPerLiquidity
					cache.computedLatestObservation = true
				}
			}
		}

		// Ensure cache has valid values even if oracle computation fails
		if cache.secondsPerLiquidityCumulativeX128 == nil {
			cache.secondsPerLiquidityCumulativeX128 = u256.Zero()
		}

		fee0, fee1 := u256.Zero(), u256.Zero()

		if zeroForOne {
			fee0 = state.feeGrowthGlobalX128
			fee1 = pool.FeeGrowthGlobal1X128()
		} else {
			fee0 = pool.FeeGrowthGlobal0X128()
			fee1 = state.feeGrowthGlobalX128
		}

		liquidityNet := tickCross(
			pool,
			step.tickNext,
			fee0,
			fee1,
			cache.secondsPerLiquidityCumulativeX128,
			cache.tickCumulative,
			cache.blockTimestamp,
		)

		if zeroForOne {
			liquidityNet = i256.Zero().Neg(liquidityNet)
		}

		newState.liquidity = common.LiquidityMathAddDelta(state.liquidity, liquidityNet)

		if i.store.HasTickCrossHook() {
			tickCrossHook := i.store.GetTickCrossHook()

			currentTime := time.Now().Unix()
			tickCrossHook(cross, pool.PoolPath(), step.tickNext, zeroForOne, currentTime)
		}
	}

	newState.tick = step.tickNext
	if zeroForOne {
		newState.tick = step.tickNext - 1
	}

	return newState
}

package v1

import (
	"gno.land/p/nt/ufmt"

	i256 "gno.land/p/gnoswap/int256"
	u256 "gno.land/p/gnoswap/uint256"

	"gno.land/r/gnoswap/common"
	pl "gno.land/r/gnoswap/pool"
)

const (
	MIN_TICK int32 = -887272
	MAX_TICK int32 = 887272
)

// GetTickLiquidityGross returns the gross liquidity for the specified tick.
func GetTickLiquidityGross(p *pl.Pool, tick int32) *u256.Uint {
	return mustGetTick(p, tick).LiquidityGross()
}

// GetTickLiquidityNet returns the net liquidity for the specified tick.
func GetTickLiquidityNet(p *pl.Pool, tick int32) *i256.Int {
	return mustGetTick(p, tick).LiquidityNet()
}

// GetTickFeeGrowthOutside0X128 returns the fee growth outside the tick for token 0.
func GetTickFeeGrowthOutside0X128(p *pl.Pool, tick int32) *u256.Uint {
	return mustGetTick(p, tick).FeeGrowthOutside0X128()
}

// GetTickFeeGrowthOutside1X128 returns the fee growth outside the tick for token 1.
func GetTickFeeGrowthOutside1X128(p *pl.Pool, tick int32) *u256.Uint {
	return mustGetTick(p, tick).FeeGrowthOutside1X128()
}

// GetTickCumulativeOutside returns the cumulative liquidity outside the tick.
func GetTickCumulativeOutside(p *pl.Pool, tick int32) int64 {
	return mustGetTick(p, tick).TickCumulativeOutside()
}

// GetTickSecondsPerLiquidityOutsideX128 returns the seconds per liquidity outside the tick.
func GetTickSecondsPerLiquidityOutsideX128(p *pl.Pool, tick int32) *u256.Uint {
	return mustGetTick(p, tick).SecondsPerLiquidityOutsideX128()
}

// GetTickSecondsOutside returns the seconds outside the tick.
func GetTickSecondsOutside(p *pl.Pool, tick int32) uint32 {
	return mustGetTick(p, tick).SecondsOutside()
}

// GetTickInitialized returns whether the tick is initialized.
func GetTickInitialized(p *pl.Pool, tick int32) bool {
	return mustGetTick(p, tick).Initialized()
}

// getFeeGrowthInside calculates the fee growth within a specified tick range.
//
// This function computes the accumulated fee growth for token 0 and token 1 inside a given tick range
// (`tickLower` to `tickUpper`) relative to the current tick position (`tickCurrent`). It isolates the fee
// growth within the range by subtracting the fee growth below the lower tick and above the upper tick
// from the global fee growth.
//
// Parameters:
//   - tickLower: int32, the lower tick boundary of the range.
//   - tickUpper: int32, the upper tick boundary of the range.
//   - tickCurrent: int32, the current tick index.
//   - feeGrowthGlobal0X128: *u256.Uint, the global fee growth for token 0 in X128 precision.
//   - feeGrowthGlobal1X128: *u256.Uint, the global fee growth for token 1 in X128 precision.
//
// Returns:
//   - *u256.Uint: Fee growth inside the tick range for token 0.
//   - *u256.Uint: Fee growth inside the tick range for token 1.
//
// Workflow:
//  1. Retrieve the tick information (`lower` and `upper`) for the lower and upper tick boundaries
//     using `p.getTick`.
//  2. Calculate the fee growth below the lower tick using `getFeeGrowthBelowX128`.
//  3. Calculate the fee growth above the upper tick using `getFeeGrowthAboveX128`.
//  4. Subtract the fee growth below and above the range from the global fee growth values:
//     feeGrowthInside = feeGrowthGlobal - feeGrowthBelow - feeGrowthAbove
//  5. Return the computed fee growth values for token 0 and token 1 within the range.
//
// Behavior:
//   - The fee growth is isolated within the range `[tickLower, tickUpper]`.
//   - The function ensures the calculations accurately consider the tick boundaries and the current tick position.
//
// Example:
//
// ```gno
//
//	feeGrowth0, feeGrowth1 := pool.getFeeGrowthInside(
//	    100, 200, 150, globalFeeGrowth0, globalFeeGrowth1,
//	)
//	println("Fee Growth Inside (Token 0):", feeGrowth0)
//	println("Fee Growth Inside (Token 1):", feeGrowth1)
//
// ```
func getFeeGrowthInside(
	p *pl.Pool,
	tickLower int32,
	tickUpper int32,
	tickCurrent int32,
	feeGrowthGlobal0X128 *u256.Uint,
	feeGrowthGlobal1X128 *u256.Uint,
) (*u256.Uint, *u256.Uint) {
	lower := getTick(p, tickLower)
	upper := getTick(p, tickUpper)

	feeGrowthBelow0X128, feeGrowthBelow1X128 := getFeeGrowthBelowX128(tickLower, tickCurrent, feeGrowthGlobal0X128, feeGrowthGlobal1X128, lower)
	feeGrowthAbove0X128, feeGrowthAbove1X128 := getFeeGrowthAboveX128(tickUpper, tickCurrent, feeGrowthGlobal0X128, feeGrowthGlobal1X128, upper)

	feeGrowthInside0X128 := u256.Zero().Sub(u256.Zero().Sub(feeGrowthGlobal0X128, feeGrowthBelow0X128), feeGrowthAbove0X128)
	feeGrowthInside1X128 := u256.Zero().Sub(u256.Zero().Sub(feeGrowthGlobal1X128, feeGrowthBelow1X128), feeGrowthAbove1X128)

	return feeGrowthInside0X128, feeGrowthInside1X128
}

// tickUpdate updates the state of a specific tick.
//
// This function applies a given liquidity change (liquidityDelta) to the specified tick, updates
// the fee growth values if necessary, and adjusts the net liquidity based on whether the tick
// is an upper or lower boundary. It also verifies that the total liquidity does not exceed the
// maximum allowed value and ensures the net liquidity stays within the valid int128 range.
//
// Parameters:
//   - tick:          int32, the index of the tick to update.
//   - tickCurrent:   int32, the current active tick index.
//   - liquidityDelta: *i256.Int, the amount of liquidity to add or remove.
//   - feeGrowthGlobal0X128: *u256.Uint, the global fee growth value for token 0.
//   - feeGrowthGlobal1X128: *u256.Uint, the global fee growth value for token 1.
//   - upper:         bool, indicates if this is the upper boundary (true for upper, false for lower).
//   - maxLiquidity:  *u256.Uint, the maximum allowed liquidity.
//
// Returns:
//   - flipped: bool, indicates if the tick's initialization state has changed.
//     (e.g., liquidity transitioning from zero to non-zero, or vice versa)
//
// Workflow:
// 1. Nil input values are replaced with zero.
// 2. The function retrieves the tick information for the specified tick index.
// 3. Applies the liquidityDelta to compute the new total liquidity (liquidityGross).
//   - If the total liquidity exceeds the maximum allowed value, the function panics.
//     4. Checks whether the tick's initialized state has changed and sets the `flipped` flag.
//     5. If the tick was previously uninitialized and its index is less than or equal to the current tick,
//     the fee growth values are initialized to the current global values.
//     6. Updates the tick's net liquidity:
//   - For an upper boundary, it subtracts liquidityDelta.
//   - For a lower boundary, it adds liquidityDelta.
//   - Ensures the net liquidity remains within the int128 range using `checkOverFlowInt128`.
//     7. Updates the tick's state with the new values.
//     8. Returns whether the tick's initialized state has flipped.
//
// Panic Conditions:
// - The total liquidity (liquidityGross) exceeds the maximum allowed liquidity (maxLiquidity).
// - The net liquidity (liquidityNet) exceeds the int128 range.
//
// Example:
//
// ```gno
//
//	flipped := pool.tickUpdate(10, 5, liquidityDelta, feeGrowth0, feeGrowth1, true, maxLiquidity)
//	println("Tick flipped:", flipped)
//
// ```
func tickUpdate(
	p *pl.Pool,
	tick int32,
	tickCurrent int32,
	liquidityDelta *i256.Int,
	feeGrowthGlobal0X128 *u256.Uint,
	feeGrowthGlobal1X128 *u256.Uint,
	upper bool,
	maxLiquidity *u256.Uint,
) (flipped bool) {
	tickInfo := getTick(p, tick)

	liquidityGrossBefore := tickInfo.LiquidityGross().Clone()
	liquidityGrossAfter := common.LiquidityMathAddDelta(liquidityGrossBefore, liquidityDelta)

	if !liquidityGrossAfter.Lte(maxLiquidity) {
		panic(newErrorWithDetail(
			errLiquidityCalculation,
			ufmt.Sprintf("liquidityGrossAfter(%s) overflows maxLiquidity(%s)", liquidityGrossAfter.ToString(), maxLiquidity.ToString()),
		))
	}

	flipped = liquidityGrossAfter.IsZero() != liquidityGrossBefore.IsZero()

	if liquidityGrossBefore.IsZero() {
		if tick <= tickCurrent {
			tickInfo.SetFeeGrowthOutside0X128(feeGrowthGlobal0X128.Clone())
			tickInfo.SetFeeGrowthOutside1X128(feeGrowthGlobal1X128.Clone())
		}
		tickInfo.SetInitialized(true)
	}

	tickInfo.SetLiquidityGross(liquidityGrossAfter.Clone())

	if upper {
		tickInfo.SetLiquidityNet(i256.Zero().Sub(tickInfo.LiquidityNet(), liquidityDelta))
		checkOverFlowInt128(tickInfo.LiquidityNet())
	} else {
		tickInfo.SetLiquidityNet(i256.Zero().Add(tickInfo.LiquidityNet(), liquidityDelta))
		checkOverFlowInt128(tickInfo.LiquidityNet())
	}

	setTick(p, tick, tickInfo)

	return flipped
}

// tickCross updates a tick's state when it is crossed and returns the liquidity net.
// Updates fee growth and oracle accumulator values for the tick.
func tickCross(
	p *pl.Pool,
	tick int32,
	feeGrowthGlobal0X128 *u256.Uint,
	feeGrowthGlobal1X128 *u256.Uint,
	secondsPerLiquidityCumulativeX128 *u256.Uint,
	tickCumulative int64,
	blockTimestamp int64,
) *i256.Int {
	thisTick := getTick(p, tick)

	thisTick.SetFeeGrowthOutside0X128(u256.Zero().Sub(feeGrowthGlobal0X128, thisTick.FeeGrowthOutside0X128()))
	thisTick.SetFeeGrowthOutside1X128(u256.Zero().Sub(feeGrowthGlobal1X128, thisTick.FeeGrowthOutside1X128()))

	// Handle oracle fields - use zero values if nil
	tickSecondsPerLiquidity := thisTick.SecondsPerLiquidityOutsideX128()
	if tickSecondsPerLiquidity == nil {
		tickSecondsPerLiquidity = u256.Zero()
	}
	thisTick.SetSecondsPerLiquidityOutsideX128(u256.Zero().Sub(secondsPerLiquidityCumulativeX128, tickSecondsPerLiquidity))
	thisTick.SetTickCumulativeOutside(tickCumulative - thisTick.TickCumulativeOutside())
	thisTick.SetSecondsOutside(uint32(blockTimestamp) - thisTick.SecondsOutside())

	setTick(p, tick, thisTick)

	return thisTick.LiquidityNet().Clone()
}

// setTick updates the tick data for the specified tick index in the pool.
func setTick(p *pl.Pool, tick int32, newTickInfo pl.TickInfo) {
	p.SetTick(tick, newTickInfo)
}

// deleteTick deletes the tick data for the specified tick index in the pool.
func deleteTick(p *pl.Pool, tick int32) {
	p.DeleteTick(tick)
}

// getTick retrieves the TickInfo associated with the specified tick index from the pool.
// If the TickInfo contains any nil fields, they are replaced with zero values using valueOrZero.
//
// Parameters:
// - tick: The tick index (int32) for which the TickInfo is to be retrieved.
//
// Behavior:
// - Retrieves the TickInfo for the given tick from the pool's tick map.
// - Ensures that all fields of TickInfo are non-nil by calling valueOrZero, which replaces nil values with zero.
// - Returns the updated TickInfo.
//
// Returns:
// - TickInfo: The tick data with all fields guaranteed to have valid values (nil fields are set to zero).
//
// Use Case:
// This function ensures the retrieved tick data is always valid and safe for further operations,
// such as calculations or updates, by sanitizing nil fields in the TickInfo structure.
func getTick(p *pl.Pool, tick int32) pl.TickInfo {
	tickInfo, err := p.GetTick(tick)
	if err != nil {
		return pl.NewTickInfo()
	}

	return tickInfo
}

// mustGetTick retrieves the TickInfo for a specific tick, panicking if the tick does not exist.
//
// This function ensures that the requested tick data exists in the pool's tick mapping.
// If the tick does not exist, it panics with an appropriate error message.
//
// Parameters:
//   - tick: int32, the index of the tick to retrieve.
//
// Returns:
//   - TickInfo: The information associated with the specified tick.
//
// Behavior:
//   - Checks if the tick exists in the pool's tick mapping (`p.ticks`).
//   - If the tick exists, it returns the corresponding `TickInfo`.
//   - If the tick does not exist, the function panics with a descriptive error.
//
// Panic Conditions:
//   - The specified tick does not exist in the pool's mapping.
//
// Example:
//
// ```gno
//
//	tickInfo := pool.mustGetTick(10)
//	ufmt.Println("Tick Info:", tickInfo)
//
// ```
func mustGetTick(p *pl.Pool, tick int32) *pl.TickInfo {
	tickInfo, err := p.GetTick(tick)
	if err != nil {
		panic(err)
	}

	return &tickInfo
}

// calculateMaxLiquidityPerTick calculates the maximum liquidity
// per tick for a given tick spacing.
func calculateMaxLiquidityPerTick(tickSpacing int32) *u256.Uint {
	// Floor MIN_TICK and MAX_TICK to the nearest multiple of tickSpacing
	// This ensures that the tick range is properly aligned with the tickSpacing
	// For example, if tickSpacing is 60 and MIN_TICK is -887272:
	// -887272 / 60 = -14787.866... -> -14787 * 60 = -887220
	minTick := (MIN_TICK / tickSpacing) * tickSpacing
	maxTick := (MAX_TICK / tickSpacing) * tickSpacing
	numTicks := uint64((maxTick-minTick)/tickSpacing) + 1

	return u256.Zero().Div(maxUint128FromDecimal, u256.NewUint(numTicks))
}

// getFeeGrowthBelowX128 calculates the fee growth below a specified tick.
//
// This function computes the fee growth for token 0 and token 1 below a given tick (`tickLower`)
// relative to the current tick (`tickCurrent`). The fee growth values are adjusted based on whether
// the `tickCurrent` is above or below the `tickLower`.
//
// Parameters:
//   - tickLower: int32, the lower tick boundary for fee calculation.
//   - tickCurrent: int32, the current tick index.
//   - feeGrowthGlobal0X128: *u256.Uint, the global fee growth for token 0 in X128 precision.
//   - feeGrowthGlobal1X128: *u256.Uint, the global fee growth for token 1 in X128 precision.
//   - lowerTick: TickInfo, the fee growth and liquidity details for the lower tick.
//
// Returns:
//   - *u256.Uint: Fee growth below `tickLower` for token 0.
//   - *u256.Uint: Fee growth below `tickLower` for token 1.
//
// Workflow:
//  1. If `tickCurrent` is greater than or equal to `tickLower`:
//     - Return the `feeGrowthOutside0X128` and `feeGrowthOutside1X128` values of the `lowerTick`.
//  2. If `tickCurrent` is below `tickLower`:
//     - Compute the fee growth below the lower tick by subtracting `feeGrowthOutside` values
//     from the global fee growth values (`feeGrowthGlobal0X128` and `feeGrowthGlobal1X128`).
//  3. Return the calculated fee growth values for both tokens.
//
// Behavior:
//   - If `tickCurrent >= tickLower`, the fee growth outside the lower tick is returned as-is.
//   - If `tickCurrent < tickLower`, the fee growth is calculated as:
//     feeGrowthBelow = feeGrowthGlobal - feeGrowthOutside
//
// Example:
//
// ```gno
//
//	feeGrowth0, feeGrowth1 := getFeeGrowthBelowX128(
//	    100, 150, globalFeeGrowth0, globalFeeGrowth1, lowerTickInfo,
//	)
//	println("Fee Growth Below:", feeGrowth0, feeGrowth1)
func getFeeGrowthBelowX128(
	tickLower, tickCurrent int32,
	feeGrowthGlobal0X128, feeGrowthGlobal1X128 *u256.Uint,
	lowerTick pl.TickInfo,
) (*u256.Uint, *u256.Uint) {
	if tickCurrent >= tickLower {
		return lowerTick.FeeGrowthOutside0X128(), lowerTick.FeeGrowthOutside1X128()
	}

	feeGrowthBelow0X128 := u256.Zero().Sub(feeGrowthGlobal0X128, lowerTick.FeeGrowthOutside0X128())
	feeGrowthBelow1X128 := u256.Zero().Sub(feeGrowthGlobal1X128, lowerTick.FeeGrowthOutside1X128())

	return feeGrowthBelow0X128, feeGrowthBelow1X128
}

// getFeeGrowthAboveX128 calculates the fee growth above a specified tick.
//
// This function computes the fee growth for token 0 and token 1 above a given tick (`tickUpper`)
// relative to the current tick (`tickCurrent`). The fee growth values are adjusted based on whether
// the `tickCurrent` is above or below the `tickUpper`.
//
// Parameters:
//   - tickUpper: int32, the upper tick boundary for fee calculation.
//   - tickCurrent: int32, the current tick index.
//   - feeGrowthGlobal0X128: *u256.Uint, the global fee growth for token 0 in X128 precision.
//   - feeGrowthGlobal1X128: *u256.Uint, the global fee growth for token 1 in X128 precision.
//   - upperTick: TickInfo, the fee growth and liquidity details for the upper tick.
//
// Returns:
//   - *u256.Uint: Fee growth above `tickUpper` for token 0.
//   - *u256.Uint: Fee growth above `tickUpper` for token 1.
//
// Workflow:
//  1. If `tickCurrent` is less than `tickUpper`:
//     - Return the `feeGrowthOutside0X128` and `feeGrowthOutside1X128` values of the `upperTick`.
//  2. If `tickCurrent` is greater than or equal to `tickUpper`:
//     - Compute the fee growth above the upper tick by subtracting `feeGrowthOutside` values
//     from the global fee growth values (`feeGrowthGlobal0X128` and `feeGrowthGlobal1X128`).
//  3. Return the calculated fee growth values for both tokens.
//
// Behavior:
//   - If `tickCurrent < tickUpper`, the fee growth outside the upper tick is returned as-is.
//   - If `tickCurrent >= tickUpper`, the fee growth is calculated as:
//     feeGrowthAbove = feeGrowthGlobal - feeGrowthOutside
//
// Example:
//
//	feeGrowth0, feeGrowth1 := getFeeGrowthAboveX128(
//	    200, 150, globalFeeGrowth0, globalFeeGrowth1, upperTickInfo,
//	)
//	println("Fee Growth Above:", feeGrowth0, feeGrowth1)
//
// ```
func getFeeGrowthAboveX128(
	tickUpper, tickCurrent int32,
	feeGrowthGlobal0X128, feeGrowthGlobal1X128 *u256.Uint,
	upperTick pl.TickInfo,
) (*u256.Uint, *u256.Uint) {
	if tickCurrent < tickUpper {
		return upperTick.FeeGrowthOutside0X128(), upperTick.FeeGrowthOutside1X128()
	}

	feeGrowthAbove0X128 := u256.Zero().Sub(feeGrowthGlobal0X128, upperTick.FeeGrowthOutside0X128())
	feeGrowthAbove1X128 := u256.Zero().Sub(feeGrowthGlobal1X128, upperTick.FeeGrowthOutside1X128())

	return feeGrowthAbove0X128, feeGrowthAbove1X128
}

// validateTicks validates the tick range for a liquidity position.
//
// This function performs three essential checks to ensure the provided
// tick values are valid before creating or modifying a liquidity position.
func validateTicks(tickLower, tickUpper int32) error {
	if tickLower >= tickUpper {
		return makeErrorWithDetails(
			errInvalidTickRange,
			ufmt.Sprintf("tickLower(%d), tickUpper(%d)", tickLower, tickUpper),
		)
	}

	if tickLower < MIN_TICK {
		return makeErrorWithDetails(
			errTickLowerInvalid,
			ufmt.Sprintf("tickLower(%d) < MIN_TICK(%d)", tickLower, MIN_TICK),
		)
	}

	if tickUpper > MAX_TICK {
		return makeErrorWithDetails(
			errTickUpperInvalid,
			ufmt.Sprintf("tickUpper(%d) > MAX_TICK(%d)", tickUpper, MAX_TICK),
		)
	}

	return nil
}

package v1

import (
	"strconv"

	plp "gno.land/p/gnoswap/gnsmath"
	u256 "gno.land/p/gnoswap/uint256"
	"gno.land/p/nt/ufmt"
	pl "gno.land/r/gnoswap/pool"
)

// bitMask8 is used for efficient modulo 256 operations
const bitMask8 = 0xff // 256 - 1

// tickBitmapFlipTick flips the state of a tick in the tick bitmap.
//
// This function toggles the "initialized" state of a tick in the tick bitmap.
// It ensures that the tick aligns with the specified tick spacing and then
// flips the corresponding bit in the bitmap representation.
//
// Parameters:
//   - tick: int32, the tick index to toggle.
//   - tickSpacing: int32, the spacing between valid ticks.
//     The tick must align with this spacing.
//
// Workflow:
//  1. Validates that the `tick` aligns with `tickSpacing` using `checkTickSpacing`.
//  2. Computes the position of the bit in the tick bitmap:
//     - `wordPos`: Determines which word in the bitmap contains the bit.
//     - `bitPos`: Identifies the position of the bit within the word.
//  3. Creates a bitmask using `Lsh` (Left Shift) to target the bit at `bitPos`.
//  4. Toggles (flips) the bit using XOR with the current value of the tick bitmap.
//  5. Updates the tick bitmap with the modified word.
//
// Behavior:
//   - If the bit is `0` (uninitialized), it will be flipped to `1` (initialized).
//   - If the bit is `1` (initialized), it will be flipped to `0` (uninitialized).
//
// Example:
//
//	pool.tickBitmapFlipTick(120, 60)
//	// This flips the bit for tick 120 with a tick spacing of 60.
//
// Notes:
//   - The `tick` must be divisible by `tickSpacing`. If not, the function will panic.
func tickBitmapFlipTick(
	p *pl.Pool,
	tick int32,
	tickSpacing int32,
) {
	checkTickSpacing(tick, tickSpacing)
	wordPos, bitPos := tickBitmapPosition(tick / tickSpacing)

	mask := u256.Zero().Lsh(u256.One(), uint(bitPos))
	current := getTickBitmap(p, wordPos)
	setTickBitmap(p, wordPos, u256.Zero().Xor(current, mask))
}

// tickBitmapNextInitializedTickWithInOneWord finds the next initialized tick within
// one word of the bitmap.
func tickBitmapNextInitializedTickWithInOneWord(
	p *pl.Pool,
	tick int32,
	tickSpacing int32,
	lte bool,
) (int32, bool) {
	compress := tick / tickSpacing
	// Round towards negative infinity for negative ticks
	if tick < 0 && tick%tickSpacing != 0 {
		compress--
	}

	wordPos, bitPos := getWordAndBitPos(compress, lte)
	mask := getMaskBit(uint(bitPos), lte)
	masked := u256.Zero().And(getTickBitmap(p, wordPos), mask)
	initialized := !masked.IsZero()

	nextTick := getNextTick(lte, initialized, compress, bitPos, tickSpacing, masked)
	return nextTick, initialized
}

// getTickBitmap gets the tick bitmap for the given word position
// if the tick bitmap is not initialized, initialize it to zero
func getTickBitmap(p *pl.Pool, wordPos int16) *u256.Uint {
	wordPosStr := strconv.Itoa(int(wordPos))

	value, exist := p.TickBitmaps().Get(wordPosStr)
	if !exist {
		setTickBitmap(p, wordPos, u256.Zero())
		value, exist = p.TickBitmaps().Get(wordPosStr)
		if !exist {
			panic(newErrorWithDetail(
				errDataNotFound,
				ufmt.Sprintf("failed to initialize tickBitmap(%d)", wordPos),
			))
		}
	}

	bitmap, ok := value.(*u256.Uint)
	if !ok {
		panic(ufmt.Sprintf("failed to cast tickBitmap to *u256.Uint: %T", value))
	}
	return bitmap
}

// setTickBitmap sets the tick bitmap for the given word position
func setTickBitmap(p *pl.Pool, wordPos int16, tickBitmap *u256.Uint) {
	wordPosStr := strconv.Itoa(int(wordPos))
	p.TickBitmaps().Set(wordPosStr, tickBitmap)
}

// tickBitmapPosition calculates the word and bit position for a given tick
func tickBitmapPosition(tick int32) (int16, uint8) {
	return int16(tick >> 8), uint8(tick) & bitMask8
}

// getWordAndBitPos gets tick's wordPos and bitPos depending on the swap direction
func getWordAndBitPos(tick int32, lte bool) (int16, uint8) {
	if !lte {
		tick++
	}
	return tickBitmapPosition(tick)
}

// getMaskBit generates a mask based on the provided bit position (bitPos) and a boolean flag (lte).
// The function constructs a bitmask with a shift depending on the bit position and the boolean value.
// It either returns the mask or its negation, based on the value of 'lte' (swap direction).
//
// NOTE: should always use a newly created `u256.One()` object.
func getMaskBit(bitPos uint, lte bool) *u256.Uint {
	if lte {
		if bitPos == bitMask8 {
			return u256.Zero().SetAllOne()
		}
		return u256.Zero().Sub(u256.Zero().Lsh(u256.One(), bitPos+1), u256.One())
	}
	if bitPos == 0 {
		return u256.Zero().SetAllOne()
	}
	return u256.Zero().Not(u256.Zero().Sub(u256.Zero().Lsh(u256.One(), bitPos), u256.One()))
}

// getNextTick gets the next tick depending on the initialized state and the swap direction
func getNextTick(lte, initialized bool, compress int32, bitPos uint8, tickSpacing int32, masked *u256.Uint) int32 {
	if initialized {
		return getTickIfInitialized(compress, tickSpacing, bitPos, masked, lte)
	}
	return getTickIfNotInitialized(compress, tickSpacing, bitPos, lte)
}

// getTickIfInitialized gets the next tick if the tick bitmap is initialized
func getTickIfInitialized(compress, tickSpacing int32, bitPos uint8, masked *u256.Uint, lte bool) int32 {
	if lte {
		return (compress - int32(bitPos-plp.BitMathMostSignificantBit(masked))) * tickSpacing
	}
	return (compress + 1 + int32(plp.BitMathLeastSignificantBit(masked)-bitPos)) * tickSpacing
}

// getTickIfNotInitialized gets the next tick if the tick bitmap is not initialized
func getTickIfNotInitialized(compress, tickSpacing int32, bitPos uint8, lte bool) int32 {
	if lte {
		return (compress - int32(bitPos)) * tickSpacing
	}
	return (compress + 1 + int32(bitMask8-bitPos)) * tickSpacing
}

package v1

import (
	"chain/runtime"

	"gno.land/p/nt/ufmt"

	"gno.land/r/gnoswap/common"
	pl "gno.land/r/gnoswap/pool"

	i256 "gno.land/p/gnoswap/int256"
	u256 "gno.land/p/gnoswap/uint256"
)

// safeTransfer performs a token transfer out of the pool while ensuring
// the pool has sufficient balance and updating internal accounting.
// This function is typically used during swaps and liquidity removals.
//
// Important requirements:
//   - The amount must be a positive value representing tokens to transfer out
//   - The pool must have sufficient balance for the transfer
//   - The transfer amount must fit within int64 range
//
// Parameters:
//   - p: the pool instance
//   - to: destination address for the transfer
//   - tokenPath: path identifier of the token to transfer
//   - amount: amount to transfer (positive u256.Uint value)
//   - isToken0: true if transferring token0, false for token1
//
// The function will:
//  1. Check pool has sufficient balance
//  2. Execute the transfer
//  3. Subtract the amount from pool's internal balance
//
// Panics if any validation fails or if the transfer fails
func (i *poolV1) safeTransfer(
	p *pl.Pool,
	to address,
	tokenPath string,
	amount *u256.Uint,
	isToken0 bool,
) {
	token0 := p.BalanceToken0()
	token1 := p.BalanceToken1()

	if err := validatePoolBalance(token0, token1, amount, isToken0); err != nil {
		panic(err)
	}
	amountInt64 := safeConvertToInt64(amount)

	common.SafeGRC20Transfer(cross, tokenPath, to, amountInt64)

	newBalance, err := updatePoolBalance(token0, token1, amount, isToken0)
	if err != nil {
		panic(err)
	}

	poolBalances := p.Balances()

	if isToken0 {
		poolBalances.SetToken0(newBalance)
	} else {
		poolBalances.SetToken1(newBalance)
	}

	p.SetBalances(poolBalances)
}

// safeTransferFrom securely transfers tokens into the pool while ensuring balance consistency.
//
// This function performs the following steps:
// 1. Validates and converts the transfer amount to `int64` using `safeConvertToInt64`.
// 2. Executes the token transfer using `TransferFrom` via the token teller contract.
// 3. Verifies that the destination balance reflects the correct amount after transfer.
// 4. Updates the pool's internal balances (`token0` or `token1`) and validates the updated state.
//
// Parameters:
// - p (*pl.Pool): The pool instance to transfer tokens into.
// - from (address): Source address for the token transfer.
// - to (address): Destination address, typically the pool address.
// - tokenPath (string): Path identifier for the token being transferred.
// - amount (*u256.Uint): The amount of tokens to transfer (must be a positive value).
// - isToken0 (bool): A flag indicating whether the token being transferred is token0 (`true`) or token1 (`false`).
//
// Panics:
// - If the `amount` exceeds the int64 range during conversion.
// - If the token transfer (`TransferFrom`) fails.
// - If the destination balance after the transfer does not match the expected amount.
// - If the pool's internal balances (`token0` or `token1`) overflow or become inconsistent.
//
// Notes:
// - The function assumes that the sender (`from`) has approved the pool to spend the specified tokens.
// - The balance consistency check ensures that no tokens are lost or double-counted during the transfer.
// - Pool balance updates are performed atomically to ensure internal consistency.
func (i *poolV1) safeTransferFrom(
	p *pl.Pool,
	from, to address,
	tokenPath string,
	amount *u256.Uint,
	isToken0 bool,
) {
	amountInt64 := safeConvertToInt64(amount)

	token := common.GetToken(tokenPath)
	beforeBalance := token.BalanceOf(to)

	common.SafeGRC20TransferFrom(cross, tokenPath, from, to, amountInt64)

	afterBalance := token.BalanceOf(to)
	if (beforeBalance + amountInt64) != afterBalance {
		panic(ufmt.Sprintf(
			"%v. beforeBalance(%d) + amount(%d) != afterBalance(%d)",
			errTransferFailed, beforeBalance, amountInt64, afterBalance,
		))
	}

	poolBalances := p.Balances()

	// update pool balances
	if isToken0 {
		beforeToken0 := poolBalances.Token0().Clone()
		poolBalances.SetToken0(u256.Zero().Add(poolBalances.Token0(), amount))
		if poolBalances.Token0().Lt(beforeToken0) {
			panic(ufmt.Sprintf(
				"%v. token0(%s) < beforeToken0(%s)",
				errBalanceUpdateFailed, poolBalances.Token0().ToString(), beforeToken0.ToString(),
			))
		}
	} else {
		beforeToken1 := poolBalances.Token1().Clone()
		poolBalances.SetToken1(u256.Zero().Add(poolBalances.Token1(), amount))
		if poolBalances.Token1().Lt(beforeToken1) {
			panic(ufmt.Sprintf(
				"%v. token1(%s) < beforeToken1(%s)",
				errBalanceUpdateFailed, poolBalances.Token1().ToString(), beforeToken1.ToString(),
			))
		}
	}

	p.SetBalances(poolBalances)
}

// safeSwapCallback executes a swap callback and validates the token payment.
//
// This function implements the flash swap pattern where the pool first sends output tokens
// to the recipient, then invokes the callback to receive input tokens from the caller.
// The callback is responsible for transferring the required input tokens to the pool.
//
// Callback Signature:
//
//	func(cur realm, amount0Delta, amount1Delta int64, _ *pool.CallbackMarker) error
//
// Delta Convention (following Uniswap V3 standard):
//   - Positive delta: Amount the pool must RECEIVE (input token)
//   - Negative delta: Amount the pool has SENT (output token)
//
// For zeroForOne swaps (token0 → token1):
//   - amount0Delta > 0: Pool receives token0 (input)
//   - amount1Delta < 0: Pool sends token1 (output)
//
// For oneForZero swaps (token1 → token0):
//   - amount0Delta < 0: Pool sends token0 (output)
//   - amount1Delta > 0: Pool receives token1 (input)
//
// Parameters:
//   - p: The pool instance
//   - tokenPath: Path of the input token that pool must receive
//   - amountInInt256: Amount pool must receive (positive i256.Int)
//   - amountOutInt256: Amount pool has sent (negative i256.Int)
//   - zeroForOne: Swap direction (true = token0 to token1)
//   - swapCallback: Callback function that must transfer input tokens to pool
//
// The callback needed:
//  1. Verify the caller is the legitimate pool contract address to prevent unauthorized invocations
//  2. Transfer at least `amountIn` of input tokens to the pool
//  3. Return nil on success, or an error to revert the swap
//
// Example callback implementation:
//
//	func(cur realm, amount0Delta, amount1Delta int64, _ *pool.CallbackMarker) error {
//	    // Security check: ensure this callback is invoked by the legitimate pool
//	    caller := runtime.PreviousRealm().Address()
//	    poolAddr := chain.PackageAddress("gno.land/r/gnoswap/pool")
//
//	    if caller != poolAddr {
//	        panic("unauthorized caller")
//	    }
//
//	    if amount0Delta > 0 {
//	        // Transfer token0 to pool
//	        token0.Transfer(cross, poolAddr, amount0Delta)
//	    }
//	    if amount1Delta > 0 {
//	        // Transfer token1 to pool
//	        token1.Transfer(cross, poolAddr, amount1Delta)
//	    }
//	    return nil
//	}
func (i *poolV1) safeSwapCallback(
	p *pl.Pool,
	tokenPath string,
	amountInInt256 *i256.Int,
	amountOutInt256 *i256.Int,
	zeroForOne bool,
	swapCallback func(cur realm, amount0Delta, amount1Delta int64, _ *pl.CallbackMarker) error,
) {
	if swapCallback == nil {
		panic(makeErrorWithDetails(
			errInvalidInput,
			"swapCallback is nil",
		))
	}

	currentAddress := runtime.CurrentRealm().Address()

	amountIn := amountInInt256.Int64()
	amountOut := amountOutInt256.Int64()
	balanceBefore := common.BalanceOf(tokenPath, currentAddress)

	// Make callback to the calling contract
	// The contract should transfer tokens to pool within this callback
	// Following Uniswap V3 convention:
	// - Positive delta: amount the pool must receive (input token)
	// - Negative delta: amount the pool has sent (output token)
	var amount0Delta, amount1Delta, beforeTokenBalance int64

	if zeroForOne {
		// zeroForOne: pool receives token0 (positive), sends token1 (negative)
		amount0Delta = amountIn
		amount1Delta = amountOut
		beforeTokenBalance = p.BalanceToken0().Int64()
	} else {
		// !zeroForOne: pool receives token1 (positive), sends token0 (negative)
		amount0Delta = amountOut
		amount1Delta = amountIn
		beforeTokenBalance = p.BalanceToken1().Int64()
	}

	// execute swap callback
	// CallbackMarker is created by the pool module to enforce type-system level validation.
	err := swapCallback(cross, amount0Delta, amount1Delta, &pl.CallbackMarker{})
	if err != nil {
		panic(err)
	}

	balanceAfter := common.BalanceOf(tokenPath, currentAddress)
	balanceIncrease := safeSubInt64(balanceAfter, balanceBefore)

	// check insufficient payment by swap callback
	if balanceIncrease < amountIn {
		panic(makeErrorWithDetails(
			errInsufficientPayment,
			ufmt.Sprintf("insufficient payment: expected %d, received %d", amountIn, balanceIncrease),
		))
	}

	// check overflow update pool balance
	resultTokenBalance := safeAddInt64(beforeTokenBalance, amountIn)
	resultTokenBalanceUint := u256.NewUintFromInt64(resultTokenBalance)

	poolBalances := p.Balances()

	if zeroForOne {
		poolBalances.SetToken0(resultTokenBalanceUint)
	} else {
		poolBalances.SetToken1(resultTokenBalanceUint)
	}

	p.SetBalances(poolBalances)
}

// validatePoolBalance checks if the pool has sufficient balance of either token0 and token1
// before proceeding with a transfer. This prevents the pool won't go into a negative balance.
func validatePoolBalance(token0, token1, amount *u256.Uint, isToken0 bool) error {
	if token0 == nil || token1 == nil || amount == nil {
		return ufmt.Errorf(
			"%v. token0(%s) or token1(%s) or amount(%s) is nil",
			errTransferFailed, token0.ToString(), token1.ToString(), amount.ToString(),
		)
	}

	if isToken0 {
		if token0.Lt(amount) {
			return ufmt.Errorf(
				"%v. token0(%s) >= amount(%s)",
				errTransferFailed, token0.ToString(), amount.ToString(),
			)
		}
		return nil
	}
	if token1.Lt(amount) {
		return ufmt.Errorf(
			"%v. token1(%s) >= amount(%s)",
			errTransferFailed, token1.ToString(), amount.ToString(),
		)
	}
	return nil
}

// updatePoolBalance calculates the new balance after a transfer and validate.
// It ensures the resulting balance won't be negative or overflow.
func updatePoolBalance(
	token0, token1, amount *u256.Uint,
	isToken0 bool,
) (*u256.Uint, error) {
	var overflow bool
	var newBalance *u256.Uint

	if isToken0 {
		newBalance, overflow = u256.Zero().SubOverflow(token0, amount)
		if isBalanceOverflowOrNegative(overflow, newBalance) {
			return nil, ufmt.Errorf(
				"%v. cannot decrease, token0(%s) - amount(%s)",
				errBalanceUpdateFailed, token0.ToString(), amount.ToString(),
			)
		}
		return newBalance, nil
	}

	newBalance, overflow = u256.Zero().SubOverflow(token1, amount)
	if isBalanceOverflowOrNegative(overflow, newBalance) {
		return nil, ufmt.Errorf(
			"%v. cannot decrease, token1(%s) - amount(%s)",
			errBalanceUpdateFailed, token1.ToString(), amount.ToString(),
		)
	}
	return newBalance, nil
}

// isBalanceOverflowOrNegative checks if the balance calculation resulted in an overflow or negative value.
func isBalanceOverflowOrNegative(overflow bool, newBalance *u256.Uint) bool {
	return overflow || newBalance.Lt(zero)
}

package v1

import (
	"time"

	i256 "gno.land/p/gnoswap/int256"
	u256 "gno.land/p/gnoswap/uint256"

	"gno.land/r/gnoswap/common"
	pl "gno.land/r/gnoswap/pool"
)

// ModifyPositionParams repersents the parameters for modifying a liquidity position.
// This structure is used internally both `Mint` and `Burn` operation to manage
// the liquidity positions.
type ModifyPositionParams struct {
	// owner is the address that owns the position
	owner address

	// tickLower and atickUpper define the price range
	// The actual price range is calculated as 1.0001^tick
	// This allows for precision in price range while using integer math.

	tickLower int32 // lower tick of the position
	tickUpper int32 // upper tick of the position

	// liquidityDelta represents the change in liquidity
	// Positive for minting, negative for burning
	liquidityDelta *i256.Int
}

// newModifyPositionParams creates a new `ModifyPositionParams` instance.
// This is used to preare parameters for the `modifyPosition` function,
// which handles both minting and burning of liquidity positions.
//
// Parameters:
//   - owner: address that will own (or owns) the position
//   - tickLower: lower tick bound of the position
//   - tickUpper: upper tick bound of the position
//   - liquidityDelta: amount of liquidity to add (positive) or remove (negative)
//
// The tick parameters represent prices as powers of 1.0001:
// - actual_price = 1.0001^tick
// - For example, tick = 100 means price = 1.0001^100
//
// Returns:
//   - ModifyPositionParams: a new instance of ModifyPositionParams
func newModifyPositionParams(
	owner address,
	tickLower int32,
	tickUpper int32,
	liquidityDelta *i256.Int,
) ModifyPositionParams {
	return ModifyPositionParams{
		owner:          owner,
		tickLower:      tickLower,
		tickUpper:      tickUpper,
		liquidityDelta: liquidityDelta,
	}
}

// SwapCache holds data that remains constant throughout a swap.
type SwapCache struct {
	feeProtocol                       uint8      // protocol fee for the input token
	liquidityStart                    *u256.Uint // liquidity at the beginning of the swap
	blockTimestamp                    int64      // current block timestamp
	tickCumulative                    int64      // current tick accumulator value
	secondsPerLiquidityCumulativeX128 *u256.Uint // current seconds per liquidity accumulator
	computedLatestObservation         bool       // whether we've computed the above accumulators
}

func newSwapCache(
	feeProtocol uint8,
	liquidityStart *u256.Uint,
) *SwapCache {
	return &SwapCache{
		feeProtocol:                       feeProtocol,
		liquidityStart:                    liquidityStart,
		blockTimestamp:                    time.Now().Unix(),
		tickCumulative:                    0,
		secondsPerLiquidityCumulativeX128: u256.Zero(),
		computedLatestObservation:         false,
	}
}

// SwapState tracks the changing values during a swap.
// This type helps manage the state transitions that occur as the swap progresses
// across different price ranges.
type SwapState struct {
	amountSpecifiedRemaining *i256.Int  // amount remaining to be swapped in/out of the input/output token
	amountCalculated         *i256.Int  // amount already swapped out/in of the output/input token
	sqrtPriceX96             *u256.Uint // current sqrt(price)
	tick                     int32      // tick associated with the current sqrt(price)
	feeGrowthGlobalX128      *u256.Uint // global fee growth of the input token
	protocolFee              *u256.Uint // amount of input token paid as protocol fee
	liquidity                *u256.Uint // current liquidity in range
}

func newSwapState(
	amountSpecifiedRemaining *i256.Int,
	feeGrowthGlobalX128 *u256.Uint,
	liquidity *u256.Uint,
	slot0 pl.Slot0,
) SwapState {
	return SwapState{
		amountSpecifiedRemaining: amountSpecifiedRemaining,
		amountCalculated:         i256.Zero(),
		sqrtPriceX96:             slot0.SqrtPriceX96(),
		tick:                     slot0.Tick(),
		feeGrowthGlobalX128:      feeGrowthGlobalX128,
		protocolFee:              u256.Zero(),
		liquidity:                liquidity,
	}
}

func (s *SwapState) setSqrtPriceX96(sqrtPriceX96 *u256.Uint) {
	s.sqrtPriceX96 = sqrtPriceX96.Clone()
}

func (s *SwapState) setTick(tick int32) {
	s.tick = tick
}

func (s *SwapState) setFeeGrowthGlobalX128(feeGrowthGlobalX128 *u256.Uint) {
	s.feeGrowthGlobalX128 = feeGrowthGlobalX128
}

func (s *SwapState) setProtocolFee(fee *u256.Uint) {
	s.protocolFee = fee
}

// StepComputations holds intermediate values used during a single step of a swap.
// Each step represents movement from the current tick to the next initialized tick
// or the target price, whichever comes first.
type StepComputations struct {
	sqrtPriceStartX96 *u256.Uint // price at the beginning of the step
	tickNext          int32      // next tick to swap to from the current tick in the swap direction
	initialized       bool       // whether tickNext is initialized
	sqrtPriceNextX96  *u256.Uint // sqrt(price) for the next tick (token1/token0) Q96
	amountIn          *u256.Uint // how much being swapped in this step
	amountOut         *u256.Uint // how much is being swapped out in this step
	feeAmount         *u256.Uint // how much fee is being paid in this step
}

// init initializes the computation for a single swap step
func (step *StepComputations) initSwapStep(state SwapState, p *pl.Pool, zeroForOne bool) {
	step.sqrtPriceStartX96 = state.sqrtPriceX96
	step.tickNext, step.initialized = tickBitmapNextInitializedTickWithInOneWord(
		p,
		state.tick,
		p.TickSpacing(),
		zeroForOne,
	)

	// prevent overshoot the min/max tick
	step.clampTickNext()

	// get the price for the next tick
	step.sqrtPriceNextX96 = common.TickMathGetSqrtRatioAtTick(step.tickNext)
}

// clampTickNext ensures that `tickNext` stays within the min, max tick boundaries
// as the tick bitmap is not aware of these bounds
func (step *StepComputations) clampTickNext() {
	if step.tickNext < MIN_TICK {
		step.tickNext = MIN_TICK
	} else if step.tickNext > MAX_TICK {
		step.tickNext = MAX_TICK
	}
}

func newPool(poolInfo *poolCreateConfig) *pl.Pool {
	maxLiquidityPerTick := calculateMaxLiquidityPerTick(poolInfo.tickSpacing)
	tick := common.TickMathGetTickAtSqrtRatio(poolInfo.SqrtPriceX96())

	return pl.NewPool(
		poolInfo.Token0Path(),
		poolInfo.Token1Path(),
		poolInfo.Fee(),
		poolInfo.SqrtPriceX96(),
		poolInfo.TickSpacing(),
		tick,
		poolInfo.slot0FeeProtocol,
		maxLiquidityPerTick,
	)
}

package v1

import (
	"math"
	"strconv"
	"strings"

	i256 "gno.land/p/gnoswap/int256"
	u256 "gno.land/p/gnoswap/uint256"
	"gno.land/p/nt/ufmt"
	pl "gno.land/r/gnoswap/pool"
)

const (
	MAX_UINT64  string = "18446744073709551615"
	MAX_INT64   string = "9223372036854775807"
	MAX_INT128  string = "170141183460469231731687303715884105727"
	MAX_UINT128 string = "340282366920938463463374607431768211455"
	MAX_INT256  string = "57896044618658097711785492504343953926634992332820282019728792003956564819967"

	INT64_MIN int64 = -9223372036854775808
	INT64_MAX int64 = 9223372036854775807

	Q96_RESOLUTION  uint = 96
	Q128_RESOLUTION uint = 128

	Q64  string = "18446744073709551616"                    // 2 ** 64
	Q96  string = "79228162514264337593543950336"           // 2 ** 96
	Q128 string = "340282366920938463463374607431768211456" // 2 ** 128
)

var (
	maxInt128FromDecimal  = i256.MustFromDecimal(MAX_INT128)
	maxUint128FromDecimal = u256.MustFromDecimal(MAX_UINT128)
	q128FromDecimal       = u256.MustFromDecimal(Q128)
)

var uint128Mask = func() *u256.Uint {
	m := u256.Zero().Lsh(u256.One(), Q128_RESOLUTION)
	return m.Sub(m, u256.One())
}()

// safeConvertToUint64 safely converts a *u256.Uint value to a uint64, ensuring no overflow.
// This function attempts to convert the given *u256.Uint value to a uint64.
// If the value exceeds the maximum allowable range for uint64 (2^64 - 1), it panics.
func safeConvertToUint64(value *u256.Uint) uint64 {
	if value == nil {
		panic(newErrorWithDetail(errInvalidInput, "value is nil"))
	}
	res, overflow := value.Uint64WithOverflow()
	if overflow {
		panic(ufmt.Sprintf(
			"%v: amount(%s) overflows uint64 range (max %s)",
			errOutOfRange,
			value.ToString(),
			MAX_UINT64,
		))
	}
	return res
}

// safeConvertToInt64 safely converts a *u256.Uint value to an int64, ensuring no overflow.
// This function attempts to convert the given *u256.Uint value to an int64.
// If the value exceeds the maximum allowable range for int64 (2^63 - 1), it panics.
func safeConvertToInt64(value *u256.Uint) int64 {
	if value == nil {
		panic(newErrorWithDetail(errInvalidInput, "value is nil"))
	}
	res, overflow := value.Uint64WithOverflow()
	if overflow || res > uint64(INT64_MAX) {
		panic(ufmt.Sprintf(
			"%v: amount(%s) overflows int64 range (max %s)",
			errOutOfRange,
			value.ToString(),
			MAX_INT64,
		))
	}
	return int64(res)
}

// safeConvertToInt128 safely converts a *u256.Uint value to an *i256.Int, ensuring it does not exceed the int128 range.
// This function converts an unsigned 256-bit integer to a signed 256-bit integer.
// If the value exceeds the maximum allowable int128 range (2^127 - 1), it panics.
func safeConvertToInt128(value *u256.Uint) *i256.Int {
	liquidityDelta := i256.FromUint256(value)
	if liquidityDelta.Gt(maxInt128FromDecimal) {
		panic(ufmt.Sprintf(
			"%v: amount(%s) overflows int128 range",
			errOverflow, value.ToString()))
	}
	return liquidityDelta
}

// toUint128 ensures a *u256.Uint value fits within the uint128 range.
//
// This function validates that the given `value` is properly initialized and checks whether
// it exceeds the maximum value of uint128. If the value exceeds the uint128 range,
// it applies a masking operation to truncate the value to fit within the uint128 limit.
//
// Parameters:
//   - value: *u256.Uint, the value to be checked and possibly truncated.
//
// Returns:
//   - *u256.Uint: A value guaranteed to fit within the uint128 range.
//
// Notes:
//   - The function first checks if the value is not nil to avoid potential runtime errors.
//   - The mask ensures that only the lower 128 bits of the value are retained.
//   - If the input value is already within the uint128 range, it is returned unchanged.
//   - If masking is required, a new instance is returned without modifying the input.
//   - MAX_UINT128 is a constant representing `2^128 - 1`.
func toUint128(value *u256.Uint) *u256.Uint {
	if value == nil {
		panic(newErrorWithDetail(errInvalidInput, "value is nil"))
	}

	if value.Gt(maxUint128FromDecimal) {
		return u256.Zero().And(value, uint128Mask)
	}
	return value
}

// u256Min returns the smaller of two *u256.Uint values.
//
// This function compares two unsigned 256-bit integers and returns the smaller of the two.
// If `num1` is less than `num2`, it returns `num1`; otherwise, it returns `num2`.
//
// Parameters:
// - num1 (*u256.Uint): The first unsigned 256-bit integer.
// - num2 (*u256.Uint): The second unsigned 256-bit integer.
//
// Returns:
// - *u256.Uint: The smaller of `num1` and `num2`.
//
// Notes:
//   - This function uses the `Lt` (less than) method of `*u256.Uint` to perform the comparison.
//   - The function assumes both input values are non-nil. If nil inputs are possible in the usage context,
//     additional validation may be needed.
//
// Example:
// smaller := u256Min(u256.MustFromDecimal("10"), u256.MustFromDecimal("20")) // Returns 10
// smaller := u256Min(u256.MustFromDecimal("30"), u256.MustFromDecimal("20")) // Returns 20
func u256Min(num1, num2 *u256.Uint) *u256.Uint {
	if num1.Lt(num2) {
		return num1
	}
	return num2
}

// checkOverFlowInt128 checks if the value overflows the int128 range.
func checkOverFlowInt128(value *i256.Int) {
	if value.Gt(maxInt128FromDecimal) {
		panic(ufmt.Sprintf(
			"%v: amount(%s) overflows int128 range",
			errOverflow, value.ToString()))
	}
}

// checkTickSpacing checks if the tick is divisible by the tickSpacing.
func checkTickSpacing(tick, tickSpacing int32) {
	if tick%tickSpacing != 0 {
		panic(newErrorWithDetail(
			errInvalidTickAndTickSpacing,
			ufmt.Sprintf("tick(%d) MOD tickSpacing(%d) != 0(%d)", tick, tickSpacing, tick%tickSpacing),
		))
	}
}

// formatUint converts various unsigned integer types to string representation.
func formatUint(v any) string {
	switch v := v.(type) {
	case uint8:
		return strconv.FormatUint(uint64(v), 10)
	case uint16:
		return strconv.FormatUint(uint64(v), 10)
	case uint32:
		return strconv.FormatUint(uint64(v), 10)
	case uint64:
		return strconv.FormatUint(v, 10)
	default:
		panic(ufmt.Sprintf("invalid type: %T", v))
	}
}

// formatInt converts various signed integer types to string representation.
func formatInt(v any) string {
	switch v := v.(type) {
	case int32:
		return strconv.FormatInt(int64(v), 10)
	case int64:
		return strconv.FormatInt(v, 10)
	case int:
		return strconv.Itoa(v)
	default:
		panic(ufmt.Sprintf("invalid type: %T", v))
	}
}

// formatBool converts a boolean value to string representation.
func formatBool(v bool) string {
	return strconv.FormatBool(v)
}

// ticksToString converts tick indices within a range to their string representation,
// including detailed tick information from the pool's tick storage.
func ticksToString(pool *pl.Pool, startTick, endTick int32) string {
	minTick, maxTick := startTick, endTick

	if minTick > maxTick {
		minTick, maxTick = maxTick, minTick
	}

	tickInfoStrings := make([]string, 0)

	pool.IterateTicks(minTick, maxTick, func(tick int32, tickInfo pl.TickInfo) bool {
		tickEventInfo := NewTickEventInfo(tick, tickInfo)
		tickInfoStrings = append(tickInfoStrings, tickEventInfo.ToString())

		return false
	})

	if len(tickInfoStrings) == 0 {
		return "[]"
	}

	return "[" + strings.Join(tickInfoStrings, ",") + "]"
}

// safeAddInt64 performs safe addition of int64 values, panicking on overflow or underflow
func safeAddInt64(a, b int64) int64 {
	if a > 0 && b > math.MaxInt64-a {
		panic("int64 addition overflow")
	}
	if a < 0 && b < math.MinInt64-a {
		panic("int64 addition underflow")
	}
	return a + b
}

// safeSubInt64 performs safe subtraction of int64 values, panicking on overflow or underflow
func safeSubInt64(a, b int64) int64 {
	if b > 0 && a < math.MinInt64+b {
		panic("int64 subtraction underflow")
	}
	if b < 0 && a > math.MaxInt64+b {
		panic("int64 subtraction overflow")
	}
	return a - b
}

package v1

import (
	"time"

	u256 "gno.land/p/gnoswap/uint256"
	"gno.land/p/nt/ufmt"

	"gno.land/r/gnoswap/access"
	"gno.land/r/gnoswap/common"
)

// assertIsNotExpired panics if the deadline is expired.
func assertIsNotExpired(deadline int64) {
	now := time.Now().Unix()

	if now > deadline {
		panic(makeErrorWithDetails(
			errExpired,
			ufmt.Sprintf("transaction too old, now(%d) > deadline(%d)", now, deadline),
		))
	}
}

// assertValidNumberString panics if the input string does not represent a valid integer.
func assertValidNumberString(input string) {
	if len(input) == 0 {
		panic(newErrorWithDetail(errInvalidInput, "input is empty"))
	}

	bytes := []byte(input)
	for i, b := range bytes {
		if i == 0 && b == '-' {
			continue // Allow if the first character is a negative sign (-)
		}
		if b < '0' || b > '9' {
			panic(newErrorWithDetail(
				errInvalidInput,
				ufmt.Sprintf("input string : %s", input)))
		}
	}
}

// assertValidLiquidityAmount panics if the liquidity amount is zero.
func assertValidLiquidityAmount(liquidity string) {
	if u256.MustFromDecimal(liquidity).IsZero() {
		panic(newErrorWithDetail(
			errZeroLiquidity,
			ufmt.Sprintf("liquidity amount must be greater than 0, got %s", liquidity),
		))
	}
}

// assertExistsPosition panics if the position does not exist.
func assertExistsPosition(p *positionV1, positionId uint64) {
	if !p.exists(positionId) {
		panic(newErrorWithDetail(
			errPositionDoesNotExist,
			ufmt.Sprintf("position with position ID(%d) doesn't exist", positionId),
		))
	}
}

// assertIsOwnerForToken panics if caller is not the owner of the position.
func assertIsOwnerForToken(p *positionV1, positionId uint64, caller address) {
	assertExistsPosition(p, positionId)

	if !p.isOwner(positionId, caller) {
		panic(newErrorWithDetail(
			errNoPermission,
			ufmt.Sprintf("caller(%s) is not owner of positionId(%d)", caller, positionId),
		))
	}
}

// assertIsOwnerOrOperatorForToken panics if caller is not the owner or operator of the position.
func assertIsOwnerOrOperatorForToken(p *positionV1, positionId uint64, caller address) {
	assertExistsPosition(p, positionId)

	if !p.isOwnerOrOperator(positionId, caller) {
		panic(newErrorWithDetail(
			errNoPermission,
			ufmt.Sprintf("caller(%s) is not owner or approved operator of positionId(%d)", caller, positionId),
		))
	}
}

// assertEqualsAddress panics if addresses are invalid or not equal.
func assertEqualsAddress(prevAddr, otherAddr address) {
	access.AssertIsValidAddress(prevAddr)
	access.AssertIsValidAddress(otherAddr)

	if prevAddr != otherAddr {
		panic(newErrorWithDetail(
			errInvalidAddress,
			ufmt.Sprintf("(%s, %s)", prevAddr, otherAddr),
		))
	}
}

// assertSlippageIsNotExceeded panics if slippage tolerance is exceeded.
func assertSlippageIsNotExceeded(amount0, amount1, amount0Min, amount1Min *u256.Uint) {
	if !(amount0.Gte(amount0Min) && amount1.Gte(amount1Min)) {
		panic(newErrorWithDetail(
			errSlippage,
			ufmt.Sprintf("amount0(%s) >= amount0Min(%s) && amount1(%s) >= amount1Min(%s)",
				amount0.ToString(), amount0Min.ToString(), amount1.ToString(), amount1Min.ToString()),
		))
	}
}

// assertIsValidUserCoinSendWithTokenPair asserts that the user has sent the correct amount of native coin.
func assertIsValidUserCoinSendWithTokenPair(token0, token1 string, amount0, amount1 string) {
	if common.IsGNOTNativePath(token0) {
		common.AssertIsUserSendGNOTAmount(mustParseInt64(amount0))

		return
	}

	if common.IsGNOTNativePath(token1) {
		common.AssertIsUserSendGNOTAmount(mustParseInt64(amount1))

		return
	}

	common.AssertIsNotHandleNativeCoin()
}

// assertIsValidUserCoinSendWithWrappedTokenPair asserts that the user has sent the correct amount of native coin.
func assertIsValidUserCoinSendWithWrappedTokenPair(token0, token1 string, amount0, amount1 string) {
	isExistsUserSendCoins := common.ExistsUserSendCoins()

	if isExistsUserSendCoins {
		if common.IsGNOTPath(token0) {
			common.AssertIsUserSendGNOTAmount(mustParseInt64(amount0))

			return
		}

		if common.IsGNOTPath(token1) {
			common.AssertIsUserSendGNOTAmount(mustParseInt64(amount1))

			return
		}
	}

	common.AssertIsNotHandleNativeCoin()
}

// assertValidOperatorAddress validates operator address.
// Empty address is allowed (for operator removal), but non-empty addresses must be valid.
func assertValidOperatorAddress(operator address) {
	if operator != address("") && !operator.IsValid() {
		panic(newErrorWithDetail(errInvalidAddress, ufmt.Sprintf("operator(%s)", operator)))
	}
}

package v1

import (
	prabc "gno.land/p/gnoswap/rbac"
	u256 "gno.land/p/gnoswap/uint256"
	"gno.land/p/nt/ufmt"

	"gno.land/r/gnoswap/access"
	"gno.land/r/gnoswap/common"
	pl "gno.land/r/gnoswap/pool"
	"gno.land/r/gnoswap/position"
)

// decreaseLiquidity reduces position liquidity and collects fees.
// If unwrapResult is true, unwraps WUGNOT to GNOT.
// Returns positionId, liquidity, fee0, fee1, amount0, amount1, poolPath.
func (p *positionV1) decreaseLiquidity(params DecreaseLiquidityParams) (uint64, string, string, string, string, string, string, error) {
	caller := params.caller

	// before decrease liquidity, collect fee first
	_, fee0Str, fee1Str, _, _, _ := p.collectFee(params.positionId, params.unwrapResult, params.caller)

	position := p.mustGetPosition(params.positionId)
	if position.Liquidity().IsZero() {
		return params.positionId,
			"",
			fee0Str,
			fee1Str,
			"", "",
			position.PoolKey(),
			makeErrorWithDetails(
				errZeroLiquidity,
				ufmt.Sprintf("position(position ID:%d) has 0 liquidity", params.positionId),
			)
	}

	liquidityToRemove := u256.MustFromDecimal(params.liquidity)
	if liquidityToRemove.Gt(position.Liquidity()) {
		return params.positionId,
			liquidityToRemove.ToString(),
			fee0Str,
			fee1Str,
			"", "",
			position.PoolKey(),
			makeErrorWithDetails(
				errInvalidLiquidity,
				ufmt.Sprintf("Liquidity requested(%s) is greater than liquidity held(%s)", liquidityToRemove.ToString(), position.Liquidity().ToString()),
			)
	}

	pToken0, pToken1, pFee := splitOf(position.PoolKey())
	burn0, burn1 := pl.Burn(cross, pToken0, pToken1, pFee, position.TickLower(), position.TickUpper(), liquidityToRemove.ToString(), caller)

	burnedAmount0 := u256.MustFromDecimal(burn0)
	burnedAmount1 := u256.MustFromDecimal(burn1)

	positionKey := computePositionKey(position.TickLower(), position.TickUpper())
	feeGrowthInside0LastX128, feeGrowthInside1LastX128 := pl.GetPositionFeeGrowthInsideLastX128(position.PoolKey(), positionKey)

	calculatedToken0Balance, calculatedToken1Balance := calculatePositionBalances(position)

	// Add only burned amounts to tokensOwed since fees were already collected and processed in collectFee
	tokensOwed0 := u256.Zero().Add(position.TokensOwed0(), burnedAmount0)
	tokensOwed1 := u256.Zero().Add(position.TokensOwed1(), burnedAmount1)

	newLiquidity, underflow := u256.Zero().SubOverflow(position.Liquidity(), liquidityToRemove)
	if underflow {
		panic(newErrorWithDetail(errUnderflow, "positionLiquidity - liquidityToRemove underflow"))
	}

	newToken0Balance, underflow := u256.Zero().SubOverflow(calculatedToken0Balance, burnedAmount0)
	if underflow {
		panic(newErrorWithDetail(errUnderflow, "calculatedToken0Balance - burnedAmount0 underflow"))
	}

	newToken1Balance, underflow := u256.Zero().SubOverflow(calculatedToken1Balance, burnedAmount1)
	if underflow {
		panic(newErrorWithDetail(errUnderflow, "calculatedToken1Balance - burnedAmount1 underflow"))
	}

	position.SetTokensOwed0(tokensOwed0)
	position.SetTokensOwed1(tokensOwed1)
	position.SetFeeGrowthInside0LastX128(feeGrowthInside0LastX128)
	position.SetFeeGrowthInside1LastX128(feeGrowthInside1LastX128)
	position.SetLiquidity(newLiquidity)
	position.SetToken0Balance(newToken0Balance)
	position.SetToken1Balance(newToken1Balance)

	p.mustUpdatePosition(params.positionId, *position)

	collect0, collect1 := pl.Collect(
		cross,
		pToken0,
		pToken1,
		pFee,
		caller,
		position.TickLower(),
		position.TickUpper(),
		burn0,
		burn1,
	)

	collectAmount0 := u256.MustFromDecimal(collect0)
	collectAmount1 := u256.MustFromDecimal(collect1)

	// Slippage check on actually collected amounts to ensure user receives minimum expected tokens
	if isSlippageExceeded(collectAmount0, collectAmount1, params.amount0Min, params.amount1Min) {
		return params.positionId,
			liquidityToRemove.ToString(),
			fee0Str,
			fee1Str,
			collect0,
			collect1,
			position.PoolKey(),
			makeErrorWithDetails(
				errSlippage,
				ufmt.Sprintf("collectAmount0(%s) >= amount0Min(%s) && collectAmount1(%s) >= amount1Min(%s)",
					collectAmount0.ToString(),
					params.amount0Min.ToString(),
					collectAmount1.ToString(),
					params.amount1Min.ToString(),
				),
			)
	}

	poolAddr := access.MustGetAddress(prabc.ROLE_POOL.String())

	if isWrappedToken(pToken0) && params.unwrapResult {
		p.unwrapWithTransferFrom(poolAddr, caller, safeConvertToInt64(collectAmount0))
	} else {
		common.SafeGRC20TransferFrom(cross, pToken0, poolAddr, caller, safeConvertToInt64(collectAmount0))
	}

	if isWrappedToken(pToken1) && params.unwrapResult {
		p.unwrapWithTransferFrom(poolAddr, caller, safeConvertToInt64(collectAmount1))
	} else {
		common.SafeGRC20TransferFrom(cross, pToken1, poolAddr, caller, safeConvertToInt64(collectAmount1))
	}

	// Check for underflow when subtracting collected amounts from tokens owed
	newOwed0, underflow0 := u256.Zero().SubOverflow(position.TokensOwed0(), collectAmount0)
	if underflow0 {
		panic(ufmt.Sprintf("[POSITION] burn.gno | collect() | tokensOwed0(%s) < collectAmount0(%s)", position.TokensOwed0().ToString(), collectAmount0.ToString()))
	}
	position.SetTokensOwed0(newOwed0)

	newOwed1, underflow1 := u256.Zero().SubOverflow(position.TokensOwed1(), collectAmount1)
	if underflow1 {
		panic(ufmt.Sprintf("[POSITION] burn.gno | collect() | tokensOwed1(%s) < collectAmount1(%s)", position.TokensOwed1().ToString(), collectAmount1.ToString()))
	}
	position.SetTokensOwed1(newOwed1)

	if position.IsClear() {
		position.SetBurned(true) // just update flag (we don't want to burn actual position)
	}

	p.mustUpdatePosition(params.positionId, *position)

	return params.positionId, liquidityToRemove.ToString(), fee0Str, fee1Str, collect0, collect1, position.PoolKey(), nil
}

// calculateFees calculates the fees for the current position.
func (p *positionV1) calculateFees(position *position.Position, currentFeeGrowth FeeGrowthInside) (*u256.Uint, *u256.Uint) {
	fee0 := calculateTokensOwed(
		currentFeeGrowth.feeGrowthInside0LastX128,
		position.FeeGrowthInside0LastX128(),
		position.Liquidity(),
	)

	fee1 := calculateTokensOwed(
		currentFeeGrowth.feeGrowthInside1LastX128,
		position.FeeGrowthInside1LastX128(),
		position.Liquidity(),
	)

	tokensOwed0, overflow0 := u256.Zero().AddOverflow(u256.Zero().Set(position.TokensOwed0()), fee0)
	if overflow0 {
		panic(newErrorWithDetail(errOverflow, "tokensOwed0 + fee0 overflow"))
	}

	tokensOwed1, overflow1 := u256.Zero().AddOverflow(u256.Zero().Set(position.TokensOwed1()), fee1)
	if overflow1 {
		panic(newErrorWithDetail(errOverflow, "tokensOwed1 + fee1 overflow"))
	}

	return tokensOwed0, tokensOwed1
}

func calculateTokensOwed(
	feeGrowthInsideLastX128 *u256.Uint,
	positionFeeGrowthInsideLastX128 *u256.Uint,
	positionLiquidity *u256.Uint,
) *u256.Uint {
	diff, underflow := u256.Zero().SubOverflow(feeGrowthInsideLastX128, positionFeeGrowthInsideLastX128)
	if underflow {
		panic(newErrorWithDetail(errUnderflow, "feeGrowthInsideLastX128 - positionFeeGrowthInsideLastX128 underflow"))
	}
	return u256.MulDiv(diff, positionLiquidity, q128)
}

// package v1 manages liquidity positions as NFTs in GnoSwap pools.
//
// Each position is represented as a non-transferable GRC721 NFT with concentrated
// liquidity within a specific tick range. The package handles position lifecycle
// including minting, liquidity adjustments, fee collection, and repositioning.
package v1

package v1

import (
	"errors"

	"gno.land/p/nt/ufmt"
)

var (
	errNoPermission         = errors.New("[GNOSWAP-POSITION-001] caller has no permission")
	errSlippage             = errors.New("[GNOSWAP-POSITION-002] slippage failed")
	errWrapUnwrap           = errors.New("[GNOSWAP-POSITION-003] wrap, unwrap failed")
	errInvalidInput         = errors.New("[GNOSWAP-POSITION-004] invalid input data")
	errDataNotFound         = errors.New("[GNOSWAP-POSITION-005] requested data not found")
	errExpired              = errors.New("[GNOSWAP-POSITION-006] transaction expired")
	errWugnotMinimum        = errors.New("[GNOSWAP-POSITION-007] cannot wrap less than minimum amount")
	errNotClear             = errors.New("[GNOSWAP-POSITION-008] position is not clear")
	errZeroLiquidity        = errors.New("[GNOSWAP-POSITION-009] zero liquidity")
	errPositionExist        = errors.New("[GNOSWAP-POSITION-010] position with same positionId already exists")
	errInvalidAddress       = errors.New("[GNOSWAP-POSITION-011] invalid address")
	errPositionDoesNotExist = errors.New("[GNOSWAP-POSITION-012] position does not exist")
	errZeroUGNOT            = errors.New("[GNOSWAP-POSITION-013] no UGNOTs were sent")
	errInsufficientUGNOT    = errors.New("[GNOSWAP-POSITION-014] insufficient UGNOT provided")
	errInvalidTokenPath     = errors.New("[GNOSWAP-POSITION-015] invalid token address")
	errUnderflow            = errors.New("[GNOSWAP-POSITION-016] underflow")
	errOverflow             = errors.New("[GNOSWAP-POSITION-017] overflow")
	errInvalidLiquidity     = errors.New("[GNOSWAP-POSITION-018] invalid liquidity")
)

// newErrorWithDetail appends additional context or details to an existing error message.
func newErrorWithDetail(err error, detail string) string {
	return ufmt.Errorf("%s || %s", err.Error(), detail).Error()
}

// makeErrorWithDetails creates an error with additional context.
func makeErrorWithDetails(err error, details string) error {
	return ufmt.Errorf("%s || %s", err.Error(), details)
}

package v1

import (
	"strconv"

	u256 "gno.land/p/gnoswap/uint256"
	ufmt "gno.land/p/nt/ufmt"

	pl "gno.land/r/gnoswap/pool"
	"gno.land/r/gnoswap/position"
)

// MustGetPosition returns a position for a given position ID.
// panics if position doesn't exist
func (p *positionV1) mustGetPosition(positionId uint64) *position.Position {
	pos, exist := p.GetPosition(positionId)
	if !exist {
		panic(newErrorWithDetail(
			errPositionDoesNotExist,
			ufmt.Sprintf("position with position ID(%d) doesn't exist", positionId),
		))
	}

	return &pos
}

// GetPositionCount returns the total number of positions.
func (p *positionV1) GetPositionCount() int {
	return p.store.GetPositions().Size()
}

// GetPositionIDs returns a paginated list of position IDs.
func (p *positionV1) GetPositionIDs(offset, count int) []uint64 {
	positions := p.store.GetPositions()
	positionIDs := make([]uint64, 0)

	positions.IterateByOffset(offset, count, func(key string, _ any) bool {
		id, err := strconv.ParseUint(key, 10, 64)
		if err != nil {
			return false
		}

		positionIDs = append(positionIDs, id)

		return false
	})

	return positionIDs
}

// GetPosition returns a position for a given position ID.
// Returns false if position doesn't exist
func (p *positionV1) GetPosition(id uint64) (position.Position, bool) {
	return p.store.GetPosition(id)
}

// ExistPosition checks if a position exists for a given position ID
func (p *positionV1) ExistPosition(positionId uint64) bool {
	return p.store.HasPosition(positionId)
}

func (p *positionV1) IsBurned(positionId uint64) bool {
	return p.mustGetPosition(positionId).Burned()
}

func (p *positionV1) IsInRange(positionId uint64) bool {
	position := p.mustGetPosition(positionId)
	poolPath := position.PoolKey()
	poolCurrentTick := pl.GetSlot0Tick(poolPath)

	return position.TickLower() <= poolCurrentTick && poolCurrentTick < position.TickUpper()
}

func (p *positionV1) GetPositionOperator(positionId uint64) address {
	return p.mustGetPosition(positionId).Operator()
}

func (p *positionV1) GetPositionPoolKey(positionId uint64) string {
	return p.mustGetPosition(positionId).PoolKey()
}

func (p *positionV1) GetPositionTickLower(positionId uint64) int32 {
	return p.mustGetPosition(positionId).TickLower()
}

func (p *positionV1) GetPositionTickUpper(positionId uint64) int32 {
	return p.mustGetPosition(positionId).TickUpper()
}

func (p *positionV1) GetPositionLiquidity(positionId uint64) *u256.Uint {
	return p.mustGetPosition(positionId).Liquidity()
}

func (p *positionV1) GetPositionFeeGrowthInside0LastX128(positionId uint64) *u256.Uint {
	return p.mustGetPosition(positionId).FeeGrowthInside0LastX128()
}

func (p *positionV1) GetPositionFeeGrowthInside1LastX128(positionId uint64) *u256.Uint {
	return p.mustGetPosition(positionId).FeeGrowthInside1LastX128()
}

func (p *positionV1) GetPositionTokensOwed0(positionId uint64) *u256.Uint {
	return p.mustGetPosition(positionId).TokensOwed0()
}

func (p *positionV1) GetPositionTokensOwed1(positionId uint64) *u256.Uint {
	return p.mustGetPosition(positionId).TokensOwed1()
}

func (p *positionV1) GetPositionOwner(positionId uint64) address {
	owner, err := p.nftAccessor.OwnerOf(positionIdFrom(positionId))
	if err != nil {
		panic(newErrorWithDetail(
			errDataNotFound, err.Error()))
	}

	return owner
}

func (p *positionV1) GetUnclaimedFee(positionId uint64) (*u256.Uint, *u256.Uint) {
	// ref: https://blog.uniswap.org/uniswap-v3-math-primer-2#calculating-uncollected-fees
	position := p.mustGetPosition(positionId)

	liquidity := position.Liquidity()
	tickLower := position.TickLower()
	tickUpper := position.TickUpper()

	poolKey := position.PoolKey()

	currentTick := pl.GetSlot0Tick(poolKey)

	feeGrowthGlobal0X128, feeGrowthGlobal1X128 := pl.GetFeeGrowthGlobalX128(poolKey)
	tickUpperFeeGrowthOutside0X128, tickUpperFeeGrowthOutside1X128 := pl.GetTickFeeGrowthOutsideX128(poolKey, tickUpper)
	tickLowerFeeGrowthOutside0X128, tickLowerFeeGrowthOutside1X128 := pl.GetTickFeeGrowthOutsideX128(poolKey, tickLower)

	feeGrowthInside0LastX128 := position.FeeGrowthInside0LastX128()
	feeGrowthInside1LastX128 := position.FeeGrowthInside1LastX128()

	var tickLowerFeeGrowthBelow0, tickLowerFeeGrowthBelow1, tickUpperFeeGrowthAbove0, tickUpperFeeGrowthAbove1 *u256.Uint

	if currentTick >= tickUpper {
		tickUpperFeeGrowthAbove0 = subUint256(feeGrowthGlobal0X128, tickUpperFeeGrowthOutside0X128)
		tickUpperFeeGrowthAbove1 = subUint256(feeGrowthGlobal1X128, tickUpperFeeGrowthOutside1X128)
	} else {
		tickUpperFeeGrowthAbove0 = tickUpperFeeGrowthOutside0X128
		tickUpperFeeGrowthAbove1 = tickUpperFeeGrowthOutside1X128
	}

	if currentTick >= tickLower {
		tickLowerFeeGrowthBelow0 = tickLowerFeeGrowthOutside0X128
		tickLowerFeeGrowthBelow1 = tickLowerFeeGrowthOutside1X128
	} else {
		tickLowerFeeGrowthBelow0 = subUint256(feeGrowthGlobal0X128, tickLowerFeeGrowthOutside0X128)
		tickLowerFeeGrowthBelow1 = subUint256(feeGrowthGlobal1X128, tickLowerFeeGrowthOutside1X128)
	}

	feeGrowthInside0X128 := subUint256(feeGrowthGlobal0X128, tickLowerFeeGrowthBelow0)
	feeGrowthInside0X128 = subUint256(feeGrowthInside0X128, tickUpperFeeGrowthAbove0)

	feeGrowthInside1X128 := subUint256(feeGrowthGlobal1X128, tickLowerFeeGrowthBelow1)
	feeGrowthInside1X128 = subUint256(feeGrowthInside1X128, tickUpperFeeGrowthAbove1)

	diffGrowthInside0X128 := subUint256(feeGrowthInside0X128, feeGrowthInside0LastX128)
	unclaimedFee0X128, overflow := u256.Zero().MulOverflow(liquidity, diffGrowthInside0X128)
	if overflow {
		panic(errOverflow)
	}
	unclaimedFee0 := u256.Zero().Div(unclaimedFee0X128, q128)

	diffGrowthInside1X128 := subUint256(feeGrowthInside1X128, feeGrowthInside1LastX128)
	unclaimedFee1X128, overflow := u256.Zero().MulOverflow(liquidity, diffGrowthInside1X128)
	if overflow {
		panic(errOverflow)
	}

	return unclaimedFee0, u256.Zero().Div(unclaimedFee1X128, q128)
}

package v1

import (
	"gno.land/p/nt/avl"
	"gno.land/r/gnoswap/position"
)

func init() {
	registerPositionV1()
}

func registerPositionV1() {
	position.RegisterInitializer(cross, func(positionStore position.IPositionStore) position.IPosition {
		err := initStoreData(positionStore)
		if err != nil {
			panic(err)
		}

		return NewPositionV1(positionStore, newGNFTAccessor())
	})
}

func initStoreData(positionStore position.IPositionStore) error {
	if !positionStore.HasPositionNextIDStoreKey() {
		err := positionStore.SetPositionNextID(uint64(1))
		if err != nil {
			return err
		}
	}

	if !positionStore.HasPositionsStoreKey() {
		err := positionStore.SetPositions(avl.NewTree())
		if err != nil {
			return err
		}
	}

	return nil
}

