import (
	"chain"
	"chain/runtime"

	"gno.land/p/nt/ufmt"

	prbac "gno.land/p/gnoswap/rbac"
	u256 "gno.land/p/gnoswap/uint256"

	"gno.land/r/gnoswap/access"
	"gno.land/r/gnoswap/common"
	"gno.land/r/gnoswap/halt"

	pf "gno.land/r/gnoswap/protocol_fee"
	_ "gno.land/r/gnoswap/protocol_fee/v1"
)

// GetSwapFee returns the current swap fee rate in basis points.
func (r *routerV1) GetSwapFee() uint64 {
	return r.store.GetSwapFee()
}

// SetSwapFee sets the protocol swap fee rate.
//
// Fee is deducted from swap output and sent to protocol fee contract.
// Only callable by admin or governance.
//
// Parameters:
//   - fee: Fee rate in basis points (0-1000 = 0%-10%)
//
// Access:
//   - Requires: Admin or Governance role
//   - Halt check: Router and ProtocolFee must not be halted
//
// Events:
//   - SetSwapFee: Emits previous and new fee values
//
// Reverts if:
//   - Caller is not admin/governance
//   - Fee > 1000 bps (10%)
//   - Router or ProtocolFee is halted
func (r *routerV1) SetSwapFee(fee uint64) {
	halt.AssertIsNotHaltedRouter()
	halt.AssertIsNotHaltedProtocolFee()

	caller := runtime.PreviousRealm().Address()
	access.AssertIsAdminOrGovernance(caller)

	// max swap fee is 1000 (bps)
	if fee > 1000 {
		panic(ufmt.Errorf(
			"%s: fee must be in range 0 to 1000 (10%). got %d",
			errInvalidSwapFee.Error(), fee,
		))
	}

	prevSwapFee := r.store.GetSwapFee()
	if err := r.store.SetSwapFee(fee); err != nil {
		panic(err)
	}

	previousRealm := runtime.PreviousRealm()
	chain.Emit(
		"SetSwapFee",
		"prevAddr", previousRealm.Address().String(),
		"prevRealm", previousRealm.PkgPath(),
		"newFee", formatUint(fee),
		"prevFee", formatUint(prevSwapFee),
	)
}

// handleSwapFee deducts the protocol fee from the swap amount and transfers it to the protocol fee contract.
func (r *routerV1) handleSwapFee(
	outputToken string,
	amount int64,
) int64 {
	swapFee := r.store.GetSwapFee()
	if swapFee <= 0 {
		return amount
	}

	currentTokenPath := outputToken

	if common.IsGNOTNativePath(outputToken) {
		currentTokenPath = wugnotPath
	}

	feeAmountInt64 := calculateRouterFee(amount, swapFee)

	protocolFeeAddr := access.MustGetAddress(prbac.ROLE_PROTOCOL_FEE.String())
	common.SafeGRC20Transfer(cross, currentTokenPath, protocolFeeAddr, feeAmountInt64)

	pf.AddToProtocolFee(cross, currentTokenPath, feeAmountInt64)

	previousRealm := runtime.PreviousRealm()
	chain.Emit(
		"SwapRouteFee",
		"prevAddr", previousRealm.Address().String(),
		"prevRealm", previousRealm.PkgPath(),
		"tokenPath", currentTokenPath,
		"amount", formatInt64(feeAmountInt64),
	)

	return safeSubInt64(amount, feeAmountInt64)
}

func calculateRouterFee(amount int64, swapFee uint64) int64 {
	if swapFee <= 0 {
		return 0
	}

	feeAmount := u256.MulDiv(u256.NewUintFromInt64(amount), u256.NewUint(swapFee), u256.NewUint(10000))
	return safeConvertToInt64(feeAmount)
}

// calculate amount to fetch from pool including router fee
// poolAmount = userAmount / (1 - feeRate)
// = userAmount * 10000 / (10000 - swapFeeBPS)
func calculateExactOutWithRouterFee(amount int64, swapFee uint64) int64 {
	if amount == 0 {
		return amount
	}

	if swapFee > 0 {
		// Use MulDiv to prevent overflow and maintain precision
		poolAmount := u256.MulDiv(
			u256.NewUintFromInt64(amount),
			u256.NewUint(10000),
			u256.NewUint(10000-swapFee),
		)

		return safeConvertToInt64(poolAmount)
	}

	return amount
}

package v1

import (
	"chain/runtime"
	"strconv"

	u256 "gno.land/p/gnoswap/uint256"
	"gno.land/p/nt/ufmt"

	"gno.land/r/gnoland/wugnot"
	"gno.land/r/gnoswap/common"
)

var one = u256.One()

// ErrorMessages define all error message templates used throughout the router
const (
	// slippage validation
	errExactOutAmountExceeded = "received more than requested in requested=%d, actual=%d"

	// route validation
	errInvalidRouteLength = "route length(%d) must be 1~7"

	// quote validation
	errRoutesQuotesMismatch = "mismatch between routes(%d) and quotes(%d) length"
	errInvalidQuote         = "invalid quote(%s) at index(%d)"
	errInvalidQuoteValue    = "quote(%s) at index(%d) must be positive value"
	errQuoteExceedsMax      = "quote(%s) at index(%d) must be less than or equal to %d"
	errQuoteSumExceedsMax   = "quote sum exceeds 100 at index(%d)"
	errInvalidQuoteSum      = "quote sum(%d) must be 100"

	// balance and overflow validation
	errOverflowInBalance  = "overflow in balance calculation: beforeBalance(%d) + wrappedAmount(%d)"
	errTooMuchWugnotSpent = "too much wugnot spent (wrapped: %d, spend: %d)"

	// swap type validation
	errExactInTooFewReceived = "ExactIn: too few received (min:%d, got:%d)"
	errExactOutTooMuchSpent  = "ExactOut: too much spent (max:%d, used:%d)"

	// route parsing validation
	errEmptyRoutes = "routes cannot be empty"
)

// GnotSwapHandler encapsulates methods for handling GNOT token swaps
type GnotSwapHandler struct {
	BeforeBalance int64
	WrappedAmount int64
	NewBalance    int64
}

// newGnotSwapHandler creates a new handler for GNOT swaps.
func newGnotSwapHandler(beforeBalance, wrappedAmount int64) *GnotSwapHandler {
	return &GnotSwapHandler{
		BeforeBalance: beforeBalance,
		WrappedAmount: wrappedAmount,
	}
}

// UpdateNewBalance updates the current balance after swap operations.
func (h *GnotSwapHandler) UpdateNewBalance() {
	h.NewBalance = wugnot.BalanceOf(runtime.PreviousRealm().Address())
}

// HandleInputSwap manages unwrapping logic for GNOT input tokens.
//
// When user sends native GNOT for swap:
// 1. GNOT was wrapped to WUGNOT at start
// 2. Swap consumed some WUGNOT
// 3. Remaining WUGNOT must be unwrapped back to GNOT
//
// Returns:
//   - error: overflow/insufficient balance errors, or unwrap errors
func (h *GnotSwapHandler) HandleInputSwap() error {
	// Check for overflow when adding balances
	if h.BeforeBalance > 0 && h.WrappedAmount > 0 {
		if h.BeforeBalance > (1<<63-1)-h.WrappedAmount {
			return ufmt.Errorf(errOverflowInBalance,
				h.BeforeBalance, h.WrappedAmount)
		}
	}

	totalBefore := h.BeforeBalance + h.WrappedAmount
	spend := totalBefore - h.NewBalance

	if spend > h.WrappedAmount {
		return ufmt.Errorf(errTooMuchWugnotSpent,
			h.WrappedAmount, spend)
	}

	toUnwrap := h.WrappedAmount - spend

	caller := runtime.PreviousRealm().Address()
	return unwrapWithTransferFrom(caller, caller, toUnwrap)
}

// SwapValidator provides validation methods for swap operations
type SwapValidator struct{}

// exactOutAmount checks if output amount meets specified requirements.
// For exact-out swaps, the output must be exactly the specified amount with tolerance up to swapCount units for rounding.
func (v *SwapValidator) exactOutAmount(resultAmount, specifiedAmount int64, swapCount int64) error {
	diff := int64(0)

	if resultAmount >= specifiedAmount {
		diff = resultAmount - specifiedAmount
	} else {
		diff = specifiedAmount - resultAmount
	}

	if diff > swapCount {
		return ufmt.Errorf(errExactOutAmountExceeded, specifiedAmount, resultAmount)
	}

	return nil
}

// slippage ensures swap amounts meet slippage requirements.
func (v *SwapValidator) slippage(swapType SwapType, amountIn, amountOut, limit int64) error {
	switch swapType {
	case ExactIn:
		if amountOut < limit {
			return ufmt.Errorf(errExactInTooFewReceived, limit, amountOut)
		}
	case ExactOut:
		if amountIn > limit {
			return ufmt.Errorf(errExactOutTooMuchSpent, limit, amountIn)
		}
	default:
		return errInvalidSwapType
	}
	return nil
}

// swapType ensures the swap type string is valid.
func (v *SwapValidator) swapType(swapTypeStr string) (SwapType, error) {
	swapType, err := trySwapTypeFromStr(swapTypeStr)
	if err != nil {
		return Unknown, errInvalidSwapType
	}
	return swapType, nil
}

// amount ensures the amount is properly formatted and positive.
func (v *SwapValidator) amount(amount int64) (int64, error) {
	if amount <= 0 {
		return 0, ufmt.Errorf(ErrInvalidPositiveAmount, amount)
	}
	return amount, nil
}

// amountLimit ensures the amount limit is properly formatted and non-zero.
func (v *SwapValidator) amountLimit(amountLimit int64) (int64, error) {
	if amountLimit <= 0 {
		return 0, ufmt.Errorf(ErrInvalidZeroAmountLimit, amountLimit)
	}
	return amountLimit, nil
}

// RouteParser handles parsing and validation of routes and quotes
type RouteParser struct{}

// NewRouteParser creates a new route parser instance.
func NewRouteParser() *RouteParser {
	return &RouteParser{}
}

// ParseRoutes parses route and quote strings into slices and validates them.
func (p *RouteParser) ParseRoutes(routes, quotes string) ([]string, []string, error) {
	// Check for empty routes
	if routes == "" || quotes == "" {
		return nil, nil, ufmt.Errorf(errEmptyRoutes)
	}

	routesArr := splitSingleChar(routes, ',')
	quotesArr := splitSingleChar(quotes, ',')

	if err := p.ValidateRoutesAndQuotes(routesArr, quotesArr); err != nil {
		return nil, nil, err
	}

	return routesArr, quotesArr, nil
}

// ValidateRoutesAndQuotes ensures routes and quotes meet required criteria.
func (p *RouteParser) ValidateRoutesAndQuotes(routes, quotes []string) error {
	rr := len(routes)
	qq := len(quotes)

	if rr < 1 || rr > 7 {
		return ufmt.Errorf(errInvalidRouteLength, rr)
	}

	if rr != qq {
		return ufmt.Errorf(errRoutesQuotesMismatch, rr, qq)
	}

	return p.ValidateQuoteSum(quotes)
}

// ValidateQuoteSum ensures all quotes add up to 100%.
func (p *RouteParser) ValidateQuoteSum(quotes []string) error {
	const (
		maxQuote int8 = 100
		minQuote int8 = 0
	)

	var sum int8

	for i, quote := range quotes {
		qt, err := strconv.ParseInt(quote, 10, 8)
		if err != nil {
			return ufmt.Errorf(errInvalidQuote, quote, i)
		}
		intQuote := int8(qt)

		// Quote must be positive (> 0) as each route needs a non-zero allocation.
		// A quote of 0 would mean no swap through that route, which is invalid.
		if intQuote <= minQuote { // minQuote = 0, so this rejects quote = 0
			return ufmt.Errorf(errInvalidQuoteValue, quote, i)
		}

		if intQuote > maxQuote {
			return ufmt.Errorf(errQuoteExceedsMax, quote, i, maxQuote)
		}

		if sum > maxQuote-intQuote {
			return ufmt.Errorf(errQuoteSumExceedsMax, i)
		}

		sum += intQuote
	}

	if sum != maxQuote {
		return ufmt.Errorf(errInvalidQuoteSum, sum)
	}

	return nil
}

// finalizeSwap handles post-swap operations and validations.
func (r *routerV1) finalizeSwap(
	inputToken, outputToken string,
	resultAmountIn, resultAmountOut int64,
	swapType SwapType,
	tokenAmountLimit int64,
	userBeforeWugnotBalance, userWrappedWugnot int64,
	amountSpecified int64,
	swapCount int64,
	isSetSqrtPriceLimitX96 bool,
) (int64, int64) {
	validator := &SwapValidator{}

	// Handle swap fee
	resultAmountOutWithoutFee := r.handleSwapFee(outputToken, resultAmountOut)

	// Validate exact out amount if applicable
	// If sqrtPriceLimitX96 is set, slippage check is not needed
	if swapType == ExactOut && !isSetSqrtPriceLimitX96 {
		if err := validator.exactOutAmount(resultAmountOutWithoutFee, amountSpecified, swapCount); err != nil {
			panic(addDetailToError(errSlippage, err.Error()))
		}
	}

	// Handle GNOT token swaps
	handler := newGnotSwapHandler(userBeforeWugnotBalance, userWrappedWugnot)
	handler.UpdateNewBalance()

	// Handle input GNOT token swap
	if common.IsGNOTNativePath(inputToken) {
		if err := handler.HandleInputSwap(); err != nil {
			panic(err)
		}
	}

	if err := validator.slippage(swapType, resultAmountIn, resultAmountOutWithoutFee, tokenAmountLimit); err != nil {
		panic(addDetailToError(errSlippage, err.Error()))
	}

	return resultAmountIn, resultAmountOutWithoutFee
}

// validateRoutesAndQuotes is a convenience function that parses and validates routes in one call.
func validateRoutesAndQuotes(routes, quotes string) ([]string, []string, error) {
	return NewRouteParser().ParseRoutes(routes, quotes)
}

package v1

import (
	"chain/runtime"
	"strings"

	"gno.land/p/nt/ufmt"

	"gno.land/r/gnoswap/common"
)

// QuoteConstraints defines the valid range for swap quote percentages
const (
	MaxQuotePercentage     = 100
	MinQuotePercentage     = 0
	PERCENTAGE_DENOMINATOR = int64(100)
)

// ErrorMessages for DrySwapRoute operations
const (
	ErrOverflowResultAmountIn      = "overflow in resultAmountIn"
	ErrOverflowResultAmountOut     = "overflow in resultAmountOut"
	ErrUnknownSwapType             = "unknown swapType(%s)"
	ErrInvalidPositiveAmount       = "invalid amount(%s), must be positive"
	ErrInvalidZeroAmountLimit      = "invalid amountLimit(%s), should not be zero"
	ErrInvalidQuoteRange           = "quote(%d) must be %d~%d"
	ErrOverflowCalculateSwapAmount = "overflow in calculateSwapAmount"
)

// SwapProcessor handles the execution of swap operations
type SwapProcessor struct {
	router *routerV1
}

// ProcessSingleSwap handles a single-hop swap simulation.
//
// Parameters:
//   - route: Single pool path "TOKEN0:TOKEN1:FEE"
//   - amountSpecified: Input/output amount depending on swap type
//
// Returns:
//   - amountIn: Expected input amount
//   - amountOut: Expected output amount
//   - err: Error if swap simulation fails
func (p *SwapProcessor) ProcessSingleSwap(route string, amountSpecified int64) (amountIn, amountOut int64, err error) {
	input, output, fee := getDataForSinglePath(route)
	singleParams := SingleSwapParams{
		tokenIn:         input,
		tokenOut:        output,
		fee:             fee,
		amountSpecified: amountSpecified,
	}

	amountIn, amountOut = p.router.singleDrySwap(&singleParams)
	return amountIn, amountOut, nil
}

// ProcessMultiSwap handles a multi-hop swap simulation.
//
// Parameters:
//   - swapType: ExactIn or ExactOut
//   - route: Multi-hop route with POOL_SEPARATOR
//   - numHops: Number of hops in the route
//   - amountSpecified: Input/output amount depending on swap type
//
// Returns:
//   - amountIn: Expected input amount
//   - amountOut: Expected output amount
//   - err: Error if swap simulation fails
func (p *SwapProcessor) ProcessMultiSwap(
	swapType SwapType,
	route string,
	numHops int,
	amountSpecified int64,
) (int64, int64, error) {
	recipient := runtime.PreviousRealm().Address()
	pathIndex := getPathIndex(swapType, numHops)

	input, output, fee := getDataForMultiPath(route, pathIndex)
	swapParams := newSwapParams(input, output, fee, recipient, amountSpecified, false)

	switch swapType {
	case ExactIn:
		return p.router.multiDrySwap(*swapParams, numHops, route)
	case ExactOut:
		return p.router.multiDrySwapNegative(*swapParams, numHops, route)
	default:
		return 0, 0, ufmt.Errorf(ErrUnknownSwapType, swapType)
	}
}

// ValidateSwapResults checks if the swap results meet the required constraints.
//
// Parameters:
//   - swapType: ExactIn or ExactOut
//   - resultAmountIn, resultAmountOut: Swap simulation results
//   - amountSpecified: User's specified exact amount
//   - amountLimit: Slippage protection limit
//   - swapCount: Number of swap operations (for tolerance)
//
// Returns:
//   - amountIn: Input amount (same as resultAmountIn)
//   - amountOut: Output amount (same as resultAmountOut)
//   - success: true if slippage constraints are met, false otherwise
func (p *SwapProcessor) ValidateSwapResults(
	swapType SwapType,
	resultAmountIn, resultAmountOut int64,
	amountSpecified, amountLimit int64,
	swapCount int64,
) (amountIn, amountOut int64, success bool) {
	if resultAmountIn == 0 || resultAmountOut == 0 {
		return 0, 0, false
	}

	validator := &SwapValidator{}

	if swapType == ExactOut {
		if err := validator.exactOutAmount(resultAmountOut, safeAbsInt64(amountSpecified), swapCount); err != nil {
			return resultAmountIn, resultAmountOut, false
		}
	}

	if err := validator.slippage(swapType, resultAmountIn, resultAmountOut, amountLimit); err != nil {
		return resultAmountIn, resultAmountOut, false
	}

	return resultAmountIn, resultAmountOut, true
}

// AddSwapResults safely adds swap result amounts, checking for overflow.
//
// Parameters:
//   - resultAmountIn, resultAmountOut: Accumulated results from previous routes
//   - amountIn, amountOut: Results from current route
//
// Returns:
//   - newAmountIn: resultAmountIn + amountIn
//   - newAmountOut: resultAmountOut + amountOut
//   - err: Always nil (uses safe addition that panics on overflow)
func (p *SwapProcessor) AddSwapResults(
	resultAmountIn, resultAmountOut, amountIn, amountOut int64,
) (int64, int64, error) {
	newAmountIn := safeAddInt64(resultAmountIn, amountIn)
	newAmountOut := safeAddInt64(resultAmountOut, amountOut)

	return newAmountIn, newAmountOut, nil
}

// DrySwapRoute simulates a token swap route without executing the swap.
//
// Calculates expected amounts without modifying any state.
// Useful for price quotes, UI previews, and slippage estimation.
//
// Parameters:
//   - inputToken, outputToken: Token contract paths
//   - specifiedAmount: Input amount (ExactIn) or output amount (ExactOut)
//   - swapTypeStr: "EXACT_IN" or "EXACT_OUT"
//   - strRouteArr: Swap routes (comma-separated, max 7)
//   - quoteArr: Route split percentages (must sum to 100)
//   - tokenAmountLimit: Min output (ExactIn) or max input (ExactOut)
//
// Returns:
//   - amountIn: Expected input amount as string
//   - amountOut: Expected output amount as string
//   - success: true if swap would succeed, false if slippage/validation fails
//
// Note: Does not validate deadline or execute actual transfers.
func (r *routerV1) DrySwapRoute(
	inputToken, outputToken string,
	specifiedAmount string,
	swapTypeStr string,
	strRouteArr, quoteArr string,
	tokenAmountLimit string,
) (string, string, bool) {
	inputAmount, outputAmount, success := r.drySwapRoute(
		inputToken,
		outputToken,
		safeParseInt64(specifiedAmount),
		swapTypeStr,
		strRouteArr,
		quoteArr,
		safeParseInt64(tokenAmountLimit),
	)

	return formatInt64(inputAmount), formatInt64(outputAmount), success
}

// drySwapRoute is a function for applying cross realm.
func (r *routerV1) drySwapRoute(
	inputToken, outputToken string,
	specifiedAmount int64,
	swapTypeStr string,
	strRouteArr, quoteArr string,
	tokenAmountLimit int64,
) (int64, int64, bool) {
	common.MustRegistered(inputToken, outputToken)
	// initialize components
	validator := &SwapValidator{}
	processor := &SwapProcessor{router: r}

	// validate and parse inputs
	swapType, err := validator.swapType(swapTypeStr)
	if err != nil {
		panic(addDetailToError(errInvalidSwapType, err.Error()))
	}

	amountSpecified, err := validator.amount(specifiedAmount)
	if err != nil {
		panic(addDetailToError(errInvalidInput, err.Error()))
	}

	amountLimit, err := validator.amountLimit(tokenAmountLimit)
	if err != nil {
		panic(addDetailToError(errInvalidInput, err.Error()))
	}

	routes, quotes, err := NewRouteParser().ParseRoutes(strRouteArr, quoteArr)
	if err != nil {
		panic(addDetailToError(errInvalidRoutesAndQuotes, err.Error()))
	}

	swapFee := r.store.GetSwapFee()

	// Store original amount for validation (before router fee adjustment)
	originalAmountSpecified := amountSpecified

	// adjust amount sign for exact out swaps
	if swapType == ExactOut {
		amountSpecifiedWithRouterFee := calculateExactOutWithRouterFee(safeAbsInt64(amountSpecified), swapFee)
		amountSpecified = -amountSpecifiedWithRouterFee
	}

	// initialize accumulators for swap results
	resultAmountIn, resultAmountOut := int64(0), int64(0)
	remainRequestAmount := amountSpecified
	swapCount := int64(0)

	// Process each route
	for i, route := range routes {
		toSwapAmount := int64(0)

		// if it's the last route, use the remaining amount
		isLastRoute := i == len(routes)-1
		if !isLastRoute {
			// calculate the amount to swap for this route
			swapAmount, err := calculateSwapAmountByQuote(amountSpecified, quotes[i])
			if err != nil {
				return 0, 0, false
			}

			// update the remaining amount
			resultRemainRequestAmount := safeSubInt64(remainRequestAmount, swapAmount)

			remainRequestAmount = resultRemainRequestAmount
			toSwapAmount = swapAmount
		} else {
			toSwapAmount = remainRequestAmount
		}

		// determine the number of hops and validate
		numHops := strings.Count(route, POOL_SEPARATOR) + 1
		assertHopsInRange(numHops)

		// accumulate total swap count for validation
		swapCount += int64(numHops)

		// execute the appropriate swap type
		var amountIn, amountOut int64
		if numHops == 1 {
			amountIn, amountOut, err = processor.ProcessSingleSwap(route, toSwapAmount)
		} else {
			amountIn, amountOut, err = processor.ProcessMultiSwap(swapType, route, numHops, toSwapAmount)
		}

		if err != nil {
			panic(addDetailToError(errInvalidSwapType, err.Error()))
		}

		if amountIn == 0 || amountOut == 0 {
			return 0, 0, false
		}

		// update accumulated results
		resultAmountIn, resultAmountOut, err = processor.AddSwapResults(resultAmountIn, resultAmountOut, amountIn, amountOut)
		if err != nil {
			panic(addDetailToError(errInvalidInput, err.Error()))
		}
	}

	// simulate deduct router fee
	feeAmountInt64 := calculateRouterFee(resultAmountOut, swapFee)

	resultAmountOut = safeSubInt64(resultAmountOut, feeAmountInt64)

	return processor.ValidateSwapResults(swapType, resultAmountIn, resultAmountOut, originalAmountSpecified, amountLimit, swapCount)
}

// getPathIndex returns the path index based on swap type and number of hops.
func getPathIndex(swapType SwapType, numHops int) int {
	switch swapType {
	case ExactIn:
		// first data for exact input swaps
		return 0
	case ExactOut:
		// last data for exact output swaps
		return numHops - 1
	default:
		panic("should not happen")
	}
}

package v1

import (
	"chain/runtime"

	prbac "gno.land/p/gnoswap/rbac"
	u256 "gno.land/p/gnoswap/uint256"

	"gno.land/r/gnoswap/access"
	"gno.land/r/gnoswap/common"
	"gno.land/r/gnoswap/halt"
)

// SwapCallback implements the pool's SwapCallback interface.
// This is called by the pool after it has sent output tokens to the recipient.
// The router must transfer the required input tokens to the pool.
//
// This callback pattern enables:
// 1. Flash swaps (receive tokens before paying)
// 2. Just-in-time token transfers
// 3. Complex multi-hop swaps without intermediate transfers
//
// Parameters:
//   - token0Path, token1Path: Pool token paths
//   - amount0Delta, amount1Delta: Token deltas (positive = owe, negative = received)
//   - payer: Address that will pay for the swap
//
// Access:
//   - Only callable by Router v1 address (self-callback from pool)
//
// Returns:
//   - error: nil on success, error if transfer fails
//
// Delta convention (Uniswap V3):
//   - Positive delta: tokens the pool must receive (input token)
//   - Negative delta: tokens the pool has sent (output token)
func (r *routerV1) SwapCallback(
	token0Path, token1Path string,
	amount0Delta, amount1Delta int64,
	payer address,
) error {
	halt.AssertIsNotHaltedRouter()

	caller := runtime.PreviousRealm().Address()
	assertIsRouterV1(caller)

	var tokenToPay string
	var amountToPay int64

	// amount0Delta > 0 means pool wants token0
	// amount1Delta > 0 means pool wants token1
	if amount0Delta > 0 {
		amountToPay = amount0Delta
		tokenToPay = token0Path
	} else if amount1Delta > 0 {
		amountToPay = amount1Delta
		tokenToPay = token1Path
	} else {
		return nil
	}

	// Transfer tokens from router to pool
	// The router should already have the tokens from the user
	r.transferToPool(tokenToPay, u256.NewUintFromInt64(amountToPay), payer)

	return nil
}

// transferToPool transfers tokens from router to pool
func (r *routerV1) transferToPool(token string, amount *u256.Uint, payer address) {
	balance := common.BalanceOf(token, payer)

	if u256.NewUintFromInt64(balance).Lt(amount) {
		panic("insufficient balance in router for callback")
	}

	poolAddr := access.MustGetAddress(prbac.ROLE_POOL.String())
	routerAddr := access.MustGetAddress(prbac.ROLE_ROUTER.String())

	if payer == routerAddr {
		common.SafeGRC20Transfer(cross, token, poolAddr, amount.Int64())
	} else {
		common.SafeGRC20TransferFrom(cross, token, payer, poolAddr, amount.Int64())
	}
}

package v1

import (
	"chain/runtime"

	"gno.land/p/nt/ufmt"

	"gno.land/r/gnoswap/access"
	"gno.land/r/gnoswap/common"
	"gno.land/r/gnoswap/router"

	i256 "gno.land/p/gnoswap/int256"
	prbac "gno.land/p/gnoswap/rbac"
	u256 "gno.land/p/gnoswap/uint256"

	pl "gno.land/r/gnoswap/pool"
)

const (
	MIN_SQRT_RATIO string = "4295128739"                                        // same as TickMathGetSqrtRatioAtTick(MIN_TICK)
	MAX_SQRT_RATIO string = "1461446703485210103287273052203988822378723970342" // same as TickMathGetSqrtRatioAtTick(MAX_TICK)
)

// swapInner executes the core swap logic by interacting with the pool contract.
// Returns poolRecv (tokens received by pool) and poolOut (tokens sent by pool).
func (r *routerV1) swapInner(
	amountSpecified int64,
	recipient address,
	sqrtPriceLimitX96 *u256.Uint,
	data SwapCallbackData,
) (int64, int64) {
	token0Path, token1Path := data.tokenIn, data.tokenOut
	zeroForOne := data.tokenIn < data.tokenOut

	if !zeroForOne {
		token0Path, token1Path = token1Path, token0Path
	}

	sqrtPriceLimitX96 = calculateSqrtPriceLimitForSwap(zeroForOne, data.fee, sqrtPriceLimitX96)

	amount0Str, amount1Str := pl.Swap(
		cross,
		token0Path,
		token1Path,
		data.fee,
		recipient,
		zeroForOne,
		formatInt64(amountSpecified),
		sqrtPriceLimitX96.ToString(),
		data.payer,
		func(cur realm, amount0Delta, amount1Delta int64, _ *pl.CallbackMarker) error {
			// assert is pool to prevent unauthorized callback
			caller := runtime.PreviousRealm().Address()
			access.AssertIsPool(caller)

			return router.SwapCallback(token0Path, token1Path, amount0Delta, amount1Delta, data.payer)
		},
	)

	amount0 := i256.MustFromDecimal(amount0Str)
	amount1 := i256.MustFromDecimal(amount1Str)

	poolOut, poolRecv := i256MinMax(amount0, amount1)
	if poolRecv.IsOverflow() || poolOut.IsOverflow() {
		panic("overflow in swapInner")
	}

	return poolRecv.Int64(), poolOut.Int64()
}

// swapDryInner performs a dry-run of a swap operation without executing it.
func (r *routerV1) swapDryInner(
	amountSpecified int64,
	sqrtPriceLimitX96 *u256.Uint,
	data SwapCallbackData,
) (int64, int64) {
	zeroForOne := data.tokenIn < data.tokenOut
	sqrtPriceLimitX96 = calculateSqrtPriceLimitForSwap(zeroForOne, data.fee, sqrtPriceLimitX96)

	// check possible
	amount0Str, amount1Str, ok := pl.DrySwap(
		data.tokenIn,
		data.tokenOut,
		data.fee,
		zeroForOne,
		formatInt64(amountSpecified),
		sqrtPriceLimitX96.ToString(),
	)
	if !ok {
		return 0, 0
	}

	amount0 := i256.MustFromDecimal(amount0Str)
	amount1 := i256.MustFromDecimal(amount1Str)

	poolOut, poolRecv := i256MinMax(amount0, amount1)
	if poolRecv.IsOverflow() || poolOut.IsOverflow() {
		panic("overflow in swapDryInner")
	}

	return poolRecv.Int64(), poolOut.Int64()
}

// RealSwapExecutor implements SwapExecutor for actual swaps.
type RealSwapExecutor struct {
	router *routerV1
}

// execute performs the actual swap execution.
func (e *RealSwapExecutor) execute(p *SingleSwapParams) (int64, int64) {
	caller := runtime.PreviousRealm().Address()
	recipient := access.MustGetAddress(prbac.ROLE_ROUTER.String())

	return e.router.swapInner(
		p.amountSpecified,
		recipient,             // if single swap => user will receive
		p.SqrtPriceLimitX96(), // sqrtPriceLimitX96
		newSwapCallbackData(p, caller),
	)
}

// DrySwapExecutor implements SwapExecutor for dry swaps.
type DrySwapExecutor struct {
	router *routerV1
}

// execute performs the dry swap execution.
func (e *DrySwapExecutor) execute(p *SingleSwapParams) (int64, int64) {
	previousRealmAddr := runtime.PreviousRealm().Address()

	return e.router.swapDryInner(
		p.amountSpecified,
		zero,
		newSwapCallbackData(p, previousRealmAddr),
	)
}

// calculateSqrtPriceLimitForSwap calculates the price limit for a swap operation.
func calculateSqrtPriceLimitForSwap(zeroForOne bool, fee uint32, sqrtPriceLimitX96 *u256.Uint) *u256.Uint {
	if !sqrtPriceLimitX96.IsZero() {
		return sqrtPriceLimitX96
	}

	if zeroForOne {
		minTick := getMinTick(fee) + 1
		sqrtPriceLimitX96 = u256.Zero().Set(common.TickMathGetSqrtRatioAtTick(minTick))
		if sqrtPriceLimitX96.IsZero() {
			sqrtPriceLimitX96 = u256.MustFromDecimal(MIN_SQRT_RATIO)
		}
		return u256.Zero().Add(sqrtPriceLimitX96, one)
	}

	maxTick := getMaxTick(fee) - 1
	sqrtPriceLimitX96 = u256.Zero().Set(common.TickMathGetSqrtRatioAtTick(maxTick))
	if sqrtPriceLimitX96.IsZero() {
		sqrtPriceLimitX96 = u256.MustFromDecimal(MAX_SQRT_RATIO)
	}
	return u256.Zero().Sub(sqrtPriceLimitX96, one)
}

// getMinTick returns the minimum tick value for a given fee tier.
// The implementation follows Uniswap V3's tick spacing rules where
// lower fee tiers allow for finer price granularity.
func getMinTick(fee uint32) int32 {
	switch fee {
	case 100:
		return -887272
	case 500:
		return -887270
	case 3000:
		return -887220
	case 10000:
		return -887200
	default:
		panic(addDetailToError(
			errInvalidPoolFeeTier,
			ufmt.Sprintf("unknown fee(%d)", fee),
		))
	}
}

// getMaxTick returns the maximum tick value for a given fee tier.
// The max tick values are the exact negatives of min tick values.
func getMaxTick(fee uint32) int32 {
	switch fee {
	case 100:
		return 887272
	case 500:
		return 887270
	case 3000:
		return 887220
	case 10000:
		return 887200
	default:
		panic(addDetailToError(
			errInvalidPoolFeeTier,
			ufmt.Sprintf("unknown fee(%d)", fee),
		))
	}
}

package v1

import (
	"chain/runtime"

	prbac "gno.land/p/gnoswap/rbac"
	"gno.land/r/gnoswap/access"
)

// SwapDirection represents the direction of swap execution in multi-hop swaps.
// It determines whether swaps are processed in forward order (first to last pool)
// or backward order (last to first pool).
type SwapDirection int

const (
	_ SwapDirection = iota
	// Forward indicates a swap processing direction from the first pool to the last pool.
	// Used primarily for exactIn swaps where the input amount is known.
	Forward

	// Backward indicates a swap processing direction from the last pool to the first pool.
	// Used primarily for exactOut swaps where the output amount is known and input amounts
	// Need to be calculated in reverse order.
	Backward
)

// MultiSwapExecutor defines the interface for multi-hop swap operation execution.
type MultiSwapExecutor interface {
	// Run performs the swap operation and returns pool received and pool output amounts.
	Run(p SwapParams, data SwapCallbackData, recipient address) (int64, int64)
}

// DryMultiSwapExecutor implements MultiSwapExecutor for dry run simulations.
type DryMultiSwapExecutor struct {
	router *routerV1
}

// Run performs a dry swap operation without changing state.
func (e *DryMultiSwapExecutor) Run(p SwapParams, data SwapCallbackData, _ address) (int64, int64) {
	return e.router.swapDryInner(p.amountSpecified, zero, data)
}

// RealMultiSwapExecutor implements MultiSwapExecutor for actual swap operations.
type RealMultiSwapExecutor struct {
	router *routerV1
}

// Run performs a real swap operation with state changes.
func (e *RealMultiSwapExecutor) Run(p SwapParams, data SwapCallbackData, recipient address) (int64, int64) {
	return e.router.swapInner(p.amountSpecified, recipient, zero, data)
}

// MultiSwapProcessor handles the execution flow for multi-hop swaps.
type MultiSwapProcessor struct {
	executor   MultiSwapExecutor
	direction  SwapDirection
	router     *routerV1
	isSimulate bool
}

var (
	_ MultiSwapExecutor = (*DryMultiSwapExecutor)(nil)
	_ MultiSwapExecutor = (*RealMultiSwapExecutor)(nil)
)

// NewMultiSwapProcessor creates a new MultiSwapProcessor with the specified configuration.
func NewMultiSwapProcessor(r *routerV1, isSimulate bool, direction SwapDirection) *MultiSwapProcessor {
	var executor MultiSwapExecutor
	if isSimulate {
		executor = &DryMultiSwapExecutor{router: r}
	} else {
		executor = &RealMultiSwapExecutor{router: r}
	}

	return &MultiSwapProcessor{
		executor:   executor,
		direction:  direction,
		router:     r,
		isSimulate: isSimulate,
	}
}

// processForwardSwap handles forward direction swaps (exactIn).
func (p *MultiSwapProcessor) processForwardSwap(sp SwapParams, numPools int, swapPath string) (int64, int64, error) {
	payer := runtime.PreviousRealm().Address() // Initial payer is the user
	routerAddr := access.MustGetAddress(prbac.ROLE_ROUTER.String())

	firstAmountIn := int64(0)
	currentPoolIndex := 0

	for {
		currentPoolIndex++

		// Execute the swap operation
		callbackData := newSwapCallbackData(sp, payer)
		amountIn, amountOut := p.executor.Run(sp, callbackData, sp.recipient)

		// Record the first hop's input amount
		if currentPoolIndex == 1 {
			firstAmountIn = amountIn
		}

		// Check if we've processed all hops
		if currentPoolIndex >= numPools {
			return firstAmountIn, amountOut, nil
		}

		// Update parameters for the next hop
		payer = routerAddr
		nextInput, nextOutput, nextFee := getDataForMultiPath(swapPath, currentPoolIndex)
		sp.tokenIn = nextInput
		sp.tokenOut = nextOutput
		sp.fee = nextFee
		sp.amountSpecified = amountOut
	}
}

// processBackwardSwap handles backward direction swaps (exactOut).
func (p *MultiSwapProcessor) processBackwardSwap(sp SwapParams, numPools int, swapPath string) (int64, int64, error) {
	if !p.isSimulate {
		return p.processBackwardRealSwap(sp, numPools, swapPath)
	}
	return p.processBackwardDrySwap(sp, numPools, swapPath)
}

// processBackwardDrySwap handles backward simulated swaps.
func (p *MultiSwapProcessor) processBackwardDrySwap(sp SwapParams, numPools int, swapPath string) (int64, int64, error) {
	firstAmountIn := int64(0)
	currentPoolIndex := numPools - 1
	routerAddr := access.MustGetAddress(prbac.ROLE_ROUTER.String())
	payer := routerAddr

	for {
		callbackData := newSwapCallbackData(sp, payer)
		amountIn, amountOut := p.executor.Run(sp, callbackData, sp.recipient)

		if currentPoolIndex == 0 {
			firstAmountIn = amountIn
		}

		currentPoolIndex--

		if currentPoolIndex == -1 {
			return firstAmountIn, amountOut, nil
		}

		// Update parameters for the next hop
		nextInput, nextOutput, nextFee := getDataForMultiPath(swapPath, currentPoolIndex)

		sp.amountSpecified = -amountIn
		sp.tokenIn = nextInput
		sp.tokenOut = nextOutput
		sp.fee = nextFee
	}
}

// processBackwardRealSwap handles backward real swaps.
func (p *MultiSwapProcessor) processBackwardRealSwap(sp SwapParams, numPools int, swapPath string) (int64, int64, error) {
	// First collect all swap information by simulating backward
	swapInfo := p.collectBackwardSwapInfo(sp, numPools, swapPath)

	// Then execute swaps in forward order
	return p.executeCollectedSwaps(swapInfo, sp.recipient, sp.withUnwrap)
}

// collectBackwardSwapInfo simulates swaps backward to collect parameters.
func (p *MultiSwapProcessor) collectBackwardSwapInfo(sp SwapParams, numPools int, swapPath string) []SingleSwapParams {
	currentPoolIndex := numPools - 1
	swapInfo := make([]SingleSwapParams, 0, currentPoolIndex)

	for currentPoolIndex >= 0 {
		thisSwap := SingleSwapParams{
			tokenIn:         sp.tokenIn,
			tokenOut:        sp.tokenOut,
			fee:             sp.fee,
			amountSpecified: sp.amountSpecified,
		}

		// dry simulation to calculate input amount
		amountIn, _ := p.router.singleDrySwap(&thisSwap)
		swapInfo = append(swapInfo, thisSwap)

		if currentPoolIndex == 0 {
			break
		}
		currentPoolIndex--

		// Update parameters for the next simulation
		nextInput, nextOutput, nextFee := getDataForMultiPath(swapPath, currentPoolIndex)

		sp.tokenIn = nextInput
		sp.tokenOut = nextOutput
		sp.fee = nextFee
		sp.amountSpecified = -amountIn
	}

	return swapInfo
}

// executeCollectedSwaps performs the collected swaps in forward order.
func (p *MultiSwapProcessor) executeCollectedSwaps(swapInfo []SingleSwapParams, recipient address, withUnwrap bool) (int64, int64, error) {
	firstAmountIn := int64(0)
	currentPoolIndex := len(swapInfo) - 1
	payer := runtime.PreviousRealm().Address() // Initial payer is the user
	routerAddr := access.MustGetAddress(prbac.ROLE_ROUTER.String())

	for currentPoolIndex >= 0 {
		// Execute the swap
		callbackData := newSwapCallbackData(
			swapInfo[currentPoolIndex],
			payer,
		)

		amountIn, amountOut := p.router.swapInner(
			swapInfo[currentPoolIndex].amountSpecified,
			recipient,
			zero,
			callbackData,
		)

		// Record the first hop's input amount
		if currentPoolIndex == len(swapInfo)-1 {
			firstAmountIn = amountIn
		}

		if currentPoolIndex == 0 {
			return firstAmountIn, amountOut, nil
		}

		// Update parameters for the next swap
		swapInfo[currentPoolIndex-1].amountSpecified = amountOut
		payer = routerAddr
		currentPoolIndex--
	}

	return firstAmountIn, 0, nil
}

// multiSwap performs a multi-hop swap in forward direction.
func (r *routerV1) multiSwap(p SwapParams, numPools int, swapPath string) (int64, int64) {
	result, output, err := NewMultiSwapProcessor(r, false, Forward).
		processForwardSwap(p, numPools, swapPath)
	if err != nil {
		panic(err)
	}
	return result, output
}

// multiSwapNegative performs a multi-hop swap in backward direction.
func (r *routerV1) multiSwapNegative(p SwapParams, numPools int, swapPath string) (int64, int64) {
	result, output, err := NewMultiSwapProcessor(r, false, Backward).
		processBackwardSwap(p, numPools, swapPath)
	if err != nil {
		panic(err)
	}
	return result, output
}

// multiDrySwap simulates a multi-hop swap in forward direction.
func (r *routerV1) multiDrySwap(p SwapParams, numPool int, swapPath string) (int64, int64, error) {
	return NewMultiSwapProcessor(r, true, Forward).
		processForwardSwap(p, numPool, swapPath)
}

// multiDrySwapNegative simulates a multi-hop swap in backward direction.
func (r *routerV1) multiDrySwapNegative(p SwapParams, numPool int, swapPath string) (int64, int64, error) {
	return NewMultiSwapProcessor(r, true, Backward).
		processBackwardSwap(p, numPool, swapPath)
}

package v1

import (
	u256 "gno.land/p/gnoswap/uint256"
	"gno.land/r/gnoswap/common"
)

var zero = u256.Zero()

// SwapExecutor defines the interface for executing swaps.
type SwapExecutor interface {
	// execute performs the swap operation.
	execute(p *SingleSwapParams) (int64, int64)
}

// executeSwap is the common logic for both real and dry swaps.
func (r *routerV1) executeSwap(executor SwapExecutor, p *SingleSwapParams) (int64, int64) {
	if p.tokenIn == p.tokenOut {
		panic(errSameTokenSwap)
	}

	common.MustRegistered(p.tokenIn, p.tokenOut)

	return executor.execute(p)
}

var (
	_ SwapExecutor = (*RealSwapExecutor)(nil)
	_ SwapExecutor = (*DrySwapExecutor)(nil)
)

// singleSwap executes a swap within a single pool using the provided parameters.
// It processes a token swap within two assets using a specific fee tier and
// automatically sets the recipient to the caller's address.
func (r *routerV1) singleSwap(p *SingleSwapParams) (int64, int64) {
	return r.executeSwap(&RealSwapExecutor{router: r}, p)
}

// singleDrySwap simulates a single-token swap operation without executing it.
// It performs a dry run simulation and does not alter the state.
func (r *routerV1) singleDrySwap(p *SingleSwapParams) (int64, int64) {
	return r.executeSwap(&DrySwapExecutor{router: r}, p)
}

package v1

import (
	u256 "gno.land/p/gnoswap/uint256"

	"gno.land/p/nt/ufmt"
)

const (
	rawUnknown  = "UNKNOWN"
	rawExactIn  = "EXACT_IN"
	rawExactOut = "EXACT_OUT"
)

type SwapType string

const (
	Unknown SwapType = rawUnknown
	// ExactIn represents a swap type where the input amount is exact and the output amount may vary.
	// Used when a user wants to swap a specific amount of input tokens.
	ExactIn SwapType = rawExactIn

	// ExactOut represents a swap type where the output amount is exact and the input amount may vary.
	// Used when a user wants to swap a specific amount of output tokens.
	ExactOut SwapType = rawExactOut
)

// trySwapTypeFromStr attempts to convert a string into a SwapType.
// It validates and converts string representations of swap types into their corresponding enum values.
func trySwapTypeFromStr(swapType string) (SwapType, error) {
	switch swapType {
	case rawExactIn:
		return ExactIn, nil
	case rawExactOut:
		return ExactOut, nil
	default:
		return "", ufmt.Errorf("unknown swapType: expected ExactIn or ExactOut, got %s", swapType)
	}
}

// String returns the string representation of SwapType.
func (s SwapType) String() string {
	switch s {
	case ExactIn:
		return rawExactIn
	case ExactOut:
		return rawExactOut
	default:
		return ""
	}
}

// SingleSwapParams contains parameters for executing a single pool swap.
// It represents the simplest form of swap that occurs within a single liquidity pool.
type SingleSwapParams struct {
	tokenIn    string // token to spend
	tokenOut   string // token to receive
	fee        uint32 // fee of the pool used to swap
	withUnwrap bool   // whether to unwrap the token

	// Amount specified for the swap:
	//  - Positive: exact input amount (tokenIn)
	//  - Negative: exact output amount (tokenOut)
	amountSpecified int64

	sqrtPriceLimitX96 *u256.Uint // sqrtPriceLimitX96 for the swap, empty string or zero string means no limit
}

// TokenIn returns the input token address.
func (p SingleSwapParams) TokenIn() string { return p.tokenIn }

// TokenOut returns the output token address.
func (p SingleSwapParams) TokenOut() string { return p.tokenOut }

// Fee returns the pool fee tier.
func (p SingleSwapParams) Fee() uint32 { return p.fee }

// SqrtPriceLimitX96 returns the sqrtPriceLimitX96 for the swap.
// If sqrtPriceLimitX96 is empty string, it will return zero.
func (p SingleSwapParams) SqrtPriceLimitX96() *u256.Uint {
	if p.sqrtPriceLimitX96 == nil {
		return u256.Zero()
	}

	return p.sqrtPriceLimitX96
}

// SwapParams contains parameters for executing a multi-hop swap operation.
type SwapParams struct {
	SingleSwapParams
	recipient  address // address to receive the token
	withUnwrap bool    // whether to unwrap the token
}

// TokenIn returns the input token address.
func (p SwapParams) TokenIn() string { return p.tokenIn }

// TokenOut returns the output token address.
func (p SwapParams) TokenOut() string { return p.tokenOut }

// Fee returns the pool fee tier.
func (p SwapParams) Fee() uint32 { return p.fee }

// Recipient returns the recipient address.
func (p SwapParams) Recipient() address { return p.recipient }

// newSwapParams creates a new SwapParams instance with the provided parameters.
func newSwapParams(tokenIn, tokenOut string, fee uint32, recipient address, amountSpecified int64, withUnwrap bool) *SwapParams {
	return &SwapParams{
		SingleSwapParams: SingleSwapParams{
			tokenIn:         tokenIn,
			tokenOut:        tokenOut,
			fee:             fee,
			amountSpecified: amountSpecified,
		},
		withUnwrap: withUnwrap,
		recipient:  recipient,
	}
}

// SwapResult encapsulates the outcome of a swap operation.
type SwapResult struct {
	Routes          []string
	Quotes          []string
	AmountIn        int64
	AmountOut       int64
	AmountSpecified int64
	WithUnwrap      bool
}

// SwapParamsI defines the common interface for swap parameters.
type SwapParamsI interface {
	TokenIn() string
	TokenOut() string
	Fee() uint32
}

// SwapCallbackData contains the callback data required for swap execution.
// This type is used to pass necessary information during the swap callback process,
// ensuring proper token transfers and pool data updates.
type SwapCallbackData struct {
	tokenIn  string  // token to spend
	tokenOut string  // token to receive
	fee      uint32  // fee of the pool used to swap
	payer    address // address to spend the token
}

// newSwapCallbackData creates a new SwapCallbackData from a SwapParamsI.
func newSwapCallbackData(params SwapParamsI, payer address) SwapCallbackData {
	return SwapCallbackData{
		tokenIn:  params.TokenIn(),
		tokenOut: params.TokenOut(),
		fee:      params.Fee(),
		payer:    payer,
	}
}

// ExactInParams contains parameters for exact input swaps.
type ExactInParams struct {
	BaseSwapParams
	AmountIn     int64
	AmountOutMin int64
}

// NewExactInParams creates a new ExactInParams instance.
func NewExactInParams(
	baseParams BaseSwapParams,
	amountIn int64,
	amountOutMin int64,
) ExactInParams {
	return ExactInParams{
		BaseSwapParams: baseParams,
		AmountIn:       amountIn,
		AmountOutMin:   amountOutMin,
	}
}

// ExactOutParams contains parameters for exact output swaps.
type ExactOutParams struct {
	BaseSwapParams
	AmountOut   int64
	AmountInMax int64
}

// NewExactOutParams creates a new ExactOutParams instance.
func NewExactOutParams(
	baseParams BaseSwapParams,
	amountOut int64,
	amountInMax int64,
) ExactOutParams {
	return ExactOutParams{
		BaseSwapParams: baseParams,
		AmountOut:      amountOut,
		AmountInMax:    amountInMax,
	}
}

package v1

import (
	"bytes"
	"math"
	"strconv"
	"strings"

	"gno.land/p/nt/ufmt"
	"gno.land/r/gnoswap/common"
	"gno.land/r/gnoswap/pool"

	i256 "gno.land/p/gnoswap/int256"
	u256 "gno.land/p/gnoswap/uint256"
)

var (
	errRouterHalted = "router contract operations are currently disabled"
	errTxExpired    = "transaction too old, now(%d) > deadline(%d)"
)

// calculateSwapAmountByQuote calculates swap amount based on quote percentage.
func calculateSwapAmountByQuote(amountSpecified int64, quote string) (int64, error) {
	quoteInt, err := strconv.ParseInt(quote, 10, 64)
	if err != nil {
		return 0, ufmt.Errorf("invalid quote(%s)", quote)
	}

	if quoteInt < MinQuotePercentage || quoteInt > MaxQuotePercentage {
		return 0, ufmt.Errorf(ErrInvalidQuoteRange, quoteInt, MinQuotePercentage, MaxQuotePercentage)
	}

	toSwap := safeMulDivInt64(amountSpecified, quoteInt, PERCENTAGE_DENOMINATOR)
	if toSwap == 0 {
		return 0, errInvalidSwapAmount
	}

	return toSwap, nil
}

// assertHopsInRange ensures the number of hops is within the valid range of 1-3.
func assertHopsInRange(hops int) {
	switch hops {
	case 1, 2, 3:
		return
	default:
		panic(errHopsOutOfRange)
	}
}

// getDataForSinglePath extracts token addresses and fee from a single pool path.
//
// IMPORTANT: This function returns tokens in the order they appear in the route string,
// which represents the swap direction (tokenIn:tokenOut:fee), NOT the canonical pool ordering.
func getDataForSinglePath(poolPath string) (token0, token1 string, fee uint32) {
	token0, token1, fee, err := getDataForSinglePathWithError(poolPath)
	if err != nil {
		panic(err)
	}

	return token0, token1, fee
}

// getDataForSinglePathWithError extracts token addresses and fee from a single pool path with error handling.
func getDataForSinglePathWithError(poolPath string) (string, string, uint32, error) {
	poolPathSplit := strings.Split(poolPath, ":")
	if len(poolPathSplit) != 3 {
		return "", "", 0, makeErrorWithDetails(
			errInvalidPoolPath,
			ufmt.Sprintf("len(poolPathSplit) != 3, poolPath: %s", poolPath),
		)
	}

	poolPathSplit[0] = strings.TrimSpace(poolPathSplit[0])
	poolPathSplit[1] = strings.TrimSpace(poolPathSplit[1])

	if poolPathSplit[0] == "" || poolPathSplit[1] == "" {
		return "", "", 0, makeErrorWithDetails(
			errInvalidPoolPath,
			ufmt.Sprintf("token addresses cannot be empty: %s", poolPath),
		)
	}

	f, err := strconv.Atoi(poolPathSplit[2])
	if err != nil {
		return "", "", 0, makeErrorWithDetails(
			errInvalidPoolPath,
			ufmt.Sprintf("invalid fee: %s", poolPathSplit[2]),
		)
	}

	return poolPathSplit[0], poolPathSplit[1], uint32(f), nil
}

// getDataForMultiPath extracts token addresses and fee from a multi-hop path at specified index.
func getDataForMultiPath(possiblePath string, poolIdx int) (token0, token1 string, fee uint32) {
	pools := strings.Split(possiblePath, POOL_SEPARATOR)

	switch poolIdx {
	case 0:
		return getDataForSinglePath(pools[0])
	case 1:
		return getDataForSinglePath(pools[1])
	case 2:
		return getDataForSinglePath(pools[2])
	default:
		return "", "", uint32(0)
	}
}

// i256MinMax returns the absolute values of x and y in min-max order.
func i256MinMax(x, y *i256.Int) (min, max *u256.Uint) {
	if x.Lt(y) || x.Eq(y) {
		return x.Abs(), y.Abs()
	}
	return y.Abs(), x.Abs()
}

// validateRoutePaths validates multiple route paths to ensure they all start with inputToken and end with outputToken.
// This function processes comma-separated route paths and validates each path individually.
//
// Validates:
// - Each route path starts with the specified inputToken
// - Each route path ends with the specified outputToken
// - Route path format consistency (prevents swap-direction vs alphabetical pool ordering confusion)
//
// Parameters:
// - routePathArrString: comma-separated route paths (e.g., "gno.land/r/demo/wugnot:gno.land/r/demo/usdc:500,gno.land/r/demo/wugnot:gno.land/r/demo/gns:3000*POOL*gno.land/r/demo/gns:gno.land/r/demo/usdc:500")
// - inputToken: expected first token in all route paths
// - outputToken: expected last token in all route paths
//
// Examples:
// - Single route: "tokenA:tokenB:500" with inputToken="tokenA", outputToken="tokenB"
// - Multi-route: "tokenA:tokenB:500,tokenA:tokenC:3000*POOL*tokenC:tokenB:500" with inputToken="tokenA", outputToken="tokenB"
//
// Returns error if any route path validation fails.
func validateRoutePaths(routePathArrString, inputToken, outputToken string) error {
	routePaths := strings.Split(routePathArrString, ",")

	for _, routePath := range routePaths {
		if err := validateRoutePath(routePath, inputToken, outputToken); err != nil {
			return err
		}
	}

	return nil
}

// validateRoutePath validates a single route path to ensure it starts with inputToken and ends with outputToken.
// This function handles both single-hop and multi-hop route paths.
//
// Validates:
// - Route path starts with the specified inputToken
// - Route path ends with the specified outputToken
// - Proper token ordering in swap direction (not alphabetical pool ordering)
//
// Route Path Formats:
// - single-hop: "tokenA:tokenB:fee" (direct swap between two tokens)
// - multi-hop: "tokenA:tokenB:fee1*POOL*tokenB:tokenC:fee2" (swap through intermediate tokens)
//
// Parameters:
// - routePath: single route path string (e.g., "gno.land/r/demo/wugnot:gno.land/r/demo/usdc:500")
// - inputToken: expected first token in the route path
// - outputToken: expected last token in the route path
//
// Examples:
// - single-hop: "tokenA:tokenB:500" with inputToken="tokenA", outputToken="tokenB"
// - multi-hop: "tokenA:tokenB:3000*POOL*tokenB:tokenC:500" with inputToken="tokenA", outputToken="tokenC"
//
// Returns error with specific details if validation fails.
func validateRoutePath(routePath, inputToken, outputToken string) error {
	inputWrappedPath := inputToken
	outputWrappedPath := outputToken

	if common.IsGNOTNativePath(inputToken) {
		inputWrappedPath = common.WUGNOT_PATH
	}

	if common.IsGNOTNativePath(outputToken) {
		outputWrappedPath = common.WUGNOT_PATH
	}

	// Extract first and last tokens from the routePath
	var (
		firstToken, lastToken string
		err                   error
	)

	// multi-hop routePath
	if strings.Contains(routePath, POOL_SEPARATOR) {
		pools := strings.Split(routePath, POOL_SEPARATOR)

		// Get first token from first pool
		firstPool := pools[0]
		firstToken, _, _, err = getDataForSinglePathWithError(firstPool)
		if err != nil {
			return err
		}

		// Get last token from last pool
		lastPool := pools[len(pools)-1]
		_, lastToken, _, err = getDataForSinglePathWithError(lastPool)
		if err != nil {
			return err
		}
	} else {
		// single-hop routePath
		firstToken, lastToken, _, err = getDataForSinglePathWithError(routePath)
		if err != nil {
			return err
		}
	}

	if firstToken == "" || lastToken == "" {
		return makeErrorWithDetails(errInvalidRoutePath, ufmt.Sprintf("firstToken: %s, lastToken: %s", firstToken, lastToken))
	}

	// Validate consistency
	if firstToken != inputWrappedPath {
		return makeErrorWithDetails(errInvalidRouteFirstToken, ufmt.Sprintf("firstToken: %s, inputToken: %s", firstToken, inputWrappedPath))
	}

	if lastToken != outputWrappedPath {
		return makeErrorWithDetails(errInvalidRouteLastToken, ufmt.Sprintf("lastToken: %s, outputToken: %s", lastToken, outputWrappedPath))
	}

	return nil
}

// splitSingleChar splits a string by a single character separator.
// This function is optimized for splitting strings with a single-byte separator
// and is more memory efficient than strings.Split for this use case.
func splitSingleChar(s string, sep byte) []string {
	if s == "" {
		return []string{""}
	}

	result := make([]string, 0, bytes.Count([]byte(s), []byte{sep})+1)
	start := 0
	for i := range s {
		if s[i] == sep {
			result = append(result, s[start:i])
			start = i + 1
		}
	}
	result = append(result, s[start:])
	return result
}

// formatUint formats an unsigned integer to string.
func formatUint(v any) string {
	switch v := v.(type) {
	case uint8:
		return strconv.FormatUint(uint64(v), 10)
	case uint32:
		return strconv.FormatUint(uint64(v), 10)
	case uint64:
		return strconv.FormatUint(v, 10)
	default:
		panic(ufmt.Sprintf("invalid type: %T", v))
	}
}

// formatInt64 formats a signed integer to string.
func formatInt64(v any) string {
	switch v := v.(type) {
	case int8:
		return strconv.FormatInt(int64(v), 10)
	case int16:
		return strconv.FormatInt(int64(v), 10)
	case int32:
		return strconv.FormatInt(int64(v), 10)
	case int64:
		return strconv.FormatInt(v, 10)
	default:
		panic(ufmt.Sprintf("invalid type %T", v))
	}
}

// safeConvertToInt64 safely converts a *u256.Uint value to an int64, ensuring no overflow.
//
// This function attempts to convert the given *u256.Uint value to an int64. If the value exceeds
// the maximum allowable range for int64 (`2^63 - 1`), it triggers a panic with a descriptive error message.
//
// Parameters:
// - value (*u256.Uint): The unsigned 256-bit integer to be converted.
//
// Returns:
// - int64: The converted value if it falls within the int64 range.
//
// Panics:
//   - If the `value` exceeds the range of int64, the function will panic with an error indicating
//     the overflow and the original value.
func safeConvertToInt64(value *u256.Uint) int64 {
	res, overflow := value.Uint64WithOverflow()
	if overflow || res > uint64(9223372036854775807) {
		panic(ufmt.Sprintf(
			"amount(%s) overflows int64 range (max 9223372036854775807)",
			value.ToString(),
		))
	}
	return int64(res)
}

func safeParseInt64(value string) int64 {
	amountInt64, err := strconv.ParseInt(value, 10, 64)
	if err != nil {
		panic(err)
	}

	return amountInt64
}

// parsePoolPathsByRoutePathArr parses route path array string and returns a slice of pool paths.
// This function converts route paths (which maintain swap direction) into canonical pool paths
// (which use alphabetical token ordering).
//
// The function processes comma-separated route paths and extracts individual pool information
// from each route, ensuring tokens are ordered alphabetically for consistent pool identification.
//
// Parameters:
//   - routePathArr: comma-separated route paths string containing single or multi-hop routes
//     Format examples:
//   - Single route: "tokenA:tokenB:500"
//   - Multiple routes: "tokenA:tokenB:500,tokenC:tokenD:3000"
//   - Multi-hop routes: "tokenA:tokenB:500*POOL*tokenB:tokenC:3000"
//
// Returns:
// - []string: slice of canonical pool paths with alphabetically ordered tokens
// - error: parsing error if any route path is invalid
//
// Example:
//
//	input: "gno.land/r/demo/wugnot:gno.land/r/demo/usdc:500,gno.land/r/demo/usdc:gno.land/r/demo/gns:3000"
//	output: ["gno.land/r/demo/usdc:gno.land/r/demo/wugnot:500", "gno.land/r/demo/gns:gno.land/r/demo/usdc:3000"]
func parsePoolPathsByRoutePathArr(routePathArr string) ([]string, error) {
	poolPaths := make([]string, 0)

	for _, routePaths := range strings.Split(routePathArr, ",") {
		for _, routePath := range strings.Split(routePaths, POOL_SEPARATOR) {
			token0Path, token1Path, fee, err := getDataForSinglePathWithError(routePath)
			if err != nil {
				return []string{}, err
			}

			if token0Path > token1Path {
				token0Path, token1Path = token1Path, token0Path
			}

			poolPath := pool.GetPoolPath(token0Path, token1Path, fee)
			poolPaths = append(poolPaths, poolPath)
		}
	}

	return poolPaths, nil
}

// BuildSingleHopPath creates a single-hop route path string.
// Format: "tokenA:tokenB:fee"
//
// Parameters:
// - tokenA: input token address
// - tokenB: output token address
// - fee: pool fee (e.g., 500, 3000, 10000)
//
// Returns:
// - string: formatted single-hop route path
//
// Example:
//   - BuildSingleHopPath("gno.land/r/demo/wugnot", "gno.land/r/demo/usdc", 500)
//     returns "gno.land/r/demo/wugnot:gno.land/r/demo/usdc:500"
func BuildSingleHopRoutePath(tokenA, tokenB string, fee uint32) string {
	if tokenA == "" || tokenB == "" {
		panic("token addresses cannot be empty")
	}
	if tokenA == tokenB {
		panic("tokenA and tokenB cannot be the same")
	}

	return tokenA + ":" + tokenB + ":" + formatUint(fee)
}

// BuildMultiHopPath creates a multi-hop route path string by connecting multiple single hops.
// Format: "tokenA:tokenB:fee1*POOL*tokenB:tokenC:fee2*POOL*tokenC:tokenD:fee3"
//
// Parameters:
// - hops: slice of single-hop path strings
//
// Returns:
// - string: formatted multi-hop route path
//
// Example:
//   - hops := []string{"tokenA:tokenB:500", "tokenB:tokenC:3000"}
//     returns "tokenA:tokenB:500*POOL*tokenB:tokenC:3000"
func BuildMultiHopRoutePath(hops ...string) string {
	if len(hops) < 1 {
		panic("multi-hop path requires at least 2 hops")
	}

	if len(hops) > 3 {
		panic("multi-hop path supports maximum 3 hops")
	}

	return strings.Join(hops, POOL_SEPARATOR)
}

// safeAddInt64 performs safe addition of int64 values, panicking on overflow or underflow
func safeAddInt64(a, b int64) int64 {
	if a > 0 && b > math.MaxInt64-a {
		panic("int64 addition overflow")
	}
	if a < 0 && b < math.MinInt64-a {
		panic("int64 addition underflow")
	}
	return a + b
}

// safeSubInt64 performs safe subtraction of int64 values, panicking on overflow or underflow
func safeSubInt64(a, b int64) int64 {
	if b > 0 && a < math.MinInt64+b {
		panic("int64 subtraction underflow")
	}
	if b < 0 && a > math.MaxInt64+b {
		panic("int64 subtraction overflow")
	}
	return a - b
}

func safeMulDivInt64(a, b, c int64) int64 {
	if c == 0 {
		panic("division by zero in safeMulDivInt64")
	}

	if a == 0 || b == 0 {
		return 0
	}

	// calculate amount to swap for this route
	result, overflow := i256.Zero().MulOverflow(i256.NewInt(a), i256.NewInt(b))
	if overflow {
		panic(errOverflow)
	}

	result = i256.Zero().Div(result, i256.NewInt(c))
	if !result.IsInt64() {
		panic(errOverflow)
	}

	return result.Int64()
}

func safeAbsInt64(a int64) int64 {
	if a == math.MinInt64 {
		panic(errOverflow)
	}

	if a < 0 {
		return -a
	}

	return a
}

package v1

import (
	"chain"
	"chain/banker"
	"chain/runtime"

	"gno.land/r/gnoland/wugnot"

	"gno.land/p/nt/ufmt"
)

const (
	UGNOT_MIN_DEPOSIT_TO_WRAP int64 = 1000
	WUGNOT_PATH                     = "gno.land/r/gnoland/wugnot"
	GNOT_DENOM                      = "ugnot"
)

var (
	errFailedToWrapZeroUgnot = "cannot wrap 0 ugnot"
	errFailedToWrapBelowMin  = "amount(%d) < minimum(%d)"
)

// wrapWithTransfer wraps GNOT into WUGNOT and transfers it to the specified address.
func wrapWithTransfer(toAddress address, amount int64) error {
	if amount <= 0 {
		return nil
	}

	if amount < UGNOT_MIN_DEPOSIT_TO_WRAP {
		return makeErrorWithDetails(
			errWugnotMinimum,
			ufmt.Sprintf("amount(%d) < minimum(%d)", amount, UGNOT_MIN_DEPOSIT_TO_WRAP),
		)
	}

	// transfer ugnot from fromAddress to current realm
	currentRealmAddr := runtime.CurrentRealm().Address()

	sentCoins := banker.OriginSend()
	ugnotSent := sentCoins.AmountOf(GNOT_DENOM)
	if ugnotSent != amount {
		return makeErrorWithDetails(
			errInvalidInput,
			ufmt.Sprintf("user(%s) sent ugnot(%d) amount not equal to rewardAmount(%d)", toAddress.String(), ugnotSent, amount),
		)
	}

	// wrap ugnot to wugnot
	wugnotAddr := chain.PackageAddress(WUGNOT_PATH)
	banker_ := banker.NewBanker(banker.BankerTypeRealmSend)
	banker_.SendCoins(currentRealmAddr, wugnotAddr, sentCoins)
	wugnot.Deposit(cross)

	// if to address is not current realm, transfer wugnot to to address
	if toAddress != currentRealmAddr {
		wugnot.Transfer(cross, toAddress, amount)
	}

	return nil
}

// unwrapWithTransferFrom transfers WUGNOT from a source address, unwraps it to GNOT, and sends it to the target.
func unwrapWithTransferFrom(fromAddress, toAddress address, wugnotAmount int64) error {
	if wugnotAmount == 0 {
		return nil
	}

	currentRealmAddr := runtime.CurrentRealm().Address()
	if fromAddress != currentRealmAddr {
		wugnot.TransferFrom(cross, fromAddress, currentRealmAddr, wugnotAmount)
	}

	wugnot.Withdraw(cross, wugnotAmount)

	sendCoins := chain.Coins{{Denom: GNOT_DENOM, Amount: wugnotAmount}}
	banker_ := banker.NewBanker(banker.BankerTypeRealmSend)
	banker_.SendCoins(currentRealmAddr, toAddress, sendCoins)

	return nil
}

// unwrapWithTransfer unwraps WUGNOT to GNOT and sends it to the specified address.
func unwrapWithTransfer(toAddress address, amount int64) error {
	if amount <= 0 {
		return nil
	}

	// unwrap wugnot to ugnot
	wugnot.Withdraw(cross, amount)

	// send ugnot to user
	sendCoins := chain.Coins{{Denom: GNOT_DENOM, Amount: amount}}
	banker_ := banker.NewBanker(banker.BankerTypeRealmSend)
	currentRealmAddr := runtime.CurrentRealm().Address()
	banker_.SendCoins(currentRealmAddr, toAddress, sendCoins)

	return nil
}

package v1

import (
	"strconv"
	"strings"
	"time"

	"gno.land/p/nt/ufmt"
	"gno.land/r/gnoswap/common"
)

const (
	TIMESTAMP_90DAYS  = int64(7776000)
	TIMESTAMP_180DAYS = int64(15552000)
	TIMESTAMP_365DAYS = int64(31536000)

	MAX_UNIX_EPOCH_TIME = 253402300799 // 9999-12-31 23:59:59
)

// assertIsValidAmount ensures the amount is non-negative.
func assertIsValidAmount(amount int64) {
	if amount < 0 {
		panic(makeErrorWithDetails(
			errInvalidInput,
			ufmt.Sprintf("amount(%d) must be positive", amount),
		))
	}
}

// assertIsValidRewardAmountFormat ensures the reward amount string is formatted as "tokenPath:amount".
func assertIsValidRewardAmountFormat(rewardAmountStr string) {
	parts := strings.SplitN(rewardAmountStr, ":", 2)
	if len(parts) != 2 {
		panic(makeErrorWithDetails(
			errInvalidInput,
			ufmt.Sprintf("invalid format for SetTokenMinimumRewardAmount params: expected 'tokenPath:amount', got '%s'", rewardAmountStr),
		))
	}
}

// assertIsDepositor ensures the caller is the owner of the deposit.
func assertIsDepositor(s *stakerV1, caller address, positionId uint64) {
	deposit := s.getDeposits().get(positionId)
	if deposit == nil {
		panic(makeErrorWithDetails(
			errDataNotFound,
			ufmt.Sprintf("positionId(%d) not found", positionId),
		))
	}

	if caller != deposit.Owner() {
		panic(makeErrorWithDetails(
			errNoPermission,
			ufmt.Sprintf("caller(%s) is not depositor(%s)", caller.String(), deposit.Owner().String()),
		))
	}
}

// assertIsNotStaked ensures the position is not already staked.
func assertIsNotStaked(s *stakerV1, positionId uint64) {
	if s.getDeposits().Has(positionId) {
		panic(makeErrorWithDetails(
			errAlreadyStaked,
			ufmt.Sprintf("positionId(%d) already staked", positionId),
		))
	}
}

// assertIsPositionOwner ensures the caller owns the position NFT.
func assertIsPositionOwner(s *stakerV1, positionId uint64, caller address) {
	owner := s.nftAccessor.MustOwnerOf(positionIdFrom(positionId))
	if owner != caller {
		panic(makeErrorWithDetails(
			errNoPermission,
			ufmt.Sprintf("caller(%s) is not owner(%s)", caller.String(), owner.String()),
		))
	}
}

// assertIsPoolExists ensures the pool exists.
func assertIsPoolExists(s *stakerV1, poolPath string) {
	if !s.poolAccessor.ExistsPoolPath(poolPath) {
		panic(makeErrorWithDetails(
			errInvalidPoolPath,
			ufmt.Sprintf("pool(%s) does not exist", poolPath),
		))
	}
}

// assertIsValidPoolTier ensures the tier is within valid range.
func assertIsValidPoolTier(tier uint64) {
	if tier >= AllTierCount {
		panic(makeErrorWithDetails(
			errInvalidPoolTier,
			ufmt.Sprintf("tier(%d) must be less than %d", tier, AllTierCount),
		))
	}
}

// assertIsGreaterThanMinimumRewardAmount ensures the reward amount meets minimum requirements.
func assertIsGreaterThanMinimumRewardAmount(s *stakerV1, rewardToken string, rewardAmount int64) {
	minReward := s.getMinimumRewardAmount()

	if minRewardI, found := s.store.GetTokenSpecificMinimumRewards().Get(rewardToken); found {
		minRewardInt64, ok := minRewardI.(int64)
		if !ok {
			panic(makeErrorWithDetails(
				errInvalidInput,
				ufmt.Sprintf("rewardToken(%s) is not int64", rewardToken),
			))
		}

		minReward = minRewardInt64
	}

	if rewardAmount < minReward {
		panic(makeErrorWithDetails(
			errInvalidInput,
			ufmt.Sprintf("rewardAmount(%d) is less than minimum required amount(%d)", rewardAmount, minReward),
		))
	}
}

// assertIsAllowedForExternalReward ensures the token is allowed for external rewards.
func assertIsAllowedForExternalReward(s *stakerV1, poolPath, tokenPath string) {
	token0, token1, _ := poolPathDivide(poolPath)

	if tokenPath == token0 || tokenPath == token1 {
		return
	}

	allowed := contains(s.store.GetAllowedTokens(), tokenPath)
	if allowed {
		return
	}

	panic(makeErrorWithDetails(
		errNotAllowedForExternalReward,
		ufmt.Sprintf("tokenPath(%s) is not allowed for external reward for poolPath(%s)", tokenPath, poolPath),
	))
}

const maxUnstakingFee = int64(1000) // 10%

// assertIsValidFeeRate ensures the fee rate is within valid range (0-1000 basis points).
func assertIsValidFeeRate(fee int64) {
	if fee < 0 || fee > maxUnstakingFee {
		panic(makeErrorWithDetails(
			errInvalidUnstakingFee,
			ufmt.Sprintf("fee(%d) must be in range 0 ~ %d", fee, maxUnstakingFee),
		))
	}
}

// assertIsValidIncentiveStartTime ensures the incentive starts at midnight of a future date.
func assertIsValidIncentiveStartTime(startTimestamp int64) {
	// must be in seconds format, not milliseconds
	// REF: https://stackoverflow.com/a/23982005
	numStr := strconv.Itoa(int(startTimestamp))

	if len(numStr) >= 13 {
		panic(makeErrorWithDetails(
			errInvalidIncentiveStartTime,
			ufmt.Sprintf("startTimestamp(%d) must be in seconds format, not milliseconds", startTimestamp),
		))
	}

	// must be at least +1 day midnight
	tomorrowMidnight := time.Now().AddDate(0, 0, 1).Truncate(24 * time.Hour).Unix()
	if startTimestamp < tomorrowMidnight {
		panic(makeErrorWithDetails(
			errInvalidIncentiveStartTime,
			ufmt.Sprintf("startTimestamp(%d) must be at least +1 day midnight(%d)", startTimestamp, tomorrowMidnight),
		))
	}

	// must be midnight of the day
	startTime := time.Unix(startTimestamp, 0)
	if !isMidnight(startTime) {
		panic(makeErrorWithDetails(
			errInvalidIncentiveStartTime,
			ufmt.Sprintf("startTime(%d = %s) must be midnight of the day", startTimestamp, startTime.String()),
		))
	}
}

// assertIsValidIncentiveEndTime ensures the end timestamp is within valid epoch range.
func assertIsValidIncentiveEndTime(endTimestamp int64) {
	if endTimestamp >= MAX_UNIX_EPOCH_TIME {
		panic(makeErrorWithDetails(
			errInvalidInput,
			ufmt.Sprintf("endTimestamp(%d) cannot be later than 253402300799 (9999-12-31 23:59:59)", endTimestamp),
		))
	}
}

// assertIsValidIncentiveDuration ensures the duration is 90, 180, or 365 days.
func assertIsValidIncentiveDuration(externalDuration int64) {
	switch externalDuration {
	case TIMESTAMP_90DAYS, TIMESTAMP_180DAYS, TIMESTAMP_365DAYS:
		return
	}

	panic(makeErrorWithDetails(
		errInvalidIncentiveDuration,
		ufmt.Sprintf("externalDuration(%d) must be 90, 180, 365 days", externalDuration),
	))
}

// isMidnight checks if a time represents midnight (00:00:00).
func isMidnight(startTime time.Time) bool {
	hour := startTime.Hour()
	minute := startTime.Minute()
	second := startTime.Second()

	return hour == 0 && minute == 0 && second == 0
}

func assertIsValidUserCoinSend(tokenPath string, amount int64) {
	if common.IsGNOTNativePath(tokenPath) {
		common.AssertIsUserSendGNOTAmount(amount)
	} else {
		common.AssertIsNotHandleNativeCoin()
	}
}

package v1

import (
	"gno.land/p/nt/avl"
	sr "gno.land/r/gnoswap/staker"
)

// Reward is a struct for storing reward for a position.
// Internal reward is the GNS reward, external reward is the reward for other incentives.
// Penalties are the amount that is deducted from the reward due to the position's warmup.
type Reward struct {
	Internal        int64
	InternalPenalty int64
	External        map[string]int64 // Incentive ID -> TokenAmount
	ExternalPenalty map[string]int64 // Incentive ID -> TokenAmount
}

// calculate total position rewards and penalties
func (s *stakerV1) calcPositionReward(currentHeight, currentTimestamp int64, positionId uint64) Reward {
	rewards := s.calculatePositionReward(&CalcPositionRewardParam{
		CurrentHeight: currentHeight,
		CurrentTime:   currentTimestamp,
		Deposits:      s.getDeposits(),
		Pools:         s.getPools(),
		PoolTier:      s.getPoolTier(),
		PositionId:    positionId,
	})

	internal := int64(0)
	internalPenalty := int64(0)

	rewardLen := len(rewards)
	externalReward := make(map[string]int64, rewardLen)
	externalPenalty := make(map[string]int64, rewardLen)

	for _, reward := range rewards {
		internal = safeAddInt64(internal, reward.Internal)
		internalPenalty = safeAddInt64(internalPenalty, reward.InternalPenalty)

		for incentive, amount := range reward.External {
			externalReward[incentive] = safeAddInt64(externalReward[incentive], amount)
		}

		for incentive, penalty := range reward.ExternalPenalty {
			externalPenalty[incentive] = safeAddInt64(externalPenalty[incentive], penalty)
		}
	}

	return Reward{
		Internal:        internal,
		InternalPenalty: internalPenalty,
		External:        externalReward,
		ExternalPenalty: externalPenalty,
	}
}

// CalcPositionRewardParam is a struct for calculating position reward
type CalcPositionRewardParam struct {
	// Environmental variables
	CurrentHeight int64
	CurrentTime   int64
	Deposits      *Deposits
	Pools         *Pools
	PoolTier      *PoolTier

	// Position variables
	PositionId uint64
}

func (s *stakerV1) calculatePositionReward(param *CalcPositionRewardParam) []Reward {
	// cache per-pool rewards in the internal incentive(tiers)
	param.PoolTier.cacheReward(param.CurrentHeight, param.CurrentTime, param.Pools)
	s.updatePoolTier(param.PoolTier)

	deposit := param.Deposits.get(param.PositionId)
	depositResolver := NewDepositResolver(deposit)
	poolPath := deposit.TargetPoolPath()

	pool, ok := param.Pools.Get(poolPath)
	if !ok {
		pool = sr.NewPool(poolPath, param.CurrentTime)
		param.Pools.set(poolPath, pool)
	}
	poolResolver := NewPoolResolver(pool)

	lastCollectTime := depositResolver.InternalRewardLastCollectTime()

	// Initializes reward/penalty arrays for rewards and penalties for each warmup
	rewardState := poolResolver.RewardStateOf(deposit)

	// Calculate internal rewards regardless of current tier status
	// The reward cache system will automatically handle periods with 0 rewards
	// This allows collecting rewards earned while the pool was in a tier,
	// while preventing new rewards after tier removal
	calculatedInternalRewards, calculatedInternalPenalties := rewardState.calculateInternalReward(lastCollectTime, param.CurrentTime)

	warmupLen := len(deposit.Warmups())
	rewards := make([]Reward, warmupLen)
	for i := 0; i < warmupLen; i++ {
		rewards[i] = Reward{
			Internal:        calculatedInternalRewards[i],
			InternalPenalty: calculatedInternalPenalties[i],
			External:        make(map[string]int64),
			ExternalPenalty: make(map[string]int64),
		}
	}
	rewardState.reset()

	lastExternalIncentiveUpdatedAt := depositResolver.LastExternalIncentiveUpdatedAt()

	// update deposit's incentive list with new incentives created since last update
	if lastExternalIncentiveUpdatedAt < param.CurrentTime {
		// get new incentives created since last update
		currentIncentiveIds := s.getExternalIncentiveIdsBy(poolPath, lastExternalIncentiveUpdatedAt, param.CurrentTime)

		// add new created incentives to deposit
		for _, incentiveId := range currentIncentiveIds {
			deposit.AddExternalIncentiveId(incentiveId)
		}

		deposit.SetLastExternalIncentiveUpdatedAt(param.CurrentTime)
	}

	incentivesResolver := poolResolver.IncentivesResolver()

	// Use deposit's indexed incentive IDs instead of iterating all pool incentives
	deposit.IterateExternalIncentiveIds(func(incentiveId string) bool {
		incentive, ok := incentivesResolver.Get(incentiveId)
		if !ok {
			return false
		}

		incentiveResolver := NewExternalIncentiveResolver(incentive)

		// Check if incentive is active during this specific collection period
		if !incentiveResolver.IsStarted(param.CurrentTime) {
			return false
		}

		// External incentivized pool.
		// Calculate reward for each warmup using per-incentive lastCollectTime
		externalLastCollectTime := depositResolver.ExternalRewardLastCollectTime(incentiveId)
		externalReward, externalPenalty := rewardState.calculateExternalReward(externalLastCollectTime, param.CurrentTime, incentive)

		for i := range externalReward {
			if externalReward[i] > 0 || externalPenalty[i] > 0 {
				rewards[i].External[incentiveId] = externalReward[i]
				rewards[i].ExternalPenalty[incentiveId] = externalPenalty[i]
			}
		}

		rewardState.reset()

		return false
	})

	return rewards
}

// calculates internal unclaimable reward for the pool
func (s *stakerV1) processUnClaimableReward(poolPath string, endTimestamp int64) int64 {
	pool, ok := s.getPools().Get(poolPath)
	if !ok {
		return 0
	}
	poolResolver := NewPoolResolver(pool)
	return poolResolver.processUnclaimableReward(endTimestamp)
}

// update deposit's incentive list with new incentives created since last update
func (s *stakerV1) getExternalIncentiveIdsBy(poolPath string, startTime, endTime int64) []string {
	currentIncentiveIds := make([]string, 0)

	incentivesByTime := s.getExternalIncentivesByCreationTime()

	incentivesByTime.Iterate(startTime, endTime, func(_ int64, value any) bool {
		// Value is a slice of incentive IDs (handles timestamp collisions)
		poolIncentiveIds, ok := value.(*avl.Tree)
		if !ok {
			return false
		}

		incentiveIdsValue, exists := poolIncentiveIds.Get(poolPath)
		if !exists {
			return false
		}

		incentiveIds, ok := incentiveIdsValue.([]string)
		if !ok {
			return false
		}

		currentIncentiveIds = append(currentIncentiveIds, incentiveIds...)

		return false
	})

	return currentIncentiveIds
}

// getInitialCollectTime determines the initial collection time for an incentive
// by taking the maximum of the deposit's stake time and the incentive's start time.
// This ensures rewards are only calculated from when both conditions are met:
// - The position must be staked (deposit.stakeTime)
// - The incentive must be active (incentive.startTimestamp)
//
// This function is used for lazy initialization when a position collects
// from an incentive for the first time, avoiding the need to iterate through
// all deposits when a new incentive is created.
func getInitialCollectTime(deposit *sr.Deposit, incentive *sr.ExternalIncentive) int64 {
	if deposit.StakeTime() > incentive.StartTimestamp() {
		return deposit.StakeTime()
	}
	return incentive.StartTimestamp()
}

