// GetDepositGnsAmount returns the current deposit amount in GNS.
func (s *stakerV1) GetDepositGnsAmount() int64 {
	return s.store.GetDepositGnsAmount()
}

// GetMinimumRewardAmount returns the default minimum reward amount required for external incentives.
func (s *stakerV1) GetMinimumRewardAmount() int64 {
	return s.store.GetMinimumRewardAmount()
}

// GetMinimumRewardAmountForToken returns the minimum reward amount for a specific token.
func (s *stakerV1) GetMinimumRewardAmountForToken(tokenPath string) int64 {
	amountI, found := s.store.GetTokenSpecificMinimumRewards().Get(tokenPath)
	if found {
		amount, ok := amountI.(int64)
		if !ok {
			panic("failed to cast amount to int64")
		}
		return amount
	}
	// Fallback to default if not found
	return s.GetMinimumRewardAmount()
}

// GetSpecificTokenMinimumRewardAmount returns the explicitly set minimum reward amount for a token.
func (s *stakerV1) GetSpecificTokenMinimumRewardAmount(tokenPath string) (int64, bool) {
	amountI, found := s.store.GetTokenSpecificMinimumRewards().Get(tokenPath)
	if !found {
		return 0, false
	}
	v, ok := amountI.(int64)
	if !ok {
		panic("failed to cast amount to int64")
	}
	return v, true
}

// SetDepositGnsAmount sets the GNS deposit amount required for creating external incentives.
// Only admin or governance can call this function.
func (s *stakerV1) SetDepositGnsAmount(amount int64) {
	halt.AssertIsNotHaltedStaker()

	previousRealm := runtime.PreviousRealm()
	caller := previousRealm.Address()
	access.AssertIsAdminOrGovernance(caller)

	assertIsValidAmount(amount)

	prevDepositGnsAmount := s.GetDepositGnsAmount()
	s.setDepositGnsAmount(amount)

	chain.Emit(
		"SetDepositGnsAmount",
		"prevAddr", caller.String(),
		"prevRealm", previousRealm.PkgPath(),
		"prevAmount", formatAnyInt(prevDepositGnsAmount),
		"newAmount", formatAnyInt(amount),
	)
}

// SetMinimumRewardAmount sets the default minimum reward amount for external incentives.
// Only admin or governance can call this function.
func (s *stakerV1) SetMinimumRewardAmount(amount int64) {
	halt.AssertIsNotHaltedStaker()

	previousRealm := runtime.PreviousRealm()
	caller := previousRealm.Address()
	access.AssertIsAdminOrGovernance(caller)

	assertIsValidAmount(amount)

	prevMinimumRewardAmount := s.getMinimumRewardAmount()
	s.setMinimumRewardAmount(amount)

	chain.Emit(
		"SetMinimumRewardAmount",
		"prevAddr", caller.String(),
		"prevRealm", previousRealm.PkgPath(),
		"prevAmount", formatAnyInt(prevMinimumRewardAmount),
		"newAmount", formatAnyInt(amount),
	)
}

// SetTokenMinimumRewardAmount sets the minimum reward amount for a specific token.
// Only admin or governance can call this function.
func (s *stakerV1) SetTokenMinimumRewardAmount(paramsStr string) {
	halt.AssertIsNotHaltedStaker()

	previousRealm := runtime.PreviousRealm()
	caller := previousRealm.Address()
	access.AssertIsAdminOrGovernance(caller)

	assertIsValidRewardAmountFormat(paramsStr)

	// Parse the paramsStr
	parts := strings.SplitN(paramsStr, ":", 2)
	tokenPath := parts[0]
	amountStr := parts[1]
	amount64, err := strconv.ParseInt(amountStr, 10, 64)
	if err != nil {
		panic(makeErrorWithDetails(
			errInvalidInput,
			ufmt.Sprintf("invalid amount format in params '%s': %v", paramsStr, err),
		))
	}

	prevAmount, found := s.GetSpecificTokenMinimumRewardAmount(tokenPath)

	// If amount is 0, remove the entry; otherwise, set it.
	if amount64 == 0 {
		// Only attempt removal if an entry actually existed
		if found {
			s.store.GetTokenSpecificMinimumRewards().Remove(tokenPath)
		}
	} else {
		s.store.GetTokenSpecificMinimumRewards().Set(tokenPath, amount64)
	}

	chain.Emit(
		"SetTokenMinimumRewardAmount",
		"prevAddr", caller.String(),
		"prevRealm", previousRealm.PkgPath(),
		"paramsStr", paramsStr, // Log the raw input string
		"tokenPath", tokenPath,
		"prevAmountFound", formatBool(found),
		"prevAmount", formatAnyInt(prevAmount), // Will be 0 if !found
		"newAmount", formatAnyInt(amount64),
	)
}

// setDepositGnsAmount internally updates the deposit GNS amount.
func (s *stakerV1) setDepositGnsAmount(amount int64) {
	s.store.SetDepositGnsAmount(amount)
}

// setMinimumRewardAmount internally updates the minimum reward amount.
func (s *stakerV1) setMinimumRewardAmount(amount int64) {
	s.store.SetMinimumRewardAmount(amount)
}

// getMinimumRewardAmount internally retrieves the minimum reward amount.
func (s *stakerV1) getMinimumRewardAmount() int64 {
	return s.store.GetMinimumRewardAmount()
}

package v1

import (
	"chain"
	"chain/runtime"
	"math"
	"time"

	prbac "gno.land/p/gnoswap/rbac"
	"gno.land/p/nt/avl"
	"gno.land/p/nt/ufmt"

	"gno.land/r/gnoswap/access"
	"gno.land/r/gnoswap/common"
	en "gno.land/r/gnoswap/emission"
	"gno.land/r/gnoswap/gns"
	"gno.land/r/gnoswap/halt"
	sr "gno.land/r/gnoswap/staker"
)

// CreateExternalIncentive creates an external incentive program for a pool.
//
// Parameters:
//   - targetPoolPath: pool to incentivize
//   - rewardToken: reward token path
//   - rewardAmount: total reward amount
//   - startTimestamp, endTimestamp: incentive period
//
// Only callable by users.
func (s *stakerV1) CreateExternalIncentive(
	targetPoolPath string,
	rewardToken string, // token path should be registered
	rewardAmount int64,
	startTimestamp int64,
	endTimestamp int64,
) {
	halt.AssertIsNotHaltedStaker()

	prevRealm := runtime.PreviousRealm()
	caller := prevRealm.Address()
	access.AssertIsUser(prevRealm)

	assertIsPoolExists(s, targetPoolPath)
	assertIsGreaterThanMinimumRewardAmount(s, rewardToken, rewardAmount)
	assertIsAllowedForExternalReward(s, targetPoolPath, rewardToken)
	assertIsValidIncentiveStartTime(startTimestamp)
	assertIsValidIncentiveEndTime(endTimestamp)
	assertIsValidIncentiveDuration(safeSubInt64(endTimestamp, startTimestamp))
	// assert that the user has sent the correct amount of native coin
	assertIsValidUserCoinSend(rewardToken, rewardAmount)

	en.MintAndDistributeGns(cross)

	stakerAddr := access.MustGetAddress(prbac.ROLE_STAKER.String())

	// transfer reward token from user to staker
	isRequestUnwrap := false
	if rewardToken == GNOT_DENOM {
		isRequestUnwrap = true
		rewardToken = WUGNOT_PATH
		err := wrapWithTransfer(stakerAddr, rewardAmount)
		if err != nil {
			panic(err)
		}
	} else {
		common.SafeGRC20TransferFrom(cross, rewardToken, caller, stakerAddr, rewardAmount)
	}

	depositGnsAmount := s.store.GetDepositGnsAmount()

	// deposit gns amount
	gns.TransferFrom(cross, caller, stakerAddr, depositGnsAmount)

	currentTime := time.Now().Unix()
	currentHeight := runtime.ChainHeight()
	incentiveId := s.store.NextIncentiveID(caller, currentTime)
	pool := s.getPools().GetPoolOrNil(targetPoolPath)
	if pool == nil {
		pool = sr.NewPool(targetPoolPath, currentTime)
		s.getPools().set(targetPoolPath, pool)
	}

	incentive := sr.NewExternalIncentive(
		incentiveId,
		targetPoolPath,
		rewardToken,
		rewardAmount,
		startTimestamp,
		endTimestamp,
		caller,
		depositGnsAmount,
		currentHeight,
		currentTime,
		isRequestUnwrap,
	)

	externalIncentives := s.store.GetExternalIncentives()
	if externalIncentives.Has(incentiveId) {
		panic(makeErrorWithDetails(
			errIncentiveAlreadyExists,
			ufmt.Sprintf("incentiveId(%s)", incentiveId),
		))
	}
	// store external incentive information for each incentiveId
	externalIncentives.Set(incentiveId, incentive)

	poolResolver := NewPoolResolver(pool)
	poolResolver.IncentivesResolver().create(caller, incentive)

	// add incentive to time-based index for lazy discovery during CollectReward
	s.addIncentiveIdByCreationTime(targetPoolPath, incentiveId, currentTime)

	chain.Emit(
		"CreateExternalIncentive",
		"prevAddr", caller.String(),
		"prevRealm", prevRealm.PkgPath(),
		"incentiveId", incentiveId,
		"targetPoolPath", targetPoolPath,
		"rewardToken", rewardToken,
		"rewardAmount", formatAnyInt(rewardAmount),
		"startTimestamp", formatAnyInt(startTimestamp),
		"endTimestamp", formatAnyInt(endTimestamp),
		"depositGnsAmount", formatAnyInt(depositGnsAmount),
		"currentHeight", formatAnyInt(currentHeight),
		"currentTime", formatAnyInt(currentTime),
	)
}

// EndExternalIncentive ends an external incentive and refunds remaining rewards.
//
// Finalizes incentive program after end timestamp.
// Returns unallocated rewards and GNS deposit.
// Calculates unclaimable rewards for refund.
//
// Parameters:
//   - targetPoolPath: Pool with the incentive
//   - incentiveId: Unique incentive identifier
//
// Process:
//  1. Validates incentive end time reached
//  2. Calculates remaining and unclaimable rewards
//  3. Refunds rewards to original creator
//  4. Returns 100 GNS deposit
//  5. Removes incentive from active list
//
// Only callable by Refundee or Admin.
func (s *stakerV1) EndExternalIncentive(targetPoolPath, incentiveId string) {
	halt.AssertIsNotHaltedStaker()
	halt.AssertIsNotHaltedWithdraw()

	// checks pool registry
	assertIsPoolExists(s, targetPoolPath)

	// checks if the pool has been incentivized
	pool, exists := s.getPools().Get(targetPoolPath)
	if !exists {
		panic(makeErrorWithDetails(
			errDataNotFound,
			ufmt.Sprintf("targetPoolPath(%s) not found", targetPoolPath),
		))
	}

	poolResolver := NewPoolResolver(pool)
	incentivesResolver := poolResolver.IncentivesResolver()

	// Get incentive to check if GNS already refunded
	incentiveResolver, exists := incentivesResolver.GetIncentiveResolver(incentiveId)
	if !exists {
		panic(makeErrorWithDetails(
			errCannotEndIncentive,
			ufmt.Sprintf("cannot end non existent incentive(%s)", incentiveId),
		))
	}

	// Check if incentive has already been refunded
	if incentiveResolver.Refunded() {
		panic(makeErrorWithDetails(
			errCannotEndIncentive,
			ufmt.Sprintf("incentive(%s) has already been refunded", incentiveId),
		))
	}

	caller := runtime.PreviousRealm().Address()

	// Process ending
	incentive, refund, err := s.endExternalIncentive(poolResolver, incentiveResolver, caller, time.Now().Unix())
	if err != nil {
		panic(err)
	}

	// remove incentive from time-based index
	s.removeIncentiveIdByCreationTime(targetPoolPath, incentiveId, incentive.CreatedTimestamp())

	stakerAddr := access.MustGetAddress(prbac.ROLE_STAKER.String())
	poolLeftExternalRewardAmount := common.BalanceOf(incentiveResolver.RewardToken(), stakerAddr)
	if poolLeftExternalRewardAmount < refund {
		refund = poolLeftExternalRewardAmount
	}

	// handle refund based on original token type
	if incentiveResolver.IsRequestUnwrap() {
		// unwrap to GNOT if originally deposited as native GNOT
		transferErr := unwrapWithTransfer(incentiveResolver.Refundee(), refund)
		if transferErr != nil {
			panic(transferErr)
		}
	} else {
		// keep as WUGNOT or other token if originally deposited as wrapped token
		common.SafeGRC20Transfer(cross, incentiveResolver.RewardToken(), incentiveResolver.Refundee(), refund)
	}

	// Transfer GNS deposit back to refundee
	gns.Transfer(cross, incentiveResolver.Refundee(), incentiveResolver.DepositGnsAmount())

	// Mark incentive as refunded and update
	// After this update, attempts to re-claim GNS or rewards that were deposited
	// through the `endExternalIncentive` function will be blocked.
	incentiveResolver.SetRefunded(true)
	incentiveResolver.addDistributedRewardAmount(refund)
	incentivesResolver.update(incentive.Refundee(), incentive)

	previousRealm := runtime.PreviousRealm()
	chain.Emit(
		"EndExternalIncentive",
		"prevAddr", previousRealm.Address().String(),
		"prevRealm", previousRealm.PkgPath(),
		"incentiveId", incentiveId,
		"targetPoolPath", targetPoolPath,
		"refundee", incentiveResolver.Refundee().String(),
		"refundToken", incentiveResolver.RewardToken(),
		"refundAmount", formatAnyInt(refund),
		"refundGnsAmount", formatAnyInt(incentiveResolver.DepositGnsAmount()),
		"isRequestUnwrap", formatBool(incentiveResolver.IsRequestUnwrap()),
		"externalIncentiveEndBy", previousRealm.Address().String(),
	)
}

// endExternalIncentive processes the end of an external incentive program.
func (s *stakerV1) endExternalIncentive(resolver *PoolResolver, incentiveResolver *ExternalIncentiveResolver, caller address, currentTime int64) (*sr.ExternalIncentive, int64, error) {
	if currentTime < incentiveResolver.EndTimestamp() {
		return nil, 0, makeErrorWithDetails(
			errCannotEndIncentive,
			ufmt.Sprintf("cannot end incentive before endTime(%d), current(%d)", incentiveResolver.EndTimestamp(), currentTime),
		)
	}

	// only refundee or admin can end incentive
	if !access.IsAuthorized(prbac.ROLE_ADMIN.String(), caller) && caller != incentiveResolver.Refundee() {
		adminAddr := access.MustGetAddress(prbac.ROLE_ADMIN.String())
		return nil, 0, makeErrorWithDetails(
			errNoPermission,
			ufmt.Sprintf(
				"only refundee(%s) or admin(%s) can end incentive, but called from %s",
				incentiveResolver.Refundee(), adminAddr.String(), caller,
			),
		)
	}

	totalReward := int64(0)

	// calculate total external reward for the incentive
	s.getDeposits().IterateByPoolPath(0, math.MaxUint64, incentiveResolver.TargetPoolPath(), func(positionId uint64, deposit *sr.Deposit) bool {
		depositResolver := NewDepositResolver(deposit)
		lastCollectTime := depositResolver.ExternalRewardLastCollectTime(incentiveResolver.IncentiveId())

		if lastCollectTime > incentiveResolver.EndTimestamp() {
			return false
		}

		rewardState := resolver.RewardStateOf(deposit)
		calculatedTotalReward := rewardState.calculateCollectableExternalReward(lastCollectTime, currentTime, incentiveResolver.ExternalIncentive)
		totalReward = safeAddInt64(totalReward, calculatedTotalReward)

		return false
	})

	// calculate refund amount is the difference between the incentive reward amount and the total external reward
	refund := safeSubInt64(incentiveResolver.TotalRewardAmount(), totalReward)
	refund = safeSubInt64(refund, incentiveResolver.DistributedRewardAmount())

	return incentiveResolver.ExternalIncentive, refund, nil
}

// addIncentiveIdByCreationTime adds an external incentive to the time-based index.
//
// The index structure is:
//   - creationTime (int64) -> poolPath (string) -> []incentiveIds
func (s *stakerV1) addIncentiveIdByCreationTime(poolPath, incentiveId string, creationTime int64) {
	incentivesByTime := s.getExternalIncentivesByCreationTime()

	currentPoolIncentiveIdsValue, exists := incentivesByTime.Get(creationTime)
	if !exists {
		currentPoolIncentiveIdsValue = avl.NewTree()
	}

	currentPoolIncentiveIds, ok := currentPoolIncentiveIdsValue.(*avl.Tree)
	if !ok {
		panic(ufmt.Sprintf("invalid type in incentivesByTime tree: expected *avl.Tree, got %T", currentPoolIncentiveIdsValue))
	}

	incentiveIdsValue, exists := currentPoolIncentiveIds.Get(poolPath)
	if !exists {
		incentiveIdsValue = []string{}
	}

	incentiveIds, ok := incentiveIdsValue.([]string)
	if !ok {
		panic(ufmt.Sprintf("invalid type in incentivesByTime tree: expected []string, got %T", incentiveIdsValue))
	}

	incentiveIds = append(incentiveIds, incentiveId)
	currentPoolIncentiveIds.Set(poolPath, incentiveIds)
	incentivesByTime.Set(creationTime, currentPoolIncentiveIds)

	s.updateExternalIncentivesByCreationTime(incentivesByTime)
}

// removeIncentiveIdByCreationTime removes an incentive from the time-based index.
// This is called when an external incentive is ended via EndExternalIncentive.
//
// The index structure is:
//   - creationTime (int64) -> poolPath (string) -> []incentiveId
func (s *stakerV1) removeIncentiveIdByCreationTime(poolPath, incentiveId string, creationTime int64) {
	incentivesByTime := s.getExternalIncentivesByCreationTime()

	// check if creation time exists
	currentPoolIncentiveIdsValue, exists := incentivesByTime.Get(creationTime)
	if !exists {
		return
	}

	currentPoolIncentiveIds, ok := currentPoolIncentiveIdsValue.(*avl.Tree)
	if !ok {
		panic(ufmt.Sprintf("invalid type in incentivesByTime tree: expected *avl.Tree, got %T", currentPoolIncentiveIdsValue))
	}

	// check if pool path exists at this time
	incentiveIdsValue, exists := currentPoolIncentiveIds.Get(poolPath)
	if !exists {
		return
	}

	incentiveIds, ok := incentiveIdsValue.([]string)
	if !ok {
		panic(ufmt.Sprintf("invalid type in incentivesByTime tree: expected []string, got %T", incentiveIdsValue))
	}

	// if only incentive exists for this pool,remove the entire pool entry
	if len(incentiveIds) == 1 && incentiveIds[0] == incentiveId {
		currentPoolIncentiveIds.Remove(poolPath)

		// if no pools remain at this time, remove the time entry
		if currentPoolIncentiveIds.Size() == 0 {
			incentivesByTime.Remove(creationTime)
		} else {
			incentivesByTime.Set(creationTime, currentPoolIncentiveIds)
		}

		s.updateExternalIncentivesByCreationTime(incentivesByTime)

		return
	}

	// remove only the target incentive from slice
	for index, id := range incentiveIds {
		if id == incentiveId {
			incentiveIds = append(incentiveIds[:index], incentiveIds[index+1:]...)
			break
		}
	}

	currentPoolIncentiveIds.Set(poolPath, incentiveIds)
	incentivesByTime.Set(creationTime, currentPoolIncentiveIds)

	s.updateExternalIncentivesByCreationTime(incentivesByTime)
}

package v1

import (
	"chain"
	"chain/runtime"

	"gno.land/p/nt/ufmt"
	"gno.land/r/gnoswap/access"
	"gno.land/r/gnoswap/halt"
)

var defaultAllowed = []string{GNOT_DENOM, GNS_PATH}

// AddToken adds a new token path to the list of allowed tokens
// Only the admin can add a new token.
//
// Parameters:
//   - tokenPath (string): The path of the token to add
//
// Panics:
//   - If the caller is not the admin
func (s *stakerV1) AddToken(tokenPath string) {
	halt.AssertIsNotHaltedStaker()

	previousRealm := runtime.PreviousRealm()
	caller := previousRealm.Address()
	access.AssertIsAdminOrGovernance(caller)

	if err := modifyTokenList(s, tokenPath, addTokenValidator, addTokenExecutor); err != nil {
		panic(err.Error())
	}

	chain.Emit(
		"AddToken",
		"prevAddr", caller.String(),
		"prevRealm", previousRealm.PkgPath(),
		"tokenPath", tokenPath,
	)
}

// RemoveToken removes a token path from the list of allowed tokens.
// Only the admin  can remove a token.
//
// Default tokens cannot be removed.
//
// Parameters:
//   - tokenPath (string): The path of the token to remove
//
// Panics:
//   - If the caller is not the admin
func (s *stakerV1) RemoveToken(tokenPath string) {
	halt.AssertIsNotHaltedStaker()

	previousRealm := runtime.PreviousRealm()
	caller := previousRealm.Address()
	access.AssertIsAdminOrGovernance(caller)

	if err := modifyTokenList(s, tokenPath, removeTokenValidator, removeTokenExecutor); err != nil {
		panic(err.Error())
	}

	chain.Emit(
		"RemoveToken",
		"prevAddr", caller.String(),
		"prevRealm", previousRealm.PkgPath(),
		"tokenPath", tokenPath,
	)
}

// TokenValidator is a function type that validates a token
type TokenValidator func(tokenPath string) error

// TokenExecutor is a token manipulation function type
type TokenExecutor func(tokenPath string, tokens []string) []string

// modifyTokenList handles common token modification logics, such as admin check, validation, and execution.
func modifyTokenList(s *stakerV1, tokenPath string, validator TokenValidator, executor TokenExecutor) error {
	// validate token operation if validator is provided
	if validator != nil {
		if err := validator(tokenPath); err != nil {
			return err
		}
	}

	allowedTokens := s.store.GetAllowedTokens()
	allowedTokens = executor(tokenPath, allowedTokens)
	s.store.SetAllowedTokens(allowedTokens)
	return nil
}

// addTokenExecutor executes token append operation
func addTokenExecutor(tokenPath string, tokens []string) []string {
	if contains(tokens, tokenPath) {
		return tokens
	}

	return append(tokens, tokenPath)
}

// addTokenValidator validates token addition operation
func addTokenValidator(tokenPath string) error {
	if contains(defaultAllowed, tokenPath) {
		return ufmt.Errorf("%v: cannot add existing token(%s)", errAddExistingToken, tokenPath)
	}

	return nil
}

// removeTokenExecutor executes token removal operation
func removeTokenExecutor(tokenPath string, tokens []string) []string {
	// find and remove token
	for i, t := range tokens {
		if t == tokenPath {
			return append(tokens[:i], tokens[i+1:]...)
		}
	}

	// if token not found, return the original list
	return tokens
}

// removeTokenValidator validates token removal operation
func removeTokenValidator(tokenPath string) error {
	if contains(defaultAllowed, tokenPath) {
		return ufmt.Errorf("%v: cannot remove default token(%s)", errDefaultExternalToken, tokenPath)
	}

	return nil
}

package v1

import (
	"chain/runtime"
	"time"

	"gno.land/p/nt/ufmt"

	u256 "gno.land/p/gnoswap/uint256"

	sr "gno.land/r/gnoswap/staker"
)

// getPoolByPoolPath retrieves the pool by its path.
func (s *stakerV1) getPoolByPoolPath(poolPath string) *sr.Pool {
	result, ok := s.store.GetPools().Get(poolPath)
	if !ok {
		panic(makeErrorWithDetails(
			errDataNotFound,
			ufmt.Sprintf("poolPath(%s) pool does not exist", poolPath)),
		)
	}

	pool, ok := result.(*sr.Pool)
	if !ok {
		panic(makeErrorWithDetails(
			errDataNotFound,
			ufmt.Sprintf("poolPath(%s) pool does not exist", poolPath)),
		)
	}

	return pool
}

// GetPool returns the pool for the given path.
func (s *stakerV1) GetPool(poolPath string) *sr.Pool {
	return s.getPoolByPoolPath(poolPath)
}

// GetPoolIncentiveIdList returns all incentive IDs for a pool.
func (s *stakerV1) GetPoolIncentiveIdList(poolPath string) []string {
	pool := s.getPoolByPoolPath(poolPath)

	incentives := pool.Incentives()

	ids := []string{}
	incentives.IncentiveTrees().Iterate("", "", func(key string, value any) bool {
		ids = append(ids, key)
		return false
	})

	return ids
}

// getIncentive retrieves an external incentive by ID.
func (s *stakerV1) getIncentive(poolPath string, incentiveId string) *sr.ExternalIncentive {
	pool := s.getPoolByPoolPath(poolPath)

	incentives := pool.Incentives()
	incentive, exist := incentives.IncentiveTrees().Get(incentiveId)
	if !exist {
		panic(ufmt.Sprintf("incentiveId(%s) incentive does not exist", incentiveId))
	}

	ictv, ok := incentive.(*sr.ExternalIncentive)
	if !ok {
		panic(ufmt.Sprintf("failed to cast incentive to *ExternalIncentive: %T", incentive))
	}
	return ictv
}

// GetIncentive returns the incentive for the given pool and ID.
func (s *stakerV1) GetIncentive(poolPath string, incentiveId string) *sr.ExternalIncentive {
	return s.getIncentive(poolPath, incentiveId)
}

// GetIncentiveStartTimestamp returns the start timestamp of an incentive.
func (s *stakerV1) GetIncentiveStartTimestamp(poolPath string, incentiveId string) int64 {
	incentive := s.getIncentive(poolPath, incentiveId)

	return incentive.StartTimestamp()
}

// GetIncentiveEndTimestamp returns the end timestamp of an incentive.
func (s *stakerV1) GetIncentiveEndTimestamp(poolPath string, incentiveId string) int64 {
	incentive := s.getIncentive(poolPath, incentiveId)

	return incentive.EndTimestamp()
}

// GetTargetPoolPathByIncentiveId returns the target pool path of an incentive.
func (s *stakerV1) GetTargetPoolPathByIncentiveId(poolPath string, incentiveId string) string {
	incentive := s.getIncentive(poolPath, incentiveId)

	return incentive.TargetPoolPath()
}

// GetCreatedHeightOfIncentive returns the creation height of an incentive.
func (s *stakerV1) GetCreatedHeightOfIncentive(poolPath string, incentiveId string) int64 {
	incentive := s.getIncentive(poolPath, incentiveId)

	return incentive.CreatedHeight()
}

// GetIncentiveCreatedTimestamp returns the creation timestamp of an incentive.
func (s *stakerV1) GetIncentiveCreatedTimestamp(poolPath string, incentiveId string) int64 {
