package v1

import (
	"chain"
	"chain/runtime"
	"time"

	"gno.land/r/gnoswap/access"
	"gno.land/r/gnoswap/halt"
	sr "gno.land/r/gnoswap/staker"
)

const (
	NOT_EMISSION_TARGET_TIER uint64 = 0
)

// SetPoolTier assigns a tier level to a pool for internal GNS emission rewards.
// Only admin or governance can call this function.
func (s *stakerV1) SetPoolTier(poolPath string, tier uint64) {
	halt.AssertIsNotHaltedStaker()

	caller := runtime.PreviousRealm().Address()
	access.AssertIsAdminOrGovernance(caller)

	assertIsPoolExists(s, poolPath)
	assertIsValidPoolTier(tier)

	currentTime := time.Now().Unix()
	s.setPoolTier(poolPath, tier, currentTime)

	previousRealm := runtime.PreviousRealm()
	chain.Emit(
		"SetPoolTier",
		"prevAddr", previousRealm.Address().String(),
		"prevRealm", previousRealm.PkgPath(),
		"poolPath", poolPath,
		"tier", formatUint(tier),
		"currentTime", formatAnyInt(currentTime),
		"currentHeight", formatAnyInt(runtime.ChainHeight()),
	)
}

// ChangePoolTier modifies the tier level of an existing pool.
// Only admin or governance can call this function.
func (s *stakerV1) ChangePoolTier(poolPath string, tier uint64) {
	halt.AssertIsNotHaltedStaker()

	previousRealm := runtime.PreviousRealm()
	caller := previousRealm.Address()
	access.AssertIsAdminOrGovernance(caller)

	assertIsPoolExists(s, poolPath)
	assertIsValidPoolTier(tier)

	currentTime := time.Now().Unix()
	previousTier, newTier := s.changePoolTier(poolPath, tier, currentTime)

	chain.Emit(
		"ChangePoolTier",
		"prevAddr", caller.String(),
		"prevRealm", previousRealm.PkgPath(),
		"poolPath", poolPath,
		"prevTier", formatUint(previousTier),
		"newTier", formatUint(newTier),
		"currentTime", formatAnyInt(currentTime),
		"currentHeight", formatAnyInt(runtime.ChainHeight()),
	)
}

// RemovePoolTier removes a pool from internal GNS emission rewards.
// Only admin or governance can call this function.
func (s *stakerV1) RemovePoolTier(poolPath string) {
	halt.AssertIsNotHaltedStaker()

	previousRealm := runtime.PreviousRealm()
	caller := previousRealm.Address()
	access.AssertIsAdminOrGovernance(caller)

	assertIsPoolExists(s, poolPath)

	currentTime := time.Now().Unix()
	s.removePoolTier(poolPath, currentTime)

	chain.Emit(
		"RemovePoolTier",
		"prevAddr", caller.String(),
		"prevRealm", previousRealm.PkgPath(),
		"poolPath", poolPath,
		"currentTime", formatAnyInt(currentTime),
		"currentHeight", formatAnyInt(runtime.ChainHeight()),
	)
}

// SetWarmUp configures the warm-up percentage and duration for rewards.
// Only admin or governance can call this function.
func (s *stakerV1) SetWarmUp(pct, timeDuration int64) {
	halt.AssertIsNotHaltedStaker()

	previousRealm := runtime.PreviousRealm()
	caller := previousRealm.Address()
	access.AssertIsAdminOrGovernance(caller)

	s.setWarmUp(pct, timeDuration)

	chain.Emit(
		"SetWarmUp",
		"prevAddr", caller.String(),
		"prevRealm", previousRealm.PkgPath(),
		"pct", formatAnyInt(pct),
		"timeDuration", formatAnyInt(timeDuration),
	)
}

// setPoolTier internally sets the pool tier.
func (s *stakerV1) setPoolTier(poolPath string, tier uint64, currentTime int64) {
	s.emissionAccessor.MintAndDistributeGns()

	pool := s.getPools().GetPoolOrNil(poolPath)
	if pool == nil {
		pool = sr.NewPool(poolPath, currentTime)
		s.getPools().set(poolPath, pool)
	}
	poolTier := s.getPoolTier()
	poolTier.changeTier(runtime.ChainHeight(), currentTime, s.getPools(), poolPath, tier)
	s.updatePoolTier(poolTier)
}

// changePoolTier internally changes the pool tier and returns old and new tiers.
func (s *stakerV1) changePoolTier(poolPath string, tier uint64, currentTime int64) (uint64, uint64) {
	s.emissionAccessor.MintAndDistributeGns()
	poolTier := s.getPoolTier()
	previousTier := poolTier.CurrentTier(poolPath)

	poolTier.changeTier(runtime.ChainHeight(), currentTime, s.getPools(), poolPath, tier)
	s.updatePoolTier(poolTier)

	return previousTier, tier
}

// removePoolTier internally removes the pool from tier system.
func (s *stakerV1) removePoolTier(poolPath string, currentTime int64) {
	s.emissionAccessor.MintAndDistributeGns()

	poolTier := s.getPoolTier()
	poolTier.changeTier(runtime.ChainHeight(), currentTime, s.getPools(), poolPath, NOT_EMISSION_TARGET_TIER)
	s.updatePoolTier(poolTier)
}

// setWarmUp internally sets the warm-up parameters.
func (s *stakerV1) setWarmUp(pct, timeDuration int64) {
	s.emissionAccessor.MintAndDistributeGns()

	warmupTemplate := s.store.GetWarmupTemplate()
	warmupTemplate = modifyWarmup(warmupTemplate, pctToIndex(pct), timeDuration)

	err := s.store.SetWarmupTemplate(warmupTemplate)
	if err != nil {
		panic(err)
	}
}

// pctToIndex converts percentage to warmup index.
func pctToIndex(pct int64) int {
	switch pct {
	case 30:
		return 0
	case 50:
		return 1
	case 70:
		return 2
	case 100:
		return 3
	default:
		panic("staker.gno__pctToIndex() || pct is not valid")
	}
}

package v1

import (
	"chain"
	"chain/banker"
	"chain/runtime"

	prbac "gno.land/p/gnoswap/rbac"
	"gno.land/p/nt/ufmt"

	"gno.land/r/gnoswap/access"
	"gno.land/r/gnoswap/halt"

	pn "gno.land/r/gnoswap/position"
)

// MintAndStake mints a new liquidity position and immediately stakes it.
//
// Atomic operation combining position creation and staking.
// Saves gas by avoiding separate mint and stake transactions.
// Position NFT transferred directly to staker contract.
//
// Parameters:
//   - token0, token1: Token contract paths
//   - fee: Pool fee tier (500=0.05%, 3000=0.3%, 10000=1%)
//   - tickLower, tickUpper: Price range boundaries
//   - amount0Desired, amount1Desired: Target token amounts
//   - amount0Min, amount1Min: Minimum amounts (slippage protection)
//   - deadline: Transaction expiration timestamp
//   - referrer: Optional referral address
//
// Native token support:
//   - Accepts GNOT via std.OriginSend()
//   - Auto-wraps to WUGNOT for liquidity
//   - Minimum 1 GNOT required
//
// Returns:
//   - positionId: New NFT token ID
//   - liquidity: Amount of liquidity minted
//   - amount0, amount1: Actual tokens deposited
//   - poolPath: Pool identifier
func (s *stakerV1) MintAndStake(
	token0 string,
	token1 string,
	fee uint32,
	tickLower int32,
	tickUpper int32,
	amount0Desired string,
	amount1Desired string,
	amount0Min string,
	amount1Min string,
	deadline int64,
	referrer string,
) (uint64, string, string, string, string) {
	halt.AssertIsNotHaltedStaker()

	stakerAddr := access.MustGetAddress(prbac.ROLE_STAKER.String())

	// if one click native
	if token0 == GNOT_DENOM || token1 == GNOT_DENOM {
		// check sent ugnot
		sent := banker.OriginSend()
		ugnotSent := sent.AmountOf("ugnot")

		// not enough ugnot sent
		if ugnotSent < UGNOT_MIN_DEPOSIT_TO_WRAP {
			panic(ufmt.Errorf(
				"%v: too less ugnot sent(%d), minimum:%d",
				errWugnotMinimum, ugnotSent, UGNOT_MIN_DEPOSIT_TO_WRAP,
			))
		}

		// send it over to position to wrap
		positionAddr := access.MustGetAddress(prbac.ROLE_POSITION.String())
		banker_ := banker.NewBanker(banker.BankerTypeRealmSend)
		banker_.SendCoins(stakerAddr, positionAddr, chain.Coins{{Denom: GNOT_DENOM, Amount: ugnotSent}})
	}

	positionId, liquidity, amount0, amount1 := pn.Mint(
		cross,
		token0,
		token1,
		fee,
		tickLower,
		tickUpper,
		amount0Desired,
		amount1Desired,
		amount0Min,
		amount1Min,
		deadline,
		stakerAddr,
		runtime.PreviousRealm().Address(),
		referrer,
	)

	poolPath := s.StakeToken(positionId, referrer)

	return positionId, liquidity, amount0, amount1, poolPath
}

package v1

import (
	"chain"
	"chain/runtime"
	"errors"

	prbac "gno.land/p/gnoswap/rbac"
	"gno.land/r/gnoswap/access"
	"gno.land/r/gnoswap/common"
	"gno.land/r/gnoswap/halt"

	pf "gno.land/r/gnoswap/protocol_fee"
)

// GetUnstakingFee returns the current unstaking fee rate in basis points.
func (s *stakerV1) GetUnstakingFee() int64 { return s.store.GetUnstakingFee() }

// handleStakingRewardFee calculates and applies the unstaking fee.
func (s *stakerV1) handleStakingRewardFee(
	tokenPath string,
	amount int64,
	internal bool,
) (int64, int64, error) {
	unstakingFee := s.GetUnstakingFee()
	if unstakingFee == 0 {
		return amount, 0, nil
	}

	// Do not change the order of the operation.
	feeAmount := safeMulDivInt64(amount, unstakingFee, 10000)
	if feeAmount < 0 {
		return 0, 0, errors.New("fee amount cannot be negative")
	}

	if feeAmount == 0 {
		return amount, 0, nil
	}

	if internal {
		tokenPath = GNS_PATH
	}

	// external contract has fee
	protocolFeeAddr := access.MustGetAddress(prbac.ROLE_PROTOCOL_FEE.String())
	common.SafeGRC20Transfer(cross, tokenPath, protocolFeeAddr, feeAmount)
	pf.AddToProtocolFee(cross, tokenPath, feeAmount)

	return safeSubInt64(amount, feeAmount), feeAmount, nil
}

// SetUnStakingFee sets the unstaking fee rate in basis points.
// Only admin or governance can call this function.
func (s *stakerV1) SetUnStakingFee(fee int64) {
	halt.AssertIsNotHaltedStaker()

	previousRealm := runtime.PreviousRealm()
	caller := previousRealm.Address()
	access.AssertIsAdminOrGovernance(caller)

	assertIsValidFeeRate(fee)

	prevUnStakingFee := s.GetUnstakingFee()

	err := s.setUnStakingFee(fee)
	if err != nil {
		panic(err)
	}

	chain.Emit(
		"SetUnStakingFee",
		"prevAddr", caller.String(),
		"prevRealm", previousRealm.PkgPath(),
		"prevFee", formatAnyInt(prevUnStakingFee),
		"newFee", formatAnyInt(fee),
	)
}

// setUnStakingFee internally updates the unstaking fee.
func (s *stakerV1) setUnStakingFee(fee int64) error {
	return s.store.SetUnstakingFee(fee)
}

package v1

import (
	"gno.land/p/nt/avl"

	sr "gno.land/r/gnoswap/staker"
)

type IncentivesResolver struct {
	*sr.Incentives
}

func NewIncentivesResolver(incentives *sr.Incentives) *IncentivesResolver {
	return &IncentivesResolver{
		Incentives: incentives,
	}
}

// Get incentive by incentiveId
func (self *IncentivesResolver) Get(incentiveId string) (*sr.ExternalIncentive, bool) {
	return retrieveIncentive(self.IncentiveTrees(), incentiveId)
}

func (self *IncentivesResolver) GetIncentiveResolver(incentiveId string) (*ExternalIncentiveResolver, bool) {
	if incentive, ok := self.Get(incentiveId); ok {
		return NewExternalIncentiveResolver(incentive), true
	}
	return nil, false
}

func retrieveIncentive(tree *avl.Tree, id string) (*sr.ExternalIncentive, bool) {
	value, ok := tree.Get(id)
	if !ok {
		return nil, false
	}
	v, ok := value.(*sr.ExternalIncentive)
	if !ok {
		panic("failed to cast value to *sr.ExternalIncentive")
	}
	return v, true
}

// Create a new external incentive
// Panics if the incentive already exists.
func (self *IncentivesResolver) create(
	creator address,
	incentive *sr.ExternalIncentive,
) {
	self.IncentiveTrees().Set(incentive.IncentiveId(), incentive)
}

// update updates an existing incentive with new information
func (self *IncentivesResolver) update(
	creator address,
	incentive *sr.ExternalIncentive,
) {
	self.IncentiveTrees().Set(incentive.IncentiveId(), incentive)
}

// starts incentive unclaimable period for this pool
func (self *IncentivesResolver) startUnclaimablePeriod(startTimestamp int64) {
	self.UnclaimablePeriods().Set(startTimestamp, int64(0))
}

// ends incentive unclaimable period for this pool
// ignores if currently not in unclaimable period
func (self *IncentivesResolver) endUnclaimablePeriod(endTimestamp int64) {
	startTimestamp := int64(0)
	self.UnclaimablePeriods().ReverseIterate(0, endTimestamp, func(key int64, value any) bool {
		v, ok := value.(int64)
		if !ok {
			panic("failed to cast value to int64")
		}
		if v != 0 {
			// Already ended, no need to update
			// keeping startTimestamp as 0 to indicate this
			return true
		}
		startTimestamp = key
		return true
	})

	if startTimestamp == 0 {
		// No ongoing unclaimable period found
		return
	}

	if startTimestamp == endTimestamp {
		self.UnclaimablePeriods().Remove(startTimestamp)
	} else {
		self.UnclaimablePeriods().Set(startTimestamp, endTimestamp)
	}
}

// calculate unclaimable reward by checking unclaimable periods
func (self *IncentivesResolver) calculateUnclaimableReward(incentiveId string) int64 {
	incentive, ok := self.Get(incentiveId)
	if !ok {
		return 0
	}

	timeDiff := int64(0)

	// Find unclaimable periods that end before or at incentive start
	self.UnclaimablePeriods().ReverseIterate(0, incentive.StartTimestamp(), func(startTimestamp int64, value any) bool {
		endTimestamp, ok := value.(int64)
		if !ok {
			panic("failed to cast value to int64")
		}

		if endTimestamp == 0 {
			endTimestamp = incentive.EndTimestamp()
		}

		if endTimestamp <= incentive.StartTimestamp() {
			return true
		}

		// Calculate duration of unclaimable period that overlaps with incentive period
		duration := calculateUnClaimableDuration(
			startTimestamp,
			endTimestamp,
			incentive.StartTimestamp(),
			incentive.EndTimestamp(),
		)

		timeDiff = safeAddInt64(timeDiff, duration)

		return true
	})

	// Find unclaimable periods that start within incentive period
	self.UnclaimablePeriods().Iterate(incentive.StartTimestamp(), incentive.EndTimestamp(), func(startTimestamp int64, value any) bool {
		endTimestamp, ok := value.(int64)
		if !ok {
			panic("failed to cast value to int64")
		}

		if endTimestamp == 0 {
			endTimestamp = incentive.EndTimestamp()
		}

		// Calculate duration of unclaimable period that overlaps with incentive period
		duration := calculateUnClaimableDuration(
			startTimestamp,
			endTimestamp,
			incentive.StartTimestamp(),
			incentive.EndTimestamp(),
		)
		timeDiff = safeAddInt64(timeDiff, duration)

		// ensures continue iterating through all unclaimable periods
		return false
	})

	return safeMulInt64(timeDiff, incentive.RewardPerSecond())
}

// calculateUnClaimableDuration calculates the duration of overlap between an unclaimable period and incentive period
func calculateUnClaimableDuration(unclaimableStart, unclaimableEnd, incentiveStartTimestamp, incentiveEndTimestamp int64) int64 {
	// Use later timestamp between unclaimable start and incentive start
	startTime := unclaimableStart
	if startTime < incentiveStartTimestamp {
		startTime = incentiveStartTimestamp
	}

	// Use earlier timestamp between unclaimable end and incentive end
	endTime := unclaimableEnd
	if endTime > incentiveEndTimestamp {
		endTime = incentiveEndTimestamp
	}

	// Return 0 if no overlap
	if endTime < startTime {
		return 0
	}

	// Calculate overlap duration
	return safeSubInt64(endTime, startTime)
}

package v1

import (
	"time"

	"gno.land/p/nt/avl"
	"gno.land/p/nt/ufmt"

	i256 "gno.land/p/gnoswap/int256"
	u256 "gno.land/p/gnoswap/uint256"

	"gno.land/r/gnoswap/common"
	sr "gno.land/r/gnoswap/staker"
)

var q128 = u256.MustFromDecimal("340282366920938463463374607431768211456")

// Pools represents the global pool storage
type Pools struct {
	tree *avl.Tree // string poolPath -> pool
}

func NewPools() *Pools {
	return &Pools{
		tree: avl.NewTree(),
	}
}

// Get returns the pool for the given poolPath
func (self *Pools) Get(poolPath string) (*sr.Pool, bool) {
	v, ok := self.tree.Get(poolPath)
	if !ok {
		return nil, false
	}
	p, ok := v.(*sr.Pool)
	if !ok {
		panic(ufmt.Sprintf("failed to cast v to *Pool: %T", v))
	}
	return p, true
}

// GetPoolOrNil returns the pool for the given poolPath, or returns nil if it does not exist
func (self *Pools) GetPoolOrNil(poolPath string) *sr.Pool {
	pool, ok := self.Get(poolPath)
	if !ok {
		return nil
	}
	return pool
}

// set sets the pool for the given poolPath
func (self *Pools) set(poolPath string, pool *sr.Pool) {
	self.tree.Set(poolPath, pool)
}

// Has returns true if the pool exists for the given poolPath
func (self *Pools) Has(poolPath string) bool {
	return self.tree.Has(poolPath)
}

func (self *Pools) IterateAll(fn func(key string, pool *sr.Pool) bool) {
	self.tree.Iterate("", "", func(key string, value any) bool {
		p, ok := value.(*sr.Pool)
		if !ok {
			panic(ufmt.Sprintf("failed to cast value to *Pool: %T", value))
		}
		return fn(key, p)
	})
}

type PoolResolver struct {
	*sr.Pool
}

func (self *PoolResolver) IncentivesResolver() *IncentivesResolver {
	return NewIncentivesResolver(self.Incentives())
}

// Get the latest global reward ratio accumulation in [0, currentTime] range.
// Returns the time and the accumulation.
func (self *PoolResolver) CurrentGlobalRewardRatioAccumulation(currentTime int64) (time int64, acc *u256.Uint) {
	acc = u256.Zero()

	self.GlobalRewardRatioAccumulation().ReverseIterate(0, currentTime, func(key int64, value any) bool {
		time = key
		v, ok := value.(*u256.Uint)
		if !ok {
			panic(ufmt.Sprintf("failed to cast value to *u256.Uint: %T", value))
		}
		acc = v
		return true
	})
	if acc == nil {
		panic("should not happen, globalRewardRatioAccumulation must be set when pool is created")
	}
	return time, acc
}

// Get the latest tick in [0, currentTime] range.
// Returns the tick.
func (self *PoolResolver) CurrentTick(currentTime int64) (tick int32) {
	self.HistoricalTick().ReverseIterate(0, currentTime, func(key int64, value any) bool {
		res, ok := value.(int32)
		if !ok {
			panic(ufmt.Sprintf("failed to cast value to int32: %T", value))
		}
		tick = res
		return true
	})
	return tick
}

func (self *PoolResolver) CurrentStakedLiquidity(currentTime int64) (liquidity *u256.Uint) {
	liquidity = u256.Zero()

	self.StakedLiquidity().ReverseIterate(0, currentTime, func(key int64, value any) bool {
		res, ok := value.(*u256.Uint)
		if !ok {
			panic(ufmt.Sprintf("failed to cast value to *u256.Uint: %T", value))
		}
		liquidity = res
		return true
	})
	return liquidity
}

func (self *PoolResolver) TickResolver(tickId int32) *TickResolver {
	return NewTickResolver(self.Ticks().Get(tickId))
}

// IsExternallyIncentivizedPool returns true if the pool has any active external incentives.
func (self *PoolResolver) IsExternallyIncentivizedPool() bool {
	currentTime := time.Now().Unix()
	hasIncentive := false
	self.Incentives().IncentiveTrees().Iterate("", "", func(key string, value any) bool {
		incentive, ok := value.(*sr.ExternalIncentive)
		if !ok {
			panic("failed to cast value to *ExternalIncentive")
		}

		resolver := NewExternalIncentiveResolver(incentive)
		if !resolver.IsEnded(currentTime) {
			hasIncentive = true
			return true
		}

		return false
	})

	return hasIncentive
}

// Get the latest reward in [0, currentTime] range.
// Returns the reward.
func (self *PoolResolver) CurrentReward(currentTime int64) (reward int64) {
	self.RewardCache().ReverseIterate(0, currentTime, func(key int64, value any) bool {
		res, ok := value.(int64)
		if !ok {
			panic(ufmt.Sprintf("failed to cast value to int64: %T", value))
		}
		reward = res
		return true
	})
	return reward
}

// cacheReward sets the current reward for the pool
// If the pool is in unclaimable period, it will end the unclaimable period, updates the reward, and start the unclaimable period again.
//
// Important behavior for initial tier assignment:
// - When a pool first receives a tier, oldTierReward=0 and currentTierReward>0
// - If the pool has zero liquidity at this point, startUnclaimablePeriod() is called
// - This ensures unclaimable period tracking begins from the moment rewards start emitting
func (self *PoolResolver) cacheReward(currentTime int64, currentTierReward int64) {
	oldTierReward := self.CurrentReward(currentTime)
	if oldTierReward == currentTierReward {
		return
	}

	isInUnclaimable := self.CurrentStakedLiquidity(currentTime).IsZero()
	if isInUnclaimable {
		// End any existing unclaimable period
		// Note: If lastUnclaimableTime is 0 (not yet tracking), this is a no-op
		self.endUnclaimablePeriod(currentTime)
	}

	self.RewardCache().Set(currentTime, currentTierReward)

	if isInUnclaimable {
		// Start/restart unclaimable period tracking
		// This handles initial tier assignment when lastUnclaimableTime is 0
		self.startUnclaimablePeriod(currentTime)
	}
}

// cacheInternalReward caches the current emission and updates the global reward ratio accumulation.
func (self *PoolResolver) cacheInternalReward(currentTime int64, currentEmission int64) {
	self.cacheReward(currentTime, currentEmission)

	currentStakedLiquidity := self.CurrentStakedLiquidity(currentTime)
	self.updateGlobalRewardRatioAccumulation(currentTime, currentStakedLiquidity)
}

func (self *PoolResolver) calculateGlobalRewardRatioAccumulation(currentTime int64, currentStakedLiquidity *u256.Uint) *u256.Uint {
	oldAccTime, oldAcc := self.CurrentGlobalRewardRatioAccumulation(currentTime)
	timeDiff := safeSubInt64(currentTime, oldAccTime)
	if timeDiff == 0 {
		return oldAcc.Clone()
	}
	if timeDiff < 0 {
		panic("time cannot go backwards")
	}

	if currentStakedLiquidity.IsZero() {
		return oldAcc.Clone()
	}

	acc := u256.MulDiv(
		u256.NewUintFromInt64(timeDiff),
		q128,
		currentStakedLiquidity,
	)
	return u256.Zero().Add(oldAcc, acc)
}

// updateGlobalRewardRatioAccumulation updates the global reward ratio accumulation and returns the new accumulation.
func (self *PoolResolver) updateGlobalRewardRatioAccumulation(currentTime int64, currentStakedLiquidity *u256.Uint) *u256.Uint {
	newAcc := self.calculateGlobalRewardRatioAccumulation(currentTime, currentStakedLiquidity)

	self.GlobalRewardRatioAccumulation().Set(currentTime, newAcc)
	return newAcc
}

// RewardStateOf initializes a new RewardState for the given deposit.
func (self *PoolResolver) RewardStateOf(deposit *sr.Deposit) *RewardState {
	warmups := len(deposit.Warmups())
	result := &RewardState{
		pool:      self,
		deposit:   NewDepositResolver(deposit),
		rewards:   make([]int64, warmups),
		penalties: make([]int64, warmups),
	}

	for i := range result.rewards {
		result.rewards[i] = 0
		result.penalties[i] = 0
	}

	return result
}

// reset clears cached rewards/penalties so a RewardState can be reused without re-allocating.
func (self *RewardState) reset() {
	for i := range self.rewards {
		self.rewards[i] = 0
		self.penalties[i] = 0
	}
}

// NewPool creates a new pool with the given poolPath and currentHeight.
func NewPoolResolver(pool *sr.Pool) *PoolResolver {
	return &PoolResolver{
		Pool: pool,
	}
}

// RewardState is a struct for storing the intermediate state for reward calculation.
type RewardState struct {
	pool    *PoolResolver
	deposit *DepositResolver

	// accumulated rewards for each warmup
	rewards   []int64
	penalties []int64
}

// calculateInternalReward calculates the internal reward for the deposit.
// It calls rewardPerWarmup for each rewardCache interval, applies warmup, and returns the rewards and penalties.
func (self *RewardState) calculateInternalReward(startTime, endTime int64) ([]int64, []int64) {
	currentReward := self.pool.CurrentReward(startTime)

	self.pool.RewardCache().Iterate(startTime, endTime, func(key int64, value any) bool {
		reward, ok := value.(int64)
		if !ok {
			panic(ufmt.Sprintf("failed to cast value to int64: %T", value))
		}

		// Calculate reward for the period before this cache entry
		err := self.rewardPerWarmup(startTime, key, currentReward)
		if err != nil {
			panic(err)
		}

		startTime = key
		currentReward = reward
		return false
	})

	if startTime < endTime {
		// For the remaining period, use the last cached reward value
		// If the pool was de-tiered and the last cached value is 0, this ensures no new rewards
		err := self.rewardPerWarmup(startTime, endTime, currentReward)
		if err != nil {
			panic(err)
		}
	}

	self.applyWarmup()

	return self.rewards, self.penalties
}

// updateExternalReward updates the external reward for the deposit.
// It updates the last collect time for the external reward for the given incentive ID.
// It returns an error if the current time is less than the last collect time for the external reward for the given incentive ID.
func (self *RewardState) updateExternalReward(startTime, endTime int64, incentive *sr.ExternalIncentive) error {
	lastCollectTime := self.deposit.ExternalRewardLastCollectTime(incentive.IncentiveId())
	if startTime < lastCollectTime {
		// This must not happen, but adding some guards just in case.
		startTime = lastCollectTime
	}

	ictvStart := incentive.StartTimestamp()
	if endTime < ictvStart {
		return nil // Not started yet
	}

	if startTime < ictvStart {
		startTime = ictvStart
	}

	ictvEnd := incentive.EndTimestamp()
	if endTime > ictvEnd {
		endTime = ictvEnd
	}

	if startTime > ictvEnd {
		return nil // Already ended
	}

	return self.rewardPerWarmup(startTime, endTime, incentive.RewardPerSecond())
}

// calculateCollectableExternalReward calculates the calculated external reward for the deposit.
// It calls updateExternalReward for the incentive period, applies warmup and returns the rewards and penalties.
// used for reward calculation for a calculatable incentive
func (self *RewardState) calculateCollectableExternalReward(startTime, endTime int64, incentive *sr.ExternalIncentive) int64 {
	err := self.updateExternalReward(startTime, endTime, incentive)
	if err != nil {
		panic(err)
	}

	currentReward := u256.Zero()

	for i := range self.rewards {
		currentReward = currentReward.Add(currentReward, u256.NewUintFromInt64(self.rewards[i]))
	}

	return safeConvertToInt64(currentReward)
}

// calculateExternalReward calculates the external reward for the deposit.
// It calls rewardPerWarmup for startTime to endTime(clamped to the incentive period), applies warmup and returns the rewards and penalties.
func (self *RewardState) calculateExternalReward(startTime, endTime int64, incentive *sr.ExternalIncentive) ([]int64, []int64) {
	err := self.updateExternalReward(startTime, endTime, incentive)
	if err != nil {
		panic(err)
	}

	// apply warmup to collect rewards
	self.applyWarmup()

	return self.rewards, self.penalties
}

// applyWarmup applies the warmup to the rewards and calculate penalties.
func (self *RewardState) applyWarmup() {
	for i, warmup := range self.deposit.Warmups() {
		warmupReward := self.rewards[i]

		// calculate warmup reward applying warmup ratio
		self.rewards[i] = safeMulInt64(warmupReward, int64(warmup.WarmupRatio)) / 100

		// warmup penalty is the difference between the warmup reward and the warmup reward applying warmup ratio
		self.penalties[i] = safeSubInt64(warmupReward, self.rewards[i])
	}
}

// rewardPerWarmup calculates the reward for each warmup, adds to the RewardState's rewards array.
func (self *RewardState) rewardPerWarmup(startTime, endTime int64, rewardPerSecond int64) error {
	// Return early if startTime equals endTime to avoid unnecessary computation
	if startTime == endTime {
		return nil
	}

	for i, warmup := range self.deposit.Warmups() {
		if startTime >= warmup.NextWarmupTime {
			// passed the warmup
			continue
		}

		if endTime < warmup.NextWarmupTime {
			rewardAcc := self.pool.CalculateRewardForPosition(
				startTime,
				self.pool.CurrentTick(startTime),
				endTime,
				self.pool.CurrentTick(endTime),
				self.deposit.Deposit,
			)

			rewardAcc = u256.Zero().Mul(rewardAcc, self.deposit.Liquidity())
			rewardAcc = u256.MulDiv(rewardAcc, u256.NewUintFromInt64(rewardPerSecond), q128)
			self.rewards[i] = safeAddInt64(self.rewards[i], safeConvertToInt64(rewardAcc))

			break
		}

		rewardAcc := self.pool.CalculateRewardForPosition(
			startTime,
			self.pool.CurrentTick(startTime),
			warmup.NextWarmupTime,
			self.pool.CurrentTick(warmup.NextWarmupTime),
			self.deposit.Deposit,
		)

		rewardAcc = u256.Zero().Mul(rewardAcc, self.deposit.Liquidity())
		rewardAcc = u256.MulDiv(rewardAcc, u256.NewUintFromInt64(rewardPerSecond), q128)
		self.rewards[i] = safeAddInt64(self.rewards[i], safeConvertToInt64(rewardAcc))

		startTime = warmup.NextWarmupTime
	}

	return nil
}

// modifyDeposit updates the pool's staked liquidity and returns the new staked liquidity.
// updates when there is a change in the staked liquidity(tick cross, stake, unstake)
func (self *PoolResolver) modifyDeposit(delta *i256.Int, currentTime int64, nextTick int32) *u256.Uint {
	// update staker side pool info
	lastStakedLiquidity := self.CurrentStakedLiquidity(currentTime)
	deltaApplied := common.LiquidityMathAddDelta(lastStakedLiquidity, delta)
	result := self.updateGlobalRewardRatioAccumulation(currentTime, lastStakedLiquidity)

	// historical tick does NOT actually reflect the tick at the timestamp, but it provides correct ordering for the staked positions
	// because TickCrossHook is assured to be called for the staked-initialized ticks
	self.HistoricalTick().Set(currentTime, nextTick)

	switch deltaApplied.Sign() {
	case -1:
		panic("stakedLiquidity is less than 0, should not happen")
	case 0:
		if lastStakedLiquidity.Sign() == 1 {
			// StakedLiquidity moved from positive to zero, start unclaimable period
			self.startUnclaimablePeriod(currentTime)
			self.IncentivesResolver().startUnclaimablePeriod(currentTime)
		}
	case 1:
		if lastStakedLiquidity.Sign() == 0 {
			// StakedLiquidity moved from zero to positive, end unclaimable period
			self.endUnclaimablePeriod(currentTime)
			self.IncentivesResolver().endUnclaimablePeriod(currentTime)
		}
	}

	self.Pool.StakedLiquidity().Set(currentTime, deltaApplied)

	return result
}

// startUnclaimablePeriod starts the unclaimable period.
func (self *PoolResolver) startUnclaimablePeriod(currentTime int64) {
	if self.LastUnclaimableTime() == 0 {
		// We set only if it's the first time entering(0 indicates not set yet)
		self.SetLastUnclaimableTime(currentTime)
	}
}

// endUnclaimablePeriod ends the unclaimable period.
// Accumulates to unclaimableAcc and resets lastUnclaimableTime to 0.
func (self *PoolResolver) endUnclaimablePeriod(currentTime int64) {
	if self.LastUnclaimableTime() == 0 {
		// lastUnclaimableTime = 0 means tracking hasn't started yet
		// This is normal during initial pool creation or when called from cacheReward
		// during tier assignment with zero liquidity
		return
	}

	self.updateUnclaimableAccumulateRewards(currentTime)
	self.SetLastUnclaimableTime(0)
}

// updateUnclaimableAccumulateRewards ends the unclaimable period.
// Accumulates to unclaimableAcc and resets lastUnclaimableTime to 0.
func (self *PoolResolver) updateUnclaimableAccumulateRewards(currentTime int64) {
	if self.LastUnclaimableTime() >= currentTime {
		return
	}

	unclaimableDuration := safeSubInt64(currentTime, self.LastUnclaimableTime())
	currentUnclaimableReward := safeMulInt64(unclaimableDuration, self.CurrentReward(self.LastUnclaimableTime()))
	self.SetUnclaimableAcc(safeAddInt64(self.UnclaimableAcc(), currentUnclaimableReward))
}

// processUnclaimableReward processes the unclaimable reward and returns the accumulated reward.
// It resets unclaimableAcc to 0 and properly manages lastUnclaimableTime based on pool state.
func (self *PoolResolver) processUnclaimableReward(endTime int64) int64 {
	// Check current pool liquidity state
	isZeroStakedLiquidity := self.CurrentStakedLiquidity(endTime).IsZero()

	if self.LastUnclaimableTime() > 0 {
		// We have an ongoing unclaimable period tracking
		self.updateUnclaimableAccumulateRewards(endTime)

		if isZeroStakedLiquidity {
			// Still unclaimable - accumulate rewards up to endTime
			// Update tracking time for continuing unclaimable period
			self.SetLastUnclaimableTime(endTime)
		} else {
			// Was unclaimable but now has liquidity - properly end the period
			self.SetLastUnclaimableTime(0)
		}
	} else {
		if isZeroStakedLiquidity {
			// No previous tracking but currently unclaimable - this shouldn't normally happen
			// as startUnclaimablePeriod should have been called when liquidity reached 0
			// Start tracking from now
			self.SetLastUnclaimableTime(endTime)
		}
	}

	// Return and reset accumulated unclaimable rewards
	internalUnClaimable := self.UnclaimableAcc()
	self.SetUnclaimableAcc(0)
	return internalUnClaimable
}

// Calculates reward for a position *without* considering debt or warmup
// It calculates the theoretical total reward for the position if it has been staked since the pool creation
func (self *PoolResolver) CalculateRawRewardForPosition(currentTime int64, currentTick int32, deposit *sr.Deposit) *u256.Uint {
	var rewardAcc *u256.Uint

	globalAcc := self.calculateGlobalRewardRatioAccumulation(currentTime, self.CurrentStakedLiquidity(currentTime))

	lowerAcc := self.TickResolver(deposit.TickLower()).CurrentOutsideAccumulation(currentTime)
	upperAcc := self.TickResolver(deposit.TickUpper()).CurrentOutsideAccumulation(currentTime)
	if currentTick < deposit.TickLower() {
		rewardAcc = u256.Zero().Sub(lowerAcc, upperAcc)
	} else if currentTick >= deposit.TickUpper() {
		rewardAcc = u256.Zero().Sub(upperAcc, lowerAcc)
	} else {
		rewardAcc = u256.Zero().Sub(globalAcc, lowerAcc)
		rewardAcc = rewardAcc.Sub(rewardAcc, upperAcc)
	}

	return rewardAcc
}

// Calculate actual reward in [startTime, endTime) for a position by
// subtracting the startTime's raw reward from the endTime's raw reward
func (self *PoolResolver) CalculateRewardForPosition(
	startTime int64,
	startTick int32,
	endTime int64,
	endTick int32,
	deposit *sr.Deposit,
) *u256.Uint {
	rewardAcc := self.CalculateRawRewardForPosition(endTime, endTick, deposit)
	debtAcc := self.CalculateRawRewardForPosition(startTime, startTick, deposit)

	return u256.Zero().Sub(rewardAcc, debtAcc)
}

package v1

import (
	"gno.land/p/nt/avl"

	sr "gno.land/r/gnoswap/staker"
)

const (
	AllTierCount = 4 // 0, 1, 2, 3
	Tier1        = 1
	Tier2        = 2
	Tier3        = 3
)

// TierRatioFromCounts calculates the ratio distribution for each tier based on pool counts.
//
// Parameters:
// - tier1Count (uint64): Number of pools in tier 1.
// - tier2Count (uint64): Number of pools in tier 2.
// - tier3Count (uint64): Number of pools in tier 3.
//
// Returns:
// - TierRatio: The ratio distribution across tier 1, 2, and 3, scaled up by 100.
func TierRatioFromCounts(tier1Count, tier2Count, tier3Count uint64) sr.TierRatio {
	// tier1 always exists
	if tier2Count == 0 && tier3Count == 0 {
		return sr.TierRatio{
			Tier1: 100,
			Tier2: 0,
			Tier3: 0,
		}
	}
	if tier2Count == 0 {
		return sr.TierRatio{
			Tier1: 80,
			Tier2: 0,
			Tier3: 20,
		}
	}
	if tier3Count == 0 {
		return sr.TierRatio{
			Tier1: 70,
			Tier2: 30,
			Tier3: 0,
		}
	}
	return sr.TierRatio{
		Tier1: 50,
		Tier2: 30,
		Tier3: 20,
	}
}

// PoolTier manages pool counts, ratios, and rewards for different tiers.
//
// Fields:
// - membership: Tracks which tier a pool belongs to (poolPath -> blockNumber -> tier).
//
// Methods:
// - CurrentCount: Returns the current count of pools in a tier at a specific timestamp.
// - CurrentRatio: Returns the current ratio for a tier at a specific timestamp.
// - CurrentTier: Returns the tier of a specific pool at a given timestamp.
// - CurrentReward: Retrieves the reward for a tier at a specific timestamp.
// - changeTier: Updates the tier of a pool and recalculates ratios.
type PoolTier struct {
	membership *avl.Tree // poolPath -> tier(1, 2, 3)

	tierRatio sr.TierRatio

	counts [AllTierCount]uint64

	lastRewardCacheTimestamp int64
	lastRewardCacheHeight    int64

	currentEmission int64

	// returns current emission.
	getEmission func() int64
	// Returns a list of halving timestamps and their emission amounts within the interval [start, end) in ascending order.
	// The first return value is a list of timestamps where halving occurs.
	// The second return value is a list of emission amounts corresponding to each halving timestamp.
	getHalvingBlocksInRange func(start, end int64) ([]int64, []int64)
}

// NewPoolTier creates a new PoolTier instance with single initial 1 tier pool.
//
// Parameters:
// - pools: The pool collection.
// - currentHeight: The current block height.
// - initialPoolPath: The path of the initial pool.
// - getEmission: A function that returns the current emission to the staker contract.
// - getHalvingBlocksInRange: A function that returns a list of halving blocks within the interval [start, end) in ascending order.
//
// Returns:
// - *PoolTier: The new PoolTier instance.
func NewPoolTier(pools *Pools, currentHeight int64, currentTime int64, initialPoolPath string, getEmission func() int64, getHalvingBlocksInRange func(start, end int64) ([]int64, []int64)) *PoolTier {
	result := &PoolTier{
		membership:               avl.NewTree(),
		tierRatio:                TierRatioFromCounts(1, 0, 0),
		lastRewardCacheTimestamp: safeAddInt64(currentTime, 1),
		lastRewardCacheHeight:    safeAddInt64(currentHeight, 1),
		getEmission:              getEmission,
		getHalvingBlocksInRange:  getHalvingBlocksInRange,
		currentEmission:          getEmission(),
	}

	pools.set(initialPoolPath, sr.NewPool(initialPoolPath, currentTime+1))
	result.changeTier(currentHeight+1, currentTime+1, pools, initialPoolPath, 1)
	return result
}

func NewPoolTierBy(
	membership *avl.Tree,
	tierRatio sr.TierRatio,
	counts [AllTierCount]uint64,
	lastRewardCacheTimestamp int64,
	lastRewardCacheHeight int64,
	currentEmission int64,
	getEmission func() int64,
	getHalvingBlocksInRange func(start, end int64) ([]int64, []int64),
) *PoolTier {
	return &PoolTier{
		membership:               membership,
		tierRatio:                tierRatio,
		counts:                   counts,
		lastRewardCacheTimestamp: lastRewardCacheTimestamp,
		lastRewardCacheHeight:    lastRewardCacheHeight,
		getEmission:              getEmission,
		getHalvingBlocksInRange:  getHalvingBlocksInRange,
		currentEmission:          currentEmission,
	}
}

// CurrentReward returns the current per-pool reward for the given tier.
func (self *PoolTier) CurrentReward(tier uint64) int64 {
	currentEmission := self.getEmission()
	tierRatio, err := self.tierRatio.Get(tier)
	if err != nil {
		panic(makeErrorWithDetails(errInvalidPoolTier, err.Error()))
	}

	tierRatioInt64 := int64(tierRatio)
	count := int64(self.CurrentCount(tier))

	// Check for zero count to prevent division by zero
	if count == 0 {
		return 0
	}

	tierEmission := safeMulInt64(currentEmission, tierRatioInt64)

	return tierEmission / count / 100
}

// CurrentCount returns the current count of pools in the given tier.
func (self *PoolTier) CurrentCount(tier uint64) int {
	if tier >= AllTierCount {
		return 0
	}
	return int(self.counts[tier])
}

// CurrentAllTierCounts returns the current count of pools in each tier.
func (self *PoolTier) CurrentAllTierCounts() []uint64 {
	out := make([]uint64, AllTierCount)
	copy(out, self.counts[:])
	return out // returning snapshot
}

// CurrentTier returns the tier of the given pool.
func (self *PoolTier) CurrentTier(poolPath string) (tier uint64) {
	if tierI, ok := self.membership.Get(poolPath); !ok {
		return 0
	} else {
		tier, ok = tierI.(uint64)
		if !ok {
			panic("failed to cast tier to uint64")
		}
		return tier
	}
}

// changeTier updates the tier of a pool, recalculates ratios, and applies
// updated per-pool reward to each of the pools.
func (self *PoolTier) changeTier(currentHeight int64, currentTime int64, pools *Pools, poolPath string, nextTier uint64) {
	self.cacheReward(currentHeight, currentTime, pools)
	// same as prev. no need to update
	currentTier := self.CurrentTier(poolPath)
	if currentTier == nextTier {
		// no change, return
		return
	}

	// decrement count from current tier if it exists
	if currentTier > 0 {
		if self.counts[currentTier] == 0 {
			panic("counts underflow: removing from empty tier")
		}
		self.counts[currentTier]--
	}

	if nextTier == 0 {
		// removed from the tier
		self.membership.Remove(poolPath)
		pool, ok := pools.Get(poolPath)
		if !ok {
			panic("changeTier: pool not found")
		}
		poolResolver := NewPoolResolver(pool)
		// prevent new rewards from accumulating after tier removal
		poolResolver.cacheReward(currentTime, 0)
	} else {
		// handle all move/add operations
		self.membership.Set(poolPath, nextTier)
		self.counts[nextTier]++
	}

	self.tierRatio = TierRatioFromCounts(self.counts[Tier1], self.counts[Tier2], self.counts[Tier3])
	currentEmission := self.getEmission()
	tierRewards := self.computeTierRewards(currentEmission)

	// Cache updated reward for each tiered pool
	self.membership.Iterate("", "", func(key string, value any) bool {
		pool, ok := pools.Get(key)
		if !ok {
			panic("changeTier: pool not found")
		}
		tier, ok := value.(uint64)
		if !ok {
			panic("failed to cast value to uint64")
		}

		poolReward, ok := tierRewards[tier]
		if !ok {
			return false // Skip if no pools in tier
		}

		poolResolver := NewPoolResolver(pool)
		poolResolver.cacheReward(currentTime, poolReward)
		return false
	})

	self.currentEmission = currentEmission
}

// cacheReward MUST be called before calculating any position reward.
// cacheReward updates the reward cache for each pool, accounting for any halving events
// that occurred between the last cached timestamp and the current timestamp.
// Note: Block height is used only for event tracking purposes.
func (self *PoolTier) cacheReward(currentHeight int64, currentTimestamp int64, pools *Pools) {
	lastTimestamp := self.lastRewardCacheTimestamp

	if currentTimestamp <= lastTimestamp {
		// no need to check
		return
	}

	// find halving blocks in range
	halvingTimestamps, halvingEmissions := self.getHalvingBlocksInRange(lastTimestamp, currentTimestamp)

	if len(halvingTimestamps) == 0 {
		self.applyCacheToAllPools(pools, currentTimestamp, self.currentEmission)
		self.lastRewardCacheTimestamp = currentTimestamp
		return
	}

	for i, hvTimestamp := range halvingTimestamps {
		emission := halvingEmissions[i]
		// caching: [lastTimestamp, hvTimestamp)
		self.applyCacheToAllPools(pools, hvTimestamp, emission)

		// halve emissions when halvingBlock is reached
		self.currentEmission = emission
	}

	// remaining range [lastTimestamp, currentTimestamp)
	self.applyCacheToAllPools(pools, currentTimestamp, self.currentEmission)

	// update lastRewardCacheHeight and currentEmission
	self.lastRewardCacheTimestamp = currentTimestamp
	self.lastRewardCacheHeight = currentHeight
}

// applyCacheToAllPools applies the cached reward to all tiered pools.
func (self *PoolTier) applyCacheToAllPools(pools *Pools, currentTimestamp, emissionInThisInterval int64) {
	// calculate denominator and number of pools in each tier
	counts := self.CurrentAllTierCounts()
	tierRewards := self.computeTierRewards(emissionInThisInterval)

	// apply cache to all pools
	self.membership.Iterate("", "", func(key string, value any) bool {
		pool, ok := pools.Get(key)
		if !ok {
			return false
		}

		tierNum, ok := value.(uint64)
		if !ok {
			panic("failed to cast value to uint64")
		}
		// Skip pools with tier 0 (removed from tier system)
		if tierNum == 0 {
			return false
		}

		if counts[tierNum] == 0 {
			return false // Skip if no pools in tier
		}

		poolReward, ok := tierRewards[tierNum]
		if !ok {
			return false
		}

		// accumulate the reward for the interval (startBlock to endBlock) in the Pool
		poolResolver := NewPoolResolver(pool)
		poolResolver.cacheInternalReward(currentTimestamp, poolReward)
		return false
	})
}

// IsInternallyIncentivizedPool returns true if the pool is in a tier.
func (self *PoolTier) IsInternallyIncentivizedPool(poolPath string) bool {
	return self.CurrentTier(poolPath) > 0
}

func (self *PoolTier) CurrentRewardPerPool(poolPath string) int64 {
	tierNum := self.CurrentTier(poolPath)
	if tierNum == 0 {
		return 0 // Pool not in any tier
	}

	tierRatio, err := self.tierRatio.Get(tierNum)
	if err != nil {
		panic(makeErrorWithDetails(errInvalidPoolTier, err.Error()))
	}
	tierRatioInt64 := int64(tierRatio)

	counts := self.CurrentAllTierCounts()
	tierCount := int64(counts[tierNum])
	if tierCount == 0 {
		return 0 // No pools in tier
	}

	return calculatePoolReward(self.getEmission(), tierRatioInt64, tierCount)
}

// calculatePoolReward calculates the reward for a pool based on the emission, tier ratio, and tier count.
//
// Parameters:
// - emission: The emission for the pool.
// - tierRatio: The tier ratio for the pool.
// - tierCount: The tier count for the pool.
//
// Returns:
// - int64: The reward for the pool.
func calculatePoolReward(emission int64, tierRatio int64, tierCount int64) int64 {
	if emission < 0 || tierRatio < 0 || tierCount < 0 {
		panic(errCalculationError)
	}

	if emission == 0 || tierRatio == 0 || tierCount == 0 {
		return 0
	}

	tierReward := safeMulDivInt64(emission, tierRatio, 100)

	return tierReward / tierCount
}

// computeTierRewards caches per-tier pool rewards to avoid recalculating for each pool iteration.
func (self *PoolTier) computeTierRewards(emission int64) map[uint64]int64 {
	tierRewards := make(map[uint64]int64, AllTierCount-1)

	for tierNum := uint64(1); tierNum < AllTierCount; tierNum++ {
		tierCount := int64(self.counts[tierNum])
		if tierCount == 0 {
			continue
		}

		tierRatio, err := self.tierRatio.Get(tierNum)
		if err != nil {
			panic(makeErrorWithDetails(errInvalidPoolTier, err.Error()))
		}

		tierRewards[tierNum] = calculatePoolReward(emission, int64(tierRatio), tierCount)
	}

	return tierRewards
}

package v1

import (
	"chain"
	"chain/runtime"
	"strings"

	i256 "gno.land/p/gnoswap/int256"
	u256 "gno.land/p/gnoswap/uint256"

	"gno.land/r/gnoswap/common"
	sr "gno.land/r/gnoswap/staker"
)

var zeroUint256 = u256.Zero()

type TickResolver struct {
	*sr.Tick
}

// CurrentOutsideAccumulation returns the latest outside accumulation for the tick
func (self *TickResolver) CurrentOutsideAccumulation(timestamp int64) *u256.Uint {
	acc := u256.Zero()
	self.OutsideAccumulation().ReverseIterate(0, timestamp, func(key int64, value any) bool {
		v, ok := value.(*u256.Uint)
		if !ok {
			panic("failed to cast value to *u256.Uint")
		}
		acc = v
		return true
	})
	if acc == nil {
		acc = u256.Zero()
	}
	return acc
}

// modifyDepositLower updates the tick's liquidity info by treating the deposit as a lower tick
func (self *TickResolver) modifyDepositLower(currentTime int64, liquidity *i256.Int) {
	// update staker side tick info
	self.SetStakedLiquidityGross(common.LiquidityMathAddDelta(self.StakedLiquidityGross(), liquidity))
	if self.StakedLiquidityGross().Lt(zeroUint256) {
		panic("stakedLiquidityGross is negative")
	}
	self.SetStakedLiquidityDelta(i256.Zero().Add(self.StakedLiquidityDelta(), liquidity))
}

// modifyDepositUpper updates the tick's liquidity info by treating the deposit as an upper tick
func (self *TickResolver) modifyDepositUpper(currentTime int64, liquidity *i256.Int) {
	self.SetStakedLiquidityGross(common.LiquidityMathAddDelta(self.StakedLiquidityGross(), liquidity))
	if self.StakedLiquidityGross().Lt(zeroUint256) {
		panic("stakedLiquidityGross is negative")
	}
	self.SetStakedLiquidityDelta(i256.Zero().Sub(self.StakedLiquidityDelta(), liquidity))
}

// updateCurrentOutsideAccumulation updates the tick's outside accumulation
// It "flips" the accumulation's inside/outside by subtracting the current outside accumulation from the global accumulation
func (self *TickResolver) updateCurrentOutsideAccumulation(timestamp int64, acc *u256.Uint) {
	currentOutsideAccumulation := self.CurrentOutsideAccumulation(timestamp)
	newOutsideAccumulation := u256.Zero().Sub(acc, currentOutsideAccumulation)
	self.OutsideAccumulation().Set(timestamp, newOutsideAccumulation)
}

func NewTickResolver(tick *sr.Tick) *TickResolver {
	return &TickResolver{
		Tick: tick,
	}
}

// swapStartHook is called when a swap starts
// This hook initializes the batch processor for accumulating tick crosses
func (s *stakerV1) swapStartHook(poolPath string, timestamp int64) {
	pool, ok := s.getPools().Get(poolPath)
	if !ok {
		return
	}

	// Initialize batch processor for this swap
	// This will accumulate all tick crosses until swap completion
	currentSwapBatch := sr.NewSwapBatchProcessor(poolPath, pool, timestamp)
	err := s.store.SetCurrentSwapBatch(currentSwapBatch)
	if err != nil {
		panic(err)
	}
}

// swapEndHook is called when a swap ends
// This hook processes all accumulated tick crosses in a single batch operation
// and cleans up the batch processor. The batch processing approach provides:
// 1. O(1) pool state updates instead of O(n) where n = number of tick crosses
// 2. Reduced computational overhead for reward calculations
// 3. Atomic processing ensuring consistency across all tick updates
func (s *stakerV1) swapEndHook(poolPath string) error {
	// Validate batch processor state
	currentSwapBatch := s.store.GetCurrentSwapBatch()

	if currentSwapBatch == nil || !currentSwapBatch.IsActive() || currentSwapBatch.PoolPath() != poolPath {
		return nil
	}

	// Disable further accumulation
	currentSwapBatch.SetIsActive(false)

	// Process all accumulated tick crosses in a single batch
	// This is where the optimization happens - instead of processing
	// each tick cross individually, we calculate cumulative effects
	err := s.processBatchedTickCrosses()
	if err != nil {
		return err
	}

	// Clean up batch processor
	err = s.store.SetCurrentSwapBatch(nil)
	if err != nil {
		return err
	}

	return nil
}

// tickCrossHook is called when a tick is crossed
// This hook implements intelligent routing between batch processing and immediate processing:
// - During swaps: accumulates tick crosses for batch processing at swap end
// - Outside swaps: processes tick crosses immediately for real-time updates
// The hybrid approach optimizes for both swap performance and non-swap responsiveness
func (s *stakerV1) tickCrossHook(poolPath string, tickId int32, zeroForOne bool, timestamp int64) {
	pool, ok := s.getPools().Get(poolPath)
	if !ok {
		return
	}

	tick := pool.Ticks().Get(tickId)

	// Skip ticks with zero staked liquidity (no reward impact)
	if tick.StakedLiquidityDelta().Sign() == 0 {
		return
	}

	currentSwapBatch := s.store.GetCurrentSwapBatch()
	// Batch processing path: accumulate tick crosses during active swap
	if currentSwapBatch != nil && currentSwapBatch.IsActive() && currentSwapBatch.PoolPath() == poolPath {
		// Pre-calculate liquidity delta with direction consideration
		// zeroForOne swap: liquidity delta is negated (liquidity being removed from current tick)
		liquidityDelta := tick.StakedLiquidityDelta()
		if zeroForOne {
			liquidityDelta = i256.Zero().Neg(liquidityDelta)
		}

		// Accumulate this tick cross for batch processing
		currentSwapBatch.AddCross(sr.NewSwapTickCross(tickId, zeroForOne, liquidityDelta))
		return
	}

	// Immediate processing path: handle tick crosses outside of swap context
	// This ensures real-time updates for non-swap operations (e.g., position modifications)
	s.processTickCrossImmediate(pool, tick, tickId, zeroForOne, timestamp)
}

// processTickCrossImmediate processes a single tick cross immediately
// This function handles individual tick crosses for non-swap operations
// where batch processing is not applicable (e.g., position modifications, liquidations)
func (s *stakerV1) processTickCrossImmediate(pool *sr.Pool, tick *sr.Tick, tickId int32, zeroForOne bool, timestamp int64) {
	// Calculate the effective tick position after crossing
	// For zeroForOne swaps, liquidity becomes effective one tick lower
	nextTick := tickId
	if zeroForOne {
		nextTick-- // Move to the lower tick where liquidity becomes active
	}

	// Calculate liquidity delta with direction consideration
	liquidityDelta := tick.StakedLiquidityDelta()
	if zeroForOne {
		// Negate delta for zeroForOne direction (liquidity being removed from current range)
		liquidityDelta = i256.Zero().Neg(liquidityDelta)
	}

	// Update pool's cumulative deposit with the liquidity change
	poolResolver := NewPoolResolver(pool)
	newAcc := poolResolver.modifyDeposit(liquidityDelta, timestamp, nextTick)

	// Update the tick's outside accumulation for reward calculations
	// This ensures proper reward distribution tracking across tick boundaries
	tickResolver := NewTickResolver(tick)
	tickResolver.updateCurrentOutsideAccumulation(timestamp, newAcc)
}

// processBatchedTickCrosses processes all accumulated tick crosses at once
// This is the core optimization function that processes multiple tick crosses in a single operation.
// Instead of updating pool state for each tick cross individually (O(n) operations),
// it calculates the cumulative effect and applies it once (O(1) pool updates + O(n) tick updates).
func (s *stakerV1) processBatchedTickCrosses() error {
	// Early exit for empty batches
	currentSwapBatch := s.store.GetCurrentSwapBatch()
	if currentSwapBatch == nil || len(currentSwapBatch.Crosses()) == 0 {
		return nil
	}

	// Validate pool reference
	if currentSwapBatch.Pool() == nil {
		return errPoolNotFound
	}

	batch := currentSwapBatch
	timestamp := batch.Timestamp()

	// Phase 1: Calculate cumulative liquidity delta across all tick crosses
	// This replaces multiple individual pool updates with a single cumulative update
	cumulativeDelta := i256.Zero()
	for _, tickCross := range batch.Crosses() {
		newDelta := cumulativeDelta.Add(cumulativeDelta, tickCross.Delta())
		cumulativeDelta = newDelta
	}

	// Phase 2: Determine the effective tick position for pool state update
	// Use the last crossed tick as the reference point for cumulative changes
	lastCross := batch.LastCross()
	if lastCross == nil {
		return nil
	}

	lastTick := lastCross.TickID()
	if lastCross.ZeroForOne() {
		lastTick-- // Adjust for zeroForOne direction
	}

	// Phase 3: Apply cumulative changes to pool state in a single operation
	// This is the key optimization - one pool update instead of many
	poolResolver := NewPoolResolver(batch.Pool())
	newAcc := poolResolver.modifyDeposit(cumulativeDelta, timestamp, lastTick)

	// Phase 4: Update individual tick outside accumulations for reward tracking
	// While we optimize pool updates, each tick still needs its accumulation updated
	// for proper reward distribution calculations
	tickInfos := make([]string, 0, len(batch.Crosses()))

	for _, tickCross := range batch.Crosses() {
		tick := batch.Pool().Ticks().Get(tickCross.TickID())
		tickResolver := NewTickResolver(tick)
		tickResolver.updateCurrentOutsideAccumulation(timestamp, newAcc)

		tickCrossEventInfo := NewTickCrossEventInfo(
			tickCross.TickID(),
			tick.StakedLiquidityGross(),
			tick.StakedLiquidityDelta(),
			tickResolver.CurrentOutsideAccumulation(timestamp),
		)
		tickInfos = append(tickInfos, tickCrossEventInfo.ToString())
	}

	// Emit event with staker-side tick cross information
	previousRealm := runtime.PreviousRealm()
	stakedLiquidity := poolResolver.CurrentStakedLiquidity(timestamp)

	chain.Emit(
		"SwapTickCross",
		"prevAddr", previousRealm.Address().String(),
		"prevRealm", previousRealm.PkgPath(),
		"poolPath", batch.PoolPath(),
		"blockTimestamp", formatAnyInt(timestamp),
		"stakedLiquidity", stakedLiquidity.ToString(),
		"globalRewardRatioAccX128", newAcc.ToString(),
		"crossedTicks", "["+strings.Join(tickInfos, ",")+"]",
	)

	return nil
}

func (s *stakerV1) setupSwapHooks() {
	// Set tick cross hook for pool contract
	s.poolAccessor.SetTickCrossHook(s.tickCrossHook)

	// Set swap start/end hooks for batch processing
	s.poolAccessor.SetSwapStartHook(s.swapStartHook)

	// Set swap end hook for batch processing
	s.poolAccessor.SetSwapEndHook(s.swapEndHook)
}

package v1

import (
	"strconv"
	"strings"

	"gno.land/p/nt/avl"
	"gno.land/p/nt/ufmt"
)

// EncodeUint converts a uint64 number into a zero-padded 20-character string.
//
// Parameters:
// - num (uint64): The number to encode.
//
// Returns:
// - string: A zero-padded string representation of the number.
//
// Example:
// Input: 12345
// Output: "00000000000000012345"
func EncodeUint(num uint64) string {
	// Convert the value to a decimal string.
	s := strconv.FormatUint(num, 10)

	// Zero-pad to a total length of 20 characters.
	zerosNeeded := 20 - len(s)
	return strings.Repeat("0", zerosNeeded) + s
}

func EncodeInt64(num int64) string {
	if num < 0 {
		panic(ufmt.Sprintf("negative value not supported: %d", num))
	}
	return EncodeUint(uint64(num))
}

// DecodeUint converts a zero-padded string back into a uint64 number.
//
// Parameters:
// - s (string): The zero-padded string.
//
// Returns:
// - uint64: The decoded number.
//
// Panics:
// - If the string cannot be parsed into a uint64.
//
// Example:
// Input: "00000000000000012345"
// Output: 12345
func DecodeUint(s string) uint64 {
	num, err := strconv.ParseUint(s, 10, 64)
	if err != nil {
		panic(err)
	}
	return num
}

func DecodeInt64(s string) int64 {
	num, err := strconv.ParseInt(s, 10, 64)
	if err != nil {
		panic(err)
	}
	return num
}

// UintTree is a wrapper around an AVL tree for storing block timestamps as strings.
// Since block timestamps are defined as int64, we take int64 and convert it to uint64 for the tree.
//
// Methods:
// - Get: Retrieves a value associated with a uint64 key.
// - set: Stores a value with a uint64 key.
// - Has: Checks if a uint64 key exists in the tree.
// - remove: Removes a uint64 key and its associated value.
// - Iterate: Iterates over keys and values in a range.
// - ReverseIterate: Iterates in reverse order over keys and values in a range.
type UintTree struct {
	tree *avl.Tree // blockTimestamp -> any
}

// NewUintTree creates a new UintTree instance.
func NewUintTree() *UintTree {
	return &UintTree{
		tree: avl.NewTree(),
	}
}

func (self *UintTree) Get(key int64) (any, bool) {
	v, ok := self.tree.Get(EncodeInt64(key))
	if !ok {
		return nil, false
	}
	return v, true
}

func (self *UintTree) set(key int64, value any) {
	self.tree.Set(EncodeInt64(key), value)
}

func (self *UintTree) Has(key int64) bool {
	return self.tree.Has(EncodeInt64(key))
}

func (self *UintTree) remove(key int64) {
	self.tree.Remove(EncodeInt64(key))
}

func (self *UintTree) Iterate(start, end int64, fn func(key int64, value any) bool) {
	self.tree.Iterate(EncodeInt64(start), EncodeInt64(end), func(key string, value any) bool {
		return fn(DecodeInt64(key), value)
	})
}

func (self *UintTree) ReverseIterate(start, end int64, fn func(key int64, value any) bool) {
	self.tree.ReverseIterate(EncodeInt64(start), EncodeInt64(end), func(key string, value any) bool {
		return fn(DecodeInt64(key), value)
	})
}

package v1

import (
	"math"

	u256 "gno.land/p/gnoswap/uint256"
	"gno.land/p/nt/ufmt"
	sr "gno.land/r/gnoswap/staker"
)

const maxDurationOneYear = int64(365 * 86400) // 31,536,000 seconds

// expected to be called by governance
func modifyWarmup(warmupTemplate []sr.Warmup, index int, timeDuration int64) []sr.Warmup {
	if index >= len(warmupTemplate) {
		panic(ufmt.Sprintf("index(%d) is out of range", index))
	}

	// Handle negative duration - panic with error
	if timeDuration < 0 {
		panic(ufmt.Sprintf("warmup duration cannot be negative, got %d seconds", timeDuration))
	}

	// Early return for last tier - must always be math.MaxInt64
	if index == len(warmupTemplate)-1 {
		if timeDuration != math.MaxInt64 {
			panic(ufmt.Sprintf("last warmup tier must have duration of math.MaxInt64, got %d", timeDuration))
		}
		// No modification needed as it's already math.MaxInt64
		return warmupTemplate
	}

	// Limit non-final tier durations to 1 year (365 days)
	if timeDuration > maxDurationOneYear {
		panic(ufmt.Sprintf("warmup duration cannot exceed 1 year (365 days), got %d seconds", timeDuration))
	}

	warmupTemplate[index].SetTimeDuration(timeDuration)

	return warmupTemplate
}

func instantiateWarmup(warmupTemplate []sr.Warmup, currentTime int64) []sr.Warmup {
	warmups := make([]sr.Warmup, 0, len(warmupTemplate))
	for i, warmup := range warmupTemplate {
		nextWarmupTime := safeAddTime(currentTime, warmup.TimeDuration)

		warmups = append(warmups, sr.Warmup{
			Index:          warmup.Index,
			TimeDuration:   warmup.TimeDuration,
			NextWarmupTime: nextWarmupTime,
			WarmupRatio:    warmup.WarmupRatio,
		})

		// Only update currentTime if not the last tier
		if i < len(warmupTemplate)-1 {
			currentTime = safeAddTime(currentTime, warmup.TimeDuration)
		}
	}
	return warmups
}

func applyWarmup(warmup sr.Warmup, poolReward int64, positionLiquidity, stakedLiquidity *u256.Uint) (int64, int64) {
	if stakedLiquidity.IsZero() {
		return 0, 0
	}

	divisor := u256.NewUint(100)
	poolRewardUint := u256.NewUintFromInt64(poolReward)
	perPositionReward, overflow := u256.Zero().MulOverflow(poolRewardUint, positionLiquidity)
	if overflow {
		panic(errOverflow)
	}
	perPositionReward = u256.Zero().Div(perPositionReward, stakedLiquidity)

	penaltyRatio := u256.NewUint(100 - warmup.WarmupRatio)
	rewardRatio := u256.NewUint(warmup.WarmupRatio)
	totalReward, overflow := u256.Zero().MulOverflow(perPositionReward, rewardRatio)
	if overflow {
		panic(errOverflow)
	}
	totalReward = u256.Zero().Div(totalReward, divisor)

	totalPenalty, overflow := u256.Zero().MulOverflow(perPositionReward, penaltyRatio)
	if overflow {
		panic(errOverflow)
	}
	totalPenalty = u256.Zero().Div(totalPenalty, divisor)
	return safeConvertToInt64(totalReward), safeConvertToInt64(totalPenalty)
}

// safeAddTime performs safe addition with overflow protection
func safeAddTime(currentTime, duration int64) int64 {
	if duration == math.MaxInt64 {
		return math.MaxInt64
	}

	// Check for overflow before addition
	if currentTime > 0 && duration > math.MaxInt64-currentTime {
		return math.MaxInt64
	}

	return safeAddInt64(currentTime, duration)
}

