	return proposal.ID()
}

// ProposeParameterChange creates a protocol parameter update proposal.
//
// Modifies system parameters through governance.
// Supports multiple parameter changes in single proposal.
// Changes apply atomically on execution.
//
// Parameters:
//   - title: Clear description of changes
//   - description: Rationale and impact analysis
//   - numToExecute: Number of parameter changes
//   - executions: JSON array of changes, each containing:
//   - target: Contract address to modify
//   - function: Function name to call
//   - params: Parameters for the function
//
// Example executions format:
//
//	[{
//	  "target": "gno.land/r/gnoswap/v1/gov",
//	  "function": "SetVotingPeriod",
//	  "params": ["604800"]
//	}]
//
// Requirements:
//   - Valid JSON format for executions
//   - Target contracts must exist
//   - Functions must be governance-callable
//   - Parameters must match function signatures
//
// Returns new proposal ID.
func (gv *governanceV1) ProposeParameterChange(
	title string,
	description string,
	numToExecute int64,
	executions string,
) (newProposalId int64) {
	halt.AssertIsNotHaltedGovernance()

	callerAddress := runtime.PreviousRealm().Address()

	createdAt := time.Now().Unix()
	createdHeight := runtime.ChainHeight()
	gnsBalance := gns.BalanceOf(callerAddress)

	config, ok := gv.getCurrentConfig()
	if !ok {
		panic(errDataNotFound)
	}

	// Clean up inactive user proposals before checking if caller already has an active proposal
	err := gv.removeInactiveUserProposals(callerAddress, createdAt)
	if err != nil {
		panic(err)
	}

	// Check if caller already has an active proposal (one proposal per address)
	if gv.hasActiveProposal(callerAddress, createdAt) {
		panic(errAlreadyActiveProposal)
	}

	// Get snapshot time and total voting weight for proposal creation
	maxVotingWeight, snapshotTime, err := gv.getVotingWeightSnapshot(
		createdAt,
		config.VotingWeightSmoothingDuration,
	)
	if err != nil {
		panic(err)
	}

	// Validate executions before creating proposal to fail fast on invalid handlers
	if err := validateExecutions(numToExecute, executions); err != nil {
		panic(err)
	}

	// Create the parameter change proposal with execution data
	proposal, err := gv.createProposal(
		governance.ParameterChange,
		config,
		maxVotingWeight,
		snapshotTime,
		governance.NewProposalMetadata(title, description),
		NewProposalExecutionData(numToExecute, executions),
		callerAddress,
		gnsBalance,
		createdAt,
		createdHeight,
	)
	if err != nil {
		panic(err)
	}

	// Initialize empty voting info tree for this proposal (votes will be added as users vote)
	err = gv.updateProposalUserVotes(proposal, avl.NewTree())
	if err != nil {
		panic(err)
	}

	// Emit proposal creation event for indexing and tracking
	previousRealm := runtime.PreviousRealm()
	chain.Emit(
		"ProposeParameterChange",
		"prevAddr", previousRealm.Address().String(),
		"prevRealm", previousRealm.PkgPath(),
		"title", title,
		"description", description,
		"numToExecute", formatInt(numToExecute),
		"executions", executions,
		"proposalId", formatInt(proposal.ID()),
		"quorumAmount", formatInt(proposal.VotingQuorumAmount()),
		"maxVotingWeight", formatInt(proposal.VotingMaxWeight()),
		"configVersion", formatInt(proposal.ConfigVersion()),
		"createdAt", formatInt(proposal.CreatedAt()),
	)

	return proposal.ID()
}

// createProposal handles proposal creation logic.
// Validates input data, checks proposer eligibility, and creates proposal object.
func (gv *governanceV1) createProposal(
	proposalType governance.ProposalType,
	config governance.Config,
	maxVotingWeight int64,
	snapshotTime int64,
	proposalMetadata *governance.ProposalMetadata,
	proposalData *governance.ProposalData,
	proposerAddress address,
	proposerGnsBalance int64,
	createdAt int64,
	createdHeight int64,
) (*governance.Proposal, error) {
	// Validate proposal metadata (title and description)
	metadataResolver := NewProposalMetadataResolver(proposalMetadata)
	err := metadataResolver.Validate()
	if err != nil {
		return nil, err
	}

	// Validate proposal data (type-specific validation)
	dataResolver := NewProposalDataResolver(proposalData)
	err = dataResolver.Validate()
	if err != nil {
		return nil, err
	}

	// Check if proposer has enough GNS balance to create proposal
	if proposerGnsBalance < config.ProposalCreationThreshold {
		return nil, errNotEnoughBalance
	}

	// Generate unique proposal ID
	proposalID := gv.nextProposalID()

	// Create proposal status with voting schedule and requirements
	proposalStatus := NewProposalStatus(
		config,
		maxVotingWeight,
		proposalType.IsExecutable(),
		createdAt,
	)

	// Get current configuration version for tracking
	configVersion := gv.getCurrentConfigVersion()

	// Create the proposal object with snapshotTime for lazy voting weight lookup
	proposal := governance.NewProposal(
		proposalID,
		proposalStatus,
		proposalMetadata,
		proposalData,
		proposerAddress,
		configVersion,
		snapshotTime,
		createdAt,
		createdHeight,
	)

	// Store the proposal in state
	success := gv.addProposal(proposal)
	if !success {
		return nil, errDataNotFound
	}

	return proposal, nil
}

// getVotingWeightSnapshot retrieves the averaged total voting weight for proposal creation.
// It uses two snapshots (current and current - smoothingPeriod) and averages them.
func (gv *governanceV1) getVotingWeightSnapshot(
	current,
	smoothingPeriod int64,
) (int64, int64, error) {
	// Calculate snapshot time by going back by smoothing period
	snapshotTime := current - smoothingPeriod
	if snapshotTime < 0 {
		snapshotTime = 0
	}

	// Get total delegation amount at snapshot time from staker contract via accessor
	totalAtSnapshot, ok := gv.stakerAccessor.GetTotalDelegationAmountAtSnapshot(snapshotTime)
	if !ok {
		totalAtSnapshot = 0
	}

	totalAtCurrent, ok := gv.stakerAccessor.GetTotalDelegationAmountAtSnapshot(current)
	if !ok {
		totalAtCurrent = 0
	}

	totalVotingWeight := safeAddInt64(totalAtSnapshot, totalAtCurrent) / 2
	if totalVotingWeight <= 0 {
		return 0, snapshotTime, errNotEnoughVotingWeight
	}

	return totalVotingWeight, snapshotTime, nil
}

package v1

import (
	"chain"
	"chain/runtime"
	"time"

	"gno.land/r/gnoswap/emission"
	"gno.land/r/gnoswap/halt"

	"gno.land/r/gnoswap/gov/governance"
)

// Vote casts a vote on a proposal.
//
// Records on-chain vote with weight based on delegated xGNS.
// Uses 24-hour average voting power to prevent manipulation.
// Votes are final and cannot be changed.
//
// Parameters:
//   - proposalID: ID of the proposal to vote on
//   - yes: true for yes vote, false for no vote
//
// Vote Weight Calculation:
//   - Based on delegated xGNS amount
//   - 24-hour average before proposal creation
//   - Prevents flash loan attacks
//   - Includes both self-stake and delegations received
//
// Requirements:
//   - Proposal must be in voting period
//   - Voter must have xGNS delegated
//   - Cannot vote twice on same proposal
//   - Voting period typically 7 days
//
// Returns voting weight used as string.
func (gv *governanceV1) Vote(proposalID int64, yes bool) string {
	halt.AssertIsNotHaltedGovernance()

	// Get current blockchain state and caller information
	currentHeight := runtime.ChainHeight()
	currentAt := time.Now()

	// Mint and distribute GNS tokens as part of the voting process
	emission.MintAndDistributeGns(cross)

	// Extract voter address from realm context
	voterRealm := runtime.PreviousRealm()
	voter := voterRealm.Address()

	// Process the vote and get updated vote tallies
	userVote, totalYesVoteWeight, totalNoVoteWeight, err := gv.vote(
		proposalID,
		voter,
		yes,
		currentHeight,
		currentAt.Unix(),
	)
	if err != nil {
		panic(err)
	}

	// Emit voting event for tracking and transparency
	// previousRealm := runtime.PreviousRealm()
	userVoteWeight := formatInt(userVote.VotedWeight())
	voterStr := voter.String()

	chain.Emit(
		"Vote",
		"prevAddr", voterStr,
		"prevPkgPath", voterRealm.PkgPath(),
		"proposalId", formatInt(proposalID),
		"voter", voterStr,
		"yes", userVote.VotingType(),
		"voteWeight", userVoteWeight,
		"voteYes", formatInt(totalYesVoteWeight),
		"voteNo", formatInt(totalNoVoteWeight),
	)

	return userVoteWeight
}

// vote handles core voting logic.
func (gv *governanceV1) vote(
	proposalID int64,
	voterAddress address,
	votedYes bool,
	votedHeight,
	votedAt int64,
) (*governance.VotingInfo, int64, int64, error) {
	// Retrieve the proposal from storage
	proposal, ok := gv.getProposal(proposalID)
	if !ok {
		return nil, 0, 0, makeErrorWithDetails(errDataNotFound, "not found proposal")
	}

	proposalResolver := NewProposalResolver(proposal)

	// Check if current time is within voting period
	if !proposalResolver.IsVotingPeriod(votedAt) {
		return nil, 0, 0, makeErrorWithDetails(errUnableToVoteOutOfPeriod, "cannot vote out of voting period")
	}

	// Check if user has already voted on this proposal
	userVote, hasVoted := gv.getProposalUserVotingInfo(proposalID, voterAddress)
	if hasVoted && userVote.IsVoted() {
		return nil, 0, 0, makeErrorWithDetails(errAlreadyVoted, "user has already voted")
	}

	// Get user's voting weight using average between proposal time and snapshot time.
	snapshotTime := proposal.SnapshotTime()
	createdAt := proposal.CreatedAt()

	weightAtSnapshot, ok := gv.stakerAccessor.GetUserDelegationAmountAtSnapshot(voterAddress, snapshotTime)
	if !ok {
		weightAtSnapshot = 0
	}

	weightAtCreated, ok := gv.stakerAccessor.GetUserDelegationAmountAtSnapshot(voterAddress, createdAt)
	if !ok {
		weightAtCreated = 0
	}

	votingWeight := safeAddInt64(weightAtSnapshot, weightAtCreated) / 2
	if votingWeight <= 0 {
		return nil, 0, 0, makeErrorWithDetails(
			errNotEnoughVotingWeight, "no voting weight at snapshot time")
	}

	// Create or update voting info for this user
	if userVote == nil {
		userVote = governance.NewVotingInfo(votingWeight)
	}

	userVoteResolver := NewVotingInfoResolver(userVote)
	// Record the vote in user's voting info (this also prevents double voting)
	err := userVoteResolver.vote(votedYes, votingWeight, votedHeight, votedAt)
	if err != nil {
		return nil, 0, 0, err
	}

	// Store the user's vote in the proposal voting infos
	votingInfosTree, _ := gv.getProposalUserVotingInfos(proposalID)
	if votingInfosTree == nil {
		return nil, 0, 0, makeErrorWithDetails(
			errDataNotFound, "voting infos tree not found for proposal")
	}

	votingInfosTree.Set(voterAddress.String(), userVote)
	err = gv.store.SetProposalVotingInfos(proposalID, votingInfosTree)
	if err != nil {
		return nil, 0, 0, err
	}

	// Update proposal vote tallies
	err = proposalResolver.Vote(votedYes, votingWeight)
	if err != nil {
		return nil, 0, 0, err
	}

	// Return updated vote information and current tallies
	return userVote, proposal.VotingYesWeight(), proposal.VotingNoWeight(), nil
}

package v1

import (
	"strconv"

	"gno.land/p/nt/avl"
	"gno.land/r/gnoswap/gov/governance"
)

var defaultConfig = governance.Config{
	VotingStartDelay:              86400,         // 1 day - delay before voting starts
	VotingPeriod:                  604800,        // 7 days - duration for collecting votes
	VotingWeightSmoothingDuration: 86400,         // 1 day - period for averaging voting weight
	Quorum:                        50,            // 50% of total xGNS supply required
	ProposalCreationThreshold:     1_000_000_000, // 1 billion - minimum balance to create proposals
	ExecutionDelay:                86400,         // 1 day - waiting period before execution
	ExecutionWindow:               2592000,       // 30 days - window for executing proposals
}

func init() {
	registerGovernanceV1()
}

func registerGovernanceV1() {
	governance.RegisterInitializer(cross, func(governanceStore governance.IGovernanceStore, stakerAccessor governance.GovStakerAccessor) governance.IGovernance {
		err := initStoreData(governanceStore)
		if err != nil {
			panic(err)
		}

		return NewGovernanceV1(governanceStore, stakerAccessor)
	})
}

func initStoreData(governanceStore governance.IGovernanceStore) error {
	// Initialize counters if not already set
	if !governanceStore.HasConfigCounterStoreKey() {
		err := governanceStore.SetConfigCounter(governance.NewCounter())
		if err != nil {
			return err
		}
	}

	if !governanceStore.HasProposalCounterStoreKey() {
		err := governanceStore.SetProposalCounter(governance.NewCounter())
		if err != nil {
			return err
		}
	}

	// Initialize Configs with default configuration if not already set
	if !governanceStore.HasConfigsStoreKey() {
		configs := avl.NewTree()
		nextConfigVersion := governanceStore.GetConfigCounter().Next()

		configs.Set(formatConfigKey(nextConfigVersion), defaultConfig)

		err := governanceStore.SetConfigs(configs)
		if err != nil {
			return err
		}
	}

	if !governanceStore.HasProposalsStoreKey() {
		err := governanceStore.SetProposals(avl.NewTree())
		if err != nil {
			return err
		}
	}

	if !governanceStore.HasProposalUserVotingInfosStoreKey() {
		err := governanceStore.SetProposalUserVotingInfos(avl.NewTree())
		if err != nil {
			return err
		}
	}

	if !governanceStore.HasUserProposalsStoreKey() {
		err := governanceStore.SetUserProposals(avl.NewTree())
		if err != nil {
			return err
		}
	}

	return nil
}

func formatConfigKey(version int64) string {
	return strconv.FormatInt(version, 10)
}

package v1

import (
	"gno.land/p/nt/avl"
	"gno.land/p/nt/ufmt"
	"gno.land/r/gnoswap/gov/governance"
)

type governanceV1 struct {
	store          governance.IGovernanceStore
	stakerAccessor governance.GovStakerAccessor
}

func NewGovernanceV1(
	governanceStore governance.IGovernanceStore,
	stakerAccessor governance.GovStakerAccessor,
) governance.IGovernance {
	return &governanceV1{
		store:          governanceStore,
		stakerAccessor: stakerAccessor,
	}
}

// Config version methods
func (g *governanceV1) getCurrentConfigVersion() int64 {
	return g.store.GetConfigCounter().Get()
}

func (g *governanceV1) nextConfigVersion() int64 {
	return g.store.GetConfigCounter().Next()
}

// Proposal ID methods
func (g *governanceV1) getCurrentProposalID() int64 {
	return g.store.GetProposalCounter().Get()
}

func (g *governanceV1) nextProposalID() int64 {
	return g.store.GetProposalCounter().Next()
}

// Config methods
func (g *governanceV1) getConfig(version int64) (governance.Config, bool) {
	return g.store.GetConfig(version)
}

func (g *governanceV1) setConfig(version int64, config governance.Config) error {
	return g.store.SetConfig(version, config)
}

func (g *governanceV1) getCurrentConfig() (governance.Config, bool) {
	return g.getConfig(g.getCurrentConfigVersion())
}

// Proposal methods
func (g *governanceV1) getProposal(id int64) (*governance.Proposal, bool) {
	proposal, exists := g.store.GetProposal(id)
	if !exists {
		return nil, false
	}

	return proposal, true
}

func (g *governanceV1) addProposal(proposal *governance.Proposal) bool {
	// Set the proposal (ID already set in proposal)
	err := g.store.SetProposal(proposal.ID(), proposal)
	if err != nil {
		return false
	}

	// Add to user proposals
	err = g.store.AddUserProposal(proposal.Proposer().String(), proposal.ID())
	if err != nil {
		return false
	}

	return true
}

// User proposals methods
func (g *governanceV1) getUserProposals(user string) []*governance.Proposal {
	proposalIDs, exists := g.store.GetUserProposalIDs(user)
	if !exists {
		return []*governance.Proposal{}
	}

	proposals := make([]*governance.Proposal, 0)

	for _, id := range proposalIDs {
		proposal, exists := g.store.GetProposal(id)
		if !exists {
			continue
		}

		proposals = append(proposals, proposal)
	}

	return proposals
}

func (g *governanceV1) hasActiveProposal(proposerAddress address, current int64) bool {
	proposals := g.getUserProposals(proposerAddress.String())

	return len(proposals) > 0
}

// Remove inactive user proposals
// This function is used to remove inactive proposals from the user proposals list.
// It is used to clean up user's active proposal list when creating a new proposal.
func (g *governanceV1) removeInactiveUserProposals(proposerAddress address, current int64) error {
	proposals := g.getUserProposals(proposerAddress.String())

	for _, proposal := range proposals {
		proposalResolver := NewProposalResolver(proposal)

		if !proposalResolver.IsActive(current) {
			err := g.store.RemoveUserProposal(proposerAddress.String(), proposal.ID())
			if err != nil {
				return err
			}
		}
	}

	return nil
}

// Proposal voting info methods
func (g *governanceV1) getProposalUserVotingInfos(proposalID int64) (*avl.Tree, bool) {
	return g.store.GetProposalVotingInfos(proposalID)
}

func (g *governanceV1) updateProposalUserVotes(proposal *governance.Proposal, userVotingInfos *avl.Tree) error {
	return g.store.SetProposalVotingInfos(proposal.ID(), userVotingInfos)
}

// Helper methods for API
func (g *governanceV1) mustGetProposal(id int64) *governance.Proposal {
	proposal, exists := g.getProposal(id)
	if !exists {
		panic(makeErrorWithDetails(errProposalNotFound, ufmt.Sprintf("proposal(%d) not found", id)))
	}
	return proposal
}

func (g *governanceV1) getProposalUserVotingInfo(proposalID int64, addr address) (*governance.VotingInfo, bool) {
	votingInfosTree, exists := g.getProposalUserVotingInfos(proposalID)
	if !exists {
		return nil, false
	}

	votingInfoRaw, exists := votingInfosTree.Get(addr.String())
	if !exists {
		return nil, false
	}

	votingInfo, ok := votingInfoRaw.(*governance.VotingInfo)
	if !ok {
		return nil, false
	}

	return votingInfo, true
}

