// registerHandlers batch registers all configured handlers into the registry.
// This helper function processes the handler configuration array and adds each handler to the registry.
//
// Parameters:
//   - registry: the parameter registry to add handlers to
//   - handlerOptions: slice of handler configurations to register
func registerHandlers(registry *ParameterRegistry, handlerOptions []*ParameterHandlerOptions) {
	for _, handlerOption := range handlerOptions {
		registry.Register(*handlerOption)
	}
}

// runValidator executes a validator function and converts panics to errors.
func runValidator(fn func()) (err error) {
	defer func() {
		if r := recover(); r != nil {
			if e, ok := r.(error); ok {
				err = e
				return
			}
			err = ufmt.Errorf("%v", r)
		}
	}()

	fn()
	return nil
}

// Basic reusable validators for proposal-time type checking.
var (
	stringValidator = func(s string) error {
		return nil
	}
	boolValidator = func(s string) error {
		return runValidator(func() {
			parseBool(s)
		})
	}
	uint64Validator = func(s string) error {
		return runValidator(func() {
			parseUint64(s)
		})
	}
	addressValidator = func(s string) error {
		// allow zero address
		if s == "" {
			return nil
		}
		return runValidator(func() {
			addr := address(s)
			if !addr.IsValid() {
				panic(ufmt.Sprintf("invalid address: %s", addr))
			}
		})
	}
)

func numberValidator(kind numberKind) paramValidator {
	return func(s string) error {
		return runValidator(func() {
			parseNumber(s, kind)
		})
	}
}

func uint8RangeValidator(name string) paramValidator {
	return func(s string) error {
		return runValidator(func() {
			value := parseInt64(s)
			if value < 0 || value > 255 {
				panic(ufmt.Sprintf("%s out of range: %d", name, value))
			}
		})
	}
}

// validateExecutions validates that all executions in a parameter change proposal
// correspond to registered handlers in the global parameter registry.
// This function performs comprehensive validation including:
// - Basic format validation (count, structure)
// - Handler existence verification in the registry
// - Parameter count validation against handler expectations
//
// Parameters:
//   - numToExecute: number of parameter changes to execute
//   - executions: encoded execution string with parameter changes
//
// Returns:
//   - error: validation error if any execution is invalid
func validateExecutions(numToExecute int64, executions string) error {
	// Validate execution count is positive
	if numToExecute <= 0 {
		return makeErrorWithDetails(
			errInvalidInput,
			"numToExecute is less than or equal to 0",
		)
	}

	// Check if executions string is empty
	if executions == "" {
		return makeErrorWithDetails(
			errInvalidInput,
			"executions is empty",
		)
	}

	// Split execution string into individual messages
	msgs := strings.Split(executions, messageSeparator)
	msgCount := len(msgs)

	// Validate execution count matches message count
	if msgCount != int(numToExecute) {
		return makeErrorWithDetails(
			errInvalidInput,
			ufmt.Sprintf("executions count (%d) does not match numToExecute (%d)", len(msgs), numToExecute),
		)
	}

	// Validate execution count doesn't exceed maximum
	if numToExecute > maxNumberOfExecution {
		return makeErrorWithDetails(
			errInvalidInput,
			ufmt.Sprintf("numToExecute is greater than %d", maxNumberOfExecution),
		)
	}

	// Parse and validate each execution message
	for i, msg := range msgs {
		// Split message into components: pkgPath, function, params
		parts := strings.Split(msg, parameterSeparator)
		if len(parts) != 3 {
			// Provide more helpful error message based on what's wrong
			detail := ufmt.Sprintf("execution[%d]: expected 3 parts (pkgPath, function, params), got %d", i, len(parts))
			return makeErrorWithDetails(
				errInvalidMessageFormat,
				detail,
			)
		}

		pkgPath := parts[0]
		function := parts[1]
		paramStr := parts[2]

		// Validate package path and function are not empty
		if pkgPath == "" {
			return makeErrorWithDetails(
				errInvalidInput,
				ufmt.Sprintf("execution[%d]: package path is empty", i),
			)
		}

		if function == "" {
			return makeErrorWithDetails(
				errInvalidInput,
				ufmt.Sprintf("execution[%d]: function name is empty", i),
			)
		}

		// Check if handler exists in registry
		key := makeHandlerKey(pkgPath, function)
		handler, err := globalParameterRegistry.Handler(key)
		if err != nil {
			return makeErrorWithDetails(
				errInvalidExecution,
				ufmt.Sprintf("execution[%d]: %s (key: %s)", i, err.Error(), key),
			)
		}

		// Validate parameter count matches handler's expected count
		params := []string{}
		if paramStr != "" {
			params = strings.Split(paramStr, ",")
		}

		// Get expected parameter count from handler
		handlerOpts, ok := handler.(*ParameterHandlerOptions)
		if !ok {
			return makeErrorWithDetails(
				errInvalidExecution,
				ufmt.Sprintf("execution[%d]: failed to get handler options", i),
			)
		}

		// Validate parameter types/format ahead of proposal creation
		if err := handlerOpts.ValidateParams(params); err != nil {
			return makeErrorWithDetails(
				errInvalidInput,
				ufmt.Sprintf("execution[%d]: %v", i, err),
			)
		}
	}

	return nil
}

package v1

import (
	"gno.land/r/gnoswap/gov/governance"
)

type ProposalResolver struct {
	*governance.Proposal
	statusResolver   *ProposalStatusResolver
	dataResolver     *ProposalDataResolver
	metadataResolver *ProposalMetadataResolver
}

func NewProposalResolver(proposal *governance.Proposal) *ProposalResolver {
	statusResolver := NewProposalStatusResolver(proposal.Status())
	dataResolver := NewProposalDataResolver(proposal.Data())
	metadataResolver := NewProposalMetadataResolver(proposal.Metadata())
	return &ProposalResolver{
		Proposal:         proposal,
		statusResolver:   statusResolver,
		dataResolver:     dataResolver,
		metadataResolver: metadataResolver,
	}
}

// VotingTotalWeight returns total weight of all votes cast.
func (r *ProposalResolver) VotingTotalWeight() int64 {
	return r.statusResolver.TotalVoteWeight()
}

// IsActive determines if the proposal is currently active (can be voted on or executed).
// A proposal is considered active if it's not rejected, expired, executed, or canceled.
func (r *ProposalResolver) IsActive(current int64) bool {
	// Calculate status once and reuse to avoid redundant computations
	status := r.statusResolver.StatusType(current)

	switch status {
	case governance.StatusRejected,
		governance.StatusExpired,
		governance.StatusExecuted,
		governance.StatusCanceled:
		return false
	case governance.StatusPassed:
		// Text proposals become inactive once they pass (no execution needed)
		return !r.IsTextType()
	default:
		// StatusUpcoming, StatusActive, StatusExecutable are considered active
		return true
	}
}

// Validate performs comprehensive validation of the proposal data and metadata.
// This ensures all proposal components meet requirements before storage.
func (r *ProposalResolver) Validate() error {
	// Validate type-specific proposal data
	if err := r.dataResolver.Validate(); err != nil {
		return err
	}

	// Validate proposal metadata (title and description)
	if err := r.metadataResolver.Validate(); err != nil {
		return err
	}

	return nil
}

// Status returns the current status string of the proposal at the given time.
func (r *ProposalResolver) Status(current int64) string {
	return r.statusResolver.StatusType(current).String()
}

// StatusType returns the current status type of the proposal at the given time.
func (r *ProposalResolver) StatusType(current int64) governance.ProposalStatusType {
	return r.statusResolver.StatusType(current)
}

// IsVotingPeriod checks if the proposal is currently in its voting period.
func (r *ProposalResolver) IsVotingPeriod(votedAt int64) bool {
	return r.StatusType(votedAt) == governance.StatusActive
}

// IsExecutable determines if the proposal can be executed at the given time.
// Only executable proposal types that have passed voting can be executed.
func (r *ProposalResolver) IsExecutable(current int64) bool {
	// Only certain proposal types can be executed
	if !r.dataResolver.ProposalType().IsExecutable() {
		return false
	}

	return r.statusResolver.IsExecutable(current)
}

// CommunityPoolSpendTokenPath returns the token path for community pool spend proposals.
// Returns empty string for other proposal types.
func (r *ProposalResolver) CommunityPoolSpendTokenPath() string {
	if r.Data() == nil {
		return ""
	}

	communityPoolSpend := r.dataResolver.CommunityPoolSpend()
	if communityPoolSpend == nil {
		return ""
	}

	return communityPoolSpend.TokenPath()
}

// vote records a vote for this proposal and updates vote tallies.
// This is an internal method called during voting process.
func (r *ProposalResolver) Vote(votedYes bool, weight int64) error {
	return r.statusResolver.vote(votedYes, weight)
}

// execute marks the proposal as executed and records execution details.
// This method validates execution conditions before proceeding.
func (r *ProposalResolver) execute(
	executedAt, executedHeight int64,
	executedBy address,
) error {
	// Verify proposal is in executable state
	if !r.IsExecutable(executedAt) {
		return errProposalNotExecutable
	}

	// Mark proposal as executed
	return r.statusResolver.execute(executedAt, executedHeight, executedBy)
}

// cancel marks the proposal as canceled and records cancellation details.
// This method validates cancellation conditions before proceeding.
func (r *ProposalResolver) cancel(
	canceledAt, canceledHeight int64,
	canceledBy address,
) error {
	if r.statusResolver.IsCanceled(canceledAt) {
		return errAlreadyCanceledProposal
	}

	if !r.statusResolver.IsUpcoming(canceledAt) {
		return errUnableToCancelVotingProposal
	}

	// Mark proposal as canceled
	return r.statusResolver.cancel(canceledAt, canceledHeight, canceledBy)
}

package v1

import (
	"gno.land/r/gnoswap/gov/governance"
)

type ProposalActionStatusResolver struct {
	*governance.ProposalActionStatus
}

func NewProposalActionStatusResolver(status *governance.ProposalActionStatus) *ProposalActionStatusResolver {
	return &ProposalActionStatusResolver{status}
}

// cancel marks the proposal as canceled and records cancellation details.
// This method validates that the proposal is eligible for cancellation.
//
// Parameters:
//   - canceledAt: timestamp when cancellation occurred
//   - canceledHeight: block height when cancellation occurred
//   - canceledBy: address performing the cancellation
//
// Returns:
//   - error: already canceled error if proposal action status is already canceled
func (p *ProposalActionStatusResolver) cancel(
	canceledAt, canceledHeight int64,
	canceledBy address,
) error {
	if p.Canceled() {
		return errAlreadyCanceledProposal
	}

	// Record cancellation details
	p.SetCanceled(true)
	p.SetCanceledAt(canceledAt)
	p.SetCanceledHeight(canceledHeight)
	p.SetCanceledBy(canceledBy)

	return nil
}

// execute marks the proposal as executed and records execution details.
// This method validates that the proposal is eligible for execution.
//
// Parameters:
//   - executedAt: timestamp when execution occurred
//   - executedHeight: block height when execution occurred
//   - executedBy: address performing the execution
//
// Returns:
//   - error: already canceled error if proposal action status is already canceled
func (p *ProposalActionStatusResolver) Execute(
	executedAt, executedHeight int64,
	executedBy address,
) error {
	// Only executable proposals can be executed (text proposals cannot)
	if !p.IsExecutable() {
		return errProposalNotExecutable
	}

	if p.Canceled() {
		return errAlreadyCanceledProposal
	}

	// Record execution details
	p.SetExecuted(true)
	p.SetExecutedAt(executedAt)
	p.SetExecutedHeight(executedHeight)
	p.SetExecutedBy(executedBy)

	return nil
}

