type ProposalScheduleStatusResolver struct {
	*governance.ProposalScheduleStatus
}

func NewProposalScheduleStatusResolver(status *governance.ProposalScheduleStatus) *ProposalScheduleStatusResolver {
	return &ProposalScheduleStatusResolver{status}
}

// IsPassedCreatedAt checks if the current time has passed the proposal creation time.
// This is always true once a proposal exists.
//
// Parameters:
//   - current: timestamp to check against
//
// Returns:
//   - bool: true if current time is at or after creation time
func (p *ProposalScheduleStatusResolver) IsPassedCreatedAt(current int64) bool {
	return p.CreateTime() <= current
}

// IsPassedActiveAt checks if the current time has passed the voting start time.
// When true, the proposal enters its active voting period.
//
// Parameters:
//   - current: timestamp to check against
//
// Returns:
//   - bool: true if voting period has started
func (p *ProposalScheduleStatusResolver) IsPassedActiveAt(current int64) bool {
	return p.ActiveTime() <= current
}

// IsPassedVotingEndedAt checks if the current time has passed the voting end time.
// When true, no more votes can be cast on the proposal.
//
// Parameters:
//   - current: timestamp to check against
//
// Returns:
//   - bool: true if voting period has ended
func (p *ProposalScheduleStatusResolver) IsPassedVotingEndedAt(current int64) bool {
	return p.VotingEndTime() <= current
}

// IsPassedExecutableAt checks if the current time has passed the execution start time.
// When true, approved proposals can be executed (after execution delay).
//
// Parameters:
//   - current: timestamp to check against
//
// Returns:
//   - bool: true if execution window has started
func (p *ProposalScheduleStatusResolver) IsPassedExecutableAt(current int64) bool {
	return p.ExecutableTime() <= current
}

// IsPassedExpiredAt checks if the current time has passed the execution expiration time.
// When true, the proposal can no longer be executed and has expired.
//
// Parameters:
//   - current: timestamp to check against
//
// Returns:
//   - bool: true if execution window has expired
func (p *ProposalScheduleStatusResolver) IsPassedExpiredAt(current int64) bool {
	return p.ExpiredTime() <= current
}

// NewProposalScheduleStatus creates a new schedule status with calculated timestamps.
// This constructor takes the governance timing parameters and calculates all
// important timestamps for the proposal's lifecycle.
//
// Parameters:
//   - votingStartDelay: delay before voting starts (seconds)
//   - votingPeriod: duration of voting period (seconds)
//   - executionDelay: delay before execution can start (seconds)
//   - executionWindow: window during which execution is allowed (seconds)
//   - createdAt: timestamp when proposal was created
//
// Returns:
//   - *ProposalScheduleStatus: new schedule status with calculated times
func NewProposalScheduleStatus(
	votingStartDelay,
	votingPeriod,
	executionDelay,
	executionWindow,
	createdAt int64,
) *governance.ProposalScheduleStatus {
	// Calculate all phase timestamps based on creation time and configuration
	createTime := createdAt
	activeTime := safeAddInt64(createTime, votingStartDelay)      // When voting can start
	votingEndTime := safeAddInt64(activeTime, votingPeriod)       // When voting ends
	executableTime := safeAddInt64(votingEndTime, executionDelay) // When execution can start
	expiredTime := safeAddInt64(executableTime, executionWindow)  // When execution window closes

	return governance.NewProposalScheduleStatus(createTime, activeTime, votingEndTime, executableTime, expiredTime)
}

package v1

import (
	"gno.land/r/gnoswap/gov/governance"
)

type ProposalStatusResolver struct {
	*governance.ProposalStatus
	scheduleResolver     *ProposalScheduleStatusResolver
	actionStatusResolver *ProposalActionStatusResolver
	voteStatusResolver   *ProposalVoteStatusResolver
}

func NewProposalStatusResolver(status *governance.ProposalStatus) *ProposalStatusResolver {
	return &ProposalStatusResolver{
		ProposalStatus:       status,
		scheduleResolver:     NewProposalScheduleStatusResolver(status.Schedule()),
		actionStatusResolver: NewProposalActionStatusResolver(status.ActionStatus()),
		voteStatusResolver:   NewProposalVoteStatusResolver(status.VoteStatus()),
	}
}

// TotalVoteWeight returns the total weight of all votes cast.
//
// Returns:
//   - int64: total vote weight
func (p *ProposalStatusResolver) TotalVoteWeight() int64 {
	return p.voteStatusResolver.TotalVoteWeight()
}

// StatusType determines the current status of the proposal based on timing, voting, and actions.
// This is the main status calculation method that considers all factors.
//
// Parameters:
//   - current: current timestamp to evaluate status at
//
// Returns:
//   - ProposalStatusType: current status of the proposal
func (p *ProposalStatusResolver) StatusType(current int64) governance.ProposalStatusType {
	actionStatus := p.ActionStatus()

	// Check action-based statuses first (these override time-based statuses)
	if actionStatus.IsExecuted() {
		return governance.StatusExecuted
	}

	if actionStatus.Canceled() {
		return governance.StatusCanceled
	}

	// Check time-based statuses
	if !p.scheduleResolver.IsPassedActiveAt(current) {
		return governance.StatusUpcoming
	}

	if !p.scheduleResolver.IsPassedVotingEndedAt(current) {
		return governance.StatusActive
	}

	// Check voting outcome after voting period ends
	if p.voteStatusResolver.IsRejected() {
		return governance.StatusRejected
	}

	// For passed proposals, check execution status
	if !p.ActionStatus().IsExecutable() || !p.scheduleResolver.IsPassedExecutableAt(current) {
		return governance.StatusPassed
	}

	if !p.scheduleResolver.IsPassedExpiredAt(current) {
		return governance.StatusExecutable
	}

	return governance.StatusExpired
}

// IsUpcoming checks if the proposal is in upcoming status.
//
// Parameters:
//   - current: timestamp to check status at
//
// Returns:
//   - bool: true if proposal is upcoming
func (p *ProposalStatusResolver) IsUpcoming(current int64) bool {
	return p.StatusType(current) == governance.StatusUpcoming
}

// IsActive checks if the proposal is in active voting status.
//
// Parameters:
//   - current: timestamp to check status at
//
// Returns:
//   - bool: true if proposal is active (voting period)
func (p *ProposalStatusResolver) IsActive(current int64) bool {
	return p.StatusType(current) == governance.StatusActive
}

// IsPassed checks if the proposal has passed voting.
//
// Parameters:
//   - current: timestamp to check status at
//
// Returns:
//   - bool: true if proposal has passed
func (p *ProposalStatusResolver) IsPassed(current int64) bool {
	return p.StatusType(current) == governance.StatusPassed
}

// IsRejected checks if the proposal has been rejected by voting.
//
// Parameters:
//   - current: timestamp to check status at
//
// Returns:
//   - bool: true if proposal was rejected
func (p *ProposalStatusResolver) IsRejected(current int64) bool {
	return p.StatusType(current) == governance.StatusRejected
}

// IsExecutable checks if the proposal is in executable status.
//
// Parameters:
//   - current: timestamp to check status at
//
// Returns:
//   - bool: true if proposal can be executed
func (p *ProposalStatusResolver) IsExecutable(current int64) bool {
	return p.StatusType(current) == governance.StatusExecutable
}

// IsExpired checks if the proposal execution window has expired.
//
// Parameters:
//   - current: timestamp to check status at
//
// Returns:
//   - bool: true if proposal has expired
func (p *ProposalStatusResolver) IsExpired(current int64) bool {
	return p.StatusType(current) == governance.StatusExpired
}

// IsExecuted checks if the proposal has been executed.
//
// Parameters:
//   - current: timestamp to check status at
//
// Returns:
//   - bool: true if proposal has been executed
func (p *ProposalStatusResolver) IsExecuted(current int64) bool {
	return p.StatusType(current) == governance.StatusExecuted
}

// IsCanceled checks if the proposal has been canceled.
//
// Parameters:
//   - current: timestamp to check status at
//
// Returns:
//   - bool: true if proposal has been canceled
func (p *ProposalStatusResolver) IsCanceled(current int64) bool {
	return p.StatusType(current) == governance.StatusCanceled
}

// cancel marks the proposal as canceled with the provided details.
// This delegates to the action status for actual cancellation logic.
//
// Parameters:
//   - canceledAt: timestamp when proposal was canceled
//   - canceledHeight: block height when proposal was canceled
//   - canceledBy: address that canceled the proposal
//
// Returns:
//   - error: cancellation error if operation fails
func (p *ProposalStatusResolver) cancel(canceledAt int64, canceledHeight int64, canceledBy address) error {
	return p.actionStatusResolver.cancel(canceledAt, canceledHeight, canceledBy)
}

// execute marks the proposal as executed with the provided details.
// This delegates to the action status for actual execution logic.
//
// Parameters:
//   - executedAt: timestamp when proposal was executed
//   - executedHeight: block height when proposal was executed
//   - executedBy: address that executed the proposal
//
// Returns:
//   - error: execution error if operation fails
func (p *ProposalStatusResolver) execute(executedAt int64, executedHeight int64, executedBy address) error {
	return p.actionStatusResolver.Execute(executedAt, executedHeight, executedBy)
}

// vote records a vote on the proposal and updates vote tallies.
// This delegates to the vote status for actual vote recording.
//
// Parameters:
//   - votedYes: true for "yes" vote, false for "no" vote
//   - weight: voting weight to apply
//
// Returns:
//   - error: voting error if operation fails
func (p *ProposalStatusResolver) vote(votedYes bool, weight int64) error {
	if votedYes {
		return p.voteStatusResolver.AddYesVoteWeight(weight)
	}

	return p.voteStatusResolver.AddNoVoteWeight(weight)
}

// NewProposalStatus creates a new proposal status with the specified configuration.
// This initializes all status components with the governance configuration and timing.
//
// Parameters:
//   - config: governance configuration to use
//   - maxVotingWeight: maximum voting weight for this proposal
//   - executable: whether this proposal type can be executed
//   - createdAt: timestamp when proposal was created
//
// Returns:
//   - *ProposalStatus: new proposal status instance
func NewProposalStatus(
	config governance.Config,
	maxVotingWeight int64,
	executable bool,
	createdAt int64,
) *governance.ProposalStatus {
	schedule := NewProposalScheduleStatus(
		config.VotingStartDelay,
		config.VotingPeriod,
		config.ExecutionDelay,
		config.ExecutionWindow,
		createdAt,
	)
	actionStatus := governance.NewProposalActionStatus(executable)

	// Calculate the quorum amount based on the max voting weight and quorum percentage
	quorumAmount := safeMulDiv(maxVotingWeight, config.Quorum, 100)
	voteStatus := governance.NewProposalVoteStatus(maxVotingWeight, quorumAmount)

	return governance.NewProposalStatusBy(schedule, actionStatus, voteStatus)
}

package v1

import (
	"gno.land/r/gnoswap/gov/governance"
)

type ProposalVoteStatusResolver struct {
	*governance.ProposalVoteStatus
}

func NewProposalVoteStatusResolver(voteStatus *governance.ProposalVoteStatus) *ProposalVoteStatusResolver {
	return &ProposalVoteStatusResolver{voteStatus}
}

// TotalVoteWeight returns the total weight of all votes cast (yes + no).
//
// Returns:
//   - int64: combined weight of all votes
func (p *ProposalVoteStatusResolver) TotalVoteWeight() int64 {
	return safeAddInt64(p.YesWeight(), p.NoWeight())
}

// DiffVoteWeight returns the absolute difference between yes and no votes.
// This can be used to determine the margin of victory or defeat.
//
// Returns:
//   - int64: absolute difference between yes and no vote weights
func (p *ProposalVoteStatusResolver) DiffVoteWeight() int64 {
	yes := p.YesWeight()
	no := p.NoWeight()
	if yes > no {
		return safeSubInt64(yes, no)
	}

	return safeSubInt64(no, yes)
}

// IsVotingFinished determines if voting has effectively ended due to mathematical impossibility
// of changing the outcome. This happens when the remaining uncast votes cannot change the result.
//
// Returns:
//   - bool: true if voting outcome is mathematically determined
func (p *ProposalVoteStatusResolver) IsVotingFinished() bool {
	totalVotes := p.TotalVoteWeight()

	// If we haven't reached quorum yet, voting is not finished
	if totalVotes < p.QuorumAmount() {
		return false
	}

	// Calculate remaining votes that could still be cast
	remainingVotes := safeSubInt64(p.MaxVotingWeight(), totalVotes)

	// If the difference between yes/no is greater than remaining votes,
	// the outcome cannot change, so voting is effectively finished
	return safeSubInt64(remainingVotes, p.DiffVoteWeight()) <= 0
}

// IsRejected determines if the proposal has been rejected by voting.
// A proposal is rejected if voting is finished and it did not pass.
//
// Returns:
//   - bool: true if proposal has been rejected
func (p *ProposalVoteStatusResolver) IsRejected() bool {
	// Only consider rejection if voting is finished
	if !p.IsVotingFinished() {
		return false
	}

	// Proposal is rejected if it didn't pass
	return !p.IsPassed()
}

// IsPassed determines if the proposal has passed the voting requirements.
// A proposal passes if it receives at least the quorum amount of "yes" votes.
func (p *ProposalVoteStatusResolver) IsPassed() bool {
    return p.YesWeight() >= p.QuorumAmount()
}

// addYesVoteWeight adds the specified weight to the "yes" vote tally.
// This is called when a user votes "yes" on the proposal.
//
// Parameters:
//   - yea: vote weight to add to "yes" votes
//
// Returns:
//   - error: always nil (reserved for future validation)
func (p *ProposalVoteStatusResolver) AddYesVoteWeight(yea int64) error {
	p.SetYesWeight(safeAddInt64(p.YesWeight(), yea))
	return nil
}

// addNoVoteWeight adds the specified weight to the "no" vote tally.
// This is called when a user votes "no" on the proposal.
//
// Parameters:
//   - nay: vote weight to add to "no" votes
//
// Returns:
//   - error: always nil (reserved for future validation)
func (p *ProposalVoteStatusResolver) AddNoVoteWeight(nay int64) error {
	p.SetNoWeight(safeAddInt64(p.NoWeight(), nay))
	return nil
}

package v1

import (
	"encoding/base64"
	"math"
	"strconv"
	"strings"

	"gno.land/p/nt/ufmt"
)

// b64Encode encodes a string to base64.
func b64Encode(data string) string {
	return base64.StdEncoding.EncodeToString([]byte(data))
}

// formatInt formats an integer to a string.
func formatInt(v any) string {
	switch v := v.(type) {
	case int8:
		return strconv.FormatInt(int64(v), 10)
	case int32:
		return strconv.FormatInt(int64(v), 10)
	case int64:
		return strconv.FormatInt(v, 10)
	default:
		panic(ufmt.Sprintf("invalid type: %T", v))
	}
}

// formatBool formats a boolean to a string.
func formatBool(v bool) string {
	return strconv.FormatBool(v)
}

// numberKind represents the type of number to parse.
type numberKind int

const (
	kindInt numberKind = iota
	kindInt64
	kindUint64
)

// parseNumber parses a string to a number (int, int64, or uint64) with proper validation.
func parseNumber(s string, kind numberKind) any {
	if len(strings.TrimSpace(s)) == 0 {
		panic(ufmt.Sprint("invalid number value: empty or whitespace string"))
	}

	switch kind {
	case kindInt:
		num, err := strconv.ParseInt(s, 10, 64)
		if err != nil {
			panic(ufmt.Sprintf("invalid int value: %s", s))
		}
		return int(num)
	case kindInt64:
		num, err := strconv.ParseInt(s, 10, 64)
		if err != nil {
			panic(ufmt.Sprintf("invalid int64 value: %s", s))
		}
		return num
	case kindUint64:
		num, err := strconv.ParseUint(s, 10, 64)
		if err != nil {
			panic(ufmt.Sprintf("invalid uint64 value: %s", s))
		}
		return num
	default:
		panic(ufmt.Sprintf("unsupported number kind: %v", kind))
	}
}

// parseBool parses a string to a boolean.
func parseBool(s string) bool {
	if len(strings.TrimSpace(s)) == 0 {
		panic(ufmt.Sprint("invalid bool value: empty or whitespace string"))
	}

	switch s {
	case "true":
		return true
	case "false":
		return false
	default:
		panic(ufmt.Sprintf("invalid bool value: %s", s))
	}
}

// parseInt parses a string to int with proper validation and overflow checking.
func parseInt(s string) int {
	if len(strings.TrimSpace(s)) == 0 {
		panic(ufmt.Sprint("invalid int value: empty or whitespace string"))
	}

	num, err := strconv.ParseInt(s, 10, 64)
	if err != nil {
		panic(ufmt.Sprintf("invalid int value: %s", s))
	}

	const maxInt = int(^uint(0) >> 1)
	const minInt = -maxInt - 1

	if num > int64(maxInt) || num < int64(minInt) {
		panic(ufmt.Sprintf("int overflow: value %d exceeds int range [%d, %d]", num, minInt, maxInt))
	}

	return int(num)
}

// parseInt64 parses a string to int64 with proper validation.
func parseInt64(s string) int64 {
	if len(strings.TrimSpace(s)) == 0 {
		panic(ufmt.Sprint("invalid int64 value: empty or whitespace string"))
	}

	num, err := strconv.ParseInt(s, 10, 64)
	if err != nil {
		panic(ufmt.Sprintf("invalid int64 value: %s", s))
	}

	return num
}

// parseUint64 parses a string to uint64 with proper validation.
func parseUint64(s string) uint64 {
	if len(strings.TrimSpace(s)) == 0 {
		panic(ufmt.Sprint("invalid uint64 value: empty or whitespace string"))
	}

	num, err := strconv.ParseUint(s, 10, 64)
	if err != nil {
		panic(ufmt.Sprintf("invalid uint64 value: %s", s))
	}

	return num
}

// safeAddInt64 performs safe addition of int64 values, panicking on overflow or underflow
func safeAddInt64(a, b int64) int64 {
	if a > 0 && b > math.MaxInt64-a {
		panic("int64 addition overflow")
	}
	if a < 0 && b < math.MinInt64-a {
		panic("int64 addition underflow")
	}
	return a + b
}

// safeSubInt64 performs safe subtraction of int64 values, panicking on overflow or underflow
func safeSubInt64(a, b int64) int64 {
	if b > 0 && a < math.MinInt64+b {
		panic("int64 subtraction underflow")
	}
	if b < 0 && a > math.MaxInt64+b {
		panic("int64 subtraction overflow")
	}
	return a - b
}

// safeMulDiv performs safe multiplication and division: (a * b) / c
// Prevents overflow in multiplication step by checking bounds
func safeMulDiv(a, b, c int64) int64 {
	if c == 0 {
		panic("division by zero in safeMulDiv")
	}

	// Check for multiplication overflow
	// If a * b would overflow, we need to be careful
	if a != 0 && b != 0 {
		// Check if multiplication would overflow
		if a > 0 && b > 0 && a > math.MaxInt64/b {
			panic("int64 multiplication overflow in safeMulDiv")
		}
		if a > 0 && b < 0 && b < math.MinInt64/a {
			panic("int64 multiplication underflow in safeMulDiv")
		}
		if a < 0 && b > 0 && a < math.MinInt64/b {
			panic("int64 multiplication underflow in safeMulDiv")
		}
		if a < 0 && b < 0 && a < math.MaxInt64/b {
			panic("int64 multiplication overflow in safeMulDiv")
		}
	}

	result := (a * b) / c

	return result
}

package v1

import (
	"gno.land/r/gnoswap/gov/governance"
)

type VotingInfoResolver struct {
	*governance.VotingInfo
}

func NewVotingInfoResolver(votingInfo *governance.VotingInfo) *VotingInfoResolver {
	return &VotingInfoResolver{
		VotingInfo: votingInfo,
	}
}

// voteYes records a "yes" vote with the specified weight and timing information.
// This is an internal helper method that delegates to the main vote function.
//
// Parameters:
//   - weight: voting weight to use for this vote
//   - votedHeight: block height when vote is cast
//   - votedAt: timestamp when vote is cast
//
// Returns:
//   - error: voting error if vote cannot be recorded
func (v *VotingInfoResolver) voteYes(weight int64, votedHeight int64, votedAt int64) error {
	return v.vote(true, weight, votedHeight, votedAt)
}

// voteNo records a "no" vote with the specified weight and timing information.
// This is an internal helper method that delegates to the main vote function.
//
// Parameters:
//   - weight: voting weight to use for this vote
//   - votedHeight: block height when vote is cast
//   - votedAt: timestamp when vote is cast
//
// Returns:
//   - error: voting error if vote cannot be recorded
func (v *VotingInfoResolver) voteNo(weight int64, votedHeight int64, votedAt int64) error {
	return v.vote(false, weight, votedHeight, votedAt)
}

// vote records a vote with the specified choice, weight, and timing information.
// This is the core voting method that prevents double voting and records all vote details.
//
// Parameters:
//   - votedYes: true for "yes" vote, false for "no" vote
//   - weight: voting weight to use for this vote
//   - votedHeight: block height when vote is cast
//   - votedAt: timestamp when vote is cast
//
// Returns:
//   - error: voting error if user has already voted
func (v *VotingInfoResolver) vote(votedYes bool, weight int64, votedHeight int64, votedAt int64) error {
	// Prevent double voting - each user can only vote once per proposal
	if v.IsVoted() {
		return errAlreadyVoted
	}

	// Record all voting details
	v.SetVotedWeight(weight)
	v.SetVotedHeight(votedHeight)
	v.SetVotedAt(votedAt)
	v.SetVoted(true)
	v.SetVotedYes(votedYes)

	return nil
}

